window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["a"]={"Andrzej": "<b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Adam": "<b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Antoni": "<b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Artur": "<b>Artur</b> wymowa – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Powstało ze złożenia dwóch wyrazów wywodzących się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">języków celtyckich</a>: <i>Art</i> – niedźwiedź, <i>ur</i> – młody, piękny, kwitnący. Podstawę imienia może także stanowić celtyckie słowo ard – wysoki, szlachetny.", "Aleksander": "<b>Aleksander</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἀλέξανδρος, <i>aleksandros</i> – obrońca ludzi) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> składające się z dwóch członów: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;αλέξειν (bronić, wspomagać) i ἀνδρός (od ἀνήρ – mąż, mężczyzna). Całość bywa interpretowana jako „broniący mężów, troszczący się o mężów, opiekujący się mężami”.", "Adrian": "<b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Arkadiusz": "<b>Arkadiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa Αρκαδικóς (Arkadikós) oznaczającego „pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Arkadia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Arkadii</a>”.", "Andrii": "<p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Alan": "<b>Alan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia najprawdopodobniej <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Może też wywodzić się od nazwy irańskiego plemienia <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alanów</a>. Znaczenie tego imienia nie jest dokładnie znane, prawdopodobne znaczenia:", "Albert": "<b>Albert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających <i>adal</i> (ród szlachecki) i <i>beraht</i> (jasny, błyszczący), oznaczało „pochodzącego ze szlachetnego rodu”. Jest zredukowaną formą staroniemieckiego imienia <i>Athalbraht</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbert</a>). Alternatywną wersją Alberta jest <i><b>Olbracht</b></i> – por. <a href=\"https://pl.wikipedia.org/wiki/Jan_I_Olbracht\" target=\"_blank\" rel=\"noopener noreferrer\">Jan I Olbracht</a>, król Polski.", "Aliaksandr": "<p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Alexander": "<p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Alojzy": "<b>Alojzy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa <i>alwisi</i> oznaczającego „mądry”. Popularne od <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII wieku</a>. Na gruncie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskim</a> imię to zidentyfikowało się z imieniem <a href=\"https://pl.wikipedia.org/wiki/Ludwik\" target=\"_blank\" rel=\"noopener noreferrer\">Ludwik</a> (Chlodowich, Chlodwich) i przyjęło formę <i>Louis</i>, a w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">języku włoskim</a> <i>Luigi</i> (również <i>Aloisio</i>).", "Alfred": "<b>Alfred</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „mądry jak <a href=\"https://pl.wikipedia.org/wiki/Elf_(fantastyka)\" target=\"_blank\" rel=\"noopener noreferrer\">Elf</a>”.", "Anatolii": "<p>Anatolii (rosyjski: Анатолий, romanizowany: Anatoliy, ukraiński: Анато́лій, romanized: Anatolii) jest powszechną rosyjską i ukraińską nazwą męską, pochodzącą z greckiego imienia Anatolios (⁇ νατόλιος), co oznacza \"on wschodu słońca\", z ἀνατολή anatolē, \"wychod słońca\". Anatoly było jednym z pięciu najpopularniejszych imion dla chłopców urodzonych w St.</p>", "Anton": "<p>Anton (niem. Anton) z nazwiska Anton Dobry (niem.</p>", "Alex": "<p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Aleks": "<b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Augustyn": "<b>Augustyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od łac. <i>Augustinus</i>, utworzone od przydomka ‘Augustus’, nadanego <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawianowi</a> przez senat, oznaczające „należący do <a href=\"https://pl.wikipedia.org/wiki/August_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Augusta</a>”.", "Aliaksei": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksy</b>.</p><b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Ariel": "<b>Ariel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֲרִיאֵל&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> słów oznaczających „lew Boga”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> używane było jako alternatywna nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolima</a>.", "Aleksy": "<b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Amadeusz": "<b>Amadeusz</b> lub <b>Amedeusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Amadeus</i>, powstałego w kręgach zakonnych. Wywodzi się od słów <i>amare</i> (kochać), oraz <i>Deus</i> (Bóg), co oznacza „kochający Boga”.", "Albin": "<b>Albin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „biały”. Ponadto istnieje germańskie imię <a href=\"https://pl.wikipedia.org/wiki/Albwin\" target=\"_blank\" rel=\"noopener noreferrer\">Albwin</a> (Albuin), od którego forma skrócona może być jednakowa z imieniem Albin.", "Andriy": "<p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Arnold": "<b>Arnold</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Stanowi złożenie członów oznaczających „orzeł” i „panujący”. Jednym z patronów tego imienia w Kościele katolickim jest <a href=\"https://pl.wikipedia.org/wiki/Arnold_Janssen\" target=\"_blank\" rel=\"noopener noreferrer\">Arnold Janssen</a>.", "Adolf": "<b>Adolf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów: <i>adal</i> – „szlachetny” oraz <i>wolf</i> – „wilk”. W Polsce imię to spotykane jest od XII–XIII w. Inne formy: Adulf, Odolf. Od tego imienia wywodzi się także imię Ado (Adon, Addo, Addon), będące jego zdrobnieniem.", "Anthony": "<p>Anthony może odnosić się do: Anthony Hopkins Anthony Giddens Anthony van Dyck</p>", "Alfons": "<b>Alfons</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe ze złożenia członów <i>al</i> („cały”) lub <i>adal</i> („szlachetny ród”) oraz <i>funs</i> („szybki, chętny, życzliwy”). Imię to zostało spopularyzowane w Polsce w <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a> przez zakon <a href=\"https://pl.wikipedia.org/wiki/Redemptory%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">redemptorystów</a>, którego założycielem był św. <a href=\"https://pl.wikipedia.org/wiki/Alfons_Maria_Liguori\" target=\"_blank\" rel=\"noopener noreferrer\">Alfons Maria Liguori</a>. Popularność Alfonsa następnie spadła po przedstawieniu komedii <a href=\"https://pl.wikipedia.org/wiki/Alexandre_Dumas_(syn)\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Dumasa syna</a> „Monsieur Alphonse” z 1873 r., pod wpływem której <i>alfons</i> w roli rzeczownika pospolitego zyskał w Polsce znaczenie <i><a href=\"https://pl.wikipedia.org/wiki/Sutenerstwo\" target=\"_blank\" rel=\"noopener noreferrer\">sutener</a></i>. Taka konotacja imienia Alfons nie ma charakteru ogólnoświatowego i np. w <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpanii</a>, w której imię to nosiło kilkunastu królów (d. prowincji hiszpańskich), również obecnie imię to jest dość często spotykane.", "Artsiom": "<p>Artsyom (bieloruska: Арцём), również przetransliterowany jako Artsiom, jest popularną nazwą męską w Białorusi. Jest to wersja nazwy Artem/Artyom.</p>", "Antonio": "<p>Antonio James Uri (włoski: Antonio James Uri)  Antonio jest angielski.</p>", "Ali": "<b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Arsen": "<p>Arsen (na armeńsku, Արսեն; gruzińsku, არსენ; rosyjski, Арсен; ukraiński, Арсен) jest nazwiskiem, diminutiwem greckiego Arsenios. Do wybitnych osób z tym nazwiskiem należą: Arsen Akayev (ur. 1970), Kumyk-Roski trener i były gracz piłki nożnej Arsen Avakov (ur. 1964), ukraiński polityk Arsen Awakov (ur., 1971), były tajczyk piłkarz piłkarza Arsen Avetisyan (ur. 1973), armenijski piłkarze piłkarzy Arsen Aydinian (1825-1902), armeni...</p>", "Anatol": "<b>Anatol</b>, <b>Anatoliusz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;ἀνατολικός – pochodzący ze Wschodu; analogiczne pochodzenie ma nazwa <a href=\"https://pl.wikipedia.org/wiki/Anatolia\" target=\"_blank\" rel=\"noopener noreferrer\">Anatolii</a>, krainy w Azji Mniejszej) – męskie imię pochodzenia greckiego.", "Andreas": "Jest to młody Szwajcar polskiego pochodzenia. To jedyna osoba, z którą <a href=\"https://pl.wikipedia.org/wiki/Stefan_P%C4%99ka%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan Pękała</a> miał możliwość nawiązać bliższy kontakt w <a href=\"https://pl.wikipedia.org/wiki/Zurych\" target=\"_blank\" rel=\"noopener noreferrer\">Zurychu</a>, posługując się językiem polskim.", "Andrew": "<p>Andrew może odnosić się do: Św. Andrew: jeden z dwunastu apostołów Jezusa Andrew Johnson: 17 prezydent Stanów Zjednoczonych i w pełni od 1865 do 1867 roku Andrew Jackson</p>", "Aron": "<p>Aron jest miejscowością i nagar panchayatem Guna w stanie Madhya Pradesh, India.</p>", "Aleksandr": "<p>Aleksander lub Aleksandr może odnosić się do Aleksandra Michajłowicza Zaitsewa Aleksandr Valterovich Litvinenko Aleksandr II Rosji Aleksandr Grin Aleksandr Isayevich Solzhenitsyn Aleksandr Danilovich Menshikov</p>", "Alexandr": "<p>Aleksander lub Aleksandr może odnosić się do Aleksandra Michajłowicza Zaitsewa Aleksandr Valterovich Litvinenko Aleksandr II Rosji Aleksandr Grin Aleksandr Isayevich Solzhenitsyn Aleksandr Danilovich Menshikov</p>", "August": "<b>August</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przymiotnika <i>augustus</i>, nadanego jako przydomek <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawianowi</a> przez Senat i oznaczającego „dostojny, boski, majestatyczny, poświęcony, święty, czcigodny, pomyślny, wzniosły”. Przymiotnik ten pochodzi od rzeczownika <i>augur</i> i pierwotnie odnosił się tylko do rzeczy, tłumacząc się jako „uświęcony przez (dobre) przepowiednie, znaki” lub „przedsięwzięty pod sprzyjającymi znakami”. Po raz pierwszy imię August zostało poświadczone w Polsce w <a href=\"https://pl.wikipedia.org/wiki/1349\" target=\"_blank\" rel=\"noopener noreferrer\">1349</a> roku, w łac. formie <i>Augustus</i>.", "Andres": "<p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Arsenii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arseniusz</b>.</p><b>Arseniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa ἀρσεν (<i>arsen</i>) oznaczającego „męski”.", "Ahmed": "<b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Alejandro": "<p>Alejandro - hiszpańska forma imienia Aleksandra.</p>", "Alexandru": "<p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Arthur": "<p>Arthur - męskie imię.</p>", "Aaron": "<b>Aaron</b>, <b>Aron</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> Aharon <b>אַהֲרֹן</b> – możliwa <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologia</a> <i>oświecony</i>, <i>wywyższony</i>, być może imię pochodzenia egipskiego) – <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijne</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Nosił je starszy brat i pomocnik <a href=\"https://pl.wikipedia.org/wiki/Moj%C5%BCesz\" target=\"_blank\" rel=\"noopener noreferrer\">Mojżesza</a> i <a href=\"https://pl.wikipedia.org/wiki/Miriam_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Miriam</a> (<i>zobacz <a href=\"https://pl.wikipedia.org/wiki/Aaron_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Aaron (postać biblijna)</a>).</i> Wśród świętych – m.in. św. Aaron, męczennik (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Amir": "<b>Amir</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أمير&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „książę” lub „dowódca”.", "Aureliusz": "<b>Aureliusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od nazwy rzymskiego rodu Aurelia, która z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <i>aureolus</i> – \"złocisty\", co mogło znaczyć także \"wspaniały\". Imię to posiada licznych świętych patronów.", "Alexandre": "<p>Alexandre Dumas może odnosić się do: Alexandre Dumas Alexandre Yersin Alexandre de Rhodes Alexandre Varenne Alexandre Dumas syn Alexandre Pato Alexandre Sabès Pétion</p>", "Allan": "<p>Harry Howard Barton Allan (27 kwietnia 1882 - 29 października 1957) - nowozelandski botanik.</p>", "Andrey": "<p>Andrey (Андрей) to męskie imię, które jest używane głównie w językach słowiańskich, w tym białoruskim, bułgarskim i rosyjskim. Nazwa pochodzi od starożytnego greckiego Andrzeja (⁇ νδρέας), co oznacza \"człowiek\" lub \"wojownik\".</p>", "Anatoliy": "<p>Anatolii (rosyjski: Анатолий, romanizowany: Anatoliy, ukraiński: Анато́лій, romanized: Anatolii) jest powszechną rosyjską i ukraińską nazwą męską, pochodzącą z greckiego imienia Anatolios (⁇ νατόλιος), co oznacza \"on wschodu słońca\", z ἀνατολή anatolē, \"wychod słońca\". Anatoly było jednym z pięciu najpopularniejszych imion dla chłopców urodzonych w St.</p>", "Aleksei": "<p>Alexey (rosyjski: Алексей, romanized: Aleksey [ɐljɪkˈsjej]) to rosyjskie imię męskie pochodzące od greckiego Aléxios (Αλέξιος), co oznacza \"Obrannik\", a zatem z tego samego pochodzenia jak łacina Alexius. Podobne ukraińskie i białoruskie nazwy są romanizowane odpowiednio jako Oleksii (Олексій) i Aliaksiej (Аляксей).</p>", "Angelo": "<p>Angelo, 1185 r., Jerozolimy, Judu - 5.05.1225 r., Licata, Sycylia, Włochy) - święty kościół rzymsko-katolicki, mnich ordynu karmelitów (OCarm), męczennik.</p>", "Aleksandre": "<p>Aleksandre (georgijski: ალექსანდრე) to gruzińskie imię męskie, równoważne z Aleksandrem, co oznacza \"obrony mężczyzn\". Według Sal Służby Publicznej jest to jedna z 10 najczęstszych gruzińskich nazwisk dla mężczyzn.</p>", "Angel": "<p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Ahmad": "<b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Andrea": "<b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Alexei": "<p>Alexey (rosyjski: Алексей, romanized: Aleksey [ɐljɪkˈsjej]) to rosyjskie imię męskie pochodzące od greckiego Aléxios (Αλέξιος), co oznacza \"Obrannik\", a zatem z tego samego pochodzenia jak łacina Alexius. Podobne ukraińskie i białoruskie nazwy są romanizowane odpowiednio jako Oleksii (Олексій) i Aliaksiej (Аляксей).</p>", "André": "<p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Axel": "<p>Akcel (niem. Axel, czyli angielski.</p>", "Armin": "<b>Armin</b> – oboczna forma imienia <a href=\"https://pl.wikipedia.org/wiki/Herman\" target=\"_blank\" rel=\"noopener noreferrer\">Herman</a>.", "Ambroży": "<b>Ambroży</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>ambrósios</i> – boski, nieśmiertelny, święty od <i>(am)brotós</i> – (nie)śmiertelny) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>.", "Apolinary": "<b>Apolinary</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, powstałe od imienia boga <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apollina</a>.", "Amit": "<p>Amit to imię indyjskie i żydowskie oraz żydowskie nazwisko. W języku hindi Amit (Hindi: अमित, oznacza \"nieograniczony\" lub \"bezgraniczny\", Bengali: অমিত) pochodzi od sanskrytyjskiego słowa amita (अमित:), amita (অमित:) jest zasadniczo negatywem mita (मित), co oznacza \"mierzyć\".</p>", "Armen": "<b>Armen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia ormiańskiego, wywodzi się z mitologii ormiańskiej. Skrócona forma imienia Armenak, które wyszło z użycia w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX</a> wieku. Żeński odpowiednik: Armenuhi (zdrobnienie: Armine lub Armina)", "Andre": "<p>André (francuski: André)  André, angielski.</p>", "Alexey": "<p>Alexey (rosyjski: Алексей, romanized: Aleksey [ɐljɪkˈsjej]) to rosyjskie imię męskie pochodzące od greckiego Aléxios (Αλέξιος), co oznacza \"Obrannik\", a zatem z tego samego pochodzenia jak łacina Alexius. Podobne ukraińskie i białoruskie nazwy są romanizowane odpowiednio jako Oleksii (Олексій) i Aliaksiej (Аляксей).</p>", "Abdullah": "<b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Apoloniusz": "<b>Apoloniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od imienia greckiego boga <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apollina</a>. Nosili je między innymi grecki poeta żyjący w <a href=\"https://pl.wikipedia.org/wiki/III_wiek_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">III wieku p.n.e.</a> i matematyk <a href=\"https://pl.wikipedia.org/wiki/Apoloniusz_z_Pergi\" target=\"_blank\" rel=\"noopener noreferrer\">Apoloniusz z Pergi</a>. Istnieją liczni święci o tym imieniu (m.in. <a href=\"https://pl.wikipedia.org/wiki/Ojcowie_Ko%C5%9Bcio%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">Ojcowie Kościoła</a> Apoloniusz z Efezu i Apoloniusz senator). Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Apolonia\" target=\"_blank\" rel=\"noopener noreferrer\">Apolonia</a>.", "Abraham": "<p>Abraham (Abraham) - męskie imię, niemieckie lub angielskie nazwisko, a także toponim. W starych źródłach przekazywano ją jako Abraham.</p>", "Armando": "<p>Armando - pierwszy hiszpański album studiowy (i piąty w dyskografii) repera z Miami Pitbull. Relizja albumu odbyła się 2 listopada 2010 roku.</p>", "Alisher": "<p>Alisher to drugi mini album Morgenschtern, wydany 14 lutego 2025 roku. W mini-albumie weszło 5 utworów o łącznej długości 12 minut 54 sekund.</p>", "Arseni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arsen</b>.</p><p>Arsen (na armeńsku, Արսեն; gruzińsku, არსენ; rosyjski, Арсен; ukraiński, Арсен) jest nazwiskiem, diminutiwem greckiego Arsenios. Do wybitnych osób z tym nazwiskiem należą: Arsen Akayev (ur. 1970), Kumyk-Roski trener i były gracz piłki nożnej Arsen Avakov (ur. 1964), ukraiński polityk Arsen Awakov (ur., 1971), były tajczyk piłkarz piłkarza Arsen Avetisyan (ur. 1973), armenijski piłkarze piłkarzy Arsen Aydinian (1825-1902), armeni...</p>", "Antoine": "<p>Franz Antoine (niem. Franz Antoine, 23 lutego 1815 - 11 marca 1886) - austriacki botanik, artysta i fotograf.</p>", "Antony": "<p>Antony może odnosić się do: Antony (nazwa), męskie imię</p>", "Ali̇": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aly</b>.</p><p>Alexandra Rose ⁇ Eli ⁇ Riceman (ang. Alexandra Rose ⁇ Aly ⁇ Raisman; urodz.</p>", "Anatolie": "<p>Anatolie jest rumuńskim imieniem męskim, używanym głównie w Mołdawii. Do wybitnych osób z nazwiskiem należą: Anatolie (Botnari), biskup Republiki Mołdawii Prawosławnej pod Patriarchatem Moskwim Anatolie Arhire, mołdawski polityk, członek parlamentu Mołdawy od 2009 roku Anatolie Boeștean (ur. 1985), jest mołdawskim piłkarzem Anatolie Cîrîcu (ur. 1988), mołdawska ciężarosta Anatolie Dimitriu (ur. 1973) jest...</p>", "Alon": "<p>ALON (Alon Valerievich Mullayev; ur. 16 lipca 1995, Netania, Izrael) - rosyjski muzykiem, piosenkarzem, artystą, autorem piosenek.</p>", "Andrian": "<p>Andrian (italijsky: Andriano) to gmina w prowincji Bolzano-Bozen w włoskiej regionie Trentino-Alto Adige/Südtirol, znajdująca się około 50 km na północ od miasta Trento i około 9 km na zachód od miasta Bolzano. Na dzień 31 grudnia 2004 roku mieście miało 893 mieszkańców i obszar 4,9 km2.</p>", "Alexis": "<p>Alexis może wskazywać: Alexis de Tocqueville Jacques-Édouard Alexis</p>", "Anil": "<p>Anil to rodzaj roślin kwiatowych z rodziny Białego.</p>", "Armand": "<b>Herman</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „wojownik”. Innym jego wariantem jest <b><a href=\"https://pl.wikipedia.org/wiki/Armin\" target=\"_blank\" rel=\"noopener noreferrer\">Armin</a></b>, natomiast nazwisko <a href=\"https://pl.wikipedia.org/wiki/Menzel\" target=\"_blank\" rel=\"noopener noreferrer\">Menzel</a> stanowi podwójne zdrobnienie imienia Hermann. W średniowiecznej Polsce odnotowywano polskie formy Jerzman i Jirzman.", "Alfonso": "<p>Alfonso jest 3rd classmostem w prowincji Cavite, w Filipinach. Według zeszłej ankiety populacyjnej z Filipin, mieście to liczy 47,973 mieszkańców na obszarze 70 km2.</p>", "Aziz": "<p>Aziz-bi (Azyzkul, Mirza Aziz) (z uzb. Aziz roku, Emirat Bucharsk - 1860, Emirat Bocharsk) - polityk i wojskowy, dyplomat, główny zakjatczy - minister finansów, kuszbeg - premier minister (1837-1860) Emiratu Bucharskiego.</p>", "Arian": "<b>Arian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jego patronem jest św. Arian, wspominany razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Teotyk_(m%C4%99czennik_egipski)\" target=\"_blank\" rel=\"noopener noreferrer\">Teotykiem</a>.", "Alvaro": "<b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Azamat": "<p>Azamat Agraba, Азамат Murzaev (ur. 6 stycznia 1986, Olyochowo, Kalinigradskiej Obs.) - kompozytor i wykonawca z Rosji.</p>", "Andrés": "<b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Anastazy": "<b>Anastazy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „wskrzeszenie”, „zmartwychwstanie”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Anastazja\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazja</a>.", "Amin": "<b>Amin</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Oznacza „godny zaufania” lub „prawdomówny”. Nosił je szósty <a href=\"https://pl.wikipedia.org/wiki/Kalif\" target=\"_blank\" rel=\"noopener noreferrer\">kalif</a> <a href=\"https://pl.wikipedia.org/wiki/Abbasydzi\" target=\"_blank\" rel=\"noopener noreferrer\">abbasydzki</a>.", "Andrij": "<p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Alain": "<p>Alain - rządca Harmoran w latach 1268-1290 z rodu Macруаiri.</p>", "Abel": "<b>Abel</b> (hebr. הבל) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z hebrajskiego <i>abhal</i> – „mgła, dym, tchnienie”. Być może wiązało się jednak z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>aplu || ibil</i> lub asyryjskim <i>ahbla || ablu</i> – „syn rodzony”. Nosiła je <a href=\"https://pl.wikipedia.org/wiki/Kain_i_Abel\" target=\"_blank\" rel=\"noopener noreferrer\">postać biblijna</a>, syn Adama i Ewy, który był pasterzem. Abel został zamordowany przez swego brata Kaina, rolnika. Imię to było notowane na terenie Polski już w średniowieczu, na przełomie <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIV wieku</a>, początkowo jako imię zakonne. Patronem tego imienia w Kościele katolickim są, obok Abla, syna Adama i Ewy, m.in. Abel, biskup Metzu, i <a href=\"https://pl.wikipedia.org/wiki/Abel_z_Reims\" target=\"_blank\" rel=\"noopener noreferrer\">Abel</a>, arcybiskup Reims.", "Amiran": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amirani</b>.</p>Według mitu <a href=\"https://pl.wikipedia.org/wiki/Swanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Swanów</a>, żona myśliwego, w zemście za zdradę męża, zabiła boginię, ścinając jej włosy podczas snu. Myśliwy wydobył dziecko z łona zmarłej matki i nadał mu imię <i>Amirani</i>. Chłopiec miał na ciele znamiona świadczące o jego półboskim pochodzeniu – symbole słońca i księżyca na łopatkach oraz złoty ząb.", "Aram": "<b>Aram</b> – jest to <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie popularne na <a href=\"https://pl.wikipedia.org/wiki/Bliski_Wsch%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Bliskim Wschodzie</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_kurdyjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku kurdyjskim</a> oznacza \"spokojny\". W Polsce nie obchodzi <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imienin</a>. <a href=\"https://pl.wikipedia.org/wiki/Aram_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Aram</a> był według <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> synem <a href=\"https://pl.wikipedia.org/wiki/Sem_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Sema</a> i wnukiem <a href=\"https://pl.wikipedia.org/wiki/Noe\" target=\"_blank\" rel=\"noopener noreferrer\">Noego</a>.", "Adem": "<b>Adem</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie będące <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">sturkizowaną</a> wersją imienia <a href=\"https://pl.wikipedia.org/wiki/Adam\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a>, występujące też jako nazwisko.", "Alessio": "<b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Adil": "<b>Adil</b> – arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od słowa <i>adil</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عدل&#8206;, <i>’adil</i>) – 'sprawiedliwy', 'uczciwy'.", "Arun": "<p>Arun (Mongolski: ⁇ ⁇ Arun qosiɣu, Kirin Mongoli: Арун хошуу; przenoszone: 阿荣旗; subtyp: 阿榮旗; przenośne: Āróng Qí, Hán Việt: A Vinh kỳ) jest okresem urzędu miasta Hulunbuir (Holun Luan Uy), Autonomicznego Obszaru Mongolicznego, Chiny. Miasto graniczy z prowincją Hắc Long Giang na wschodzie i południu i znajduje się 92 km (57 mi) na północno-zachodni od miasta Tề Tề Cápur w prowincji Hắc Long.</p>", "Anh": "<p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Arjun": "<b>Arjun</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskr.</a> <i>अर्जुन</i>) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjski</a> <a href=\"https://pl.wikipedia.org/wiki/Czo%C5%82g_podstawowy\" target=\"_blank\" rel=\"noopener noreferrer\">czołg podstawowy</a>, produkowany od 2004 roku, w <a href=\"https://pl.wikipedia.org/wiki/Armia_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">armii indyjskiej</a> od 2007 roku. Nazwa czołgu pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Ard%C5%BAuna\" target=\"_blank\" rel=\"noopener noreferrer\">Ardźuna</a> - jednego z bohaterów <a href=\"https://pl.wikipedia.org/wiki/Epos\" target=\"_blank\" rel=\"noopener noreferrer\">eposu</a> <i><a href=\"https://pl.wikipedia.org/wiki/Mahabharata\" target=\"_blank\" rel=\"noopener noreferrer\">Mahabharata</a></i>.", "Archil": "<p>Archil (Georgiański: არჩილ) to męskie gruzińskie imię. Do znanych osób z nazwiskiem należy: Archil z Iberii (fl.</p>", "Adriano": "<p>...Adriano (rosyjski Adriano) - zbiór muzyczny włoskiego piosenkarza i aktora filmowego Adriano Chelento, wydany 19 listopada 2013 roku.</p>", "Aleksi": "<p>Aleksi to męskie fińskie imię. Do wybitnych osób z tym nazwiskiem należą: Aleksi Bardy, fiński scenarzysta i producent filmowy Aleksi Benashvili, gruziński piłkarz Aleksi Eeben, fiński kompozytor, projektant dźwięku, muzyk i programista Aleksi Elorinne, fiński hokejista lodowy Aleksi Heimosalmi, fiński gracz lodowy Hihnavaara Aleksi, fiński granicą Aleksi Holmberg, fiński piłka hokeja Aleksi Honka-Hallila, fiński...</p>", "Attila": "<b>Attila</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, szczególnie popularne w Turcji i na <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">Węgrzech</a>, gdzie używa się także formy Etele. Żeński odpowiednik – Etelka.", "Ashot": "<p>Ashot lub Ashod (armeńska: Աշոտ) to armenijska nazwisko. Do znanych osób z nazwą należą:</p>", "Adel": "<p>Adel - wieloznaczny termin.</p>", "Amine": "<p>Aminy są związkami organicznymi, których atomem jest azot (gęstość) w grupie funkcyjnej. Aminy mają podobny konfiguracji, ale w których jeden (lub kilka) atomów wodoru są zastępowane przez grupę alkyl lub inny rodzaj grupy funkcjonalnej zawierającej węgiel (grupa R).</p>", "Anderson": "<p>Anderson - angielskie nazwisko i toponim.</p>", "Allen": "<p>Joel Asaph Allen (ang. Joel Asaph Allan; 19 lipca 1838 - 29 sierpnia 1921) - amerykański ornitolog i teryolog.</p>", "Alexandros": "<p>Alexandros może odnosić się do: Alexandros, greckie imię, pochodzenie angielskiego imienia Alexander Alexandros, Grecja, wioska na wyspie Lefkada Alexandros (band), japoński zespół rockowy</p>", "Aiden": "<p>Aidan, Aiden i Ayden są angielsko złożonymi wersjami irlandzkiego męskiego nazwiska Aodhán. Irlandzką kobiecy odpowiednik jest Aodhnait.</p>", "Agustin": "<p>Agustín to hiszpańskie imię i czasami nazwisko. Jest związany z Augustinem.</p>", "Abhishek": "<p>Abhishek to męskie imię, które ma swoje korzenie w sanskrytycznym słowie abhiseka. Konceptualne znaczenie abhisek jest związane z oczyszczeniem, oczyszczaniem lub pomazanie.</p>", "Artyom": "<p>Artyom (zwany również Artiom; rosyjski: Артём) to rosyjskie imię męskie. Jest związany z nazwiskiem Artemy.</p>", "Akhmed": "<p>Ahmad (arabski: أحمد, romanized: ʾAḥmad) jest arabską nazwą męską powszechną w większości części świata muzułmańskiego, ponieważ jest to jedno z dobrze znanych imion proroka Muhammada. Inne angielskie pisowni nazwy obejmują Ahmed, Ahmmad.</p>", "Andy": "<p>Andranic Madadian (ang. Andranik Madadian, broń.</p>", "Aleksey": "<p>Alexey (rosyjski: Алексей, romanized: Aleksey [ɐljɪkˈsjej]) to rosyjskie imię męskie pochodzące od greckiego Aléxios (Αλέξιος), co oznacza \"Obrannik\", a zatem z tego samego pochodzenia jak łacina Alexius. Podobne ukraińskie i białoruskie nazwy są romanizowane odpowiednio jako Oleksii (Олексій) i Aliaksiej (Аляксей).</p>", "Asif": "<p>Asif (arabski: آصف) to arabskie męskie imię. W językach perskim i urdu często wymawia się jako \"Asif\" lub \"Asef\".</p>", "Adolfo": "<p>21°14′8′′N 49°38′38′′D Adolfo to miasto w São José do Rio Preto, w stanie São Paulo, Brazylia. Miasto zostało założone 30 listopada 1959 roku, ma ludność (w 2007 roku) 3609 osób, obszar 210,843 km2, density ludności 18,9 osób/km2.</p>", "Antek": "<p>Antek to czesko-polska forma Antoni i Antonina, używana w Czechach i Polsce. Nazwa Antoni \"Antek\" Cierplikowski (1885-1976), polski fryzjer Antek Rozpylacz (\"Antek palnik\"), nom-de-guerre Antoni Szczęsny Godlewski (1923-1944) Antek, nom-deguerre Yitzhak Zuckerman, jeden z przywódców Powstania getto Warszawskiego (1915-1981) Imię rodziny Fritz Antek Berger (1900,...</p>", "Alim": "<b>Ulem</b> – muzułmański teolog i uczony. Słowo pochodzi z wyrazu <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> <i>alim</i>, oznaczającego uczonego. W skład grupy ulemów wchodzili wszyscy duchowni muzułmańscy: <a href=\"https://pl.wikipedia.org/wiki/Mufti\" target=\"_blank\" rel=\"noopener noreferrer\">muftiowie</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Imam\" target=\"_blank\" rel=\"noopener noreferrer\">imamowie</a>. Ulemów określa się również mianem znawców <a href=\"https://pl.wikipedia.org/wiki/Szariat\" target=\"_blank\" rel=\"noopener noreferrer\">szariatu</a>. Ich główną siedzibą były <a href=\"https://pl.wikipedia.org/wiki/Meczet\" target=\"_blank\" rel=\"noopener noreferrer\">meczety</a>. Główną rolę posiadał meczet <a href=\"https://pl.wikipedia.org/wiki/Al-Azhar\" target=\"_blank\" rel=\"noopener noreferrer\">al-Azhar</a> w <a href=\"https://pl.wikipedia.org/wiki/Kair\" target=\"_blank\" rel=\"noopener noreferrer\">Kairze</a>.", "Ashok": "<p>Ashok to imię. Może odnosić się do:</p>", "Akmal": "<p>Akmal to nazwisko i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Aidan": "<b>Aidan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia celtyckiego, od staroirlandzkiego <i>Áedán</i> – zdrobniałej formy imienia <i>Áed</i>, oznaczającego „płomień, ogień”. Jest to imię irlandzkiego świętego z <a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII</a> w.", "Alen": "<p>Alen jest konkretną formą genu, która ma określone funkcje genetyczne. Jest to jeden z najważniejszych pojęć w genezie, który jest tłumaczony z angielskiego słowa \"allelu\".</p>", "Aviv": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aviva</b>.</p><p>Aviva plc - brytyjska firma ubezpieczeniowa, jedna z największych na świecie, należąca do kategorii systematycznie istotnych dla światowej gospodarki. Głównymi rynkami dla niej są Wielka Brytania, Irlandia, Kanada i Włochy.</p>", "Anis": "<b>Anisette</b> – <a href=\"https://pl.wikipedia.org/wiki/Likier\" target=\"_blank\" rel=\"noopener noreferrer\">likier</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a> o zawartości alkoholu 25-40%. Jest produkowany z likierów korzennych na bazie <a href=\"https://pl.wikipedia.org/wiki/Biedrzeniec_any%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">anyżu</a>, oliwki anyżowej z dodatkiem aromatu <a href=\"https://pl.wikipedia.org/wiki/Koper_ogrodowy\" target=\"_blank\" rel=\"noopener noreferrer\">kopru</a>, <a href=\"https://pl.wikipedia.org/wiki/Go%C5%BAdziki\" target=\"_blank\" rel=\"noopener noreferrer\">goździków</a>, bądź <a href=\"https://pl.wikipedia.org/wiki/Kolendra_siewna\" target=\"_blank\" rel=\"noopener noreferrer\">kolendry</a>. Alkohol jest często używany z barach jako składnik <a href=\"https://pl.wikipedia.org/wiki/Koktajl_alkoholowy\" target=\"_blank\" rel=\"noopener noreferrer\">koktajli</a>.", "Akhil": "<p>Akhil (w Devanagari: अखिल, IAST: akhila) to imię pochodzenia sanskrytycznego, co oznacza \"całość\" lub \"całość\". Równoważne nazwisko kobiece to Akhila (IAST: akhilā).</p>", "Anas": "<p>Uci rzeki lub uci szlachetne (lat. Anas), to rodzaj ptaków rodziny uci.</p>", "Austin": "<p>Austen (ang. Austin) - angielskojęzyczna nazwisko, toponim i nazwa.</p>", "Abdulaziz": "<p>Abdulaziz (Turk. Abdül'l Azīz, Tur. I. Abdülaziz; 82/1830 - 4 czerwca 1876) był 32. sultanem Cesarstwa Osmańskiego, rządził od 25 czerwca 1861 do 30 maja 1876.</p>", "Akbar": "<p>Akbar (arabski akbar największy) może oznaczać:</p>", "Alwin": "<b>Alwin</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Stanowi skróconą formę imienia <a href=\"https://pl.wikipedia.org/wiki/Albwin\" target=\"_blank\" rel=\"noopener noreferrer\">Albwin</a> lub <a href=\"https://pl.wikipedia.org/wiki/Adalwin\" target=\"_blank\" rel=\"noopener noreferrer\">Adalwin</a>.", "Artak": "<p>Artak (armeńska: Արտակ) to męskie imię pochodzenia irańskiego. Wśród znanych osób zwanych Artakami są: Artak Aleksanyan (ur. 1991), piłkarz Armenia Artak Apitonian (ur. 1971), armejski dyplomat Artak Dashyan (ur. 1989), piłkerz Armen Artak Davtyan (1966-2023), armeński polityk i ekonomista Artak Davtsyan (ur., 1970), armecki major generalny, obecnie 7. szef Sztabu Generalnego...</p>", "Aryan": "<p>\"Arya\" (i jego odmiany) to słowo oznaczające \"rod\" (boże święte) które kiedyś było używane jako samozwa indyjsko-iranijskich narodów. Słowo to zostało użyte przez lud Indy-Arya od czasów wedyjskich w Indiach jako nazwisko dla siebie, a także do osób należących do szlachty i geologicznych regionów Āryāvarta, w których pochodzą indy-Aryanskiej kultury.</p>", "Aharon": "<p>Aharon אַהֲרֹן to męskie imię pierwotnie napisane, powszechnie w Izraelu, z późniejszej wersji Aarona, wybitnej postaci biblijnej w Starym Testamencie, \"Z gór\" lub \"Górnik\". Istnieją inne warianty, w tym \"Ahron\" i \"Aron\".</p>", "Azad": "<b>Azad</b>, właściwie <b>Azad Azadpour</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/24_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">24 listopada</a> <a href=\"https://pl.wikipedia.org/wiki/1973\" target=\"_blank\" rel=\"noopener noreferrer\">1973</a> w <a href=\"https://pl.wikipedia.org/wiki/Sanandad%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">Sanandadżu</a>, <a href=\"https://pl.wikipedia.org/wiki/Iran\" target=\"_blank\" rel=\"noopener noreferrer\">Iran</a>) – niemieckojęzyczny <a href=\"https://pl.wikipedia.org/wiki/Rap\" target=\"_blank\" rel=\"noopener noreferrer\">raper</a> irańsko-kurdyjskiego pochodzenia. Mieszka we <a href=\"https://pl.wikipedia.org/wiki/Frankfurt_nad_Menem\" target=\"_blank\" rel=\"noopener noreferrer\">Frankfurcie nad Menem</a>. Jego imię po kurdyjsku znaczy \"wolny\".", "Anzelm": "<b>Anzelm</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> (<i>ans</i> &lt;<a href=\"https://pl.wikipedia.org/wiki/Azowie\" target=\"_blank\" rel=\"noopener noreferrer\">Azowie</a>&gt; + <i>helm</i> &lt;hełm&gt;, oznacza „strzeżony przez bóstwa”). Imię <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">teoforyczne</a>. W Polsce używane w 1228 r. oraz od XIV w.", "Abram": "<p>Abraham (przesłanie Abraham; hebrajski: אַבְרָהָם, Standard Avraham Ashkenazi Avrohom lub Avruhom Tibr ʾA ⁇ rāhām; arabski: ابراهیم, Ibrāhīm; Ge'ez: አብርሃም, ʾAbrəham), według judaizmu, chrześcijaństwa i islamu, jest ojcem Żydów i Arabów. Bóg powołał Abrahama, aby opuścił swój rodzinną Ur i przyjechał do nowego kraju w Kanaanie.</p>", "Arkady": "<b>Arkady</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Arkadiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Arkadiusz</a>.", "Adalbert": "<b>Adalbert, Adelbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających <i>adal</i> (ród szlachecki) i <i>beraht</i> (jasny, błyszczący), oznaczało „pochodzącego ze szlachetnego rodu”. Występuje w wielu odmianach, np.: <a href=\"https://pl.wikipedia.org/wiki/Albert_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Albert</a>, Olbracht.", "Arnaud": "<p>Arnaud (francuski; zmarł około 900 lub nie później niż listopad 908) - arcybiskup Ambryona (890 - około 900/nie później niż 908).</p>", "Ayman": "<b>Ayman</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> َأيْمَن) – arabskie imię męskie, oznaczające: błogosławiony, szczęśliwy. Bywa zapisywane także jako Ajman, Aiman, Aimen, Aymen.", "Andres Felipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Antoniusz": "<b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Alonso": "<p>Alonso - hiszpańskie imię i nazwisko, gallicko-portugalska wersja imienia Alfonso.</p>", "Arseniusz": "<b>Arseniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa ἀρσεν (<i>arsen</i>) oznaczającego „męski”.", "Amos": "<b>Amos</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> עמוס <i>amos</i> – „mocny, dźwigający ciężary”. Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Amos_(prorok)\" target=\"_blank\" rel=\"noopener noreferrer\">Amos</a>, jeden z dwunastu <a href=\"https://pl.wikipedia.org/wiki/Prorocy_mniejsi\" target=\"_blank\" rel=\"noopener noreferrer\">proroków mniejszych</a>, którego imieniem nazwana jest jedna z ksiąg biblijnych – <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Amosa\" target=\"_blank\" rel=\"noopener noreferrer\">Księga Amosa</a>. Obchodzi <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> <a href=\"https://pl.wikipedia.org/wiki/31_marca\" target=\"_blank\" rel=\"noopener noreferrer\">31 marca</a>.", "Alikhan": "<p>Alikhan, również romanizowany jako Alihan lub Elihan, jest męskim imieniem wśród tradycyjnie muzułmańskich etnicznych w byłym Związku Radzieckim, a nazwisko znajduje się w Pakistanie i Indiach. Pociąga się z nazwiska Ali i sufiksu Khan.</p>", "Asen": "<p>Arsen (starowsza nazwa: arsen, pochodząca od francuskiego arsenic), również napisany jako a-sen, arsen, kwas, to element chemiczny o znaku As i liczbie atomowej 33. Arsenik został po raz pierwszy opisany przez Albertus Magnus (Niemcy) w 1250 roku.</p>", "Anand": "<p>Anand - indyjska nazwa, nazwisko i toponim: Viswanathan Anand (ur.</p>", "Aleko": "<p>Aleko (rosyjski: Алеко) to opera pierwszej rzędu wielkiego rosyjskiego kompozytora Sergei Rachmaninoffa. Autorem jest Vladimir Nemirovich-Danchenko.</p>", "Abdallah": "<b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Avram": "<p>Abraham (przesłanie Abraham; hebrajski: אַבְרָהָם, Standard Avraham Ashkenazi Avrohom lub Avruhom Tibr ʾA ⁇ rāhām; arabski: ابراهیم, Ibrāhīm; Ge'ez: አብርሃም, ʾAbrəham), według judaizmu, chrześcijaństwa i islamu, jest ojcem Żydów i Arabów. Bóg powołał Abrahama, aby opuścił swój rodzinną Ur i przyjechał do nowego kraju w Kanaanie.</p>", "Ayoub": "<p>Ajub (francuski Ayoub) - imię własne; rozpowszechnione w postaci nazwisk.</p>", "Arek": "<b>Arkadiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa Αρκαδικóς (Arkadikós) oznaczającego „pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Arkadia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Arkadii</a>”.", "Aurelian": "<b>Aurelian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Aurelianus</em>. Pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> (<em>cognomen</em>) od <i>gentilicium Aurelius</i>, oznaczający „należący do rodu Aurelia”, a wywodzi się pośrednio od słowa <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>aureolus</em> – „złocisty”. Możliwe jest też pochodzenie imienia od nazwy szczepu <a href=\"https://pl.wikipedia.org/wiki/Galia\" target=\"_blank\" rel=\"noopener noreferrer\">galijskiego</a> Aureliani ze stolicą w Cenabum (późniejsze <i>Aurelianensis</i>, dzisiejszy <a href=\"https://pl.wikipedia.org/wiki/Orlean\" target=\"_blank\" rel=\"noopener noreferrer\">Orlean</a>).", "Ashley": "<b>Ashley</b> – żeńskie, jak i męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia staroangielskiego, używane co najmniej od XVI wieku, popularne w krajach anglojęzycznych.", "Avi": "<p>Audio Video Interleave (z krótkim AVI; litery.  ⁇ ⁇ ⁇ ?? ⁇; ⁇ ł.</p>", "Ayan": "<p>⁇ Nieuchwytny ⁇ (tam. அயன், Ayan) - indyjski film przygodowy reżysera K.</p>", "Adrián": "<p>Adrián San Miguel del Castillo (Hiszpański: [aˈðɾjan san miˈɣel del kasˈtiʎo]; urodzony 3 stycznia 1987 roku), znany jako Adrián, jest hiszpańskim profesjonalnym piłkarzem, który obecnie gra w pozycji gołębiarza dla klubu Betis w La Liga. Adrián rozpoczął karierę z hiszpańskiego klubu Real Betis, początkowo z młodzieżą klubu, przed debutem z głównej drużyny w 2012 roku; został również wypożyczony...</p>", "Alin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Anatoly": "<p>Anatolii (rosyjski: Анатолий, romanizowany: Anatoliy, ukraiński: Анато́лій, romanized: Anatolii) jest powszechną rosyjską i ukraińską nazwą męską, pochodzącą z greckiego imienia Anatolios (⁇ νατόλιος), co oznacza \"on wschodu słońca\", z ἀνατολή anatolē, \"wychod słońca\". Anatoly było jednym z pięciu najpopularniejszych imion dla chłopców urodzonych w St.</p>", "Amadeus": "<p>Jest to artykuł o globalnym systemie dystrybucji. O filmie patrz.</p>", "Alika": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alica</b>.</p><p>Andrej Georjan Belan (r. Andreea Georgiana Bǎlan; urodz.</p>", "Abdelrahman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Amrit": "<p>Amrit (arabski: عمريت), starożytne imię Marathus (gr. αραθ ς, Marathos), był obecnie finiockim portem znajdującym się blisko Tartus w Syrii. Założony w III millenium pne, Marat (Fenickie: ⁇ , MRT) był ważnym północnym miastem starożytnej Feneki i był przeciwnikiem sąsiedniego Arwad.</p>", "Abdulrahman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Athanasios": "<p>Athanasios (grek. Αθανάσιος), również przetransliterowany jako Athnasious, Athanase lub Atanacio, jest greckim imieniem męskim, które oznacza \"nieśmiertelny\". W współczesnym greckim codziennym użyciu jest zwykle skrócony na Thanasis (Θανάσης), Thanos (Θάνος), Sakis (Σάκης) i Nasos (Νάσος).</p>", "Artemiusz": "<b>Artemiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, w wersji Αρτέμιος/Artemios wywodzące się od imienia bogini <a href=\"https://pl.wikipedia.org/wiki/Artemida\" target=\"_blank\" rel=\"noopener noreferrer\">Artemidy</a>, a w wersji Ἀρτεμής/Artemes znaczące „bezpieczny, idealnego zdrowia”. Imię to nosiło kilku świętych. Forma żeńska – <a href=\"https://pl.wikipedia.org/wiki/Artemia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Artemia</a>.", "Al": "<p>Aluminium (chymiczny symbol - Al, od łacińskiego Aluminium), wcześniej również gliny (od rosyjskiego.</p>", "Achilles": "<p>Achilles (lat. Achilles, grecki.</p>", "Anish": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anisha</b>.</p><p>Anisha może odnosić się do Anisha Ambrose, indyjskiej aktorki filmowej i modelu Anisha Basheel (ur. 1997), malawjskiej profesjonalnej bokserki Anisha Nagarajan (ur. 1983), amerykańskiej aktorki i piosenkarki Anisha Nicole (ur. 1985), amerykańskiej piosenkarky Anisha Rosnah (ur. 1993) brunejskiej królewskiej Anisha Vekemans (ur. 1991), belgijskiej profesjonalne rowerzystka wyścigowa</p>", "Atanas": "<p>Atanas to imię. Najczęściej używane jest to męskie imię w bułgarskim i makedonii, pochodzące od greckiego Athanasios, \"nieśmiertelny\".</p>", "Aris": "<p>Vsmart Aris Pro to najwyższa wersja smartfonów z systemem operacyjnym vos, opracowany z platformy Android 11 firmy Google. Vsmart Aris Pro to pierwszy w Wietnamie model komórki komórkowej obsługujący technologię 5G oraz projekt kamery ukrytej pod ekranem (CUD).</p>", "Asad": "<p>Asad (arabski: أسد), czasami napisany jako Assad, jest arabskim męskim imieniem dosłownie oznaczającym \"łówn\". Jest używany w nazwach takich jak Asad Allāh, jedno z nazwach Ali ibn Abi Talib.</p>", "Amirani": "Według mitu <a href=\"https://pl.wikipedia.org/wiki/Swanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Swanów</a>, żona myśliwego, w zemście za zdradę męża, zabiła boginię, ścinając jej włosy podczas snu. Myśliwy wydobył dziecko z łona zmarłej matki i nadał mu imię <i>Amirani</i>. Chłopiec miał na ciele znamiona świadczące o jego półboskim pochodzeniu – symbole słońca i księżyca na łopatkach oraz złoty ząb.", "Achim": "<p>Achim jest gminą w okręgu Verden w niemieckim stanie Niedersachsen.</p>", "Arkhyp": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arkhip</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Archip</b>.</p><b>Archip</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzenia</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów: <i>αρχος (archos)</i>, oznaczającego \"mistrz\" oraz <i>‘ιππος (híppos)</i> – „koń”.", "Ata": "<p>Ata - środek czyszczący, sprzedawany od 1920 roku przez niemiecką firmę Henkel. Pierwotnie składało się tylko z piasku i sody.</p>", "Akhmad": "<p>Ahmad (arabski: أحمد, romanized: ʾAḥmad) jest arabską nazwą męską powszechną w większości części świata muzułmańskiego, ponieważ jest to jedno z dobrze znanych imion proroka Muhammada. Inne angielskie pisowni nazwy obejmują Ahmed, Ahmmad.</p>", "Anibal": "<p>Aníbal jest hiszpańskim i portugalskim męskim nazwiskiem pochodzącym z Hannibału (q.v.), samemu latynistycznym nazwiskiem greckiego Hanníbas (⁇ ννίβας), pochodzącym od \"ḥnbʿl\" w języku kartaginskim (kartaginskim pisemnym, ⁇ ‬‬‬‬ ⁇ ‬‬ ⁇ ⁇ ‬‬), potomkiem fenickijskiego języka kananeckiego, w którym znaczenie nazwy jest \"Baʿal ([Pan] jest] moją łaską\", krewny hebrajskiego honoryficznego Baʿal (בעל) \"mistrz/pódca\".[the][is] W języku angielskim może odnosić się do:</p>", "Aleksandros": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alexandros</b>.</p><p>Alexandros może odnosić się do: Alexandros, greckie imię, pochodzenie angielskiego imienia Alexander Alexandros, Grecja, wioska na wyspie Lefkada Alexandros (band), japoński zespół rockowy</p>", "Archili": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Archil</b>.</p><p>Archil (Georgiański: არჩილ) to męskie gruzińskie imię. Do znanych osób z nazwiskiem należy: Archil z Iberii (fl.</p>", "Anoop": "<p>Anup (sanskrit: अनुप anūpa) to indyjskie imię męskie. Sanskritskie słowo anūpa ma następujące znaczenia: \"wodna\", \"położona w pobliżu wody\", \"brzeg rzeki\", \"zbiornik\", \"lagona\".</p>", "Andria": "<p>Andria to włoskie miasto. Miasto należące do prowincji Barletta-Andria-Trani w regionie Apulia.</p>", "Almaz": "<p>Diament (od greckiego ἀδάμας - ⁇ niezniszczalny) - mineral, jedna z alotropycznych form węgla.</p>", "Ariusz": "<b>Ariusz</b> (ur. ok. <a href=\"https://pl.wikipedia.org/wiki/256\" target=\"_blank\" rel=\"noopener noreferrer\">256</a> lub <a href=\"https://pl.wikipedia.org/wiki/260\" target=\"_blank\" rel=\"noopener noreferrer\">260</a> w <a href=\"https://pl.wikipedia.org/wiki/Cyrenajka\" target=\"_blank\" rel=\"noopener noreferrer\">Cyrenajce</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/336\" target=\"_blank\" rel=\"noopener noreferrer\">336</a> w <a href=\"https://pl.wikipedia.org/wiki/Konstantynopol\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantynopolu</a>) – wczesnochrześcijański <a href=\"https://pl.wikipedia.org/wiki/Prezbiter\" target=\"_blank\" rel=\"noopener noreferrer\">prezbiter</a>, <a href=\"https://pl.wikipedia.org/wiki/Teolog\" target=\"_blank\" rel=\"noopener noreferrer\">teolog</a> i <a href=\"https://pl.wikipedia.org/wiki/Poezja\" target=\"_blank\" rel=\"noopener noreferrer\">poeta</a> z <a href=\"https://pl.wikipedia.org/wiki/Aleksandria\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandrii</a>, <a href=\"https://pl.wikipedia.org/wiki/Libia\" target=\"_blank\" rel=\"noopener noreferrer\">Libijczyk</a> z pochodzenia.", "Augustine": "<p>Augustyn (ang. Augustine) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Andro": "<p>Jan Kuznetsov (ur. 19 stycznia 2001, Kijów; znany jako Andro) - ukraiński repp- wykonawca pochodzenia cyganów.</p>", "Armani": "<p>Giorgio Armani S.p. A. - włoska firma specjalizująca się w produkcji i handlu odzieżą i różnymi akcesoriami.</p>", "Ayaan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ayan</b>.</p><p>⁇ Nieuchwytny ⁇ (tam. அயன், Ayan) - indyjski film przygodowy reżysera K.</p>", "Abubakar": "<p>Abu Bakr (arabsko: أبو بكر) to arabskie imię, które oznacza \"ojciec młodego wielbłąda\" (Abu oznacza \"ojca\" i Bakr oznacza \"młody wielbłąd\"), które jest szeroko stosowane przez muzułmanów sunnitów. Inne transliteracje obejmują Abu Bakar, Abu Bekr, Ebubekir, Aboubacar, Abubakar itp.</p>", "Anri": "<p>Anri (jap. 川島 栄子 Kawasima Эйко, 31 sierpnia 1961) - japońska piosenkarka i autorka piosenek.</p>", "Apollo": "<p>Apollo - seria amerykańskich trzymieszkańskich statków kosmicznych wykorzystywanych w programach lotów na Księżyc, na stację orbitalną Skylab i na sowiecko-amerykańskiej łączy EPAS.</p>", "Atanazy": "<b>Atanazy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „nieśmiertelny” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αθανάσιος).", "Aras": "<p>Oddział antyterrorystycznych operacji Aras (Orёл) Departamentu Policji Litwy (lit. Lietuvos policijos antiteroristinių operacijų rinktinė ⁇ Aras\") - oddzielne specjalne oddział anty-terrorystyczne policji Litwy.</p>", "Azim": "<p>Azim (ʿAẓīm عظيم) jest jednym z imion Allaha w islamu, co oznacza \"Wielki\" lub \"Wspaniały\" lub \"Ochrony\". Jest używany przez wielu Sahrawiów jako nazwisko pochodzące z arabskiego Hasania.</p>", "Abdel": "<p>Abdul (tzw. Abd, Abdel, Abdil, Abdol, Abdool lub Abdoul) jest najczęstszą transliteracją połączenia arabskiego słowa Abd (عبد, oznaczające \"Służebnik\") i prefiksu al / el (ال, oznaczający \"The\"). Jest to początkowy składnik wielu nazw związanych, takich jak Abd الحميد ʿAbd al-Ḥamīd (zwykle pisane Abdel Hamid, Abdelhamid, Abd El Hamid lub Abdul Hamid; lit.</p>", "Asan": "<p>Asan (w języku wietnskim Nha Sơn) jest miastem w prowincji Chungcheong-South w Korei. Miasto znajduje się na południu od stolicy Seulu.</p>", "Ara": "<p>Ara (lat. Ara) - rodzaj ptaków rodziny papugów.</p>", "Alban": "<b>Alban</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> genetycznie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">cognomen</a> <i>Albanus</i> oznaczające „pochodzący z Alby”, tj. np. z miasta <i><a href=\"https://pl.wikipedia.org/wiki/Alba_Longa\" target=\"_blank\" rel=\"noopener noreferrer\">Alba Longa</a></i> albo <i>Alba Fucentia</i>; istniała też góra <i><a href=\"https://pl.wikipedia.org/wiki/Monte_Cavo\" target=\"_blank\" rel=\"noopener noreferrer\">Albanus mons</a></i>. Językoznawczyni <a href=\"https://pl.wikipedia.org/wiki/Maria_Malec_(j%C4%99zykoznawczyni)\" target=\"_blank\" rel=\"noopener noreferrer\">Maria Malec</a> wskazuje na odniesienie pochodzenia Albana do miasta <i>Alba Longa</i>.", "Abbos": "<p>Abbos to uzbekska męska nazwa (w skrócie od uzbekski: Alliabbos). Może również pojawić się jako nazwisko jako wariant Abbas.</p>", "Anh Tuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Aly": "<p>Alexandra Rose ⁇ Eli ⁇ Riceman (ang. Alexandra Rose ⁇ Aly ⁇ Raisman; urodz.</p>", "Abdullo": "<p>Abd Allah (arabsko: عبد الله, romanized: ʻAbd Allāh), również pisane Abdullah, Abdhullah, Abdellah, Abdollah, Abdallah, Abdulla, Abdalla i wiele innych, jest arabską nazwą teoforyczną oznaczającą sługę Boga lub \"szońca Boga\". Został zbudowany z arabskich słów ʿabd (عبد) i Allāh (Allah).</p>", "Amjad": "<p>Amjad (arabski: أمجد), to arabskie imię męskie oznaczające \"honorowe\" i \"sławne\". To superlatyw słowa majid.</p>", "Akin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akina</b>.</p><b>Akina</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきな, アキナ) – głównie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, rzadko noszone przez mężczyzn.", "Askaniusz": "Wyprowadzony przez ojca z płonącej Troi, towarzyszył mu w wędrówce do Italii. Syn <a href=\"https://pl.wikipedia.org/wiki/Eneasz\" target=\"_blank\" rel=\"noopener noreferrer\">Eneasza</a> i <a href=\"https://pl.wikipedia.org/wiki/Troja\" target=\"_blank\" rel=\"noopener noreferrer\">trojanki</a> <a href=\"https://pl.wikipedia.org/wiki/Kreuza_(c%C3%B3rka_Priama)\" target=\"_blank\" rel=\"noopener noreferrer\">Kreuzy</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Silvius\" target=\"_blank\" rel=\"noopener noreferrer\">Silviusa</a>, po śmierci ojca król <a href=\"https://pl.wikipedia.org/wiki/Latynowie\" target=\"_blank\" rel=\"noopener noreferrer\">Latynów</a> i założyciel <a href=\"https://pl.wikipedia.org/wiki/Alba_Longa\" target=\"_blank\" rel=\"noopener noreferrer\">Alby Longi</a>. Jedna z postaci występujących w księdze II <a href=\"https://pl.wikipedia.org/wiki/Eneida\" target=\"_blank\" rel=\"noopener noreferrer\">Eneidy</a>. Według legendy od Askaniusza pochodzi sławny ród Julijski, którego przedstawicielami byli patrycjusze oraz znamienici obywatele <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymu</a>, m.in. <a href=\"https://pl.wikipedia.org/wiki/Gajusz_Juliusz_Cezar\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusz Cezar</a> i <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawian August</a>. Następca Eneasza w panowaniu nad Latynami (wtedy przybrał imię Julus).", "Abdur": "<p>Abdul (tzw. Abd, Abdel, Abdil, Abdol, Abdool lub Abdoul) jest najczęstszą transliteracją połączenia arabskiego słowa Abd (عبد, oznaczające \"Służebnik\") i prefiksu al / el (ال, oznaczający \"The\"). Jest to początkowy składnik wielu nazw związanych, takich jak Abd الحميد ʿAbd al-Ḥamīd (zwykle pisane Abdel Hamid, Abdelhamid, Abd El Hamid lub Abdul Hamid; lit.</p>", "Alireza": "<p>Ali Reza (zwany również Alireza lub Ali-Reza) jest popularną nazwą wśród Iranczyków, Bengaliczyków, Turków i Albanijczyków.</p>", "Aren": "<p>Arenę lub areny to związki organiczne \"z charakterystycznymi właściwościami chemicznymi benzenu\" i \"zestawieniem zestawów\". Obecne definicje związków perfumicznych nie mają nic wspólnego z zapachami.</p>", "Arwid": "<b>Arwid</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskich</a> elementów <i>ari</i> — „orzeł” i <i>viðr</i> — „las”.", "Angus": "<p>Angus (ang. Angus, gałowski.</p>", "Arkadius": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arcadius</b>.</p><p>Arcadius (lat. Arcadius, 284 r., rzymska prowincja Maвреtańska - 305 r., tam sam) - święty Kościoła rzymskokatolicznego, męczennik.</p>", "Arvind": "<p>Aravind (z sanskrytu: अरविन्द aravinda) to powszechne indyjskie imię męskie oznaczające lotos. Nazwa jest pochodzenia hinduskiego.</p>", "An": "<p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Arkadiy": "<p>Arkadiy (rosyjski: Аркадий) może odnosić się do: Arkadiy Abramovich (ur. 1993), spadkobierca Romana Abramovicha, rosyjskiego miliarderu i właściciela Chelsea F.C. Biografia Arkadiy Akopyan (ur. 1984), rosyjskie profesjonalne piłkarz piłkarze, obecnie grający dla FC Dynamo Bryansk Arkadiy Alov (1914-1982), rosyjski rosyjski piłkarzem, trenerem i sędzią Arkadiy Babchenko (ur. 1977), rosyjskim dziennikarzem druku i telewizji Arkadiy Belinkov (1921-1970), rosy...</p>", "Antonin": "<b>Antonin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, powstałe od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Antoni_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antoni</a>.", "Albrecht": "<p>Albrecht (niem. Albrecht; 25 lipca 1336, München - 13 grudnia 1404, Haag) - książę Bawarii w latach 1347 - 1349 wraz z pięcioma braćmi, książę Niskiej Bawarii we latach 1349 - 1353 wraz z dwoma braćami, książę Bawaria-Strauing wraz z bratem Willemem, krajem Holandii, krajem Gennegau (pod nazwą Alberta I) i krajem Zelandii w latach 1388.</p>", "Adarsh": "<p>Adarsh (Devanagari: आदर्श ādarś) to indyjskie imię męskie oznaczające \"ideal\".</p>", "Ardian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ardiana</b>.</p><p>Ardian to albanska nazwa. Chociaż podobna do Adrian, nazwy pochodzenia łacińskiego, albanska Ardian (Ardjan i Ardijan są innymi wariantami) jest pochodem Ardiaei, nazwy starożytnego lyryjskiego ludu.</p>", "Adonis": "<p>Adonis, lub gorączki (lat. Adōnis) - rodzaj roślin rodziny Lutykowych (Ranunculaceae), obejmujący około 30 gatunków jednorocznych i wieloletnich traw, rozpowszechnionych w Europie i niepalących regionach Azji.</p>", "Amon": "<b>Amon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">egipskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiej</a> wersji imienia egipskiego boga <i><a href=\"https://pl.wikipedia.org/wiki/Amon_(b%C3%B3g_egipski)\" target=\"_blank\" rel=\"noopener noreferrer\">Amona</a></i>. Oznacza: „ożywiający powiew”. Znanych jest około dziesięciu świętych katolickich o tym imieniu.", "Atif": "<p>Atif (zwany również Atef lub Atiph, arabski: عاطف) jest arabskim męskim imieniem, które jest używane w świecie muzułmańskim, oznacza \"dobry\".</p>", "Alexsander": "<p>Alexsander to męskie imię, jest replika pisemna amerykańskiej fonetyki nazwiska Alexander. Może również odnosić się do: Alexsander (piłkarz, urodzony 1998), Alexsander Jhonatta de Oliveira Andrade, brytyjski obrońca piłki nożnej Alexsander, urodzona 2003), Alexsandro Christian Gomes da Costa, brytyjskiego półbrzeża</p>", "Artemiy": "<p>Artemy (rosyjski: Артемий), czasami romanizowany jako Artemiy, Artemi, lub Artemij, jest pełną unikalną formą rosyjskiego krótkiego męskiego Artyoma.</p>", "Alfie": "<p>Alfie może oznaczać: ⁇ Alfie ⁇ - piosenka z 1966 roku napisana przez Berta Bakaraca i Hal David.  ⁇ Alfie ⁇ - piosenka Lily Allen z 2007 roku.</p>", "Aamir": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amir</b>.</p><b>Amir</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أمير&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „książę” lub „dowódca”.", "Archibald": "<b>Archibald</b> – forma oboczna imienia Erchembod – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członów <i>ercan</i> („prawdziwy, autentyczny”) i <i>bald</i> („śmiały, odważny”). Inną formą oboczną jest imię <i>Erchembald</i>, a w Polsce występowało w formie <i>Archibald</i>, <i>Archambałt</i>, <i>Archambuł</i>, <i>Erkinbold</i> i <i>Erkambaldus</i>. Według stanu na 17 stycznia 2015 r. imię to miało w Polsce 5 nadań.", "Arturs": "<p>Artūrs lub Arturs to imię. Do wybitnych osób z nazwą należą: Arturs Alberings (1876-1934), były premier Łotwy Artūrs Ausējs (ur. 1990), lotyjski piłkarz koszykówki Artūrs Bērziņš (ur. 1988), lotycki piłkarze koszykówka Artūrs Brūniņš (ur., 1982), lotyński piłkarzem koszykówkę Artūrs Cavara (1901-1979), lotyckie tenor opery Artūrs Garonskis (ur. 1957), lotyjskie i radzieckie remarka Artūrs Irbe (ur. 1967), loty...</p>", "Aldin": "<p>Aldin to męskie imię i nazwisko. Na Bałkanach Aldin jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Atef": "<p>Atef był białą koroną na głowie wielu bogów w starożytnych egipskich mitologiach, w tym faraonów. Chociaż nosili go bogowie, jak Ra, Sobek, Thoth, Heryshaf... Korona Atef jest bardziej związana z osiriszem, a także symboliczna dla rządów Osirisza nad słońcem i planetami dźwiękowymi.</p>", "Ahsan": "<p>Ahsan to męskie imię pochodzące z arabskiego i sanskrytu. W arabskim, trójkononentalny korzeń Ḥ-S-N, również jako diminutiw Hasana.</p>", "Anup": "<p>Anup (sanskrit: अनुप anūpa) to indyjskie imię męskie. Sanskritskie słowo anūpa ma następujące znaczenia: \"wodna\", \"położona w pobliżu wody\", \"brzeg rzeki\", \"zbiornik\", \"lagona\".</p>", "Ararat": "<p>Ararat może referuje się do: Góry Ararat Ararat (provincia) Sz Ararat, Susquehanna County, Ararat w Pensylwanii, Armenia</p>", "Abderrahmane": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Akira": "<b>Akira</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきら, アキラ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>, czasem noszone także przez kobiety.", "Arben": "<p>Arben to albaniańska męska nazwa, która odnosi się do pierwszej albaniańskiej jednostki w średniowieczu: Księstwa Arbanon (albaniańskie: Principata e Arbënit). Arben oznacza poważny facet/osoby.</p>", "Arayik": "<p>Arayik lub Araik (armeńska: Արայիկ; rosyjska: Араик) to męskie imię. Wśród znanych osób z tej nazwy są: Araik Ambartsumov, rosyjski amatorski bokser Araik Baghdadyan, armenijski walczyk Arayik Eloyan (ur. 2004), armenijski piłkarz Arayik Gevorgyan (ur. 1973), armeniński walczyk Ariak Harutyunyan (ur., 1973), armenii polityk Arayik Mirzoyan (ur.).</p>", "Abul": "<p>Abul to arabskie imię męskie. Może odnosić się do: Abul Kalam Azad Abul A'la Maududi Abul Khair (dysambiguja), kilku osób Abul Abbas (dysambiego), kilku ludzi Abul Hasan Abul Hsan Ali Hasani Nadwi Abu'l-Fazl ibn Mubarak Abul Hasaan Qutb Shah Abul-Hasan Al-Muhajir Abul Farah Faridi, bangladeski akademik Abul Kalami Abul Kalem (dysambugacja), kilku osob Abul Karam Azad, fotograf Abul Lais Siddiqui Abul Laiss Islahi Nadvi Abul...</p>", "Abhinav": "<p>Abhinava (Devanagari: अभिनव) to indyjskie imię męskie. Sanskrit abhinava oznacza \"nowy\".</p>", "Ameer": "<p>Emir (; arabski: أمير ʾAmīr [ʔæˈmiːr]), czasami przenoszony do Amir, Amier lub Ameer, jest szlachectwem lub szlachetnym urzędnikiem używanym w wielu regionach w krajach Arabskich. Dosłownie oznacza to dowódca, generał, król lub król.</p>", "Almas": "<p>⁇ Spaick ⁇ (ang. Spike, Hebrajczyk.</p>", "Abdelhamid": "<p>'Abd al-Ḥamīd (ALA-LC romanizacja arabskiej: عبد الحميد; perskiego: عبدالحمید, romanized: Abdolhamid; tureckiego: Abdülhamit), również pisowniony jako Abdulhamid, Abdelhamid, Abd-ul Hamid i Abd ol-Hamid, jest muzułmańskie męskie imię i nazwisko. Jest to muzułmańska nazwa teoforyczna zbudowana z arabskich słów 'abd ('sługa') i al-Ḥamīd (jedno z nazw Boga w Koranie), a zatem oznacza 'sługa Wszechchchch chwalnego'.</p>", "Arash": "<p>Arash: Arash - szwedzko-iraniński piosenkarz, tancerz, artysta, kompozytor i producent. Arash - album z 2005 roku.</p>", "Alwaro": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alwar</b>.</p><b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Athul": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Atul</b>.</p><p>Atul jest miasteczkiem w Valsad w stanie Gujarat w Indiach.</p>", "Anh Tuấn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Arvid": "<p>ArVid (Archivator to Video) - interfejs płatka dla komputera zgodnego z IBM, umożliwiająca wykorzystanie domowego wideo magnetofonu w formie VHS jako strimera. W połowie lat 90. była ona powszechna w krajach byłego ZSRR, kiedy magnetofony i kasety były dla nich znacznie bardziej dostępne dla użytkowników domowych niż specjalizowane strimery.</p>", "Afgan": "Wytwarzany głównie przez plemię Ersari zamieszkujące obszary <a href=\"https://pl.wikipedia.org/wiki/Turkmenistan\" target=\"_blank\" rel=\"noopener noreferrer\">Turkmenii</a> nad rzeką <a href=\"https://pl.wikipedia.org/wiki/Amu-daria\" target=\"_blank\" rel=\"noopener noreferrer\">Amu-daria</a> od początku XVII wieku. Pochodzenie nazwy tego kobierca <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europejczycy</a> zawdzięczają pośrednictwu <a href=\"https://pl.wikipedia.org/wiki/Rosjanie\" target=\"_blank\" rel=\"noopener noreferrer\">Rosjan</a>, którzy eksportowali ten towar na <a href=\"https://pl.wikipedia.org/wiki/Europa_Zachodnia\" target=\"_blank\" rel=\"noopener noreferrer\">Zachód</a>, po uprzednim zaopatrzeniu się w <a href=\"https://pl.wikipedia.org/wiki/Kabul\" target=\"_blank\" rel=\"noopener noreferrer\">Kabulu</a>.", "Adar": "Zgodnie z <a href=\"https://pl.wikipedia.org/wiki/Talmud\" target=\"_blank\" rel=\"noopener noreferrer\">Talmudem</a> (traktat Taanit 29a) \"wraz z nadejściem adar nastaje <a href=\"https://pl.wikipedia.org/wiki/Rado%C5%9B%C4%87_(emocja)\" target=\"_blank\" rel=\"noopener noreferrer\">radość</a>\". Istnieje też powiedzenie (<a href=\"https://pl.wikipedia.org/wiki/Jidysz\" target=\"_blank\" rel=\"noopener noreferrer\">jid</a>.): \"אין חודש אדר, זאָגט די גמרא, מרבין בשׂימחה – פֿרייען זיך ייִדעלעך אויף וואָס די וועלט שטייט\", co oznacza: \"w miesiącu adar, jak powiada Gemara, radują się Żydzi na czym świat stoi\".", "Atlas": "<p>Atlas - wieloznaczne słowo: Atlas, lub Atlant - tytan w starożytnej mitologii greckiej. Atlas to zbiornik map, tabel, diagramów itp.</p>", "Abderrahim": "<p>'Abd al-Raḥīm (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów 'abd, al-Raḥīm, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Ayomide": "<p>Ayọ̀mídé to unisex nazwa pochodzenia joruba, co oznacza, że Moja radość przybyła.</p>", "Aravind": "<p>Aravind (z sanskrytu: अरविन्द aravinda) to powszechne indyjskie imię męskie oznaczające lotos. Nazwa jest pochodzenia hinduskiego.</p>", "Araik": "<p>Arayik lub Araik (armeńska: Արայիկ; rosyjska: Араик) to męskie imię. Wśród znanych osób z tej nazwy są: Araik Ambartsumov, rosyjski amatorski bokser Araik Baghdadyan, armenijski walczyk Arayik Eloyan (ur. 2004), armenijski piłkarz Arayik Gevorgyan (ur. 1973), armeniński walczyk Ariak Harutyunyan (ur., 1973), armenii polityk Arayik Mirzoyan (ur.).</p>", "Antin": "<p>Antin jest gminą w prowincji Hautes-Pyrénées w południowo-zachodniej Francji. Obszar ten znajduje się średnio na wysokości 330 metrów nad poziomem morza.</p>", "Anurag": "<p>Anurag (Devanagari: अनुराग), czasami skrócony Anu, jest powszechną indyjską nazwą. Wśród znanych osób z nazwy Anurag Basu są: Anurag Basu, reżyser filmowy, aktor i producent Bollywood Anurag Dikshit, miliarder indyjski biznesmen, współzałożyciel PartyGaming Anurag Kashyap (reżyser), scenarzysta-reżysera filmu hindi, w tym Black Friday i Dev D (2009) Anurag Singh (reżydent), reżysera filmowy z Punjab Anurag Kumar, profesor i prezes...</p>", "Avenir": "<p>Avenir (Avenir, z francuskiego - ⁇ byszczące ⁇) - groteska, stworzona przez Adriana Frutiger i opublikowana w 1988 roku przez firmę Linotype GmbH.</p>", "Arkhip": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Archip</b>.</p><b>Archip</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzenia</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów: <i>αρχος (archos)</i>, oznaczającego \"mistrz\" oraz <i>‘ιππος (híppos)</i> – „koń”.", "Alcides": "<p>Alcides to rodzaj motyli z rodziny Urania.</p>", "Ajmal": "<p>Ajmal (أجمل) to zarówno nazwisko i nazwisko pochodzenia arabskiego . Znaczy to \"najpiękniejszy\" lub \"wspanialszy\".</p>", "Antti": "<p>Antti to fińskie imię męskie pochodzące od greckiego imienia Andreas. W Estonii bardziej powszechna jest wariant anty.</p>", "Aitor": "<p>Aitor to baskijska męska nazwa, stworzona przez Agosti Xaho dla baskijskiego patriarchy pochodzącego z Biblijnej Tubal w jego pracy \"The Legend of Aitor\" (opublikowana w języku francuskim w czasopiśmie Ariel, 1845). Koldo Mitxelena uważa, że Xaho stworzył go z baskijskiego wyrazu Souletin aitoren semeak lub aitonen semeak (\"gentryja\", dosłownie \"synowie dobrych ojców\" interpretowane jako \"synowia Aitor\", aita oznacza \"ojciec\" i na znaczenie...</p>", "Ares": "<b>Ares</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Ἄρης Árēs, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Mars</em>) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> bóg wojny, syn <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a> i <a href=\"https://pl.wikipedia.org/wiki/Hera\" target=\"_blank\" rel=\"noopener noreferrer\">Hery</a>. Jego odpowiednikiem w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a> jest <a href=\"https://pl.wikipedia.org/wiki/Mars_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Mars</a>. W <a href=\"https://pl.wikipedia.org/wiki/Astrologia\" target=\"_blank\" rel=\"noopener noreferrer\">astrologii</a> identyfikowany z <a href=\"https://pl.wikipedia.org/wiki/Gwiazdozbi%C3%B3r_Barana\" target=\"_blank\" rel=\"noopener noreferrer\">Baranem</a>. Jeden z dwunastu <a href=\"https://pl.wikipedia.org/wiki/Bogowie_olimpijscy\" target=\"_blank\" rel=\"noopener noreferrer\">bogów olimpijskich</a>.", "Altay": "<p>Altay (Altay) - turecki główny czołg bojowy (OBT). Pierwszy wzór czołgu został przedstawiony 11 maja 2011 roku.</p>", "Atul": "<p>Atul jest miasteczkiem w Valsad w stanie Gujarat w Indiach.</p>", "Augustus": "Młody wódz, wówczas już właściwie jedynowładca imperium rzymskiego, dołączył go do swego imienia jako przydomek i od tamtej pory nosił imię: <i>Imperator Caesar Divi Filius Augustus</i>. Samego słowa nie da się jednoznacznie przetłumaczyć, oznacza mniej więcej \"wyniesiony dzięki boskiej mocy\", \"pełen boskiej mocy\" i wcześniej było używane na określenie obiektów inauguracji, z których przyszłości odczytywali <a href=\"https://pl.wikipedia.org/wiki/Augur\" target=\"_blank\" rel=\"noopener noreferrer\">augurowie</a>. Sam Oktawian nie uznawał ani tego tytułu, ani żadnego z imion jako oficjalnej nazwy sprawowanego przez się urzędu. W tym znaczeniu używał tytułu <a href=\"https://pl.wikipedia.org/wiki/Princeps_senatus\" target=\"_blank\" rel=\"noopener noreferrer\"><i>princeps</i> <i>senatus</i></a>, przyjętego w tym samym roku, który był jedynie honorowym tytułem nadawanym jednemu z senatorów, który znajdował się na szczycie listy senackiej i miał prawo rozpoczynać obrady. Było to świadome działanie Oktawiana, który chciał być widziany jako odnowiciel republiki zaprowadzający pokój, stąd też unikał używania militarnego tytułu <i>dux</i>, który nosił w czasie wojen domowych, a także nie przyjął władzy królewskiej wiążącej się z tytułem <i>rex</i>, a powszechnie znienawidzonej w republikańskim Rzymie.", "Aldon": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aldona</b>.</p><b>Aldona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzi ono od staropruskiego miana <i>Aldegut</i> lub białoruskiego <i>Ałdonia</i>, będącego przekształceniem greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Eudoksja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eudokia</a> (Eudocja). Nosiło je wiele księżniczek litewskich wydawanych za polskich książąt (głównie mazowieckich).", "Adeel": "<p>Adeel (arabsko: عديل) to muzułmańskie imię męskie w Azji Południowej.</p>", "Aldrin": "Została nazwana imieniem twórcy metody jej wytwarzania – noblisty z 1950 <a href=\"https://pl.wikipedia.org/wiki/Kurt_Alder\" target=\"_blank\" rel=\"noopener noreferrer\">Kurta Aldera</a>.", "Amadeo": "<p>The Municipality of Amadeo (Filipinowa: Bayan ng Amadeo) to 4 miasto w prowincji Cavite, w Filipinach. To miasto nosi nazwę \"kapitału kawy Filipin\".</p>", "Amedeo": "<p>Amadeus VIII Miłosierny (italij. Amedeo VIII di Savoia; 4 września 1383 - 7 stycznia 1451, Genewa) - graf (od 1416 roku książę) Savoii w latach 1391 - 1434, antypapus pod nazwą Felix V w latach 1439 - 1449.</p>", "Aldair": "<p>Aldair Nascimento dos Santos (Portugalski: [awdaˈiʁ]; urodzony 30 listopada 1965), znany również jako Aldair, jest brzyzyzylijskim piłkarzem, który grał w środku, i był członkiem brytyjskiego drużyny mistrzowskiej mistrzowskiego mistrzowstwa mistrzowskim mistrzowstwa mistrzowstw mistrzowstva w 1994 roku. Spędził większość swojej kariery w USA.</p>", "Ananda": "<p>A. Ananda (kr. - Nie, nie, nie. Pi.</p>", "Abdurashid": "<p>'Abd al-Rashīd (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów ʿabd i al-Rashīd, jednego z nazw Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Ary": "<p>Arnaldo Patusca da Silveira (portretowo: Arnaldo patusca da silveira; 6 sierpnia 1894 r., Santos, San Paulo - 24 czerwca 1980, Santos, San Paolo) - brazylijski piłkarz, zawodnik.</p>", "Asep": "<p>Asép (sundaneski: ⁇ , romanizowany: Asép, sundaneski wymowa: [asɛp], romanizowana jako Asep w indonezyjskim systemie pisowni) jest męskim imieniem sundanskim lub badui. Pochodzi z słowa sundańskiego Kasép (⁇), co oznacza przystojny.</p>", "Agostino": "<p>Augustyn (italicki: Agostino; 1482 - 14 kwietnia 1532 roku, Monako) - regent Monako (1523-1532) z dynastii Grimaldi, biskup Graski, biskup Mallorki.</p>", "Anil Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anil</b>.</p><p>Anil to rodzaj roślin kwiatowych z rodziny Białego.</p>", "Arlen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arlena</b>.</p><b>Arlena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, którego pochodzenie jest niepewne. Być może wywodzi się od <i>Arlene</i>, co oznacza w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_irlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">języku irlandzkim</a> „gwarancję, zobowiązanie”. Imię to może być też skróconą formą imion żeńskich kończących się na -arlena, np. <a href=\"https://pl.wikipedia.org/wiki/Marlena\" target=\"_blank\" rel=\"noopener noreferrer\">Marlena</a>. Istnieje też hipoteza, jakoby imię to miało być wariantem <i>Arline</i>, imienia prawdopodobnie wymyślonego przez mało znanego kompozytora irlandzkiego <a href=\"https://pl.wikipedia.org/wiki/Michael_William_Balfe\" target=\"_blank\" rel=\"noopener noreferrer\">Michaela Williama Balfego</a> dla głównej bohaterki najbardziej znanej jego opery „Czeszka” (<i>The Bohemian girl</i>).", "Arik": "<p>Arik to imię i może odnosić się do: Arik Ascherman, amerykański rabin reformator i palestyński działacz praw człowieka w Izraelu Arik Brauer, wizjoner artysta Arik Benado, kapitan Maccabi Haifa Arik Einstein, izraelskiego piosenkarza Arik Levy, projektanta przemysłowego i współczesnego artysty Arik Gilbert (ur. 2002), amerykańskiego piłkarza piłki nożnej Ariel \"Arik\" Ze'evi, izraelskiej judoki Arik Marshall, amerykańskiej muzyki Artoces, znanej również jako Arik, starożytnej...</p>", "Arya": "<p>\"Arya\" (i jego odmiany) to słowo oznaczające \"rod\" (boże święte) które kiedyś było używane jako samozwa indyjsko-iranijskich narodów. Słowo to zostało użyte przez lud Indy-Arya od czasów wedyjskich w Indiach jako nazwisko dla siebie, a także do osób należących do szlachty i geologicznych regionów Āryāvarta, w których pochodzą indy-Aryanskiej kultury.</p>", "Agim": "<p>Agim to albanieńskie imię męskie, które oznacza \"świt\". To też nazwisko.</p>", "Aureli": "<b>Aureli</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> męskiego <a href=\"https://pl.wikipedia.org/wiki/Aureliusz\" target=\"_blank\" rel=\"noopener noreferrer\">Aureliusz</a>, pochodzącego od nazwy rzymskiego rodu Aureliuszy, która z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <i>aureolus</i> – „złocisty” (co mogło znaczyć także „wspaniały”).", "Anass": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anas</b>.</p><p>Uci rzeki lub uci szlachetne (lat. Anas), to rodzaj ptaków rodziny uci.</p>", "Abdelhak": "<p>'Abd al-Ḥaqq (ALA-LC) to arabskie imię męskie i w nowoczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Ḥaqq, jednego z nazw Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Ardit": "<p>Ardit to albaniańska nazwa dla mężczyzn oznaczająca \"złoty dzień\". Mieszkańcy Ardit to: Ardit Aliti (ur. 1996), albano-danowski rapper Ardit Beqiri (ur. 1979), albanianki piłkarz Ardit Deliu (ur. 1997), albanianski piłkarze Ardit Gashi (ur. 1998), albanianka piłkarza Ardit Gjebrea (ur. 1963), albanianko-zwangerska Ardit Hila (ur. 1993), albaniancki piłkarzem Ardit Hoxhaj (ur. 1994), albanianzki piłkarzek Ardit Krymi (ur. 1996, w Albanii...</p>", "Amid": "<p>Amyd (lub albo), znany również jako kwas amyd, jest związkiem z grupami funkcyjnymi RnE (O) xNR′2 (R i R' są grupami H lub grupami organicznymi). Najczęściej jest to karboxamid (organiczny amyd) (n = 1, E = C x = 1), ale wiele innych ważnych rodzajów amydów jest znanych, w tym fosforamid (n = 2, E = P x = 1 i wiele związanych formuł) i sulfonamid (E = S, x = 2).</p>", "Arshak": "<p>Arshak (lub w zachodniej armenii Arshag) (w perskim آرشاک) (w armenijskim Արշակ) jest perskim i armenijskim nazwiskiem.</p>", "Admir": "<p>Admir to imię męskie. Na Bałkanach Admir jest popularny wśród Bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Antonis": "<p>Antonis (greckie alfabet: Αντώνης) jest wariantem Antonios używanym w Grecji i na Cyprze, który z kolei jest formą Antoniusa, imienia rzymskiej geny. Przypuszczamy, że pochodzenie jest w języku etruskim.</p>", "Amet": "<p>Amet jest miastem i dzielnicą miast w Rajsamand w stanie Rajasthan w Indiach.</p>", "Aiman": "<p>Aiman (arabski: أيمن) to neutralna nazwa płci z pochodzenia w języku arabskim, urdu i kazacku. Jest to alternatywne alfabet latynski śpiewki imienia Ayman.</p>", "Arun Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arun</b>.</p><p>Arun (Mongolski: ⁇ ⁇ Arun qosiɣu, Kirin Mongoli: Арун хошуу; przenoszone: 阿荣旗; subtyp: 阿榮旗; przenośne: Āróng Qí, Hán Việt: A Vinh kỳ) jest okresem urzędu miasta Hulunbuir (Holun Luan Uy), Autonomicznego Obszaru Mongolicznego, Chiny. Miasto graniczy z prowincją Hắc Long Giang na wschodzie i południu i znajduje się 92 km (57 mi) na północno-zachodni od miasta Tề Tề Cápur w prowincji Hắc Long.</p>", "Adewale": "<p>Adéwálé (wymowa joruba: [ādéwálé]) jest zarówno nazwiskiem i nazwiskiem pochodzenia jorubańskiego, co oznacza \"korona lub królewska rodzina wróciła do domu\". Do wybitnych osób z tym nazwiskiem należą:</p>", "Aayan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ayan</b>.</p><p>⁇ Nieuchwytny ⁇ (tam. அயன், Ayan) - indyjski film przygodowy reżysera K.</p>", "Arsena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arsen</b>.</p><p>Arsen (na armeńsku, Արսեն; gruzińsku, არსენ; rosyjski, Арсен; ukraiński, Арсен) jest nazwiskiem, diminutiwem greckiego Arsenios. Do wybitnych osób z tym nazwiskiem należą: Arsen Akayev (ur. 1970), Kumyk-Roski trener i były gracz piłki nożnej Arsen Avakov (ur. 1964), ukraiński polityk Arsen Awakov (ur., 1971), były tajczyk piłkarz piłkarza Arsen Avetisyan (ur. 1973), armenijski piłkarze piłkarzy Arsen Aydinian (1825-1902), armeni...</p>", "Altin": "<p>Altin to nazwa w języku albańskim. Do wybitnych osób z nazwiskiem należą: Altin Bytyçi (ur. 2001), kosowski piłkarz Altin Çuko (1974-2025), albanianki były piłkarze Altin Grbović (ur. 1986), serbski piłkerz Altin Haxhi (ur. 1975), albanianski piłka nożna Altin Hoxha (ur. 1990), albanian piłkarza Altin Kaftira (ur. 1972), albanianka tancerz Altin Kryeziu (ur. 2002), kosowskiego piłkarka Altin Lala (ur. 1975), albanianki był...</p>", "Aftab": "<p>Aftab (persk: آفتاب âftâb, oznaczający \"słońce\" lub właściwie \"słońca\") jest nazwiskiem i męskim nazwiskiem.</p>", "Aries": "<p>Aries (⁇ owen ⁇; baran) - słowo łacińskie. Może oznaczać: Aries - łacińska nazwa gwiazdki Zodiaków Owiec i odpowiedniego znaku zodiaku.</p>", "Akhtar": "<p>Akhtar (perskie: اختر, pasztów: اختر) oznacza \"gwiazdę\" w perskim i jest używany w pasztówce na Nowrudz i Dzień Wielkanocny. Jest to również powszechne nazwisko.</p>", "Armel": "<p>Armel (r. Armel) - kamienny meteoryt, zwykły chondryt o wadze 9200 g.</p>", "Andryi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andrij</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Almir": "<p>Almir (ur. 26 marca 1969) jest brazylijskim piłkarzem.</p>", "Alexi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksi</b>.</p><p>Aleksi to męskie fińskie imię. Do wybitnych osób z tym nazwiskiem należą: Aleksi Bardy, fiński scenarzysta i producent filmowy Aleksi Benashvili, gruziński piłkarz Aleksi Eeben, fiński kompozytor, projektant dźwięku, muzyk i programista Aleksi Elorinne, fiński hokejista lodowy Aleksi Heimosalmi, fiński gracz lodowy Hihnavaara Aleksi, fiński granicą Aleksi Holmberg, fiński piłka hokeja Aleksi Honka-Hallila, fiński...</p>", "Anna": "<b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Asker": "<p>Asker jest miastem w hrabstwie Akershus w Norwegii i jest przedmieściem przedmieścia Osla. Asker został założony 1 stycznia 1838 roku (patrz formannskapsdistrikt).</p>", "Aniket": "<p>Aniket to indyjskie imię męskie. Znaczenie nazwy Aniket jest: \"Ten, który uczyni świat swoim domem\", Panem świata; Niebiański, Pan Wisnu lub Kryszna, Pan Shiwa, innymi słowy, cały świat jest jego domem, a nie jakimś konkretnym miejscem.</p>", "Alok": "<p>Alok Akkar Perez Petrillo (port. - Nieźle. Alok Achkar Peres Petrillo; rodzaj.</p>", "Abdurakhman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Anicet": "<b>Anicet</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <i>Anicetus</i>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">zlatynizowanej</a> formy greckiego imienia <i>Aniketos</i>. Wywodzi się ono od słowa oznaczającego „niezwyciężony, niepokonany”. Nosił je jeden z wczesnych <a href=\"https://pl.wikipedia.org/wiki/Papie%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">papieży</a>, <a href=\"https://pl.wikipedia.org/wiki/Anicet_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Anicet</a>.", "Aleksandrov": "<p>Aleksandrov jest miastem i centrum administracyjnym Aleksandrovskiego w Vladimir Oblastie, Rosja, 120 km (75 mi) na północny wschód od Moskwy. Populacja: 61,551 (Populska ankieta 2010), 64,824 (Populsa ankieta 2002) i 68,220 (Populsta ankieta 1989).</p>", "Agaton": "<b>Agaton</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, wywodzące się od słowa 'agathós', ' agath', oznaczający „dobry”. Wśród patronów tego imienia święci: Agaton, żołnierz (zm. w 250) i papież <a href=\"https://pl.wikipedia.org/wiki/Agaton_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Agaton</a> (zm. w 681). Od tego imienia (<i>: Agafon</i>) powstała staroruska forma skrócona (zdrobniała, spieszczona) <i>Gafan(ko)</i>, utworzona za pomocą popularnej w imiennictwie zarówno ruskim, jak i polskim techniki ucinania nagłosu.", "Abdelhakim": "<p>Abdul Hakim (arabski: عبد الحكيم, romanized: ʻAbd al-Ḥakīm) to muzułmańskie imię męskie, a w nowoczesnym użyciu, imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Hakim.</p>", "Abdula": "<p>Abd Allah (arabsko: عبد الله, romanized: ʻAbd Allāh), również pisane Abdullah, Abdhullah, Abdellah, Abdollah, Abdallah, Abdulla, Abdalla i wiele innych, jest arabską nazwą teoforyczną oznaczającą sługę Boga lub \"szońca Boga\". Został zbudowany z arabskich słów ʿabd (عبد) i Allāh (Allah).</p>", "Asier": "<p>Asier to męskie imię baskiego pochodzenia, co oznacza \"początek\" (hasiera w języku baskijskim). Został stworzony dla postaci w 1877 r. powieści Fernando Navarro Villoslady Amaya o los vascos en el siglo VIII.</p>", "Aslambek": "<p>Aslambek (rosyjski: Асламбек) to rosyjskie męskie imię. Do wybitnych osób z nazwiskiem należą: Aslambek Abdulkhadzhiev (1962-2002), rosyjski oficer wojskowy Aslambek Aslakhanov (1942-2024), rosyjski wojskowy oficer Aslambek Idigov (ur. 1995), rosyjskie bokser Aslambek Vadalov (ur., 1972), rosyjska wojskowa oficer</p>", "Ademola": "<p>Adémólá jest zarówno nazwiskiem i nazwiskiem pochodzenia jorubańskiego, co oznacza \"koronę lub królewską rodzinę wraz z prestiżem i bogactwem\". Do wybitnych osób z tym nazwiskiem należą:</p>", "Avigdor": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Awigdor</b>.</p><p>Avigdor (Hebrajskie: אביגדור, również Abigdor, Awigdor, z I Kronik 4.18, אבי גדור = Avi Gedor) to hebrajskie imię męskie.</p>", "Aria": "<p>Aria: Aria to album brytyjskiego zespołu prog-rock Asia. Aria - instrumentalny album trybjutów poświęcony zespołowi ⁇ Aria ⁇ .</p>", "Adebayo": "<p>Adébáyọ̀ lub Adebayor w języku francuskim, to imię i nazwisko. Jest to tradycyjne imię joruba, które może oznaczać każdą z następujących \"przyszedł w radosnym czasie\", lub \"król / korona / królewska rząd spotyka radość\" lub \"wielkieść / szlachtę / prymat / moc nakazane z radością\".</p>", "Akhmet": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Achmet</b>.</p><p>Ahmad (arabski: أحمد, romanized: ʾAḥmad) jest arabską nazwą męską powszechną w większości części świata muzułmańskiego, ponieważ jest to jedno z dobrze znanych imion proroka Muhammada. Inne angielskie pisowni nazwy obejmują Ahmed, Ahmmad.</p>", "Achmad": "<p>Ahmad (arabski: أحمد, romanized: ʾAḥmad) jest arabską nazwą męską powszechną w większości części świata muzułmańskiego, ponieważ jest to jedno z dobrze znanych imion proroka Muhammada. Inne angielskie pisowni nazwy obejmują Ahmed, Ahmmad.</p>", "Achille": "<p>W mytologii greckiej Achilles lub Asyn (Grzecki: ⁇ χιλλεύς) był centralnym postacią i największym wojownikiem greckiego wojska w bitwie z Troją, najczęściej wspomnianym w historii Iliady. Późniejsze opowieści (zaczynające się z poezją Sateusa około 1 wieku n.e.) przedstawiają Achilles'a jako niepowtarzalnego ciała z wyjątkiem jego stóp.</p>", "Atsushi": "<b>Atsushi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;アツシ, あつし) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Arunas": "<p>Arūnas to męskie litewskie imię i może odnosić się do: Arūnas Bižokas (ur. 1978), tancerz bale Arūnas Bubnys (ur. 1961), historyczka i archiwiści Arūnas Degutis (ur. 1958), polityk Arūnas Dulkys (ur. 1972), ekonomista i minister zdrowia Arūnas Eigirdas (ur. 1953), polityk arūnas Gelažninkas (ur. 1985), motocross, enduro i rally jazdy Arūnas Jurkšas (ur. 1972), atletyka torbowy Arnas Klimavičius (ur....</p>", "Abdullah Al": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdullah</b>.</p><b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Adryian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adriian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Aliko": "<p>Aliko jest gminą w okręgu Sarandë w okręg Vlorë w Albanii. W 2005 roku liczba ludności wynosiła 2638 osób.</p>", "Abil": "<p>Abil (arabski: آبل, również przemawia Abel lub Aabel) jest wioską w środkowej Syrii, w części administracyjnej prowincji Homs, znajdującą się 10 km na południe od Homs. Sąsiednie lokalizacje obejmują al-Nuqayrah i Kafr Aya na północ, Maskanah na północny wschód, Judaydat al-Sharqiyah na wschód; Shinshar na południowy wschód. Damina al-Shariqiyah na południe; al-Buwaydah al-Shamqiyah na północnym zachodzie i Qattinah na zachód.</p>", "Ala": "<p>Alanin (2-aminopropanowy kwas) - aminokwas alifatyczny. α-alanina jest częścią wielu białek, β-alanina - w szeregu związków biologicznie aktywnych.</p>", "Abishek": "<p>Abhishek to męskie imię, które ma swoje korzenie w sanskrytycznym słowie abhiseka. Konceptualne znaczenie abhisek jest związane z oczyszczeniem, oczyszczaniem lub pomazanie.</p>", "Arnas": "<p>Arnas jest gminą w prowincji Rhone w regionie Auvergne-Rhône-Alpes wschodniej Francji. Znajduje się w regionie o średniej wysokości 190 metrów nad poziomem morza.</p>", "Alberti": "<p>Alberti jest nazwiskiem słynnego rodziny w Firenze, równoważnego Medici i Albizzi. Alberto di Giovanni Alberti (1525-1599), włoski architekt Antonio degli Alberti (około 1360-1415), włoskiej poetki Domenico Alberti (koło 1710-1740), włoskiego kompozytora i piosenkarza Friedrich August von Alberti (1795-1878), naturalisty Gasparo Alberti (ok. 1480-1560), włoskim kompozytorem Giuseppe Matteo Alberti (1685-1751), włoskim muzykiem Innocentio...</p>", "Aidos": "<p>Aidos (Grzecki: Αἰδώς, wymawia [ai̯dɔ̌ːs]) była grecką boginią wstydu, szacunku i pokory. Aidos, jako cecha, to uczucie szacunku lub wstydu, które ogranicza mężczyznę do popełniania błędów.</p>", "Alpha": "<p>Alfa: Alfa (grek. άλφα) - pierwsza litera greckiego alfabetu.</p>", "Abdelghani": "<p>Abdul Ghani (arabsko: عبد الغني) lub Abdulghani lub Abdelghani lub podobne warianty to męskie muzułmańskie nazwisko i w współczesnym użyciu nazwisko. Został zbudowany z arabskich słów Abd, al- i Ghani.</p>", "Arye": "<p>Arye jest hebrajskim męskim imieniem i czasami nazwiskiem, wariantem pisowni Aryeh. Arye Carmon Arye Gross Arye L.</p>", "Angga": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anga</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ang</b>.</p>W Wielkiej Brytanii i Australii angielski jest <i>de facto</i> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urz%C4%99dowy\" target=\"_blank\" rel=\"noopener noreferrer\">językiem urzędowym</a>, choć formalnie państwa te nie objęły takim statusem żadnego języka. Angielszczyzna należy do oficjalnych języków <a href=\"https://pl.wikipedia.org/wiki/Organizacja_Narod%C3%B3w_Zjednoczonych\" target=\"_blank\" rel=\"noopener noreferrer\">ONZ</a>, a od XX wieku jest najczęściej używanym językiem w kontaktach międzynarodowych. Bywa określana jako pierwszy uniwersalny nowożytny język ludzkości. Stanowi główny język nauki, handlu i polityki, a w niektórych krajach także kształcenia wyższego.", "Altan": "<p>Altan to irlandzka grupa folk, założona w hrabstwie Donegal w 1987 roku przez wokalistkę Mayred Ni Winney i jej męża, Franki Kennedy. Grupa była przede wszystkim pod wpływem tradycyjnych irlandzkich piosenek z Donegal i sprzedała ponad milion płyt.</p>", "Amaru": "<p>Amaru Entertainment to studio nagrywania dźwięków Afeny Shakur, matki zmarłego Tupaka Shakur, utworzonej do wydania niewylanego materiału Tupaka. Po śmierci Tupac wszystkie prawa do już wydanych albumów, a także niewydawany materiał po dziedzictwie przechodziły do jego matki.</p>", "Aktan": "<p>Aktan to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Arseny": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arseni</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arsen</b>.</p><p>Arsen (na armeńsku, Արսեն; gruzińsku, არსენ; rosyjski, Арсен; ukraiński, Арсен) jest nazwiskiem, diminutiwem greckiego Arsenios. Do wybitnych osób z tym nazwiskiem należą: Arsen Akayev (ur. 1970), Kumyk-Roski trener i były gracz piłki nożnej Arsen Avakov (ur. 1964), ukraiński polityk Arsen Awakov (ur., 1971), były tajczyk piłkarz piłkarza Arsen Avetisyan (ur. 1973), armenijski piłkarze piłkarzy Arsen Aydinian (1825-1902), armeni...</p>", "Abdoulaye": "<p>Abdoulaye to afrykańskie imię i nazwisko. Jest równoważny z arabskimi nazwami Abdallah lub Abdullah (arabski: عبد الله ʿAbdu-llahi; sługa Boga), nazwiskiem ojca Mahometa.</p>", "Aleksa": "<b>Aleksa</b> – forma żeńska <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Aleksy\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksy</a>.", "Asror": "<p>Asror to męskie imię. Znanymi osobami z imieniem są: Asror Aliqulov (ur. 1978), uzbekski piłkarz Asror Vohidov (ur. 1995), tajczykistański bokser</p>", "Antonie": "<p>Antonia (rzym. Antonie, w świecie Andrzej Georgijević Rudej, Rum.</p>", "Ami": "<b>Ami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あみ, アミ, 亜美) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Aden": "<p>Aden jest portem i tymczasowym stolicą Jemenu, położonym na brzegu wschodniego wejścia do Morza Czerwonego (Głębia Aden), około 170 km (110 mi) na wschód od szczeliny Bab-el-Mandeb. Miasto liczy około 800 000 mieszkańców.</p>", "Abdulmalik": "<p>Abdul Malik (arabsko: عبد الملك) to arabskie (muzułmańskie lub chrześcijańskie) męskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Malik.</p>", "Ahad": "<p>Ahad (perskiego: احد; hebrajskiego: אחד; arabskiego: احد, urdu: احد) to nazwa na Bliskim Wschodzie używana głównie przez muzułmanów i Żydów. Jest również używany jako nazwisko rodzinnego (nazwa) (np.</p>", "Alemayehu": "<p>Alemayehu lub ⁇ Alämayyähu (Ge'ez: ዓለማየሁ) to osobiste imię etyopskiego pochodzenia, które składa się z dwóch słów: \"Alem\" - oznacza \"świat lub życie\" i \"ayehu\" - oznacza: \"Widziałem\". Dosłownie oznacza \"Widziałem świat\".</p>", "Aleksandru": "<p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Amit Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amit</b>.</p><p>Amit to imię indyjskie i żydowskie oraz żydowskie nazwisko. W języku hindi Amit (Hindi: अमित, oznacza \"nieograniczony\" lub \"bezgraniczny\", Bengali: অমিত) pochodzi od sanskrytyjskiego słowa amita (अमित:), amita (অमित:) jest zasadniczo negatywem mita (मित), co oznacza \"mierzyć\".</p>", "Alaeddine": "<p>Aladdin (arabski: علاء الدين, powszechnie 'Alāʼ ud-Dīn/ 'Alā' ad-Dīn) (różne pisownię i transliteracje) jest imieniem męskim, co oznacza \"szlachetność wiary\" lub \"szlachety wiary/religii\". Jest to jedna z dużych klas nazw kończących się na ad-Din.</p>", "Aaryan": "<p>Aryan, również pisane Ariyan, Arian, Aryann lub Aaryan jest nazwiskiem i nazwiskiem, które jest popularne w Indiach i Iranie. Nazwa Aryjczyk pochodzi z sanskrytu (ārya) oznaczającego \"szlachetny i wykształcony\" w kontekście indyjskim, podczas gdy pochodzi od staro perskiego (aryah) (\"szlachetna i szlachetna\") w kontekście Iranu.</p>", "Arnis": "<p>Arnis (zwany również Kali, Eskrima, Escrima) jest filipińską artystką bronią. Wiele krajów w Azji Południowo-Wschodniej posiadało ten rodzaj walki pod nazwą Krabi Krabong lub Trumbu.</p>", "Astrit": "<p>Astrit to albaniańska męska nazwa i może odnosić się do: Astrit Ajdarević (ur. 1990), albanianki piłkarz Astrit Bushati (ur. 1962), albanianski piłkarze Astrit Fazliu (ur. 1987), kosowskiego-albaniańskiego piłkarza Astrit Hafizi (ur. 1953), albanian piłkarzy i trener Astrit Haraqija (ur. 1972), kosowskiej polityk Astrit Patozi (ur. 1964), albanian polityk Astritt Selmani (ur. 1997), kosowski piłkerz Astrit Ziu (ur. 1946), albanian...</p>", "Arnav": "<p>Arnav, Arnab lub Arnov to popularne w Indiach imię i oznacza \"ocean\" w sanskrycie. Arnab to bengalijska, odia i asamska forma nazwy.</p>", "Admire": "<p>Admire (r. Edmyr) - żelazny meteoryt o wadze 180 kg, znaleziony w Kansas w 1881 roku.</p>", "Aristotelis": "<p>Aristotelis (Grzecki: ?) to samodzielna dzielnica w Grecji. Autonomiczna dzielnica Aristotelis ma powierzchnię 747 km2, populacja według badania z 18 marca 2001 roku wynosi 17752 mieszkańców.</p>", "Amirhossein": "<p>Amirhossein, Amir Hossein lub Amir-Hossein to irańskie męskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Adekunle": "<p>Adékúnlé jest nazwą pochodzenia jorubańskiego, co oznacza \"koronę lub królewską siedzibę wypełnia (rodzinny) dom\".</p>", "Amarjeet": "<p>Amarjit lub Amarjeet to indyjskie imię, które oznacza \"wieczny triumf\". Wśród znanych osób z nazwiskiem to: Amarjit Singh Bal (1940-2010), oficer Indii Armia Amarjeet Singh Bedi (fl.</p>", "Ashok Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ashok</b>.</p><p>Ashok to imię. Może odnosić się do:</p>", "Antonov": "<p>Antonov, znany również jako Antonov Aviation Science/Technology Corporation (Antonov ASTC) (ukraińska: Авиационный науково-техничний комплекс имени Антонова, АНТК им. Антонова) jest Ukrainy (od 1952) (biuro projektowe z preliminarem An) z specjalizacją w produkcji superdużych samolotów transportowych.</p>", "Anh Dung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Awad": "<p>Awad lub Aouad lub Awwad (arabski: عوض lub czasami عوّاد) to arabskie imię i nazwisko. Do osób z tym nazwiskiem należą:</p>", "Adis": "<p>Adis to męskie imię. Na Bałkanach Adis jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Alister": "<p>Alistair to imię męskie. Jest angiliczowaną formą szkockiego gaelicznego imienia Alasdair.</p>", "Areg": "<p>Areg (armeńska: Արեգ) to powszechne męskie imię w języku armeńskim oznaczające \"słońce\". Więcej informacji na temat Areg w artykule Wiktionary.</p>", "Abdulkarim": "<p>'Abd al-Karīm (ALA-LC) to muzułmańskie imię męskie i w nowoczesnym użyciu także nazwisko. Została zbudowana z arabskich słów ʿabd i al-Karīm, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Abelard": "<b>Abelard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie zapewne pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a> (<a href=\"https://pl.wikipedia.org/wiki/Dialekt_prowansalski\" target=\"_blank\" rel=\"noopener noreferrer\">prowansalskiego</a>), którego pierwotne znaczenie wywodzone jest od wyrazu prowansalskiego <i>abelha</i>, oznaczającego „<a href=\"https://pl.wikipedia.org/wiki/Pszczelarz\" target=\"_blank\" rel=\"noopener noreferrer\">pszczelarza</a>”. Jednak bywa ono także łączone z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckimi</a> imionami <i>Adalhard</i> (dosł. „szlachetna siła”) bądź też <i><a href=\"https://pl.wikipedia.org/wiki/Eberhard\" target=\"_blank\" rel=\"noopener noreferrer\">Eberhard</a></i> (dosł. „silny jak dzik”).", "Abdullahi": "<p>Abdullahi (zwany również Abdollahi i Abdillahi) to męskie imię i nazwisko, które jest również powszechne jako nazwisko. Jest to wariant arabskiego imienia Abdullah.</p>", "Abed": "<p>Abid (arabski: عابد 'Ābid), również Abed, dosłownie oznacza czciciel, czciciel i pobożny, to arabska nazwa. Może to być nazwisko lub imię.</p>", "Arlind": "<p>Arlind to męskie albanskie imię. Wśród znanych osób z nazwiskiem są: Arlind Ajeti (ur. 1993), piłkarz Arlind Dakaj (ur. 2001), piłkacharz Arlind Ferhati (ur. 1994), piłkapiec Arlind Kalaja (ur. 1995), piłkawiec Arlind Kurti (ur. 2005), piłkownik Arlind Nora (ur. 1980), piłkkarz Ar Lind Pirani (ur. 1990), piłkękarz Ar lind Qori (ur. 1981), polityk Arlind Rustemi (ur. 1986), piłkąkarz Arlinde Sadiku (ur. 1989),...</p>", "Arsene": "<p>Arsène to francuskie imię męskie. Pochodzi z łacińskiego imienia Arsenius, latynistycznej formy greckiego imienia ⁇ ρσἐνιος (Arsenios), co oznacza \"męski, męski\".</p>", "Aymane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ayman</b>.</p><b>Ayman</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> َأيْمَن) – arabskie imię męskie, oznaczające: błogosławiony, szczęśliwy. Bywa zapisywane także jako Ajman, Aiman, Aimen, Aymen.", "Anik": "<p>Anik: Anik to seria satelitów telekomunikacyjnych geostacjonarnych uruchomionych przez Telesat Canada. Anik G1 - satelitę telekomunikacyjną stworzoną przez amerykańską firmę Space Systems/Loral.</p>", "Arden": "<p>Arden International to międzynarodowa drużyna wyścigowa, założona przez Christiana Hornera. Występuje w serii GP2.</p>", "Abdulatif": "<p>Abdul Latif (arabski: عبد اللطيف, romanized: ʻAbd al-Laṭīf) to muzułmańskie imię i nazwisko męskie i w nowoczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Laṭīf, jednego z imion Boga w Koranie, które dały początek muzułmańskich nazw teoforycznych.</p>", "Anh Tu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Abdelmalek": "<p>Abdul Malik (arabsko: عبد الملك) to arabskie (muzułmańskie lub chrześcijańskie) męskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Malik.</p>", "Ambrose": "<p>Ambrosius (lat. Aurelius Ambrosius) (kr. 340 - 4 kwietnia 397) - cześć świętego Ambrosius, biskupów Milana od 374 do 397.</p>", "Arutiun": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arutyun</b>.</p><p>Harutyun (armeńska: Հարություն i w zachodnim armeńskim Յարութիւն) również pisoł Haroutioun, Harutiun i jego warianty Harout, Harut i Artin jest powszechną męską nazwą armeńską; oznacza to \"wskrzeszenie\" w języku armeńsku.</p>", "Abdellatif": "<p>Abdul Latif (arabski: عبد اللطيف, romanized: ʻAbd al-Laṭīf) to muzułmańskie imię i nazwisko męskie i w nowoczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Laṭīf, jednego z imion Boga w Koranie, które dały początek muzułmańskich nazw teoforycznych.</p>", "Abd": "<b>Abd</b> albo <b>`Abd</b> – w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskich</a> imionach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskich</a> oznacza sługę. Występuje zawsze w połączeniu z jednym z <a href=\"https://pl.wikipedia.org/wiki/99_atrybut%C3%B3w_Allaha\" target=\"_blank\" rel=\"noopener noreferrer\">99 imion Boga</a>.Np.: <a href=\"https://pl.wikipedia.org/wiki/Abdallah\" target=\"_blank\" rel=\"noopener noreferrer\">Abdallah</a> – Sługa Allaha, Abd al-Aziz – Sługa Wszechmocnego, … .„Abd” używane było w imionach również w <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCahilijja\" target=\"_blank\" rel=\"noopener noreferrer\">czasach przedislamskich</a> jak np. w imieniu prapradziada <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a> <i>Abd <a href=\"https://pl.wikipedia.org/wiki/Manaf\" target=\"_blank\" rel=\"noopener noreferrer\">Manaf</a></i>.", "Aladdin": "<p>Aladdin - opowieść z cyklu \"Tysiąc i jedna noc\" i imię jej głównego bohatera.</p>", "Ardi": "<i><b>Ardipithecus ramidus</b></i> (syn. <i>Australopithecus ramidus</i>; <i>Ardipithecus ramidus ramidus</i>) – <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunek</a> wymarłego ssaka <a href=\"https://pl.wikipedia.org/wiki/Naczelne\" target=\"_blank\" rel=\"noopener noreferrer\">naczelnego</a> z rodziny <a href=\"https://pl.wikipedia.org/wiki/Cz%C5%82owiekowate\" target=\"_blank\" rel=\"noopener noreferrer\">człowiekowatych</a> (Hominidae) żyjącego w <a href=\"https://pl.wikipedia.org/wiki/Pliocen\" target=\"_blank\" rel=\"noopener noreferrer\">pliocenie</a> na terenach <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>. Najbardziej kompletne <a href=\"https://pl.wikipedia.org/wiki/Skamienia%C5%82o%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">skamieniałości</a> <i>A. ramidus</i> pochodzą z okolic wioski Aramis w <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">Etiopii</a> i liczą około 4,4 mln lat. Znaleziony tam szkielet młodej samicy nie przypomina budową szkieletu <a href=\"https://pl.wikipedia.org/wiki/Szympans\" target=\"_blank\" rel=\"noopener noreferrer\">szympansa</a>, <a href=\"https://pl.wikipedia.org/wiki/Goryl\" target=\"_blank\" rel=\"noopener noreferrer\">goryla</a>, ani innych naczelnych blisko spokrewnionych z człowiekiem. <i>A. ramidus</i> wykazywał cechy zarówno hominidów nadrzewnych, jak i pewną formę naziemnej <a href=\"https://pl.wikipedia.org/wiki/Dwuno%C5%BCno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">dwunożności</a>, bardziej prymitywną niż występująca u <i><a href=\"https://pl.wikipedia.org/wiki/Australopiteki\" target=\"_blank\" rel=\"noopener noreferrer\">Australopithecus</a></i>. Żył prawdopodobnie głównie w <a href=\"https://pl.wikipedia.org/wiki/Las\" target=\"_blank\" rel=\"noopener noreferrer\">lasach</a>. Był stworzeniem dwunożnym, miał chwytne stopy, stosunkowo niewielką czaszkę – objętość puszki mózgowej wynosiła 300–350 cm³. Wiele cech budowy czaszki występowało także u <i><a href=\"https://pl.wikipedia.org/wiki/Sahelantrop\" target=\"_blank\" rel=\"noopener noreferrer\">Sahelanthropus</a></i>, dowodząc, że czaszki środkowoplioceńskich hominidów znacząco różniły się od tych u australopiteków oraz współczesnych małp. Odnaleziono ponad 145 zębów <i>Ardipithecus ramidus</i> – ich budowa sugeruje, że hominid ten był prawdopodobnie wszystkożercą lub owocożercą. Samica miała około 120 cm wzrostu i ważyła 50 kg.", "Archer": "<p>Archer (ang. Archer, z angielskiego.</p>", "Alvi": "<p>Alvi (ang. Alvi) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Abderraouf": "<p>'Abd al-Raʼūf (ALA-LC) to męskie muzułmańskie imię. Został zbudowany z arabskich słów ʿabd i al-Raʼūf, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Abdo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abd</b>.</p><b>Abd</b> albo <b>`Abd</b> – w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskich</a> imionach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskich</a> oznacza sługę. Występuje zawsze w połączeniu z jednym z <a href=\"https://pl.wikipedia.org/wiki/99_atrybut%C3%B3w_Allaha\" target=\"_blank\" rel=\"noopener noreferrer\">99 imion Boga</a>.Np.: <a href=\"https://pl.wikipedia.org/wiki/Abdallah\" target=\"_blank\" rel=\"noopener noreferrer\">Abdallah</a> – Sługa Allaha, Abd al-Aziz – Sługa Wszechmocnego, … .„Abd” używane było w imionach również w <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCahilijja\" target=\"_blank\" rel=\"noopener noreferrer\">czasach przedislamskich</a> jak np. w imieniu prapradziada <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a> <i>Abd <a href=\"https://pl.wikipedia.org/wiki/Manaf\" target=\"_blank\" rel=\"noopener noreferrer\">Manaf</a></i>.", "Anu": "Jego imię pisano za pomocą znaku klinowego w kształcie gwiazdy, który oznacza zarówno niebo (sum. <b>AN</b>), jak i boga (sum. <b>DINGIR</b>, akad. <i>ilu</i>). Pan wszystkich bogów rozsądza ich kłótnie, a jego wyroki są nieodwołalne; niewiele obchodzą go jednak sprawy ludzkie. Majestatyczny, szanowany, ale zajmujący najwyższą sferę nieba pozostaje zawsze kimś dalekim i w gruncie rzeczy dosyć niewyraźnym.", "Andres Camilo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Andres David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Anastas": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastase</b>.</p><p>Anastase jest męskim imieniem pochodzącym z starożytnego greckiego Anastasíā. Może odnosić się do:</p>", "Abir": "<b>Abir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia arabskiego o znaczeniu \"zapach\". Obecnie rzadko nadawane.", "Alasdair": "<p>Alasdair to szkocka gaelicka nazwa. Nazwa jest gaelicką formą Aleksandra, która od dawna jest popularna w Szkocji.</p>", "Amarjit": "<p>Amarjit lub Amarjeet to indyjskie imię, które oznacza \"wieczny triumf\". Wśród znanych osób z nazwiskiem to: Amarjit Singh Bal (1940-2010), oficer Indii Armia Amarjeet Singh Bedi (fl.</p>", "Asghar": "<p>Asghar (persk. اصغر) to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Aguilar": "<p>Aguilar to 4-gorowa gmina w prowincji Pangasinan, w Filipinach. Według danych z 2007 roku, mieście miało 36.564 mieszkańców w 6.131 dzielnicach.</p>", "Assan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asan</b>.</p><p>Asan (w języku wietnskim Nha Sơn) jest miastem w prowincji Chungcheong-South w Korei. Miasto znajduje się na południu od stolicy Seulu.</p>", "Atta": "<p>Atta (Mory-listorezy, mrówki z parafinu, angielski Leaf-cutting Ants, Parasol Ants) - rodzaj mrówek plemienia grzybków Attini z podrodzinnego rodu Myrmicinae.</p>", "Artis": "<p>Amsterdamskie zoo Artis znajduje się w centrum Amsterdamu, Holandia. Jest to najstarszy zoo w kraju, założony w 1838 roku.</p>", "Aime": "<p>Aime jest gminą w prowincji Savoie w regionie Auvergne-Rhône-Alpes w południowo-wschodniej Francji.</p>", "Antuan": "<p>Antuan to afroamerykańskie imię po angielsku związane z Antoine i Anthony. Wśród znanych osób z tego nazwiska są: Antuan Bronshtein, rosyjski skazany Antuan Edwards (ur. 1977), amerykański piłkarz piłkarza siatkówki Antuan Ilgit (ur. 1972), turecko-italijski katolicki jezuitański kapłan Antuan Mayorov (ur. 1971), białoruski piłkarze Antuan Simmons (ur. 1979), amerykański piłkarzem siatkówki Anttuan Siangboxing (ur. 1991), francuski Muay ...</p>", "Asiph": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asif</b>.</p><p>Asif (arabski: آصف) to arabskie męskie imię. W językach perskim i urdu często wymawia się jako \"Asif\" lub \"Asef\".</p>", "Ansgar": "<p>Ansgar (szw. Ansgar, lat.</p>", "Abdessamad": "<p>Abdul Samad Abdul Samed, itp. Można go przenieść na \"sługa samostanowionego Mistrza\" lub \"sługowiec Wiecznego Schronienia\".</p>", "Arturas": "<p>Artūras to litewska męska nazwa. Jest krewnym angielskiego imienia Arthur.</p>", "Asaad": "<p>As'ad, nieformalnie przetłumaczony jako Asaad lub Assaad, jest arabskim imieniem męskim pochodzącym z wyższego stopnia przymiotnika Sa'id sa'īd, co oznacza \"więcej/najbardziej szczęścia, szczęśliwsza/najszczęśliwsza, szczęśliwszą/najszczesniejszą\". Istnieje też jako nazwisko.</p>", "Ace": "<p>Ace: Ace to brytyjski zespół rockowy. Ace - album Ian Van Dahla z 2002 roku.</p>", "Alif": "أ, إ – jako nośnik <a href=\"https://pl.wikipedia.org/wiki/Hamza\" target=\"_blank\" rel=\"noopener noreferrer\">hamzy (ء)</a> – wtedy może na początku wyrazów oznaczać krótkie <b>a</b>, <b>i</b> lub <b>u</b>; występowanie: np. w słowie alif (ألف).", "Akil": "<p>Akil to miasto w stanie Yucatán w Meksyku. W 2005 roku liczba mieszkańców miasta wynosiła 9765 osób.</p>", "Anselm": "<p>Andrzej Iwanovich Anselm (niem. Anselm) (5 (18) maja 1905 r., Odessa - 13 sierpnia 1988 r., Leningrad) - sowiecki fizyk-teoretycz, doktor nauk fizycznych i matematycznych (1943 r.), profesor.</p>", "Aszot": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ashot</b>.</p><p>Ashot lub Ashod (armeńska: Աշոտ) to armenijska nazwisko. Do znanych osób z nazwą należą:</p>", "Antonio Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonio</b>.</p><p>Antonio James Uri (włoski: Antonio James Uri)  Antonio jest angielski.</p>", "Agris": "<p>Agris jest gminą w prowincji Charente, w regionie Nouvelle-Aquitaine, południowo-zachodniej Francji.</p>", "Abdon": "<b>Abdon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa oznaczającego „sługa”. Nosił je <a href=\"https://pl.wikipedia.org/wiki/Abdon_i_Senen\" target=\"_blank\" rel=\"noopener noreferrer\">święty Abdon</a> żyjący w II lub III wieku. Abdon <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi 30 lipca.", "Arnoldo": "<p>Arnoldo to włoskie i hiszpańskie imię męskie. To włoskie i hiszpańskie pisownię Arnolda.</p>", "Abdelmajid": "<p>'Abd al-Majīd (ALA-LC romanizacja arabskiego: عبد المجيد, perskiego: عبدالمجید), również pisowany jako Abd ul Majid, Abd ul-Majid, Abd ol Majid, Abdul ol-Majed i Abdolmajid, jest muzułmańskie męskie imię i nazwisko. Jest to połączenie arabskich słów 'abd i al-Majīd, jednego z nazw Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Aldis": "Aldis ma istotne znaczenie w porozumiewaniu się w czasie <a href=\"https://pl.wikipedia.org/wiki/Cisza_radiowa\" target=\"_blank\" rel=\"noopener noreferrer\">ciszy radiowej</a>.", "Ashfaq": "<p>Ashfaq to męskie imię pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Abiola": "<p>Abíólá to jorubańskie imię. Znaczenie Abíólá jest \"urodzony w honor, bogactwo\".</p>", "Adama": "<p>Adama (oromo: Adaamaa lub Hadaamaa) jest miastem w centrum Oromia. Adama jest obszarem Oromia i otoczony jest obszarami wschodniej Shewa.</p>", "Aphgan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Afgan</b>.</p>Wytwarzany głównie przez plemię Ersari zamieszkujące obszary <a href=\"https://pl.wikipedia.org/wiki/Turkmenistan\" target=\"_blank\" rel=\"noopener noreferrer\">Turkmenii</a> nad rzeką <a href=\"https://pl.wikipedia.org/wiki/Amu-daria\" target=\"_blank\" rel=\"noopener noreferrer\">Amu-daria</a> od początku XVII wieku. Pochodzenie nazwy tego kobierca <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europejczycy</a> zawdzięczają pośrednictwu <a href=\"https://pl.wikipedia.org/wiki/Rosjanie\" target=\"_blank\" rel=\"noopener noreferrer\">Rosjan</a>, którzy eksportowali ten towar na <a href=\"https://pl.wikipedia.org/wiki/Europa_Zachodnia\" target=\"_blank\" rel=\"noopener noreferrer\">Zachód</a>, po uprzednim zaopatrzeniu się w <a href=\"https://pl.wikipedia.org/wiki/Kabul\" target=\"_blank\" rel=\"noopener noreferrer\">Kabulu</a>.", "Aleksandro": "<p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Alamgir": "<p>Alamgir lub Alomgir mogą odnosić się do:</p>", "Abbosbek": "<p>Abbas Bahadur (z wybr. Abbos bahodur / Abbosbek; pierwsza połowa XIV wieku, Włoska Częstyska - 1387, Imperium Timurów) - towarzysz Amir Temura, środkowoazjatyckiego wielkich kapczątów, amira lachar Imperium Timur.</p>", "Andreis": "<p>Andreis jest miastem w prowincji Pordenone w regionie Friuli-Venezia Giulia, odległym około 110 km na północny-zachodni od Trieste i około 25 km na północy od Pordenone. Na dzień 31 grudnia 2004 roku mieście miało 308 mieszkańców i obszarze 26,9 km2.</p>", "Atalay": "<p>Atalay to tureckie imię i nazwisko. Do wybitnych osób z nazwiskiem należą:</p>", "Ananiasz": "<b>Ananiasz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Grecka forma <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Hananiah</i> – „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> jest łaskawy”. Jednym z patronów tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Ananiasz_z_Damaszku\" target=\"_blank\" rel=\"noopener noreferrer\">św. Ananiasz z Damaszku</a>.", "Andree": "<p>Andree lub Andrée może odnosić się do: Andree Right Hand, wietnamskiego rapera i muzyka 1296 Andrée, asteroida</p>", "Amel": "<p>Amel (Francuz: Amblève) jest miastem w regionie Wallonie, prowincji Liège, i należy do niemieckojęzycznej społeczności w Belgii (German: Deutschsprachige Gemeinschaft Belgiens). Na 1 stycznia 2006 roku Amel miał łącznie 5.282 mieszkańców.</p>", "Avel": "<p>Avel to męskie imię. Inną definicją Avel jest HİLAL</p>", "Assad": "<p>Asad (arabski: أسد), czasami napisany jako Assad, jest arabskim męskim imieniem dosłownie oznaczającym \"łówn\". Jest używany w nazwach takich jak Asad Allāh, jedno z nazwach Ali ibn Abi Talib.</p>", "Akshat": "<p>Akshat to męskie imię w kulturach hinduskich i buddyjskich. Pochodzi od sanskryckiego słowa Aksata, co oznacza \"niepowlekany\".</p>", "Amand": "<b>Amand</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <i><a href=\"https://pl.wikipedia.org/wiki/Amandus\" target=\"_blank\" rel=\"noopener noreferrer\">Amandus</a></i> wywodzące się od słowa <i>amara</i>, 'kochać'. Amand to ten, „który powinien być kochany”. Istnieje trzech świętych patronów tego imienia.", "Andor": "<p>Andor (węgierski Andor) - węgierska nazwa i nazwisko pochodzące od greckiego imienia Andreas (grecki Andor).</p>", "Abdelali": "<p>'Abd al-ʻAlī (ALA-LC romanizacja arabskiej: عبد العلي, perskiego: عبدالعلی), również pisowany jako Abd ul Ali, Abd ul-Ali, Abd ol Ali i Abd ol-Ali, to męskie muzułmańskie imię. Został zbudowany z arabskich słów ʿabd i al-ʻAlī, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Aimable": "<p>Aimable to męskie imię, które może odnosić się do: Aimable Bayingana (ur. 1970), rwandański dyrektor sportowy Aimable Denhez (1914-1977), francuski rowerzyst Aimable Duperouzel (1831-1901), francuski urodzony skazany Aimable Robert Jonckheere (1920-2005), brytyjski psycholog i statystyk Aimable Manirakiza, burundyjskiego działacza praw człowieka Aimable Nsabimana (ur. 1997), rwandańskiego piłkarza futbolu Aimable Pélissier (1794-1864), marszałka Francji Steven...</p>", "Arron": "<p>Arron to zarówno imię, jak i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Alphonse": "<p>Alfonso (ang. Alfons, Alphons, hiszpański.</p>", "Anees": "<p>Anees to męskie imię pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Aqib": "<p>Aqib i Aaqib to imiona męskie. Znani ludzie z tymi nazwami to: Aqib Ilyas (ur. 1992), kryketar Omani Aqib Javed (ur. 1997), kryketer pakistański Aaqib Javed, ur. 1972), pakistański kryketar i trener Aqib Khan (ur. 1994), pakistajski aktor Aaqib Khan (urat. 2003), indyjski kryketar Aqib Shah (ur. 1995), pakistański kryketar Aaqib Talib (ur. 1986), amerykański piłkarz piłki nożnej</p>", "Amith": "<p>Amit to imię indyjskie i żydowskie oraz żydowskie nazwisko. W języku hindi Amit (Hindi: अमित, oznacza \"nieograniczony\" lub \"bezgraniczny\", Bengali: অমিত) pochodzi od sanskrytyjskiego słowa amita (अमित:), amita (অमित:) jest zasadniczo negatywem mita (मित), co oznacza \"mierzyć\".</p>", "Alish": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alisha</b>.</p><p>Alice Ann Itkin (ang. Alisha Ann Itkin; po ślubie - Alice Sinamon (ang.</p>", "Aurelien": "<p>Zobacz także Aurélien, powieść z 1944 roku Louis Aragona. Aurélien to francuskie męskie imię i może odnosić się do: Aurélien Agbénonci (ur. 1958), benyńskiego dyplomata Aurélien Barrau (ur. 1973), francuskiego fizyka i filozofa Aurélien Bélanger (1878-1953), kanadyjskiego polityka Aurélien Bellanger (ur. 1980), francuskiego pisarza i aktora Aurélien Boche (ur. 1981), francuskiego piłkarza Aurélien Brulé (ur. 1979), francuskiego założyciela Kalaweit Project Aurélien ...</p>", "Arjuna": "<p>Arjuna (sanskrit: अर्जुन, IAST: arjuna) lub A-chu-na (阿周那) jest centralną postacią starożytnej indyjskiej historii Mahabharaty. Arjuna był synem Pandu w Królestwie Kuru.</p>", "Abdulwahab": "<p>Abdul Wahhab (arabsko: عبد الوهاب, romanized: ʻAbd al-Wahhāb) to męskie imię i nazwisko pochodzenia arabskiego. Został zbudowany z arabskich słów ʿabd i al-Wahhāb, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Arran": "<p>Árran (lule-saam.) - lule-saamski ośrodek kulturalny na północy Norwegii. Znajduje się w miejscowości Drag w gminie Tuusfjord w prowincji (fulce) Nurlann.</p>", "Amado": "<p>Amado (portuńska Amado) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Angello": "<p>Steve Angello (szwedz. Steve Angello, pełne imię - Stephen Angello Josefsson Fragogiannis (Steven Angello Josefsson Fragoguannis); urodzony.</p>", "Anushavan": "<p>Anushavan jest miastem w prowincji Shirak w Armenii. W 2011 roku liczba ludności wynosiła 2211.</p>", "Adelbert": "<b>Adalbert, Adelbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających <i>adal</i> (ród szlachecki) i <i>beraht</i> (jasny, błyszczący), oznaczało „pochodzącego ze szlachetnego rodu”. Występuje w wielu odmianach, np.: <a href=\"https://pl.wikipedia.org/wiki/Albert_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Albert</a>, Olbracht.", "Adelin": "<p>Adelin (francuski Adelin; zmarł około 910 roku) - święty biskup Se (884 - 910).</p>", "Alla": "<b>Alla</b>, <i>Ałła</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> i wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;άλλη – „inna”. Używane przede wszystkim w Rosji, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a> i <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a>.", "Alden": "<p>Alden (ang. Alden, Olden) - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Anatolyi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anatoly</b>.</p><p>Anatolii (rosyjski: Анатолий, romanizowany: Anatoliy, ukraiński: Анато́лій, romanized: Anatolii) jest powszechną rosyjską i ukraińską nazwą męską, pochodzącą z greckiego imienia Anatolios (⁇ νατόλιος), co oznacza \"on wschodu słońca\", z ἀνατολή anatolē, \"wychod słońca\". Anatoly było jednym z pięciu najpopularniejszych imion dla chłopców urodzonych w St.</p>", "Andres Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Akio": "<b>Akio</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきお, アキオ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Arslanbek": "<p>Arslanbek (rosyjski: Арсланбек) to męskie imię. Do wybitnych osób z tym nazwiskiem należą: Arslanbek Açilow (ur. 1993), turkmenski bokser Arslanбек Makhmudov (ur. 1989), rosyjski bokser ArSlanbek Sultanbekov (ur . 1965), rosyjskie muzyczny narodowy i poeta</p>", "Aubrey": "<p>Aubrey () to unisex angielskie imię. W średniowieczu był to powszechne dla mężczyzn i kobiet, ale przez pewien czas straciło przyzwolenie przed ożyciem ponownego wzrostu popularności dla mężczyzn w XIX wieku.</p>", "Andres Mauricio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Azeez": "<p>Aziz (arabsko: عزيز, romanizowane: ʿAzīz; hebrajskie: עָזִז, romanized: ʿ Azīz; akadyjskie: ⁇ , romanizewane: ʾEzīzū) jest nazwą semityczną z korzenia dwuszayin. W hebrajskim Biblii korzenie z dwóch stron (ז-ז) oznacza 'godny imieniu, potężny, wyniosły'.</p>", "Abdus": "<p>Abdul (tzw. Abd, Abdel, Abdil, Abdol, Abdool lub Abdoul) jest najczęstszą transliteracją połączenia arabskiego słowa Abd (عبد, oznaczające \"Służebnik\") i prefiksu al / el (ال, oznaczający \"The\"). Jest to początkowy składnik wielu nazw związanych, takich jak Abd الحميد ʿAbd al-Ḥamīd (zwykle pisane Abdel Hamid, Abdelhamid, Abd El Hamid lub Abdul Hamid; lit.</p>", "Alioune": "<p>Alioune to męskie imię. Znani ludzie z nazwiska to: Alioune Ba (piłkarz) (ur. 1989), francuski piłkarz Alioune Bâ (ur. 1959), malijski fotograf Alioune Badará (ur. 1989), senegalijczyk Alioune Badara Bèye (1945-2024), senegalijski urzędnik urzędowy, pisarz, dramatyk, poeta i wydawca Alioune Diakhate (ur. 1994), senegajski piłkarze Alioune Diouf (ur. 1966), senegalijczyk w tekście Alioune Diop...</p>", "Amrik": "<p>Amrik to indyjska męska nazwa, która może odnosić się do Amrik Anand (ur. 1947), indyjskiego kryketa Amrik Singh (1948-1984), prezesa Federacji Indii Sikhów Sikhów Amrik Singh Cheema (1918-1982), indyjski urzędnik i autor Amrik Singh Dhillon, indyjski polityk Sikhów Punjabi Amrik Virk (ur. 1963 lub 1964), kanadyjski polityk</p>", "Abolfazl": "<p>Abu al-Fadl lub Abu'l-Fadle (arabski: ابو الفضل) to arabskie imię męskie, które występuje również w imionach miejsc. To znaczy ojciec cnoty.</p>", "Asa": "<b>Asa</b> – imię męskie o niepewnym znaczeniu. Według jednej z hipotez jest skróceniem hebrajskiego słowa <i>asael</i>, znaczącego „stworzył Bóg”.", "Amilcar": "Znane było z wytwarzania aut wyścigowych oraz eleganckich modeli wyższej <a href=\"https://pl.wikipedia.org/wiki/Autosegment_D\" target=\"_blank\" rel=\"noopener noreferrer\">klasy średniej</a>. Sukcesem okazał się udział w wyścigu <a href=\"https://pl.wikipedia.org/wiki/24h_Le_Mans\" target=\"_blank\" rel=\"noopener noreferrer\">Le Mans</a> w 1924 i 1932 roku. W 1937 zostało przejęte przez koncern <a href=\"https://pl.wikipedia.org/wiki/Hotchkiss\" target=\"_blank\" rel=\"noopener noreferrer\">Hotchkiss et Cie</a>. Produkcji aut tej marki zaprzestano w czasie <a href=\"https://pl.wikipedia.org/wiki/II_wojna_%C5%9Bwiatowa\" target=\"_blank\" rel=\"noopener noreferrer\">II wojny światowej</a> i już nie wznowiono. Nazwa „Amilcar” pochodzi ze złożenia nazwisk założycieli firmy (Joseph Lamy i Émile Akar). Do 1937 występowało pod nazwą „Sté Nouvelle pour l’Automobile Amilcar”, a potem „Sté Financière pour l’Automobile”.", "Abdelfattah": "<p>'Abd al-Fattāḥ (ALA-LC) to muzułmańskie imię męskie i w nowoczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Fattāḥ, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Ahmed Mohamed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Antos": "Nazwisko <b>Antos</b> (Antosz) wywodzi się od imienia <a href=\"https://pl.wikipedia.org/wiki/Antoni_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antoni</a>, notowanego w Polsce od XIII wieku; pochodzącego od łacińskiego Antonius (<a href=\"https://pl.wikipedia.org/wiki/Dynastia_Antonin%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoninowie</a>) – znanego rodu rzymskiego i dynastii w cesarstwie rzymskim panującej w latach 96–192. Jest notowane w Polsce od XIII wieku.", "Aldi": "<b>Aldi</b> (nazwa stylizowana: <b>ALDI</b>) – <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">niemiecka</a> sieć dyskontów spożywczo-przemysłowych obecna na pięciu kontynentach. Siódma pod względem sprzedaży sieć marketów na świecie. Nazwa przedsiębiorstwa pochodzi od skrótu nazwiska <b>Al</b>brecht i słowa <b>di</b>skont. Przedsiębiorstwo powstało i do dziś jest <a href=\"https://pl.wikipedia.org/wiki/Przedsi%C4%99biorstwo_rodzinne\" target=\"_blank\" rel=\"noopener noreferrer\">firmą rodzinną</a> Albrechtów z <a href=\"https://pl.wikipedia.org/wiki/Essen\" target=\"_blank\" rel=\"noopener noreferrer\">Essen</a>.", "Azriel": "<p>Azriel (lub Ezriel) to hebrajskie imię, które oznacza \"Bóg pomaga\". Do wybitnych osób z tym nazwiskiem należą:</p>", "Andersson": "<p>Nils Johan Andersson (szwedzki: Nils Johan Anderson, 20 lutego 1821 - 27 marca 1880) - szwedzki botanik.</p>", "Aki": "<b>Aki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あき, アキ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, fińskie i nigeryjskie. W Japonii występuje także jako nazwisko.", "Agenor": "<b>Agenor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „mężny”, „bohaterski”.", "Anastasiia": "<p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Amaro": "Amaro powstaje na bazie produktów pochodzących z Włoch – ziół, przypraw, kwiatów i/lub skórki <a href=\"https://pl.wikipedia.org/wiki/Cytrus\" target=\"_blank\" rel=\"noopener noreferrer\">owoców cytrusowych</a>. Skład mieszanki różni się w zależności od marki, a informacje takie jak proporcje użytych produktów, czy szczegóły procesu powstawania amaro utrzymywane są w tajemnicy. Po wybraniu składników bazowych dla danego likieru poddaje się je procesom mającym na celu uzyskanie z nich smaku i aromatu – część z nich zostaje namoczona w alkoholu, część w wodzie. Każdy z użytych produktów ma pewien określony czas, w którym oddaje rozpuszczalnikowi swoją esencję. Dlatego też składające się na końcowy efekt, czyli smak likieru, elementy często nie mogą być macerowane razem. W chwili uzyskania oczekiwanego rezultatu prowadzonych do tej pory działań, poszczególne ciecze łączy się ze sobą w ściśle określonych proporcjach, a następnie przelewa do beczek (niektóre rodzaje amari np. Fernet-Branca dojrzewają) lub butelek.", "Azariasz": "<b>Azariasz</b> – hebrajskie i biblijne imię męskie oznaczające „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> dopomógł”, „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> wspomaga” (hebr. Azarjahu, Azaria).", "Abdirahman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Abdulmajid": "<p>'Abd al-Majīd (ALA-LC romanizacja arabskiego: عبد المجيد, perskiego: عبدالمجید), również pisowany jako Abd ul Majid, Abd ul-Majid, Abd ol Majid, Abdul ol-Majed i Abdolmajid, jest muzułmańskie męskie imię i nazwisko. Jest to połączenie arabskich słów 'abd i al-Majīd, jednego z nazw Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Abdoul": "<p>Abdul (tzw. Abd, Abdel, Abdil, Abdol, Abdool lub Abdoul) jest najczęstszą transliteracją połączenia arabskiego słowa Abd (عبد, oznaczające \"Służebnik\") i prefiksu al / el (ال, oznaczający \"The\"). Jest to początkowy składnik wielu nazw związanych, takich jak Abd الحميد ʿAbd al-Ḥamīd (zwykle pisane Abdel Hamid, Abdelhamid, Abd El Hamid lub Abdul Hamid; lit.</p>", "Alvaro Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alvaro</b>.</p><b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Ayo": "<p>Áyo (yorubà Ayọ [ajɔ ⁇ ] - ⁇ rość ⁇; prawdziwa nazwa Joy Olasunmibo Ogunmakin, 14 września 1980, Frehen niedaleko Köln, Niemcy) - niemiecka piosenkarka i kompozytorka pochodzenia afrykańskiego. Jej styl wykonania odnosi się do sołu z elementami folku i reggi.</p>", "Ajin": "Oznacza <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_gard%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">szczelinową dźwięczną spółgłoskę gardłową</a> lub <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_nag%C5%82o%C5%9Bniowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">nagłośniową</a>.", "Ake": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ace</b>.</p><p>Ace: Ace to brytyjski zespół rockowy. Ace - album Ian Van Dahla z 2002 roku.</p>", "Arndt": "<p>Arndt lub Arnd to niemieckie męskie imię, skrótowa forma Arnold, a także niemieckia nazwisko patronymiczne. Do wybitnych osób z tym nazwiskiem należą:</p>", "Ash": "<p>Ash (grupo) - północnoirlandzkie zespół rockowy. ash (UNIX) - komórka polecenia UNIX.</p>", "Abdullatif": "<p>Abdul Latif (arabski: عبد اللطيف, romanized: ʻAbd al-Laṭīf) to muzułmańskie imię i nazwisko męskie i w nowoczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Laṭīf, jednego z imion Boga w Koranie, które dały początek muzułmańskich nazw teoforycznych.</p>", "Abdul Rahman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Azzedine": "<p>Izz al-Din (arabski: عزّ الدين lub powszechnie napisany عزّ الدین, 'izzu \"d-dīn, 'izza \"d-Dīn, również napisany Azzedine lub Azzeddine) jest męskie nazwisko i nazwisko pochodzenia arabskiego oznaczające \"wysoki rang (honor, szacunek, prestiż) religii islamskiej / wiary\". Prefiks \"'izz\" oznaczający \"wysoki rangę, honor, szacunek, prestiż\" jest również pojęciem, że ktoś jest szanowany, ceniony, silny lub potężny.</p>", "Anh Tú": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Abdennour": "<p>'Abd al-Nūr (ALA-LC) to męskie imię i nazwisko. Nazwa ta jest używana przez muzułmanów, a także przez koptyjskich i prawosławnych chrześcijan na Bliskim Wschodzie.</p>", "Armend": "<p>Armend to albanska imię męskie oznaczające \"złoty umysł\". Do wybitnych osób z tym nazwiskiem należą: Armend Alimi (ur. 1987), makedonii piłkarz piłkarski Armend Dallku (ur. 1983), albanianki trener piłkarza i gracz Armend Halili (ur. 1997), kosowskiego piłkarze Armend Kabashi (ur. 1995), fińskiego piłkarka Armend Mehaj (ur. 1981), kosowskiego oficera wojskowego albano-norweskiego Armend Muja (ur. 1981), kosowskiego polityka Armend...</p>", "Anastasis": "<p>Anastasis (grek. Odrodzenie, zmartwychwstanie) - ósmego albumu studiowego zespołu Dead Can Dance, wydanego w 2012 roku.</p>", "Angel David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Adyl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adil</b>.</p><b>Adil</b> – arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od słowa <i>adil</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عدل&#8206;, <i>’adil</i>) – 'sprawiedliwy', 'uczciwy'.", "Aleksii": "<p>Alexey (rosyjski: Алексей, romanized: Aleksey [ɐljɪkˈsjej]) to rosyjskie imię męskie pochodzące od greckiego Aléxios (Αλέξιος), co oznacza \"Obrannik\", a zatem z tego samego pochodzenia jak łacina Alexius. Podobne ukraińskie i białoruskie nazwy są romanizowane odpowiednio jako Oleksii (Олексій) i Aliaksiej (Аляксей).</p>", "Aibar": "<p>Aibar - Oibar to miasto w prowincji i samorządowej społeczności nawarskiej, Hiszpanii. Miasto to ma powierzchnię 47,96 km2, populacja 923 mieszkańców (w 2007 roku).</p>", "Andrews": "<p>Andrews (ang. Andrews, czasami Andrewes) - angielska nazwisko i toponim, pochodzące od imienia Andrew.</p>", "Allah": "<a href=\"https://pl.wikipedia.org/wiki/Mitologia_arabska\" target=\"_blank\" rel=\"noopener noreferrer\">Początkowo</a> słowo Allah było wykorzystywane zarówno przez <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">Arabów</a> do określania <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">boga</a> <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99%C5%BCyc\" target=\"_blank\" rel=\"noopener noreferrer\">Księżyca</a> – <a href=\"https://pl.wikipedia.org/wiki/Nanna_(b%C3%B3g)\" target=\"_blank\" rel=\"noopener noreferrer\">Sina</a>, wywodzącego się od sumeryjskiego boga księżyca <a href=\"https://pl.wikipedia.org/wiki/Nanna_(b%C3%B3g)\" target=\"_blank\" rel=\"noopener noreferrer\">Nanny</a>, jak i przez chrześcijańskich Arabów do określania Boga. Pomimo że jest tradycyjnie kojarzone z islamem, słowo Allah nie jest specyficzne dla tej religii. Także wśród przedislamskich i chrześcijańskich Arabów słowami Allah/Alihah oznaczającymi to samo co u żydów Eloh/<a href=\"https://pl.wikipedia.org/wiki/Elohim\" target=\"_blank\" rel=\"noopener noreferrer\">Elohim</a> określano Boga w rozumieniu monoteistycznym. Słowo Allah występuje między innymi na inskrypcji z Umm al-Dżimal. Od czasów <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a> zaczęło ono oznaczać dla muzułmanów w języku arabskim wyłącznie abrahamicznego Boga i dlatego chociaż ma ono lingwistycznie formy liczby mnogiej oraz rodzaju żeńskiego, to te formy gramatyczne nie są obecnie stosowane, przynajmniej wśród muzułmanów.", "Arber": "<p>Arber (niemiecki) - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Abdelhadi": "<p>'Abd al-Hādī (ALA-LC) to muzułmańskie imię męskie, a w współczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Hādī, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Affan": "<p>Affan (arabski: عفّان) to arabskie imię męskie oznaczające \"chastą, skromną, cnotliwą, czyste\". Mieszkańcy imienia Affan to: Affan ibn Abi al-'As, krewny islamskiego proroka Muhammada Affan Khan (ur. 2007), indyjski aktor Affan Kurniawan (2004-2025), indonezyjski kierowca, którego śmierć podkreśliła brutalność policji Affan Mitul, bałgajski aktor filmowy Affan Waheed, pakistański aktor Affan Yousuf (ur. 1994), indyjskie hokejistka Aban bin...</p>", "Akihiro": "<b>Akihiro</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきひろ, アキヒロ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Adams": "<p>Michał Iwanovich Adams (Michal Friedrich, Johann Friedrich, czyli Adam) (30 czerwca [11 lipca] 1780, Moskwa - 1 [13] marca 1836, Urocz Veriański, według innych danych 1 [13] marca 1836 Moskwa) - naturalisty-zoolog, botanik, członek-korespondent Imperial Sankt-Petersburg Academy of Sciences od 1 (13) lutego 1804 roku, adъюнкт po zoologii od 27 marca (8 kwietnia) 1805 roku do 11 (23) marca 1809 roku, ordynarny profesor botaniki Moskowskiego...</p>", "Azzeddine": "<p>Izz al-Din (arabski: عزّ الدين lub powszechnie napisany عزّ الدین, 'izzu \"d-dīn, 'izza \"d-Dīn, również napisany Azzedine lub Azzeddine) jest męskie nazwisko i nazwisko pochodzenia arabskiego oznaczające \"wysoki rang (honor, szacunek, prestiż) religii islamskiej / wiary\". Prefiks \"'izz\" oznaczający \"wysoki rangę, honor, szacunek, prestiż\" jest również pojęciem, że ktoś jest szanowany, ceniony, silny lub potężny.</p>", "A": "<p>A (U+0410) lub A (U +0041) może oznaczać: A - pierwsza litera alfabetu cyrylskiego. A to pierwsza litera alfabetu łacińskiego.</p>", "Anh Minh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Abdulhakim": "<p>Abdul Hakim (arabski: عبد الحكيم, romanized: ʻAbd al-Ḥakīm) to muzułmańskie imię męskie, a w nowoczesnym użyciu, imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Hakim.</p>", "Arcadius": "<p>Arcadius (lat. Arcadius, 284 r., rzymska prowincja Maвреtańska - 305 r., tam sam) - święty Kościoła rzymskokatolicznego, męczennik.</p>", "Ariyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arian</b>.</p><b>Arian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jego patronem jest św. Arian, wspominany razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Teotyk_(m%C4%99czennik_egipski)\" target=\"_blank\" rel=\"noopener noreferrer\">Teotykiem</a>.", "Afik": "<p>Afik (Hebrajski: אֲפִיק) to izraelska obóz i kibbutz, założony w 1972 roku w pobliżu syryjskiej wioski Fiq. To było pierwsze miejsce, w którym Żydzi byli założeni na Golanie po Wojne Sześciodniowej.</p>", "Alexandru-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Anh Dũng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Abdurahman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Avishek": "<p>Avishek to męskie imię, które może odnosić się do: Avishek Das (ur. 2001), Bangladesza kryker Avishek Karthik (ur. 2007-obecny), indyjski aktor w tamilskim filmach Avishek Mitra (ur. 1992), Bangladeszczyk kryker Awishek Sinha (ur. 1984), indyjskie kryker</p>", "Anan": "<p>A. Ananda (kr. - Nie, nie, nie. Pi.</p>", "Allon": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alon</b>.</p><p>ALON (Alon Valerievich Mullayev; ur. 16 lipca 1995, Netania, Izrael) - rosyjski muzykiem, piosenkarzem, artystą, autorem piosenek.</p>", "Al Amin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Al</b>.</p><p>Aluminium (chymiczny symbol - Al, od łacińskiego Aluminium), wcześniej również gliny (od rosyjskiego.</p>", "Attia": "<p>Attia może odnosić się do: Attia (gens), plebejskiej rodziny w Rzymie</p>", "Abdulsalam": "<p>Abd al-Salam (arabski: عبد السلام) to męskie muzułmańskie imię honorowe lub nazwisko, oparte na arabskich słowach Abd, al- i Salam. Nazwa oznacza \"sługę Wszechświata\", a As-Salam jest jednym z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Arturi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Artur</b>.</p><b>Artur</b> wymowa – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Powstało ze złożenia dwóch wyrazów wywodzących się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">języków celtyckich</a>: <i>Art</i> – niedźwiedź, <i>ur</i> – młody, piękny, kwitnący. Podstawę imienia może także stanowić celtyckie słowo ard – wysoki, szlachetny.", "Abderrahman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Arkan": "<p>Arkan to francuska grupa orientałowa.</p>", "Alian": "Populacja dzielnicy Alian w 2016 roku liczyła 29&#160;093 mieszkańców – 14&#160;407 kobiet i 14&#160;686 mężczyzn. Liczba gospodarstw domowych wynosiła 9407, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,09 osób.", "Adilson": "<p>Adílson to portugalska nazwa. Do wybitnych osób z nazwiskiem należą: Adílson Alves Moreira (ur. 1943), brasilijski piłkarz Adilson da Silva (ur. 1972), brazylijski profesjonalny golfacz w Południowej Afryce Adílson dos Santos (ur. 1976), brazylijski piłkacz Adilson E.</p>", "Anh Quan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Akeem": "<p>Akeem jest nazwą pochodzącą z arabskiego języka, jest to wariant Hakeem i powszechnie stosowany w Afryce i wśród afrykańskiej diaspory. Osoby z nazwiskiem Akeem to: Akeem Adams (1991-2013), trynidadyjski piłkarz Akeem Anifowoshe (1968-1994), nigeryjski bokser Akeem Auguste (urodzony 1989), amerykański piłkarze Akeem Ayers (urodzona 1989), amerykanin piłkarza Akeem Bostick (urodzono 1995), amerykański piłkarzem baseballu Akeem Davis (urodzone 1989), ameryk...</p>", "Abdelmadjid": "<p>'Abd al-Majīd (ALA-LC romanizacja arabskiego: عبد المجيد, perskiego: عبدالمجید), również pisowany jako Abd ul Majid, Abd ul-Majid, Abd ol Majid, Abdul ol-Majed i Abdolmajid, jest muzułmańskie męskie imię i nazwisko. Jest to połączenie arabskich słów 'abd i al-Majīd, jednego z nazw Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Asmir": "<p>Asmir to bosniackie imię męskie. Na Bałkanach Asmir jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Alkan": "<p>W przypadku węglowodorów zawierających jeden lub więcej krążków, zobacz Cycloalkan. Alkane (ang. alkane /ˈæl.keɪn/) w chemii organicznej są zatłoczonymi hydrocarbonami nie tworzącymi kręgów.</p>", "Arezki": "<p>Arezki lub Areski (tamazight: ⴰⵔⴻⵣⵇⵉ) to zarówno męskie imię i nazwisko, powszechnie stosowane w Kabylii w północnej Algierii. Wariant nazwy jest Rezki (tamazight: ⵔⴻⵣⴽⵉ).</p>", "Ambroise": "<p>Ambrouz (francuski: Ambrouze). Ambroise, włoski.</p>", "Amila": "<p>Amila jest miastem i nagar panchayatem w prowincji Mau w stanie Uttar Pradesh, India.</p>", "Abdeslam": "<p>Abd al-Salam (arabski: عبد السلام) to męskie muzułmańskie imię honorowe lub nazwisko, oparte na arabskich słowach Abd, al- i Salam. Nazwa oznacza \"sługę Wszechświata\", a As-Salam jest jednym z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Abubaker": "<p>Abu Bakr (arabsko: أبو بكر) to arabskie imię, które oznacza \"ojciec młodego wielbłąda\" (Abu oznacza \"ojca\" i Bakr oznacza \"młody wielbłąd\"), które jest szeroko stosowane przez muzułmanów sunnitów. Inne transliteracje obejmują Abu Bakar, Abu Bekr, Ebubekir, Aboubacar, Abubakar itp.</p>", "Akan": "<b>Akan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> עָכָן) – postać biblijna <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>. Występuje w <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Jozuego\" target=\"_blank\" rel=\"noopener noreferrer\">Księdze Jozuego</a> w rozdziale 7. Wymieniany jest także w <a href=\"https://biblia.deon.pl/otworz.php?skrot=1%20Krn%202,7\" target=\"_blank\" rel=\"noopener noreferrer\">1 Krn 2,7</a> i nosi tam imię Akor.", "Alieu": "<p>Alieu to nazwisko męskie afrykańskiego zachodniego, co oznacza \"silne\" i ma swoje pochodzenie z ludności Fula. Było to powszechne imię w rodzinie królewskiej Fulani i używane było do królewskiego życia.</p>", "Albi": "<p>Albi jest prefekturą Tarn, w francuskim regionie Occitanie. Populacja miasta w 2023 roku wynosi około 51.290 osób.</p>", "Albino": "<p>Albino, to miasto w prowincji Bergamo, Lombardy, Włochy. Miasto ma powierzchnię 31,32 km2, liczba ludności wynosi 17,807.</p>", "Abeli": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abel</b>.</p><b>Abel</b> (hebr. הבל) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z hebrajskiego <i>abhal</i> – „mgła, dym, tchnienie”. Być może wiązało się jednak z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>aplu || ibil</i> lub asyryjskim <i>ahbla || ablu</i> – „syn rodzony”. Nosiła je <a href=\"https://pl.wikipedia.org/wiki/Kain_i_Abel\" target=\"_blank\" rel=\"noopener noreferrer\">postać biblijna</a>, syn Adama i Ewy, który był pasterzem. Abel został zamordowany przez swego brata Kaina, rolnika. Imię to było notowane na terenie Polski już w średniowieczu, na przełomie <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIV wieku</a>, początkowo jako imię zakonne. Patronem tego imienia w Kościele katolickim są, obok Abla, syna Adama i Ewy, m.in. Abel, biskup Metzu, i <a href=\"https://pl.wikipedia.org/wiki/Abel_z_Reims\" target=\"_blank\" rel=\"noopener noreferrer\">Abel</a>, arcybiskup Reims.", "Abdulkhakim": "<p>Abdulkhakim to męskie imię.</p>", "Audrey": "<b>Edeltruda</b>, <b>Edeltrauda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemieckiego</a>, nienotowane w Polsce w średniowieczu; obecnie występuje w zauważalnym stopniu w Polsce na obszarach zamieszkiwanych przez mniejszość niemiecką. Imię to powstało z połączenia członów <i>adal</i> – 'szlachetny ród' oraz <i>trud</i> – 'siła, potęga' i stanowi późniejszą wersję niemieckiego imienia <i>Adeltraud</i>.", "Amelia": "<b>Amelia</b>, <b><a href=\"https://pl.wikipedia.org/wiki/Amalia\" target=\"_blank\" rel=\"noopener noreferrer\">Amalia</a></b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako skrócenie imion dwuczłonowych z pierwszym członem <i>Amal-</i>, takich jak między innymi <a href=\"https://pl.wikipedia.org/wiki/Amalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Amalgunda</a> lub <a href=\"https://pl.wikipedia.org/wiki/Amalberga\" target=\"_blank\" rel=\"noopener noreferrer\">Amalberga</a>.", "Abdul Aziz": "<p>Abdul Aziz, Abdulaziz lub Abdul-Aziz mogą odnosić się do: Abd al-Aziz, męskie arabskie nazwisko teoforyczne, powszechnie skrócone jako Aziz</p>", "Abdulkareem": "<p>'Abd al-Karīm (ALA-LC) to muzułmańskie imię męskie i w nowoczesnym użyciu także nazwisko. Została zbudowana z arabskich słów ʿabd i al-Karīm, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Antun": "<p>Antun jest męskim imieniem używanym w Chorwacji i wśród ludzi pochodzenia chorwackiego w innych krajach. To powszechne nazwisko, spokrewnione z nazwiskiem Anthony.</p>", "Alyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alian</b>.</p>Populacja dzielnicy Alian w 2016 roku liczyła 29&#160;093 mieszkańców – 14&#160;407 kobiet i 14&#160;686 mężczyzn. Liczba gospodarstw domowych wynosiła 9407, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,09 osób.", "Alit": "<b>Alit</b> – <a href=\"https://pl.wikipedia.org/wiki/Mineralogia\" target=\"_blank\" rel=\"noopener noreferrer\">mineralogiczna</a> nazwa krzemianu triwapnia (zasadowego krzemianu wapnia). Jest to <a href=\"https://pl.wikipedia.org/wiki/Zwi%C4%85zki_nieorganiczne\" target=\"_blank\" rel=\"noopener noreferrer\">nieorganiczny związek chemiczny</a>, <a href=\"https://pl.wikipedia.org/wiki/Sole\" target=\"_blank\" rel=\"noopener noreferrer\">sól</a> <a href=\"https://pl.wikipedia.org/wiki/Kwasy_krzemowe\" target=\"_blank\" rel=\"noopener noreferrer\">kwasu krzemowego</a> i <a href=\"https://pl.wikipedia.org/wiki/Wap%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">wapnia</a> o wzorze zapisywanym jako Ca3SiO5 lub 3CaO&#183;SiO2, a w notacji chemii cementu&#65279;<a href=\"https://www.wikidata.org/wiki/Q3344437#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a> oznaczanego symbolem C3S. Jest składnikiem <a href=\"https://pl.wikipedia.org/wiki/Klinkier_cementowy\" target=\"_blank\" rel=\"noopener noreferrer\">klinkieru</a> (półproduktu <a href=\"https://pl.wikipedia.org/wiki/Cement_portlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">cementu portlandzkiego</a>) odpowiedzialnym za wczesne wiązanie cementu.", "Aleem": "<p>Alim (lub ʿAlīm Aliem, również anglicized jako Aleem) jest jednym z Imion Boga w islamu, co oznacza \"Wszechwiedzący\". Jest również używane jako imię osobiste, jako skrócona forma Abdul Alim, \"Służebnik wszechwiedzącego\".</p>", "Ayyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ayan</b>.</p><p>⁇ Nieuchwytny ⁇ (tam. அயன், Ayan) - indyjski film przygodowy reżysera K.</p>", "Athanassios": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Athanasios</b>.</p><p>Athanasios (grek. Αθανάσιος), również przetransliterowany jako Athnasious, Athanase lub Atanacio, jest greckim imieniem męskim, które oznacza \"nieśmiertelny\". W współczesnym greckim codziennym użyciu jest zwykle skrócony na Thanasis (Θανάσης), Thanos (Θάνος), Sakis (Σάκης) i Nasos (Νάσος).</p>", "Anit": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anita</b>.</p><b>Anita</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które powstało z hiszpańskiej zdrobniałej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anna</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> Ana). Istnieje też teza, że <b>Anita</b> jest skróconą formą <i>Juanity</i> – hiszpańskiego odpowiednika <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanny</a>.", "Afshin": "<p>Afshin (perskie افشین, romanized Afšin) jest powszechną perską nazwą pochodzącą z Avestanu. Afshin był używany przez Sogdyjczyków.</p>", "Andile": "<p>Andile to imię pochodzące od słowa Nguni ukwanda/kwandile, co oznacza \"zwiększyć/powielżać/rozwijać/rozszerzyć\". Znani ludzie z nazwiskiem to: Andile Dlamini (ur. 1992), południowoafrykański piłkarz Andile Fikizolo (ur. 1994), połudnoafrykańczy piłkarze Andile Jali (ur. 1990), południeafrykajski piłkarzem Andile Jho (ur. 1992), południowaafrykacki piłkarza rugby Andile Khumalo (ur. 1978), południaafrykański kompozytor i wykładowca muzyki...</p>", "Abdelouahab": "<p>Abdul Wahhab (arabsko: عبد الوهاب, romanized: ʻAbd al-Wahhāb) to męskie imię i nazwisko pochodzenia arabskiego. Został zbudowany z arabskich słów ʿabd i al-Wahhāb, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Aage": "<p>Aage to duńskie imię męskie i mniej powszechne pisownię norweskiego imienia Åge. Wśród wariantów znajduje się szwedzka nazwa Åke.</p>", "Amilkar": "<b>Hamilkar</b> lub <b>Amilkar</b> – imię męskie, wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">fenickiego</a> imienia <i>Abd-Melkart</i>, oznaczającego „sługa <a href=\"https://pl.wikipedia.org/wiki/Melkart\" target=\"_blank\" rel=\"noopener noreferrer\">Melkarta</a>” (boga <a href=\"https://pl.wikipedia.org/wiki/Tyr_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyru</a>). Imię pospolite w punickiej kulturze, panujące rodziny starożytnej Kartaginy często nadawały członkom swego rodu to właśnie imię.", "Anssi": "<p>Anssi to imię. Do wybitnych osób z nazwiskiem należą: Anssi Jaakkola (ur. 1987), fiński piłkarz Anssi Joutsenlahti, emeryturz i członek parlamentu Finlandii Anssi Juutilainen (ur. 1956), fiński rywalizacyjny w skijistyce i mistrz świata Anssi Karttunen (ur. 1960), fiński wiolonczelarz Anssi Kela (ur. 1972), fiński śpiewacz-powieściarz i multi-instrumentalista, który wydał pięć albumów Anssi Kippo (ur. 1976),...</p>", "Asdrubal": "<p>Asdrubal lub Asdrúbal to hiszpańskie imię męskie, które może odnosić się do: Asdrubals Bentes (1939-2020), brazylijskiego polityka i prawnika Asdrúbala Cabrera (ur. 1985), gracza baseballu Major League z Wenezueli Asdrúbała Chávez, wenezuelskiego inżyniera chemicznego i polityka Asdrubala Colmenarez (ur. 1936), wenezuelskiej artysty Asdrúbali Fontes Bayardo (1922-2006), uruguayskiego kierowcy wyścigów Asdrúbála Padrón (ur. 1991), hiszpańskiego piłkarza Asdrúbalu...</p>", "Abdelbasset": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdelbaset</b>.</p><p>'Abd al-Bāsiṭ (ALA-LC) to męskie muzułmańskie imię. Został zbudowany z arabskich słów ʿabd i al-Bāsiṭ, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Achacy": "<b>Achacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie najprawdopodobniej pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. W takim przypadku pochodzi ono od wyrazu <i>achátēs</i> – „<a href=\"https://pl.wikipedia.org/wiki/Agat\" target=\"_blank\" rel=\"noopener noreferrer\">agat</a>”. Może również pochodzić od greckiego imienia Ἀκακίος <i>Akakios</i> (od ἀκακός <i>akakos</i> – „niewinny”, „nieznający zła”), albo od greckiego wyrazu ἀγαθός <i>agathos</i> – „dobry”. Jego żeńskim odpowiednikiem są <a href=\"https://pl.wikipedia.org/wiki/Achacja\" target=\"_blank\" rel=\"noopener noreferrer\">Achacja</a> i Akacja.", "Ali Can": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Anh Quân": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Abdiasz": "<b>Abdiasz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i>Abhadjah, Obhadjahu, Obadiah)</i> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznaczające „sługa <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>”. Nosił je jeden z dwunastu <a href=\"https://pl.wikipedia.org/wiki/Prorocy_mniejsi\" target=\"_blank\" rel=\"noopener noreferrer\">proroków mniejszych</a> — <a href=\"https://pl.wikipedia.org/wiki/Abdiasz_(prorok)\" target=\"_blank\" rel=\"noopener noreferrer\">prorok Abdiasz</a>. Według stanu na 31 stycznia 2023 r. imię to miało w Polsce 7 nadań.", "Abdelsalam": "<p>Abd al-Salam (arabski: عبد السلام) to męskie muzułmańskie imię honorowe lub nazwisko, oparte na arabskich słowach Abd, al- i Salam. Nazwa oznacza \"sługę Wszechświata\", a As-Salam jest jednym z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Ali A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Antonij": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Anderson Fabian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Aghvan": "<p>Aghvan (armeńska: Աղվան (reformowana); Աղուան (klasyczna)) to armenijska męska nazwisko. Pochodzi od nazwy Kaukazyjskich Albanańczyków.</p>", "Alvaro Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alvaro</b>.</p><b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Aquino": "<p>Aquino jest miastem w prowincji Frosinone w włoskim regionie Lazio. Święty Thomas d'Aquin urodził się w Aquino w 1225 roku.</p>", "Adriian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Alexandru-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Aian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aiana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ayan</b>.</p><p>⁇ Nieuchwytny ⁇ (tam. அயன், Ayan) - indyjski film przygodowy reżysera K.</p>", "Artemy": "<p>Artemy (rosyjski: Артемий), czasami romanizowany jako Artemiy, Artemi, lub Artemij, jest pełną unikalną formą rosyjskiego krótkiego męskiego Artyoma.</p>", "Aleck": "<p>Alec lub Aleck jest szkocką formą nazwiska Alex. Może to być skrócona forma imienia Aleksandra lub sama nazwa.</p>", "Andronik": "<b>Andronik</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od starogreckiego imienia <i>Andronikos</i> (gr. <i>Ανδρόνικος</i>) wywodzącego się od słów <i>andros</i> (człowiek) i <i>nike</i> (zwycięstwo), które w złożeniu znaczą „zwycięzca”.", "Amen": "Na <a href=\"https://pl.wikipedia.org/wiki/Bliski_Wsch%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Bliskim Wschodzie</a> termin ten pierwotnie oznaczał potwierdzenie przysięgi żołnierskiej (<a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">Asyria</a>) – odpowiednik dzisiejszego „tak jest”, „rozkaz” lub „wykonam”. Jego wypowiedzenie po wysłuchaniu modlitw i błogosławieństw zastępowało ich odmówienie – w starożytności niewiele osób znało modlitwy na pamięć.", "Ayyoub": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ayoub</b>.</p><p>Ajub (francuski Ayoub) - imię własne; rozpowszechnione w postaci nazwisk.</p>", "Addison": "<b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Asem": "<p>Asem (zwanego również Aasem, Assem, Asim, Aasim, Assim, Aassem) jest męskim imieniem arabskiego pochodzenia, co oznacza \"zbawiciel, ochroniarz, opiekun, obrońca\". Asem jest również imieniem żeńskim pochodzenia kazackiego, co oznacza: \"piękno, piękno, wyrafinowane, eleganckie, elegancką, doskonałą, wspaniałą, wspaniale\".</p>", "Assem": "<p>Asem (zwanego również Aasem, Assem, Asim, Aasim, Assim, Aassem) jest męskim imieniem arabskiego pochodzenia, co oznacza \"zbawiciel, ochroniarz, opiekun, obrońca\". Asem jest również imieniem żeńskim pochodzenia kazackiego, co oznacza: \"piękno, piękno, wyrafinowane, eleganckie, elegancką, doskonałą, wspaniałą, wspaniale\".</p>", "Asadullah": "<p>Asadullāh (arabski: أَسَدُ ٱلله), również napisany jako Asadollah, Assadullah lub Asad Ullah, to muzułmańskie imię maleńskie oznaczające Lew Allaha. Nazwa ta początkowo była używana do odniesienia się do najbliższych krewnych islamskiego proroka Muhammada, Hamzy ibn Abd al-Muttaliba i Ali ibn Abi Taliba.</p>", "Alix": "<p>Święta Alice (francuski: Alix de Schaerbeek, Alice, Adélaïde, Aleyde, 1225, Skarbek (obecnie Belgia) - 1250, Abbotstwo Cambr, Bruksela) - święta Kościoła rzymskokatolicznego, czczona jako patronka ślepych i paraliżowanych.</p>", "Abdullah A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdullah</b>.</p><b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Asteriusz": "<b>Asteriusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αστέριος: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;ἀστήρ – „gwiazda”. Stąd ἀστέριος to „gwiaździsty, jasny, lśniący, niebieski”. <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">Hagiografia</a> zna ośmiu świętych o tym imieniu: m.in. nosił je Asteriusz z <a href=\"https://pl.wikipedia.org/wiki/Cezarea_Nadmorska\" target=\"_blank\" rel=\"noopener noreferrer\">Cezarei Palestyńskiej</a>, żyjący w pierwszej połowie <a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III</a> wieku.", "Alibi": "<b>Alibi</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>gdzie indziej</i>) – <a href=\"https://pl.wikipedia.org/wiki/Dow%C3%B3d_(prawo)\" target=\"_blank\" rel=\"noopener noreferrer\">dowód</a> w <a href=\"https://pl.wikipedia.org/wiki/Post%C4%99powanie_karne\" target=\"_blank\" rel=\"noopener noreferrer\">postępowaniu karnym</a> na okoliczność, że <a href=\"https://pl.wikipedia.org/wiki/Podejrzany\" target=\"_blank\" rel=\"noopener noreferrer\">podejrzany</a> albo oskarżony znajdował się w miejscu innym niż miejsce popełnienia zarzucanego mu <a href=\"https://pl.wikipedia.org/wiki/Przest%C4%99pstwo\" target=\"_blank\" rel=\"noopener noreferrer\">przestępstwa</a>. W szerszym znaczeniu mianem alibi określany jest każdy dowód przesądzający, że podejrzany lub oskarżony nie mógł popełnić zarzuconego mu przestępstwa.", "Antoni Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Angad": "<p>Angad to hinduskie imię kobiety i męski, które może odnosić się do następujących znanych osób: Angada, postać w Ramayana, sanskrytycznej epoki starożytnej Indie Guru Angad (1504-1552), drugi z dziesięciu guruów sikhów sikhismu Angad Bedi (urodzony 1983), indyjski aktor filmowy i model Angad Hasija (urodzona 1984), indyjskie aktor telewizyjny Angad Paul (1970-2015), brytyjski biznesmen i producent filmowy</p>", "Arttu": "<p>Artturi to fińskie imię męskie, wariant nazwiska Arthur. Krótka forma nazwiska to Arttu.</p>", "Abdelatif": "<p>Abdul Latif (arabski: عبد اللطيف, romanized: ʻAbd al-Laṭīf) to muzułmańskie imię i nazwisko męskie i w nowoczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Laṭīf, jednego z imion Boga w Koranie, które dały początek muzułmańskich nazw teoforycznych.</p>", "Asael": "<p>Asael (Hebrajczy: עשהאל, \"Wykonane przez Boga\") jest hebrajskim imieniem. Do wybitnych osób z tym nazwiskiem należą: Asael (anioł), upadły anioł opisany w Księdze Enocha Asael Bielski (1908-1945), białoruski żydowski partizan Asael Lubotzky (ur. 1983), izraelski lekarz i pisarz Asael Ben Shabat (ur. 1988), izraelska piłkarz David Asael Smith (1879-1952), amerykański lider Świętych Zmartwychwstania Anthony Asael (ur. 1974), belgijski fotograf</p>", "Abass": "<p>Abass lub Abasse to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Americo": "<p>Americo (lub Américo) to portugalsko- i hiszpańskie imię, czasami używane jako nazwisko i w innych kulturach. To wariant nazwiska Henry.</p>", "Afeez": "<p>Afeez to imię. Znani ludzie z nazwiska obejmują: Afeez Agoro (1975-2023), nigerijski model, aktor i postać telewizyjna Afeez Aremu (ur. 1999), nigeriński piłkarz Afeez Awakan (ur. 1993), nigerianin Afeez Oyetoro (ur. 1963), nigerianski aktor komiksów</p>", "Alvaro Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alvaro</b>.</p><b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Alexandru-Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Andres Alfonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Asbjørn": "<p>Asbjørn to norweska i duńska imię męskie. W 2013 roku w Norwegii było ponad 7000 mężczyzn z tym nazwiskiem.</p>", "Ani": "<p>Ani (armenska: Անի; starogrek: ⁇ νιον, Ánion; latynsk: Abnicum; gruziński: ანისი, Anisi; turecki: Ani) to zmarnowane średniowieczne miasto w Armenii znajdujące się w tureckiej prowincji Kars, blisko granicy z Armenią. W latach 961-1045 był stolicą Bagratidskiego królestwa Armenii, który rozciągał się po Armenii i wschodniej części dzisiejszej Turcji.</p>", "Arnab": "<p>Arnav, Arnab lub Arnov to popularne w Indiach imię i oznacza \"ocean\" w sanskrycie. Arnab to bengalijska, odia i asamska forma nazwy.</p>", "Alexandru-Cristian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Amanpreet": "<p>Amanpreet to męskie indyjskie imię. Znanymi osobami z nazwiska są: Amanpreet Ahluwalia (fl.</p>", "Akos": "<p>Ákos to węgierska nazwa. Dziś jest to głównie imię męskie.</p>", "Audun": "<p>Audun to norweska imię męskie. Wśród znanych osób z tej nazwy są: Audun Boysen (1929-2000), norweski biegacz średniej odległości Audun Endestad (ur. 1953), norwesko urodzony amerykański narciarz krausowy, autor i przewodnik Audun Grønvold (1976-2025), norweska narciarz wolnej styl Audun Heimdal (1997-2022), norweskiej orienteer Audun Hetland (1920-1998), norweski ilustrator Audun Hugleiksson (1240-1302), norweski szlawiat na końcu...</p>", "Alijan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alian</b>.</p>Populacja dzielnicy Alian w 2016 roku liczyła 29&#160;093 mieszkańców – 14&#160;407 kobiet i 14&#160;686 mężczyzn. Liczba gospodarstw domowych wynosiła 9407, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,09 osób.", "Anh Khoa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Angeł": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angela</b>.</p><b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Athula": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Athul</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Atul</b>.</p><p>Atul jest miasteczkiem w Valsad w stanie Gujarat w Indiach.</p>", "Ardjan": "<p>Ardian to albanska nazwa. Chociaż podobna do Adrian, nazwy pochodzenia łacińskiego, albanska Ardian (Ardjan i Ardijan są innymi wariantami) jest pochodem Ardiaei, nazwy starożytnego lyryjskiego ludu.</p>", "Anirban": "<p>Anirban lub Anirvan (Bengali: অনির্বাণ) to indyjskie imię męskie. Jest używany głównie w języku bengalijskim.</p>", "Abdulahad": "<p>'Abd al-Aḥad (ALA-LC) to arabskie imię męskie. Został zbudowany z arabskich słów ʿabd i al-Aḥad, jednego z imion Boga w islamu.</p>", "Atom": "Słowo <i>atom</i> pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> ἄτομος – <i>átomos</i> (od α-, „nie-” + τέμνω – <i>temno</i>, „ciąć”), oznaczającego coś, czego nie da się przeciąć ani podzielić. Idea istnienia niepodzielnych składników materii pojawiła się już w pismach starożytnych <a href=\"https://pl.wikipedia.org/wiki/Filozofia_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">filozofów indyjskich</a> i <a href=\"https://pl.wikipedia.org/wiki/Filozofia_staro%C5%BCytna\" target=\"_blank\" rel=\"noopener noreferrer\">greckich</a>. W XVII i XVIII wieku chemicy potwierdzili te przypuszczenia, identyfikując pierwiastki chemiczne i pokazując, że reagują one ze sobą w ściśle określonych proporcjach. W XIX wieku odkryto <a href=\"https://pl.wikipedia.org/wiki/Ruchy_Browna\" target=\"_blank\" rel=\"noopener noreferrer\">ruchy Browna</a>, będące pośrednim dowodem ziarnistości materii. Na początku XX wieku fizycy zbadali wewnętrzną strukturę atomów, pokazując tym samym, że są one podzielne. Teorie <a href=\"https://pl.wikipedia.org/wiki/Mechanika_kwantowa\" target=\"_blank\" rel=\"noopener noreferrer\">mechaniki kwantowej</a> pozwoliły stworzyć matematyczne modele wnętrza atomu.", "Ajdin": "<p>Aydın, również pisane Ajdin, Aiden, Ayden, Aydin lub Aydan, to męskie imię. W językach tureckich nazwa oznacza \"oświecony\" i \"światły\"; powszechnie używana jest również do intelektualistów.</p>", "Ada": "<b>Ada</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/Kobieta\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> znaczy: upiększać się, stroić się. Imię Ada jest wymieniane w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> w pierwszej księdze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, gdzie jest jedną z żon Lemecha i matką Jubala. W Biblii jest także mowa o Adzie, matce flecistów i grających na harfie (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Rdz.</a> 4, 21).", "Anel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anele</b>.</p><p>Anele to imię. Znanymi osobami z nazwiska są: Anele Lungisa (ur. 1992), gracz rugby południowoafrykański Anele Mdoda (ur. 1984), prezenterka telewizyjna południo Afryki Anele Ngcongca (1987-2020), piłkarz południowej Afryki</p>", "Alvaro Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alvaro</b>.</p><b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Angeles": "<p>Miasto Angeles (Filipinowa: Lungsod ng Angeles; Kapampangan: Lakanbalen Ning Angeles/Siudad Ning Angeles) jest miastem pierwszym w prowincji Pampanga, w Filipinach (lokalizacja: 15°08′40′′B 120°35′30′′W). Miasto znajduje się w pobliżu Clark International Airport i CSEZ (wcześniej amerykańska baza lotnicza Clark).</p>", "Abdessalam": "<p>Abd al-Salam (arabski: عبد السلام) to męskie muzułmańskie imię honorowe lub nazwisko, oparte na arabskich słowach Abd, al- i Salam. Nazwa oznacza \"sługę Wszechświata\", a As-Salam jest jednym z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Alexandru-Mihai": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Arutyun": "<p>Harutyun (armeńska: Հարություն i w zachodnim armeńskim Յարութիւն) również pisoł Haroutioun, Harutiun i jego warianty Harout, Harut i Artin jest powszechną męską nazwą armeńską; oznacza to \"wskrzeszenie\" w języku armeńsku.</p>", "Asuncion": "<p>Asunción, czyli Nuestra Señora Santa María de la Asunción (co oznacza: Święta Maria Matka Niebiańska) jest stolicą Paragwaju. Administracjonalnie Asunción jest samodzielnym miastem, nie należącym do żadnej prowincji.</p>", "Ang": "W Wielkiej Brytanii i Australii angielski jest <i>de facto</i> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urz%C4%99dowy\" target=\"_blank\" rel=\"noopener noreferrer\">językiem urzędowym</a>, choć formalnie państwa te nie objęły takim statusem żadnego języka. Angielszczyzna należy do oficjalnych języków <a href=\"https://pl.wikipedia.org/wiki/Organizacja_Narod%C3%B3w_Zjednoczonych\" target=\"_blank\" rel=\"noopener noreferrer\">ONZ</a>, a od XX wieku jest najczęściej używanym językiem w kontaktach międzynarodowych. Bywa określana jako pierwszy uniwersalny nowożytny język ludzkości. Stanowi główny język nauki, handlu i polityki, a w niektórych krajach także kształcenia wyższego.", "Agnar": "A także jedyny syn Geirröda noszący imię zaginionego na morzu <a href=\"https://pl.wikipedia.org/wiki/Stryj_(relacja_rodzinna)\" target=\"_blank\" rel=\"noopener noreferrer\">stryja</a> (może jego drugie wcielenie). Jako dziesięcioletni chłopiec był świadkiem tortur, na które ojciec skazał swego gościa Grimnira (\"Zakapturzonego\", tj. <a href=\"https://pl.wikipedia.org/wiki/Odyn\" target=\"_blank\" rel=\"noopener noreferrer\">Odyna</a>, który jak zwykle ukrywał się pod przybraną postacią). Dziecko tknięte współczuciem pokrzepiło nieszczęśnika rogiem pełnym jakiegoś napoju (prawd. miodu). Wówczas <a href=\"https://pl.wikipedia.org/wiki/Odyn\" target=\"_blank\" rel=\"noopener noreferrer\">Odyn</a> wyśpiewał chłopcu błogosławieństwo i przepowiedział mu panowanie, następnie opisał świat bogów i wyliczył swoje imiona, a w końcu rzucił na Geirröda klątwę śmierci, która natychmiast się spełniła. Agnar przejął po ojcu władzę i rządził wiele lat, choć o jego rządach nic nie wiadomo.", "Ali̇ İhsan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Agnes": "<b>Agnieszka</b> – imię żeńskie, jedno z najpopularniejszych w Polsce, gdzie pojawiło się wraz z chrześcijaństwem. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγνή – „czysta”, „dziewicza”, „nieskalana”. Może również pochodzić od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>agnus</em> – „baranek” (to jednocześnie rodzaj męski greckiej „h-agne”). Do Czech imię to dotarło w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Agnes</em>, następnie zostało zaadaptowane do języka polskiego w obecnej formie. Imię to funkcjonuje również w języku polskim w formie Inka, początkowo było ono polskim zdrobnieniem imienia Inez — francusko-iberyjskiej formy imienia Agnieszka (Inês, Inés, Inès) — z czasem jednak zaczęło funkcjonować w Polsce jako samodzielne imię.", "Antoniy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Anghel": "<p>Anghel to rumuńskie nazwisko i nazwisko.</p>", "Addar": "<b>Addar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od słowa oznaczającego „wspaniały”.", "Abdulhadi": "<p>'Abd al-Hādī (ALA-LC) to muzułmańskie imię męskie, a w współczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Hādī, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Aniss": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anis</b>.</p><b>Anisette</b> – <a href=\"https://pl.wikipedia.org/wiki/Likier\" target=\"_blank\" rel=\"noopener noreferrer\">likier</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a> o zawartości alkoholu 25-40%. Jest produkowany z likierów korzennych na bazie <a href=\"https://pl.wikipedia.org/wiki/Biedrzeniec_any%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">anyżu</a>, oliwki anyżowej z dodatkiem aromatu <a href=\"https://pl.wikipedia.org/wiki/Koper_ogrodowy\" target=\"_blank\" rel=\"noopener noreferrer\">kopru</a>, <a href=\"https://pl.wikipedia.org/wiki/Go%C5%BAdziki\" target=\"_blank\" rel=\"noopener noreferrer\">goździków</a>, bądź <a href=\"https://pl.wikipedia.org/wiki/Kolendra_siewna\" target=\"_blank\" rel=\"noopener noreferrer\">kolendry</a>. Alkohol jest często używany z barach jako składnik <a href=\"https://pl.wikipedia.org/wiki/Koktajl_alkoholowy\" target=\"_blank\" rel=\"noopener noreferrer\">koktajli</a>.", "Adedeji": "<p>Adédèjì to nigerijskie imię i nazwisko. To męskie imię pochodzące z joruby, co oznacza \"Krona stała się dwojga\".</p>", "Arijan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arian</b>.</p><b>Arian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jego patronem jest św. Arian, wspominany razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Teotyk_(m%C4%99czennik_egipski)\" target=\"_blank\" rel=\"noopener noreferrer\">Teotykiem</a>.", "Adonay": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adonai</b>.</p>W 2008 roku <a href=\"https://pl.wikipedia.org/wiki/Kongregacja_ds._Kultu_Bo%C5%BCego_i_Dyscypliny_Sakrament%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Kongregacja ds. Kultu Bożego i Dyscypliny Sakramentów</a> <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościoła katolickiego</a> wydała dyrektywę, która zawierała zalecenie, by w obrzędach liturgicznych unikać stosowanego dotąd biblijnego imienia <i>Jahwe</i>, zastępując je odpowiednikiem <i>Adonai</i>, w znaczeniu „Pan”. Zalecenie to wydano, by zgodnie z hebrajską tradycją imię Boga pozostawało niewypowiedziane.", "Alauddin": "<p>Alauddin (arabski: علاء الدين) to muzułmańskie imię męskie i, w nowoczesnym użyciu, także nazwisko. Nazwa ta pochodzi od arabskiego \"ʻAlāʼ ad-Dīn\", co oznacza \"sługa Allaha, szlachetność wiary, szlachetystwo religii, szlacheta wiary\".</p>", "Abduljabbar": "<p>ʿAbd al-Jabbār lub Abdul Jabbar (ALA-LC) to muzułmańskie imię i nazwisko męskie, a w współczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Jabbār, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Abigail": "<b>Abigail</b>, <b>Abigajl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego imienia אביגיל <i>Awigajil</i> znaczącego „radość ojca”, „mój ojciec się uradował”.", "Andres Fabian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Asef": "<p>Asif (arabski: آصف) to arabskie męskie imię. W językach perskim i urdu często wymawia się jako \"Asif\" lub \"Asef\".</p>", "Alexander Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexander</b>.</p><p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Adrian-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Alicja": "Może pochodzić od włoskiej, żeńskiej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksy\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksy</a> – Alessis, imię to przyjmowało w językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskim</a> formę Alexia.", "Abdeljalil": "<p>'Abd al-Jalīl (ALA-LC) to muzułmańskie imię męskie, używane również przez chrześcijan, a w współczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Jalil, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Atte": "<p>Atte może odnosić się do następujących osób:</p>", "Anh Duc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Anh Ðức": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Anh Vũ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Aboubakar": "<p>Abu Bakr (arabsko: أبو بكر) to arabskie imię, które oznacza \"ojciec młodego wielbłąda\" (Abu oznacza \"ojca\" i Bakr oznacza \"młody wielbłąd\"), które jest szeroko stosowane przez muzułmanów sunnitów. Inne transliteracje obejmują Abu Bakar, Abu Bekr, Ebubekir, Aboubacar, Abubakar itp.</p>", "Angel Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Alexio": "<p>Alexius jest łacińską formą nazwy Alexios (grecki: Αλέξιος, polityczny ⁇ λέξιος \"obronacz\", por. Aleksander), szczególnie powszechna w Imperium Bizantyjskim.</p>", "Abdelbaset": "<p>'Abd al-Bāsiṭ (ALA-LC) to męskie muzułmańskie imię. Został zbudowany z arabskich słów ʿabd i al-Bāsiṭ, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Ameliusz": "<b>Ameliusz</b> - (właściwe imię Gentilianus) urodzony w <a href=\"https://pl.wikipedia.org/wiki/Etruria\" target=\"_blank\" rel=\"noopener noreferrer\">Etrurii</a>, żyjący w III w. n.e. filozof <a href=\"https://pl.wikipedia.org/wiki/Neoplatonizm\" target=\"_blank\" rel=\"noopener noreferrer\">neoplatoński</a> ze szkoły rzymskiej, uznawany za najbardziej oddanego ucznia <a href=\"https://pl.wikipedia.org/wiki/Plotyn\" target=\"_blank\" rel=\"noopener noreferrer\">Plotyna</a>.", "Ajinkya": "<p>Ajinkya to imię. Znani ludzie z imieniem to: Ajinkya Deo (ur. 1964), indyjski aktor Ajinkya Joshi (ur. 1986), indyjski kryker Ajinkya Rahane (ur. 1988), indyjskie kryker</p>", "Aderemi": "<p>Adérẹ̀mí to nigerijskie nazwisko i nazwisko pochodzenia joruba, co oznacza \"Krona mnie pociesza\". Adérẹ̀mí to wariant Adérẹ́mílẹ́kún, co oznacza (korona zatrzymuje mój płacz).</p>", "Antoni Stanisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Ahmat": "<p>Ahmad (arabski: أحمد, romanized: ʾAḥmad) jest arabską nazwą męską powszechną w większości części świata muzułmańskiego, ponieważ jest to jedno z dobrze znanych imion proroka Muhammada. Inne angielskie pisowni nazwy obejmują Ahmed, Ahmmad.</p>", "Adane": "<p>Adane to imię lub nazwisko. Znani ludzie z nazwiskiem: Adane Girma (ur. 1985), etyopski piłkarz</p>", "Aadil": "<p>Aadil to imię męskie. Znani ludzie z nazwiska obejmują: Aadil Ali (ur. 1994), angielski gracz kriket Aadil Assana (ur. 1993), komoryjski piłkarz Aadil Bedi (ur. 2001), indyjski golfer Aadil Ameer Meea, mauryzyjski polityk Aadil Manzoor Peer (ur. 1997), indyjscy sportowca lodowców Aadil Rashid (ur. 1990), indyjskie gracz kryketu Aadil Sheegow Sagaar, somalijski polityk</p>", "Abu Bakar": "<p>Abu Bakr (arabsko: أبو بكر) to arabskie imię, które oznacza \"ojciec młodego wielbłąda\" (Abu oznacza \"ojca\" i Bakr oznacza \"młody wielbłąd\"), które jest szeroko stosowane przez muzułmanów sunnitów. Inne transliteracje obejmują Abu Bakar, Abu Bekr, Ebubekir, Aboubacar, Abubakar itp.</p>", "Armando Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Armando</b>.</p><p>Armando - pierwszy hiszpański album studiowy (i piąty w dyskografii) repera z Miami Pitbull. Relizja albumu odbyła się 2 listopada 2010 roku.</p>", "Alisson": "<p>Alison Ramses Becker (port. - Nieźle. Alisson Ramses Becker; rodzaj.</p>", "Azmat": "<p>Azmat to męskie imię arabskiego pochodzenia. Do wybitnych osób z tym nazwiskiem należą:</p>", "Abdulqadir": "<p>Abd al-Qadir lub Abdulkadir (arabsko: عبد القادر) to męskie muzułmańskie imię. Utworzona jest z arabskich słów Abd, al- i Qadir.</p>", "Artturi": "<p>Artturi to fińskie imię męskie, wariant nazwiska Arthur. Krótka forma nazwiska to Arttu.</p>", "Amrutlal": "<p>Amrutlal to indyjskie imię męskie. Wśród znanych osób z tym nazwiskiem są: Amrutlal Yagnik, 20 wieku indyjski krytyk Gujarati, biograf, esejista, redaktor i tłumacz Vipul Amrutlal Shah (ur. 1967), indyjski producent i reżyser filmowy</p>", "Assefa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Assef</b>.</p><p>Asif (arabski: آصف) to arabskie męskie imię. W językach perskim i urdu często wymawia się jako \"Asif\" lub \"Asef\".</p>", "Antoni Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Aggrey": "<p>Aggrey to zarówno nazwisko, jak i imię. To oznacza mocny i kompletny.</p>", "Arnulf": "<b>Arnulf</b>, <b>Arnolf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Pierwszy człon imienia stanowi <i>arn</i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemiecki (stwniem.)</a>-frankoński, średnio-dolno-niemiecki (śrdniem.) <i>arn</i> („<a href=\"https://pl.wikipedia.org/wiki/Or%C5%82y\" target=\"_blank\" rel=\"noopener noreferrer\">orzeł</a>”); drugim członem jest <i>wolf</i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germ.</a> <i>wulfa &gt; wolfa</i> („<a href=\"https://pl.wikipedia.org/wiki/Wilk_w_kulturze\" target=\"_blank\" rel=\"noopener noreferrer\">wilk</a>”); stwniem. <i>wolf</i>. Formy z <i>-ulf</i> są odbiciem zromanizowanego germ. <i>-wulf</i>. Wariantami drugiego członu są: <i>-wulf</i>, który stanowi kontynuację najstarszej, germańskiej formy, zachowanej w śrdniem. i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_dolnoniemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">dolnoniemiecki (dniem.)</a>, oraz <i>-wolf</i>, kontynuacja młodszej formy germańskiej, przejętej przez stwniem., <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">średnio-wysoko-niemiecki (śrwniem.)</a> i nowoniemiecki. Imię to notowane było w Polsce już w średniowieczu, w formie (Arnolf) (<a href=\"https://pl.wikipedia.org/wiki/1219\" target=\"_blank\" rel=\"noopener noreferrer\">1219</a>), Arnolfus (Arnulf) (<a href=\"https://pl.wikipedia.org/wiki/1435\" target=\"_blank\" rel=\"noopener noreferrer\">1435</a>). Niektóre możliwe staropolskie zdrobnienia: Arnek, Arnko.", "Abdulazeez": "<p>Abd al-Aziz (arabski: عبد العزيز, DMG: ʽAbd al-ʽAzīz), często również przetransliterowany jako Abdul Aziz, to arabskie muzułmańskie imię i nazwisko mężczyzny i, w nowoczesnym użyciu, nazwisko. Zostało zbudowane z słów ʽAbd, arabski artykuł określony i ʽAzīz \"Wszechmogący\".</p>", "Abdulrahim": "<p>'Abd al-Raḥīm (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów 'abd, al-Raḥīm, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Ali H": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Alhassan": "<p>Alhassan to nazwisko. Do wybitnych osób z nazwiskiem należą: Abdul Razak Alhassan (ur. 1985), ghanański artysta walki mieszanej Masahudu Alhassan (1992), ghanański międzynarodowy back Alhassan Mohammed Gani (1959-2025), nigerianski administrator akademicki Alhassan Wakaso (1992), ghanijski środkowy strzelanin Kalif Alhassan (1990), ghanajski piłkarz Karim Alhassan (1981) ghanański obrońca Mohammed Alhassan (1944) ghanański...</p>", "Abilio": "<p>Abilio może odnosić się do: Abilio James Acosta (ur. 1971), amerykański dziennikarz Abílio Brandão (ur. 1948), portugalski strzelanin sportowy Abílio Cabral (ur. 1960), angolański bokser Abílio Cossa (1922-2003), mozambickiego dziennikarza i pisarza Abílio Duarte (1931-1996), kapwerdeńskiego nacjonalista i polityka Abilio Diniz (ur. 1936), brazylijskiego biznesmena Abilio Estévez (ur. 1954), kubańskiego pisarza i dramatyk Abílio Fernandes (1906-1994), portugalskiego...</p>", "Akila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akil</b>.</p><p>Akil to miasto w stanie Yucatán w Meksyku. W 2005 roku liczba mieszkańców miasta wynosiła 9765 osób.</p>", "Abdelmonem": "<p>'Abd al-Mun'im (rōmaanizacja ALA-LC z arabskiego: عبد المنعم) jest męskim nazwiskiem arabskim teoforycznym, co oznacza \"sługą Najbardziej Dobryj czy Największej Posiadkowcy (Bogi) \". Jest również używane jako nazwisko.</p>", "Amara": "<p>Amara) - rodzaj żużliwych żużlów z podrodzinę harpałów, ale w niektórych źródłach rodzaj ten wchodzi w skład Pterostichinae.</p>", "Ajaz": "<p>Ajaz jest nazwiskiem arabskim. Do wybitnych osób z tym nazwiskiem należą:</p>", "Abdulhameed": "<p>'Abd al-Ḥamīd (ALA-LC romanizacja arabskiej: عبد الحميد; perskiego: عبدالحمید, romanized: Abdolhamid; tureckiego: Abdülhamit), również pisowniony jako Abdulhamid, Abdelhamid, Abd-ul Hamid i Abd ol-Hamid, jest muzułmańskie męskie imię i nazwisko. Jest to muzułmańska nazwa teoforyczna zbudowana z arabskich słów 'abd ('sługa') i al-Ḥamīd (jedno z nazw Boga w Koranie), a zatem oznacza 'sługa Wszechchchch chwalnego'.</p>", "Agis": "<b>Agis</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (gr. <i>Άγις</i>), które zostało utworzone od czasownika <i>Άγω</i> („prowadzić, przodować, wskazywać drogę”). Imię to oznacza „ten, kto prowadzi”; „ten, kto wskazuje drogę”.", "Anh Duy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Artemijs": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Artemis</b>.</p><p>Artemis (lat. Artemis) - łacińska nazwa bogini mitologii greckiej Artemidy.</p>", "Aniel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aniela</b>.</p><b>Aniela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które jest spolszczoną formą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa <i>ángelos</i> „posłaniec”. Imię trafiło do Polski z Włoch prawdopodobnie w XVIII wieku. W świecie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> upowszechniło się jako nawiązanie do <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">aniołów</a> i <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_Str%C3%B3%C5%BC_(religioznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioła Stróża</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>.", "Alin-Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Afanazy": "<b>Atanazy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „nieśmiertelny” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αθανάσιος).", "Adryan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Alexandru-Ionut": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Abdelhafid": "<p>'Abd al-Ḥafīẓ (ALA-LC) to muzułmańskie imię męskie i w nowoczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Ḥafīẓ, jednego z imion Boga w Koranie, które powstały z muzułmańskich nazw teoforycznych.</p>", "Alexandru-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Anish Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anish</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anisha</b>.</p><p>Anisha może odnosić się do Anisha Ambrose, indyjskiej aktorki filmowej i modelu Anisha Basheel (ur. 1997), malawjskiej profesjonalnej bokserki Anisha Nagarajan (ur. 1983), amerykańskiej aktorki i piosenkarki Anisha Nicole (ur. 1985), amerykańskiej piosenkarky Anisha Rosnah (ur. 1993) brunejskiej królewskiej Anisha Vekemans (ur. 1991), belgijskiej profesjonalne rowerzystka wyścigowa</p>", "Arsène": "<p>Arsène to francuskie imię męskie. Pochodzi z łacińskiego imienia Arsenius, latynistycznej formy greckiego imienia ⁇ ρσἐνιος (Arsenios), co oznacza \"męski, męski\".</p>", "Alexander De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexander</b>.</p><p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Al-Amin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Al</b>.</p><p>Aluminium (chymiczny symbol - Al, od łacińskiego Aluminium), wcześniej również gliny (od rosyjskiego.</p>", "Awit": "<b>Awit</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od łacińskiego przymiotnika pospolitego <i>avitus</i>, który oznaczał „pochodzący od przodków, wrodzony, dziedziczny”. Istniało 8 świętych o tym imieniu. W Polsce <b>Awit</b> nadawany jest co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1777\" target=\"_blank\" rel=\"noopener noreferrer\">1777</a> roku.", "Akihito": "<b>Akihito</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきひと, アキヒト) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie imię</a> męskie.", "Abdulbaki": "<p>'Abd al-Bāqī (ALA-LC) to męskie muzułmańskie imię. Został zbudowany z arabskich słów ʿabd i al-Bāqī, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Alexandru-Ioan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Amparo": "<b>Amparo</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/Kobieta\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a> pochodzące z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a> w jej hiszpańskim <a href=\"https://pl.wikipedia.org/wiki/Idiom\" target=\"_blank\" rel=\"noopener noreferrer\">wariancie</a>. Popularne w <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Portugalia\" target=\"_blank\" rel=\"noopener noreferrer\">Portugalii</a> i w kręgu oddziaływania kultury hiszpańskiej i portugalskiej. Dosłownie oznacza <i>\"ochronę, protekcję\"</i>. Brak odpowiednika tego imienia w języku polskim.", "Artemis": "<p>Artemis (lat. Artemis) - łacińska nazwa bogini mitologii greckiej Artemidy.</p>", "Arón": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arona</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aron</b>.</p><p>Aron jest miejscowością i nagar panchayatem Guna w stanie Madhya Pradesh, India.</p>", "Attyla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Attila</b>.</p><b>Attila</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, szczególnie popularne w Turcji i na <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">Węgrzech</a>, gdzie używa się także formy Etele. Żeński odpowiednik – Etelka.", "Arjun Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arjun</b>.</p><b>Arjun</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskr.</a> <i>अर्जुन</i>) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjski</a> <a href=\"https://pl.wikipedia.org/wiki/Czo%C5%82g_podstawowy\" target=\"_blank\" rel=\"noopener noreferrer\">czołg podstawowy</a>, produkowany od 2004 roku, w <a href=\"https://pl.wikipedia.org/wiki/Armia_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">armii indyjskiej</a> od 2007 roku. Nazwa czołgu pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Ard%C5%BAuna\" target=\"_blank\" rel=\"noopener noreferrer\">Ardźuna</a> - jednego z bohaterów <a href=\"https://pl.wikipedia.org/wiki/Epos\" target=\"_blank\" rel=\"noopener noreferrer\">eposu</a> <i><a href=\"https://pl.wikipedia.org/wiki/Mahabharata\" target=\"_blank\" rel=\"noopener noreferrer\">Mahabharata</a></i>.", "Ala Eddine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ala</b>.</p><p>Alanin (2-aminopropanowy kwas) - aminokwas alifatyczny. α-alanina jest częścią wielu białek, β-alanina - w szeregu związków biologicznie aktywnych.</p>", "Andres Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Andrii-Oleksandr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrii</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Asger": "<p>Asger jest głównie duńskim językiem męskim, pochodzącym z starożytnych norweskich elementów Æsir lub ás, co oznacza \"bogów\" i geirr, co oznacza\" włócznię \". Osoby noszące nazwę Asger to: Asger Aaboe (1922-2007), duński historyk nauk dokładnych i matematyka Asger Christensen (ur. 1958), duński polityk Asger Lund Christiansen (1927-1998), duński wiolonczelarz i kompozytor Asger Hamerik, również Hammerich, (1843-1923), duński...</p>", "Armando Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Armando</b>.</p><p>Armando - pierwszy hiszpański album studiowy (i piąty w dyskografii) repera z Miami Pitbull. Relizja albumu odbyła się 2 listopada 2010 roku.</p>", "Alejandro Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alejandro</b>.</p><p>Alejandro - hiszpańska forma imienia Aleksandra.</p>", "Artsiomi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Artsiom</b>.</p><p>Artsyom (bieloruska: Арцём), również przetransliterowany jako Artsiom, jest popularną nazwą męską w Białorusi. Jest to wersja nazwy Artem/Artyom.</p>", "Abou": "<p>Abou to zarówno imię, jak i nazwisko. Może odnosić się do: Ayoub Abou (ur. 1998), marokański piłkarz Samassi Abou (ura. 1973), piłkarze z Iraku Abou Diaby (ura. 1986), francuski piłkarzem Abou Maïga (ura. 1985), benyneskiego piłkarza Basel Abbas i Ruanne Abou-Rahme, artysty duo Abou Ben Adhem (poem), fikcyjny bohater wiersza 1814 przez Leigh Hunt</p>", "Ali S": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Adame": "<p>Adame to zarówno nazwisko, jak i imię. Może odnosić się do: Nazwa: Alfredo Adame (ur. 1958), meksykański aktor Joe Adame (ur., 1945), amerykański polityk Marco Antonio Adame (ur.: 1960), meksykańska politykka Lucy Adame-Clark (ur. 1972), pierwsza kobieta wybrana jako sekretarka hrabstwa Bexar w historii hrabstwa, amerykański politik Nazwa: Adame Ba Konaré (ur. 1947), malijski historyk i pisarz</p>", "Anh Cuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Alecu": "<p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Abidemi": "<p>Abidemi (Abídèmí) to nigeryjska uniseksowa nazwa pochodzenia joruba oznaczająca \"Narodzony czekając na mój powrót\". Zazwyczaj nadaje się do chłopca lub dziewczyny, gdy ojciec dziecka jest w podróży, Abídèmí spada pod jedną z kategorii nazw w języku joruba znany jako Oruko-Abiso, co oznacza nazwy przypisane / nabyte.</p>", "Aseem": "<p>Aseem, również pisane Asim, Aasim lub Aashim (sanskrit: असीम asīma) to indyjskie imię męskie oznaczające \"nieograniczone/bezgraniczne/nieograniczone\". Nie jest związany z często identycznie pisanym nazwą arabskiego pochodzenia Asim.</p>", "Alexandru-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Anthony Joseph": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anthony</b>.</p><p>Anthony może odnosić się do: Anthony Hopkins Anthony Giddens Anthony van Dyck</p>", "Arun Babu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arun</b>.</p><p>Arun (Mongolski: ⁇ ⁇ Arun qosiɣu, Kirin Mongoli: Арун хошуу; przenoszone: 阿荣旗; subtyp: 阿榮旗; przenośne: Āróng Qí, Hán Việt: A Vinh kỳ) jest okresem urzędu miasta Hulunbuir (Holun Luan Uy), Autonomicznego Obszaru Mongolicznego, Chiny. Miasto graniczy z prowincją Hắc Long Giang na wschodzie i południu i znajduje się 92 km (57 mi) na północno-zachodni od miasta Tề Tề Cápur w prowincji Hắc Long.</p>", "Abu Bakkar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abu Bakar</b>.</p><p>Abu Bakr (arabsko: أبو بكر) to arabskie imię, które oznacza \"ojciec młodego wielbłąda\" (Abu oznacza \"ojca\" i Bakr oznacza \"młody wielbłąd\"), które jest szeroko stosowane przez muzułmanów sunnitów. Inne transliteracje obejmują Abu Bakar, Abu Bekr, Ebubekir, Aboubacar, Abubakar itp.</p>", "Abdalrahman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Amram": "<b>Amram</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> עַמְרָם) – postać biblijna ze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, syn <a href=\"https://pl.wikipedia.org/wiki/Kehat\" target=\"_blank\" rel=\"noopener noreferrer\">Kehata</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Moj%C5%BCesz\" target=\"_blank\" rel=\"noopener noreferrer\">Mojżesza</a>, <a href=\"https://pl.wikipedia.org/wiki/Aaron_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Aarona</a> i <a href=\"https://pl.wikipedia.org/wiki/Miriam_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Miriam</a>. Jego żoną była <a href=\"https://pl.wikipedia.org/wiki/Jokebed\" target=\"_blank\" rel=\"noopener noreferrer\">Jokebed</a>. Żył 137 lat. Od Amrama pochodzi ród Amramitów.", "Amber": "<b>Amber</b> – imię kobiece, pochodzi od nazwy bursztynu (skamieniałej żywicy drzewa, który jest często używany do produkcji biżuterii). Słowo to pochodzi od arabskiego عنبر lub Anbar. Słowo to może również odnosić się do koloru żółto-pomarańczowego.", "Antonina": "<b>Antonina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antonin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonin</a>; uformowany przy użyciu <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, <i>-ina</i>, oznaczającego przynależność lub pochodzenie, <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwy rodowej</a> <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Antoniuszów</a>. W Polsce Antonina pojawiła się później niż obecna od średniowiecza <a href=\"https://pl.wikipedia.org/wiki/Antonia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonia</a>; notowana jest co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1637\" target=\"_blank\" rel=\"noopener noreferrer\">1637</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Antonina w 2017 r. zajmowała 15. miejsce w grupie imion żeńskich. W całej populacji Polek Antonina zajmowała w 2017 r. 90. miejsce (43 462 nadań).", "Ahmed Hassan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Adrian Camilo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Ali̇ Riza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Aleksandra": "<b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Alkiviadis": "<p>Alkiviadis to imię. Mieszkańcy nazwiska to: Alkiviadis Stefanis, oficer wojskowy i minister w rządzie greckim Alkiviatis Papageorgopoulos, grecki strzelanin sportowy i olimpijak Alkiviasis Christofi, cyprycki piłkarz Alkiviadi Diamanti di Samarina, grecki polityk i współpracownik Aksy</p>", "Abdul Hakim": "<p>Abdul Hakim (arabski: عبد الحكيم, romanized: ʻAbd al-Ḥakīm) to muzułmańskie imię męskie, a w nowoczesnym użyciu, imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Hakim.</p>", "Ali Ihsan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Abd Allah": "<p>Abd Allah (arabsko: عبد الله, romanized: ʻAbd Allāh), również pisane Abdullah, Abdhullah, Abdellah, Abdollah, Abdallah, Abdulla, Abdalla i wiele innych, jest arabską nazwą teoforyczną oznaczającą sługę Boga lub \"szońca Boga\". Został zbudowany z arabskich słów ʿabd (عبد) i Allāh (Allah).</p>", "Ali̇ Can": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Abdul-Aziz": "<p>Abdul Aziz, Abdulaziz lub Abdul-Aziz mogą odnosić się do: Abd al-Aziz, męskie arabskie nazwisko teoforyczne, powszechnie skrócone jako Aziz</p>", "Achacjusz": "<b>Achacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie najprawdopodobniej pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. W takim przypadku pochodzi ono od wyrazu <i>achátēs</i> – „<a href=\"https://pl.wikipedia.org/wiki/Agat\" target=\"_blank\" rel=\"noopener noreferrer\">agat</a>”. Może również pochodzić od greckiego imienia Ἀκακίος <i>Akakios</i> (od ἀκακός <i>akakos</i> – „niewinny”, „nieznający zła”), albo od greckiego wyrazu ἀγαθός <i>agathos</i> – „dobry”. Jego żeńskim odpowiednikiem są <a href=\"https://pl.wikipedia.org/wiki/Achacja\" target=\"_blank\" rel=\"noopener noreferrer\">Achacja</a> i Akacja.", "Abdenour": "<p>'Abd al-Nūr (ALA-LC) to męskie imię i nazwisko. Nazwa ta jest używana przez muzułmanów, a także przez koptyjskich i prawosławnych chrześcijan na Bliskim Wschodzie.</p>", "Akter": "<p>Akhtar (perskie: اختر, pasztów: اختر) oznacza \"gwiazdę\" w perskim i jest używany w pasztówce na Nowrudz i Dzień Wielkanocny. Jest to również powszechne nazwisko.</p>", "Ahmed Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Abdulali": "<p>'Abd al-ʻAlī (ALA-LC romanizacja arabskiej: عبد العلي, perskiego: عبدالعلی), również pisowany jako Abd ul Ali, Abd ul-Ali, Abd ol Ali i Abd ol-Ali, to męskie muzułmańskie imię. Został zbudowany z arabskich słów ʿabd i al-ʻAlī, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Ajish": "<p>Ajish (Ajeesh) jest powszechną nazwą w języku Malayalam, regionalnym języku stanu Kerala w Indiach. Najczęściej używa się go Hinduszy i Chrześcijanie.</p>", "Adonai": "W 2008 roku <a href=\"https://pl.wikipedia.org/wiki/Kongregacja_ds._Kultu_Bo%C5%BCego_i_Dyscypliny_Sakrament%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Kongregacja ds. Kultu Bożego i Dyscypliny Sakramentów</a> <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościoła katolickiego</a> wydała dyrektywę, która zawierała zalecenie, by w obrzędach liturgicznych unikać stosowanego dotąd biblijnego imienia <i>Jahwe</i>, zastępując je odpowiednikiem <i>Adonai</i>, w znaczeniu „Pan”. Zalecenie to wydano, by zgodnie z hebrajską tradycją imię Boga pozostawało niewypowiedziane.", "Anxo": "<p>Anxo może odnosić się do: Anxo, nazwisko w języku galickijskim i języku językowym oksycjanie pochodzące od Anjela. Anxo, to inna nazwa Tartaro.</p>", "Ambrogio": "<b>Ambroży</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>ambrósios</i> – boski, nieśmiertelny, święty od <i>(am)brotós</i> – (nie)śmiertelny) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>.", "Anh Sơn": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Arnie": "<p>Arnie to męskie imię, często skrócona wersja Arnold. Może odnosić się do:</p>", "Ambros": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ambrose</b>.</p><p>Ambrosius (lat. Aurelius Ambrosius) (kr. 340 - 4 kwietnia 397) - cześć świętego Ambrosius, biskupów Milana od 374 do 397.</p>", "Adriyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Aleksiy": "<p>Alexey (rosyjski: Алексей, romanized: Aleksey [ɐljɪkˈsjej]) to rosyjskie imię męskie pochodzące od greckiego Aléxios (Αλέξιος), co oznacza \"Obrannik\", a zatem z tego samego pochodzenia jak łacina Alexius. Podobne ukraińskie i białoruskie nazwy są romanizowane odpowiednio jako Oleksii (Олексій) i Aliaksiej (Аляксей).</p>", "Alexandru-Cătălin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Ahmed A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Ali Haydar": "<p>Ali Haidar (arabski: علي حيدر) lub podobne pisowni, to męskie muzułmańskie imię, oznaczające \"Ali lwiec\", w odniesieniu do renomowanej odwagi czwartego kalifa, Ali. Wśród znanych nosicieli nazwy są:</p>", "Aliyu": "<p>Aliyu to nigerijskie imię i nazwisko męskie, które są używane głównie wśród muzułmanów, szczególnie w społeczności joruba i hausa. Powodem jest arabskie słowo \"Ali\", co oznacza \"wywyższony\".</p>", "Abdullaziz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdulaziz</b>.</p><p>Abdulaziz (Turk. Abdül'l Azīz, Tur. I. Abdülaziz; 82/1830 - 4 czerwca 1876) był 32. sultanem Cesarstwa Osmańskiego, rządził od 25 czerwca 1861 do 30 maja 1876.</p>", "Awram": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Avram</b>.</p><p>Abraham (przesłanie Abraham; hebrajski: אַבְרָהָם, Standard Avraham Ashkenazi Avrohom lub Avruhom Tibr ʾA ⁇ rāhām; arabski: ابراهیم, Ibrāhīm; Ge'ez: አብርሃም, ʾAbrəham), według judaizmu, chrześcijaństwa i islamu, jest ojcem Żydów i Arabów. Bóg powołał Abrahama, aby opuścił swój rodzinną Ur i przyjechał do nowego kraju w Kanaanie.</p>", "Antonio Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonio</b>.</p><p>Antonio James Uri (włoski: Antonio James Uri)  Antonio jest angielski.</p>", "Atiq": "<p>Atiq lub Ateeq (tzw. Ateeque, Ateeq, Atteq, Atik, Ateek) (arabsko: عتیق) to męskie arabskie imię, które pojawia się w Koranie kilka razy. Oznacza to \"starość\" lub \"starożytność\", a nazwa ta jest powszechnie używana w krajach muzułmańskich.</p>", "Antoan": "<p>Antoan to imię. Do znanych osób z tym nazwiskiem należą następujące osoby:</p>", "Aster": "Nazwa rodzajowa <i>Aster</i> pochodzi od starogreckiego słowa ἀστέρı (astéri), co znaczy „gwiazda”. Nawiązuje ona do gwiaździstego kształtu <a href=\"https://pl.wikipedia.org/wiki/Koszyczek\" target=\"_blank\" rel=\"noopener noreferrer\">koszyczka</a> kwiatowego.", "Abdul Basit": "<p>'Abd al-Bāsiṭ (ALA-LC) to męskie muzułmańskie imię. Został zbudowany z arabskich słów ʿabd i al-Bāsiṭ, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Alexandru-Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Andres Julian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Amrit Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amrit</b>.</p><p>Amrit (arabski: عمريت), starożytne imię Marathus (gr. αραθ ς, Marathos), był obecnie finiockim portem znajdującym się blisko Tartus w Syrii. Założony w III millenium pne, Marat (Fenickie: ⁇ , MRT) był ważnym północnym miastem starożytnej Feneki i był przeciwnikiem sąsiedniego Arwad.</p>", "Abdulah": "<p>Abd Allah (arabsko: عبد الله, romanized: ʻAbd Allāh), również pisane Abdullah, Abdhullah, Abdellah, Abdollah, Abdallah, Abdulla, Abdalla i wiele innych, jest arabską nazwą teoforyczną oznaczającą sługę Boga lub \"szońca Boga\". Został zbudowany z arabskich słów ʿabd (عبد) i Allāh (Allah).</p>", "Abdullah S": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdullah</b>.</p><b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Arca": "<i><b>Arca</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82%C5%BCe\" target=\"_blank\" rel=\"noopener noreferrer\">małży</a> <a href=\"https://pl.wikipedia.org/wiki/Nitkoskrzelne\" target=\"_blank\" rel=\"noopener noreferrer\">nitkoskrzelnych</a> z rodziny <a href=\"https://pl.wikipedia.org/wiki/Arkowate\" target=\"_blank\" rel=\"noopener noreferrer\">arkowatych</a> (Arcidae) opisany naukowo przez <a href=\"https://pl.wikipedia.org/wiki/Karol_Linneusz\" target=\"_blank\" rel=\"noopener noreferrer\">Linneusza</a> w 1758 roku. <a href=\"https://pl.wikipedia.org/wiki/Gatunek_typowy\" target=\"_blank\" rel=\"noopener noreferrer\">Gatunkiem typowym</a> jest <i><a href=\"https://pl.wikipedia.org/wiki/Arca_noae\" target=\"_blank\" rel=\"noopener noreferrer\">Arca noae</a></i> (arka Noego). <a href=\"https://pl.wikipedia.org/wiki/Grupa_siostrzana\" target=\"_blank\" rel=\"noopener noreferrer\">Taksonem siostrzanym</a> jest <i>Acar</i>. W zapisie kopalnym najstarsi przedstawiciele tego rodzaju są znani ze skamielin pochodzących z <a href=\"https://pl.wikipedia.org/wiki/Kreda_(okres)\" target=\"_blank\" rel=\"noopener noreferrer\">kredy</a>. Współcześnie żyjące gatunki występują w wodach strefy tropikalnej i subtropikalnej. Większe gatunki zaliczane są do <a href=\"https://pl.wikipedia.org/wiki/Owoce_morza\" target=\"_blank\" rel=\"noopener noreferrer\">owoców morza</a> i poławiane komercyjnie. Do gatunków najczęściej poławianych i wykorzystywanych kulinarnie należy <a href=\"https://pl.wikipedia.org/wiki/Arka_Noego_(zwierz%C4%99ta)\" target=\"_blank\" rel=\"noopener noreferrer\">arka Noego</a>.", "Ali Reza": "<p>Ali Reza (zwany również Alireza lub Ali-Reza) jest popularną nazwą wśród Iranczyków, Bengaliczyków, Turków i Albanijczyków.</p>", "Asbjorn": "<p>Asbjørn to norweska i duńska imię męskie. W 2013 roku w Norwegii było ponad 7000 mężczyzn z tym nazwiskiem.</p>", "Anderson Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Aryel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ariel</b>.</p><b>Ariel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֲרִיאֵל&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> słów oznaczających „lew Boga”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> używane było jako alternatywna nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolima</a>.", "Aldeen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alden</b>.</p><p>Alden (ang. Alden, Olden) - własne imię; rozpowszechnione w postaci nazwisk.</p>", "Adrian-Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Arta": "<p>Arta (Greek: ?) jest samodzielnym terytorium w Grecji. Autonomiczna dzielnica Arta ma powierzchnię 457 km2, populacja według badania z 18 marca 2001 roku wynosi 44136 osób.</p>", "Alexzander": "<p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Al Ameen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Al</b>.</p><p>Aluminium (chymiczny symbol - Al, od łacińskiego Aluminium), wcześniej również gliny (od rosyjskiego.</p>", "Anita": "<b>Anita</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które powstało z hiszpańskiej zdrobniałej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anna</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> Ana). Istnieje też teza, że <b>Anita</b> jest skróconą formą <i>Juanity</i> – hiszpańskiego odpowiednika <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanny</a>.", "Andrii-Mykola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrii</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Alexandru-Cosmin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Aboubaker": "<p>Abu Bakr (arabsko: أبو بكر) to arabskie imię, które oznacza \"ojciec młodego wielbłąda\" (Abu oznacza \"ojca\" i Bakr oznacza \"młody wielbłąd\"), które jest szeroko stosowane przez muzułmanów sunnitów. Inne transliteracje obejmują Abu Bakar, Abu Bekr, Ebubekir, Aboubacar, Abubakar itp.</p>", "Abdulsamad": "<p>Abdul Samad Abdul Samed, itp. Można go przenieść na \"sługa samostanowionego Mistrza\" lub \"sługowiec Wiecznego Schronienia\".</p>", "Ardeshir": "<p>Ardeshir, Ardashir lub Ardasher mogą odnosić się do:</p>", "Alexandra": "<p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Aapo": "<p>Aapo jest fińskim i estonijskim imieniem pochodzącym od Abrahama. Do wybitnych osób z nazwiskiem należą: Aapo Häkkinen (ur. 1976), fiński muzyk Aapo Halme (ur. 1998), fiński piłkarz Aapo Harjula (1880-1961), fiński inspektor i polityk spółdzielni Aapo Heikkilä (ur. 1994), fiński futbolista Aapo Ilves (ur. 1970), estonii poeta, pisarz, artysta i muzyk Aopo Inkinen (1898-1960), fiński polityk Aapo Kyrölä (ur.,...</p>", "Antoin": "<p>Antoin jest irlandzką nazwą męską, pochodzącą od Antoniusa, która jest powszechnie używana w Irlandii. W irlandzkim (Gaeilge) jest przetłumaczana jako Antóin.</p>", "Alwar": "<b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Ali Ahmad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Aritra": "<p>Aritra (Bengali: অরিত্র) lub Aritro to męskie imię z Azji Południowej, często powszechne wśród ludzi pochodzenia bengalskiego w Indiach i Bangladeszu. Nazwa ta oznacza \"kto wskazuje właściwą drogę\" lub \"nawigacja\".</p>", "Arka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arca</b>.</p><i><b>Arca</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82%C5%BCe\" target=\"_blank\" rel=\"noopener noreferrer\">małży</a> <a href=\"https://pl.wikipedia.org/wiki/Nitkoskrzelne\" target=\"_blank\" rel=\"noopener noreferrer\">nitkoskrzelnych</a> z rodziny <a href=\"https://pl.wikipedia.org/wiki/Arkowate\" target=\"_blank\" rel=\"noopener noreferrer\">arkowatych</a> (Arcidae) opisany naukowo przez <a href=\"https://pl.wikipedia.org/wiki/Karol_Linneusz\" target=\"_blank\" rel=\"noopener noreferrer\">Linneusza</a> w 1758 roku. <a href=\"https://pl.wikipedia.org/wiki/Gatunek_typowy\" target=\"_blank\" rel=\"noopener noreferrer\">Gatunkiem typowym</a> jest <i><a href=\"https://pl.wikipedia.org/wiki/Arca_noae\" target=\"_blank\" rel=\"noopener noreferrer\">Arca noae</a></i> (arka Noego). <a href=\"https://pl.wikipedia.org/wiki/Grupa_siostrzana\" target=\"_blank\" rel=\"noopener noreferrer\">Taksonem siostrzanym</a> jest <i>Acar</i>. W zapisie kopalnym najstarsi przedstawiciele tego rodzaju są znani ze skamielin pochodzących z <a href=\"https://pl.wikipedia.org/wiki/Kreda_(okres)\" target=\"_blank\" rel=\"noopener noreferrer\">kredy</a>. Współcześnie żyjące gatunki występują w wodach strefy tropikalnej i subtropikalnej. Większe gatunki zaliczane są do <a href=\"https://pl.wikipedia.org/wiki/Owoce_morza\" target=\"_blank\" rel=\"noopener noreferrer\">owoców morza</a> i poławiane komercyjnie. Do gatunków najczęściej poławianych i wykorzystywanych kulinarnie należy <a href=\"https://pl.wikipedia.org/wiki/Arka_Noego_(zwierz%C4%99ta)\" target=\"_blank\" rel=\"noopener noreferrer\">arka Noego</a>.", "Abiel": "<b>Abiel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> dwóch postaci biblijnych oznaczające w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> „Bóg jest moim ojcem”. 1. Imię to nosił ojciec <a href=\"https://pl.wikipedia.org/wiki/Kisz_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Kisza</a>, dziadek <a href=\"https://pl.wikipedia.org/wiki/Saul_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Saula</a> (1 Sm 9,1) i <a href=\"https://pl.wikipedia.org/wiki/Abner\" target=\"_blank\" rel=\"noopener noreferrer\">Abnera</a> (1Sm 14,51). 2. Imię to nosił również jeden z bohaterskich wojowników <a href=\"https://pl.wikipedia.org/wiki/Dawid_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Dawida</a> (1 Krn 11,32).", "Asha": "<p>Asha (Nokia) - seria telefonów Nokia, po raz pierwszy przedstawiona w 2011 roku. Asha w tłumaczeniu hindi oznacza nadzieja.</p>", "Aniekan": "<p>Aniekan () to zarówno nazwisko i nazwisko z Nigerii. Znani ludzie z nazwiska to: Aniekan Bassey, nigerijski biznesmen i polityk Aniekan Ekpe (ur. 1986), nigerijski piłkarz Aniekan Udofia (ur. 1976), nigeriński artysta Favour Aniekan (ur. 1994), nigerianin piłkarza</p>", "Andrzej Stanisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Ardalion": "<b>Ardalion</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, prawdopodobnie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>ardalio</i> — \"skrzętny, krzątający się\". Jego patronem jest św. Ardalion, komediant.", "Abdul Salam": "<p>Abd al-Salam (arabski: عبد السلام) to męskie muzułmańskie imię honorowe lub nazwisko, oparte na arabskich słowach Abd, al- i Salam. Nazwa oznacza \"sługę Wszechświata\", a As-Salam jest jednym z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Akinori": "<b>Akinori</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきのり, アキノリ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Amir Khan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amir</b>.</p><b>Amir</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أمير&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „książę” lub „dowódca”.", "Alexandru-Adrian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Awad S": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Awad</b>.</p><p>Awad lub Aouad lub Awwad (arabski: عوض lub czasami عوّاد) to arabskie imię i nazwisko. Do osób z tym nazwiskiem należą:</p>", "Archip": "<b>Archip</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzenia</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów: <i>αρχος (archos)</i>, oznaczającego \"mistrz\" oraz <i>‘ιππος (híppos)</i> – „koń”.", "Augustín": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Augustyn</b>.</p><b>Augustyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> od łac. <i>Augustinus</i>, utworzone od przydomka ‘Augustus’, nadanego <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawianowi</a> przez senat, oznaczające „należący do <a href=\"https://pl.wikipedia.org/wiki/August_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Augusta</a>”.", "Antonel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Antonela</b>.</p><p>Antonela to chorwackie imię żeńskie, które jest diminutiwą formą Antonia i alternatywną formą Antonella używaną w Chorwacji. Znanymi osobami z tym nazwiskiem są: Antonela Anić (ur. 1985), chorwacka piłkarka koszykówki Antonela Curatola (ur. 1991), argentyńską piłkarkę siatkówki Antonella Đinđić, znana Nela, chorwacka śpiewaczka i autorka Antonela Ferenčić (ur., 1994), chorwackia rowerka Antonela Fortuna (ur. 1995),...</p>", "Adair": "<b>Adair</b> – zarówno żeńskie, jak i męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia germańskiego oznaczające „bogatą włócznię”. Występuje też w wariantach Adaire, Adare i Adayre. Obecnie imię to nie jest popularne.", "Anthoni": "<p>Anthoni to szwedzka, duńska, fińska i norweska forma nazwy i nazwy \"Antoni\", która jest używana w Finlandii, Danii, Szwecji, Norwegii, Republice Karelii, Estonii i Grenlandii. Do wybitnych osób z tym nazwiskiem należą:</p>", "Arnauld": "<p>Arnauld to nazwisko i męskie imię. Może odnosić się do:</p>", "Avyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Avian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aviana</b>.</p><p>Aviana lub Avianna jest imieniem kobiece z wieloma pochodzeniami. Jest to grönolandska nazwa, wariant grönolanderskiej nazwy Avek, co oznacza \"rodzina\", połączona z grönoländskim końcem -na, który wskazuje na imię pierwsze.</p>", "Andrzej Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Arystarch": "<b>Arystarch</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> oznaczające tyle co <i>najlepszy władca</i>.", "Abdulrazak": "<p>'Abd al-Razzāq (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów ʿabd i al-Razzāq, jednego z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "André Filipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>André</b>.</p><p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Alvaro Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alvaro</b>.</p><b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Arata": "<b>Arata</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あらた, アラタ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, jest używane także jako nazwisko.", "Andriiy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andriy</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Amrit Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amrit</b>.</p><p>Amrit (arabski: عمريت), starożytne imię Marathus (gr. αραθ ς, Marathos), był obecnie finiockim portem znajdującym się blisko Tartus w Syrii. Założony w III millenium pne, Marat (Fenickie: ⁇ , MRT) był ważnym północnym miastem starożytnej Feneki i był przeciwnikiem sąsiedniego Arwad.</p>", "Amarjeet Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amarjeet</b>.</p><p>Amarjit lub Amarjeet to indyjskie imię, które oznacza \"wieczny triumf\". Wśród znanych osób z nazwiskiem to: Amarjit Singh Bal (1940-2010), oficer Indii Armia Amarjeet Singh Bedi (fl.</p>", "Abdur Rahman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Alisa": "<p>Alisa i Alissa to nazwiska kobiet, wersje Alice, używane w Rosji, Ukrainie, Finlandii, Estonii i innych krajach. Do znanych osób i postaci z tymi nazwami należą:</p>", "Anup Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anup</b>.</p><p>Anup (sanskrit: अनुप anūpa) to indyjskie imię męskie. Sanskritskie słowo anūpa ma następujące znaczenia: \"wodna\", \"położona w pobliżu wody\", \"brzeg rzeki\", \"zbiornik\", \"lagona\".</p>", "Angel De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Azael": "<b>Azazel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> עזאזל, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> عزازل <i>Azazil</i>) – <a href=\"https://pl.wikipedia.org/wiki/Upad%C5%82y_anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">upadły anioł</a> występujący w mitologii hebrajskiej i muzułmańskiej, znany również pod imionami <b>Azael</b>, <b>Hazazel</b> i <b>Assasello</b>. Jego imię oznacza „Bóg umacnia”, a z hebrajskiego „ten, który się oddalił”.", "Alexander Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexander</b>.</p><p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Alina": "<b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Ali Akbar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Alexandru-Iulian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Abdurrakhman": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdurakhman</b>.</p><p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Abdyrahman": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdirahman</b>.</p><p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Abdul Karim": "<p>'Abd al-Karīm (ALA-LC) to muzułmańskie imię męskie i w nowoczesnym użyciu także nazwisko. Została zbudowana z arabskich słów ʿabd i al-Karīm, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Abdelrahim": "<p>'Abd al-Raḥīm (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów 'abd, al-Raḥīm, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Arkhan": "<p>Arkhan to imię. Do osób z tym nazwiskiem należą:</p>", "Amruth": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amrutha</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amruta</b>.</p><p>Amrita (sanskrit: अमृत, IAST: amṛta), Amrit lub Amata w języku Pali, (zwany również Sudha, Amiy, Ami) jest słowem sanskryckim, które oznacza \"nieśmiertelność\". Jest to centralna koncepcja w indyjskich religiach i często jest określana w starożytnych tekstach indyjskich jako elixir.</p>", "Aminu": "<b>Aminu</b>, <b>Aminum</b> (<i>Aminu</i>, zapisywane <i>A-mi-nu</i>) – według <i><a href=\"https://pl.wikipedia.org/wiki/Asyryjska_lista_kr%C3%B3l%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Asyryjskiej listy królów</a></i> 26 król <a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">Asyrii</a>, syn i następca <a href=\"https://pl.wikipedia.org/wiki/Ilu-kabkabi\" target=\"_blank\" rel=\"noopener noreferrer\">Ilu-kabkabi</a>, a tym samym starszy brat <a href=\"https://pl.wikipedia.org/wiki/Szamszi-Adad_I\" target=\"_blank\" rel=\"noopener noreferrer\">Szamszi-Adada I</a> (1808-1776 p.n.e.). Jego imię jest ostatnim w sekcji „10 królów, których ojcowie są [<i>znani</i>]”. Obecnie wiadomo, iż władcy ci nigdy nie panowali w Asyrii, a umieszczeni zostali w <i>Asyryjskiej liście królów</i> tylko dlatego, iż byli przodkami Szamszi-Adada I, <a href=\"https://pl.wikipedia.org/wiki/Amoryci\" target=\"_blank\" rel=\"noopener noreferrer\">amoryckiego</a> uzurpatora, który przejął kontrolę nad miastem-państwem <a href=\"https://pl.wikipedia.org/wiki/Aszur_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Aszur</a>. Skryba układający <i>Asyryjską listę królów</i> dodatkowo „uczynił” Aminu ojcem <a href=\"https://pl.wikipedia.org/wiki/Sulili\" target=\"_blank\" rel=\"noopener noreferrer\">Sulili</a>, jednego z wczesnych, rodzimych władców Aszur, choć ten panował ok. 200 lat przed Szamszi-Adadem I. Zabiegiem tym skryba ten chciał najprawdopodobniej włączyć amoryckich przodków Szamszi-Adada I do listy władców, którzy poprzedzali go na tronie Aszur.", "Alberth": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Albert</b>.</p><b>Albert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających <i>adal</i> (ród szlachecki) i <i>beraht</i> (jasny, błyszczący), oznaczało „pochodzącego ze szlachetnego rodu”. Jest zredukowaną formą staroniemieckiego imienia <i>Athalbraht</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbert</a>). Alternatywną wersją Alberta jest <i><b>Olbracht</b></i> – por. <a href=\"https://pl.wikipedia.org/wiki/Jan_I_Olbracht\" target=\"_blank\" rel=\"noopener noreferrer\">Jan I Olbracht</a>, król Polski.", "Andrzej Bobola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Aleksanteri": "<p>Aleksanteri to męskie fińskie imię. Do znanych osób z nazwiska należą: Aleksanteri Aava (1883-1956), fiński poeta Aleksanteri Ohola-Valo (1900-1997), fiński artysta i architekt Aleksanteri Saarvala (1913-1989), fiński gimnast Aleksanteri Toivola (1893-1987), fiński zawodowy zawódnik sportowy Veikko Aleksanteri Heiskanen (1895-1971), fiński geodetyst</p>", "Aspen": "<p>⁇ Aspen ⁇ - nieuregularny czasopism multimedialny, wydany przez Phyllis Johnson w latach 1965-1971. Johnson opisała ⁇ Aspen ⁇ jako pierwszy na świecie trójwymiarowy czasopism.</p>", "Antone": "<p>Antone to zarówno nazwisko jak i męskie imię. Znani ludzie z nazwiska obejmują: Nazwisko: Annie Antone (ur. 1955), amerykański tkaniec koszykówki Bruce Antone (ur. 1960), amerykańskiego polityka Clifford Antone (1949-2006), amerykańskiej muzyki bluesa Steve Antone (1921-2014), amerykańską politykę Nazwisko: Antone \"Tony\" Costa (1944-1974), amerykańska serial killer Antone Davis (ur. 1967), amerykańczyk piłkarz Antone Smith (ur. 1985),...</p>", "Aliszer": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alisher</b>.</p><p>Alisher to drugi mini album Morgenschtern, wydany 14 lutego 2025 roku. W mini-albumie weszło 5 utworów o łącznej długości 12 minut 54 sekund.</p>", "Andrzej Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Andréa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>André</b>.</p><p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Andrzej Tadeusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "André Bernard": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>André</b>.</p><p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Akwasi": "<p>Akwasi lub Kwasí lub Kwesi to męskie imię pochodzące od ludu Akan i ich systemu nazwisk Akan, co oznacza urodzony w niedzielę. Ludzie urodzeni w określone dni mają charakterystyczne cechy i filozofii związane z tymi dniami.</p>", "Alvaro De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alvaro</b>.</p><b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Alin-Marius": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Ali̇ Osman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Adami": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Amit Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amit</b>.</p><p>Amit to imię indyjskie i żydowskie oraz żydowskie nazwisko. W języku hindi Amit (Hindi: अमित, oznacza \"nieograniczony\" lub \"bezgraniczny\", Bengali: অমিত) pochodzi od sanskrytyjskiego słowa amita (अमित:), amita (অमित:) jest zasadniczo negatywem mita (मित), co oznacza \"mierzyć\".</p>", "Asser": "W 893 Asser napisał biografię Alfreda, zwaną <i>Life of King Alfred</i> (Żywot króla Alfreda). Rękopis przetrwał do czasów nowożytnych w tylko jednej kopii, która była częścią księgozbioru Cottona. Kopia ta uległa zniszczeniu w pożarze w 1731, ale tłumaczenia, które sporządzono wcześniej w połączeniu z fragmentami dzieła Assera, które zostały przytoczone przez innych wczesnych autorów, umożliwiły rekonstrukcję tego dzieła. Biografia ta jest obecnie głównym źródłem informacji o życiu Alfreda i dostarcza o nim o wiele więcej wiadomości niż o jakimkolwiek innym wczesnym władcy angielskim. Asser pomagał także Alfredowi w tłumaczeniu <i>Regula pastoralis</i> (traktatu dotyczącego obowiązków duchowieństwa) <a href=\"https://pl.wikipedia.org/wiki/Papie%C5%BC_Grzegorz_I\" target=\"_blank\" rel=\"noopener noreferrer\">Grzegorza Wielkiego</a> i prawdopodobnie innych dzieł.", "Adamia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adamya</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adamia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adami</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Antonio-Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonio</b>.</p><p>Antonio James Uri (włoski: Antonio James Uri)  Antonio jest angielski.</p>", "Antony Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antony</b>.</p><p>Antony może odnosić się do: Antony (nazwa), męskie imię</p>", "Amir Hossein": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amir</b>.</p><b>Amir</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أمير&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „książę” lub „dowódca”.", "Andriyi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andriy</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Abdulhadi A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdulhadi</b>.</p><p>'Abd al-Hādī (ALA-LC) to muzułmańskie imię męskie, a w współczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Hādī, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Akihiko": "<b>Akihiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきひこ, アキヒコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Abdullah M": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdullah</b>.</p><b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Agapit": "<b>Agapit</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Powstało z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγαπητός, oznaczającego „drogi, kochany”.", "Abdusalam": "<p>Abd al-Salam (arabski: عبد السلام) to męskie muzułmańskie imię honorowe lub nazwisko, oparte na arabskich słowach Abd, al- i Salam. Nazwa oznacza \"sługę Wszechświata\", a As-Salam jest jednym z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Ayumu": "<b>Ayumu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あゆむ, アユム) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Abrão": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abra</b>.</p><b>Abra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia hebrajskiego i arabskiego, spokrewnione z imieniem <a href=\"https://pl.wikipedia.org/wiki/Abraham_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Abraham</a> o znaczeniu \"ojciec wielu\". Warianty to Abame, <a href=\"https://pl.wikipedia.org/wiki/Abarrane\" target=\"_blank\" rel=\"noopener noreferrer\">Abarrane</a>, Abrah i Abrahana.", "Andres Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Abdulhamit": "<p>'Abd al-Ḥamīd (ALA-LC romanizacja arabskiej: عبد الحميد; perskiego: عبدالحمید, romanized: Abdolhamid; tureckiego: Abdülhamit), również pisowniony jako Abdulhamid, Abdelhamid, Abd-ul Hamid i Abd ol-Hamid, jest muzułmańskie męskie imię i nazwisko. Jest to muzułmańska nazwa teoforyczna zbudowana z arabskich słów 'abd ('sługa') i al-Ḥamīd (jedno z nazw Boga w Koranie), a zatem oznacza 'sługa Wszechchchch chwalnego'.</p>", "Abdesselam": "<p>Abd al-Salam (arabski: عبد السلام) to męskie muzułmańskie imię honorowe lub nazwisko, oparte na arabskich słowach Abd, al- i Salam. Nazwa oznacza \"sługę Wszechświata\", a As-Salam jest jednym z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Abdelhaq": "<p>'Abd al-Ḥaqq (ALA-LC) to arabskie imię męskie i w nowoczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Ḥaqq, jednego z nazw Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Akther": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akter</b>.</p><p>Akhtar (perskie: اختر, pasztów: اختر) oznacza \"gwiazdę\" w perskim i jest używany w pasztówce na Nowrudz i Dzień Wielkanocny. Jest to również powszechne nazwisko.</p>", "Ali Hussein": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Aldwin": "<b>Audoen</b>, <i>Aldowin</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członów <i>alt</i> – „stary” i <i>wini</i> – „przyjaciel”, a oznacza – stary przyjaciel. Patronem tego imienia jest św. Audoen (Aldowin, Aldwin), biskup <a href=\"https://pl.wikipedia.org/wiki/Rouen\" target=\"_blank\" rel=\"noopener noreferrer\">Rouen</a>.", "Adrian Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Achmet": "<p>Ahmad (arabski: أحمد, romanized: ʾAḥmad) jest arabską nazwą męską powszechną w większości części świata muzułmańskiego, ponieważ jest to jedno z dobrze znanych imion proroka Muhammada. Inne angielskie pisowni nazwy obejmują Ahmed, Ahmmad.</p>", "Alii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Ayman Abdalla": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ayman</b>.</p><b>Ayman</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> َأيْمَن) – arabskie imię męskie, oznaczające: błogosławiony, szczęśliwy. Bywa zapisywane także jako Ajman, Aiman, Aimen, Aymen.", "Andrii-Nazar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrii</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Adebisi": "<p>Adébísí to zarówno nazwisko jak i nazwisko pochodzenia joruba, co oznacza \"korona lub królewska rodzina wyprodukowała więcej lub urodziła więcej\".</p>", "Alex-Denis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Abdulrazaq": "<p>'Abd al-Razzāq (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów ʿabd i al-Razzāq, jednego z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Andres Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Asuka": "<b>Asuka</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あすか, アスカ) – głównie żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, rzadko noszone przez mężczyzn, może być używane także jako nazwisko.", "Annadurai": "<p>Annadurai (tamilsky: அண்ணாதுரை) jest tamilskim nazwiskiem patronymicznym i męskim nazwisku. Do wybitnych osób z tym nazwiskiem należą: C.</p>", "Andre Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>André</b>.</p><p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Ademar": "<b>Ademar</b>, Adalmer, Adalmar – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskie</a>, notowane w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> od <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecza</a> w formie <i>Ademarus</i> (<a href=\"https://pl.wikipedia.org/wiki/1318\" target=\"_blank\" rel=\"noopener noreferrer\">1318</a>). Pierwszy człon imienia, <i>Adal–</i> w różnych odmiankach oznacza „szlachetny ród”, „ród szlachecki, stan szlachecki”, natomiast <i>-mar</i>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">stwniem.</a> <i>māri //-meraz</i> — „sławny”. Staropolskie zdrobnienia od imion z pierwszym członem <i>Adal-</i> to: Alesz, Alis, Alsz, Alszyk, Halsz, Oberek, Oberko, Apecko, Opac(z), Opac(z)ek, Opac(z)ko, Opecko, Owruta.", "Anthonny": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anthony</b>.</p><p>Anthony może odnosić się do: Anthony Hopkins Anthony Giddens Anthony van Dyck</p>", "Antoni̇": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Antony</b>.</p><p>Antony może odnosić się do: Antony (nazwa), męskie imię</p>", "Abubakari": "<p>Abu Bakr (arabsko: أبو بكر) to arabskie imię, które oznacza \"ojciec młodego wielbłąda\" (Abu oznacza \"ojca\" i Bakr oznacza \"młody wielbłąd\"), które jest szeroko stosowane przez muzułmanów sunnitów. Inne transliteracje obejmują Abu Bakar, Abu Bekr, Ebubekir, Aboubacar, Abubakar itp.</p>", "Antoine Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoine</b>.</p><p>Franz Antoine (niem. Franz Antoine, 23 lutego 1815 - 11 marca 1886) - austriacki botanik, artysta i fotograf.</p>", "Alhassane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alhassan</b>.</p><p>Alhassan to nazwisko. Do wybitnych osób z nazwiskiem należą: Abdul Razak Alhassan (ur. 1985), ghanański artysta walki mieszanej Masahudu Alhassan (1992), ghanański międzynarodowy back Alhassan Mohammed Gani (1959-2025), nigerianski administrator akademicki Alhassan Wakaso (1992), ghanijski środkowy strzelanin Kalif Alhassan (1990), ghanajski piłkarz Karim Alhassan (1981) ghanański obrońca Mohammed Alhassan (1944) ghanański...</p>", "Aliaksey": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aliaksei</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksy</b>.</p><b>Aleksy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">późnogreckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Αλέξιος, <i>Aléxios</i>). Zostało utworzone od czasownika <i>aléks</i>, czyli „bronić” lub „wspomagać”. Imię Aleksy zostało rozpowszechnione w różnych językach dzięki <a href=\"https://pl.wikipedia.org/wiki/Legenda_o_%C5%9Bwi%C4%99tym_Aleksym\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznej legendzie</a> o <a href=\"https://pl.wikipedia.org/wiki/Aleksy_Wyznawca\" target=\"_blank\" rel=\"noopener noreferrer\">św. Aleksym</a>.", "Arun Lal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arun</b>.</p><p>Arun (Mongolski: ⁇ ⁇ Arun qosiɣu, Kirin Mongoli: Арун хошуу; przenoszone: 阿荣旗; subtyp: 阿榮旗; przenośne: Āróng Qí, Hán Việt: A Vinh kỳ) jest okresem urzędu miasta Hulunbuir (Holun Luan Uy), Autonomicznego Obszaru Mongolicznego, Chiny. Miasto graniczy z prowincją Hắc Long Giang na wschodzie i południu i znajduje się 92 km (57 mi) na północno-zachodni od miasta Tề Tề Cápur w prowincji Hắc Long.</p>", "Athan": "<p>Athan to greckie imię męskie, które oznacza \"życie wieczne\" lub \"nieśmiertelność\" lub \"wschodzące słońce\". Może to być wariant Athanasios i jest coraz bardziej popularny wśród młodych greckich rodziców w diasporze.</p>", "Anand Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anand</b>.</p><p>Anand - indyjska nazwa, nazwisko i toponim: Viswanathan Anand (ur.</p>", "Andres Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Alex David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Aurelii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aureli</b>.</p><b>Aureli</b> – oboczna forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> męskiego <a href=\"https://pl.wikipedia.org/wiki/Aureliusz\" target=\"_blank\" rel=\"noopener noreferrer\">Aureliusz</a>, pochodzącego od nazwy rzymskiego rodu Aureliuszy, która z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <i>aureolus</i> – „złocisty” (co mogło znaczyć także „wspaniały”).", "Anti": "Jego kult jest bardzo stary, pochodzi co najmniej z okresu <a href=\"https://pl.wikipedia.org/wiki/II_dynastia\" target=\"_blank\" rel=\"noopener noreferrer\">drugiej dynastii</a>, kiedy to miał już swoich kapłanów. Anti najprawdopodobniej był patronem dawnej okolicy Badari, które było centrum kultu <a href=\"https://pl.wikipedia.org/wiki/Horus\" target=\"_blank\" rel=\"noopener noreferrer\">Horusa</a>. Przedstawiany jest jako sokół stojący na łodzi.", "Asta": "<p>Asta to rodzaj roślin kwiatowych z rodziny Części.</p>", "Antonio Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonio</b>.</p><p>Antonio James Uri (włoski: Antonio James Uri)  Antonio jest angielski.</p>", "Azi̇m": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Azima</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Azim</b>.</p><p>Azim (ʿAẓīm عظيم) jest jednym z imion Allaha w islamu, co oznacza \"Wielki\" lub \"Wspaniały\" lub \"Ochrony\". Jest używany przez wielu Sahrawiów jako nazwisko pochodzące z arabskiego Hasania.</p>", "Andres Esteban": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Amitabh": "<p>Amitabha lub Amitabha może odnosić się do: Amitabha, ważny Buddy w buddyzmie Amitabha Buddha z Hancui, posąg z Hancwi, China, obecnie w British Museum Amitabha Buddhist Centre, Singapur Amitav Acharya (urodzony 1962), indyjsko-kanadyjski uczony i autor Amitabh Aurora, indyjski filmowiec Amitabh Bachchan (urodzono 1942), indyjski aktor w kinie hindi Amitabh Bagchi, indyjscy maoista Amitabh Bajpai, indyjskiego polityka Amitav Banerji (urodzona...</p>", "Ali Riza": "<p>Ali Reza (zwany również Alireza lub Ali-Reza) jest popularną nazwą wśród Iranczyków, Bengaliczyków, Turków i Albanijczyków.</p>", "Adrian-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Alann": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alan</b>.</p><b>Alan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia najprawdopodobniej <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Może też wywodzić się od nazwy irańskiego plemienia <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alanów</a>. Znaczenie tego imienia nie jest dokładnie znane, prawdopodobne znaczenia:", "Alym": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alim</b>.</p><b>Ulem</b> – muzułmański teolog i uczony. Słowo pochodzi z wyrazu <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> <i>alim</i>, oznaczającego uczonego. W skład grupy ulemów wchodzili wszyscy duchowni muzułmańscy: <a href=\"https://pl.wikipedia.org/wiki/Mufti\" target=\"_blank\" rel=\"noopener noreferrer\">muftiowie</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Imam\" target=\"_blank\" rel=\"noopener noreferrer\">imamowie</a>. Ulemów określa się również mianem znawców <a href=\"https://pl.wikipedia.org/wiki/Szariat\" target=\"_blank\" rel=\"noopener noreferrer\">szariatu</a>. Ich główną siedzibą były <a href=\"https://pl.wikipedia.org/wiki/Meczet\" target=\"_blank\" rel=\"noopener noreferrer\">meczety</a>. Główną rolę posiadał meczet <a href=\"https://pl.wikipedia.org/wiki/Al-Azhar\" target=\"_blank\" rel=\"noopener noreferrer\">al-Azhar</a> w <a href=\"https://pl.wikipedia.org/wiki/Kair\" target=\"_blank\" rel=\"noopener noreferrer\">Kairze</a>.", "Alex-David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Anderson Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Andrii-Oleh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrii</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Amour": "<p>Amour (francuski dla miłości) to słowo używane w języku angielskim i francuskim, i może również odnosić się do: Amour (1970 film), duński film Amour (2012 film), francuskojęzyczny film reżyserowany przez Michaela Haneke Amour (muzyka), 1997 scena muzyczna Michel Legrand Amour (Stockhausen), 1974-76 cyklu utworów klarnetów przez Karlheinz Stockhausen Amour (Widhan Sabha okręg wyborczy), okręg zgromadzenia w dzielnicy Purnia, Bihar, India Amour Abdenour (ur. 1952),...</p>", "Alexander Tadeusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexander</b>.</p><p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Aroon": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aron</b>.</p><p>Aron jest miejscowością i nagar panchayatem Guna w stanie Madhya Pradesh, India.</p>", "Anh Hao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Abdurrachman": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdurrakhman</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdurakhman</b>.</p><p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Alexandru-Constantin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Abdul Qadeer": "<p>Abd al-Qadir lub Abdulkadir (arabsko: عبد القادر) to męskie muzułmańskie imię. Utworzona jest z arabskich słów Abd, al- i Qadir.</p>", "Anamol": "<p>Anamol lub Anmol (nepali: अनमोल, urdu: انمول) to nazwa używana w Nepalu, Pakistanie i Indiach. Znaczy \"Dzierne\".</p>", "Adlen": "<p>Adlen to angielskie nazwisko i imię w Maghrebi, w językach arabskich, angielskich i niektórych rosyjskich. Jako nazwisko pochodzi z staroangelskiego korzeni związanych z szlachtą i ochroną (patrz Etymologia poniżej).</p>", "Anderson David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Angel Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Antoś": "Sama nazwa Antoś pochodzi od imion dwóch skoczków narciarskich ze Szczyrku – <a href=\"https://pl.wikipedia.org/wiki/Antoni_%C5%81aciak\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniego Łaciaka</a> i <a href=\"https://pl.wikipedia.org/wiki/Antoni_Wieczorek\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniego Wieczorka</a>. Skocznia nazywana była też <a href=\"https://pl.wikipedia.org/wiki/Beskidek_(860_m)\" target=\"_blank\" rel=\"noopener noreferrer\">Beskidkiem</a> – od nazwy stoku na którym była położona.", "Adria": "<p>Adria to włoska miasto i gmina. Miasto należy do prowincji Rovigo w regionie Veneto.</p>", "Andrzej Antoni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "August J": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>August</b>.</p><b>August</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przymiotnika <i>augustus</i>, nadanego jako przydomek <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawianowi</a> przez Senat i oznaczającego „dostojny, boski, majestatyczny, poświęcony, święty, czcigodny, pomyślny, wzniosły”. Przymiotnik ten pochodzi od rzeczownika <i>augur</i> i pierwotnie odnosił się tylko do rzeczy, tłumacząc się jako „uświęcony przez (dobre) przepowiednie, znaki” lub „przedsięwzięty pod sprzyjającymi znakami”. Po raz pierwszy imię August zostało poświadczone w Polsce w <a href=\"https://pl.wikipedia.org/wiki/1349\" target=\"_blank\" rel=\"noopener noreferrer\">1349</a> roku, w łac. formie <i>Augustus</i>.", "Alexandru-Stefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Alai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ala</b>.</p><p>Alanin (2-aminopropanowy kwas) - aminokwas alifatyczny. α-alanina jest częścią wielu białek, β-alanina - w szeregu związków biologicznie aktywnych.</p>", "Adrian Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Alexandru-Marius": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Alexandar": "<p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Anh Thái": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Alexandru-Valentin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Abdulraheem": "<p>'Abd al-Raḥīm (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów 'abd, al-Raḥīm, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Aan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Atul Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Atul</b>.</p><p>Atul jest miasteczkiem w Valsad w stanie Gujarat w Indiach.</p>", "Apolinario": "<p>Apolinario to portugalska i hiszpańska nazwa i nazwisko, pochodzące od łacińskiego Apollinaris. Do wybitnych osób z tym nazwiskiem należą:</p>", "Abdulai": "<p>Abd Allah (arabsko: عبد الله, romanized: ʻAbd Allāh), również pisane Abdullah, Abdhullah, Abdellah, Abdollah, Abdallah, Abdulla, Abdalla i wiele innych, jest arabską nazwą teoforyczną oznaczającą sługę Boga lub \"szońca Boga\". Został zbudowany z arabskich słów ʿabd (عبد) i Allāh (Allah).</p>", "Ali Murat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Aleksij": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksi</b>.</p><p>Aleksi to męskie fińskie imię. Do wybitnych osób z tym nazwiskiem należą: Aleksi Bardy, fiński scenarzysta i producent filmowy Aleksi Benashvili, gruziński piłkarz Aleksi Eeben, fiński kompozytor, projektant dźwięku, muzyk i programista Aleksi Elorinne, fiński hokejista lodowy Aleksi Heimosalmi, fiński gracz lodowy Hihnavaara Aleksi, fiński granicą Aleksi Holmberg, fiński piłka hokeja Aleksi Honka-Hallila, fiński...</p>", "Anibal Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anibal</b>.</p><p>Aníbal jest hiszpańskim i portugalskim męskim nazwiskiem pochodzącym z Hannibału (q.v.), samemu latynistycznym nazwiskiem greckiego Hanníbas (⁇ ννίβας), pochodzącym od \"ḥnbʿl\" w języku kartaginskim (kartaginskim pisemnym, ⁇ ‬‬‬‬ ⁇ ‬‬ ⁇ ⁇ ‬‬), potomkiem fenickijskiego języka kananeckiego, w którym znaczenie nazwy jest \"Baʿal ([Pan] jest] moją łaską\", krewny hebrajskiego honoryficznego Baʿal (בעל) \"mistrz/pódca\".[the][is] W języku angielskim może odnosić się do:</p>", "Ahmed Mahmoud": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Arjun Krishna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arjun</b>.</p><b>Arjun</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskr.</a> <i>अर्जुन</i>) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjski</a> <a href=\"https://pl.wikipedia.org/wiki/Czo%C5%82g_podstawowy\" target=\"_blank\" rel=\"noopener noreferrer\">czołg podstawowy</a>, produkowany od 2004 roku, w <a href=\"https://pl.wikipedia.org/wiki/Armia_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">armii indyjskiej</a> od 2007 roku. Nazwa czołgu pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Ard%C5%BAuna\" target=\"_blank\" rel=\"noopener noreferrer\">Ardźuna</a> - jednego z bohaterów <a href=\"https://pl.wikipedia.org/wiki/Epos\" target=\"_blank\" rel=\"noopener noreferrer\">eposu</a> <i><a href=\"https://pl.wikipedia.org/wiki/Mahabharata\" target=\"_blank\" rel=\"noopener noreferrer\">Mahabharata</a></i>.", "Alexandru-Dan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Antoni Władysław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Arvind Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arvind</b>.</p><p>Aravind (z sanskrytu: अरविन्द aravinda) to powszechne indyjskie imię męskie oznaczające lotos. Nazwa jest pochodzenia hinduskiego.</p>", "Abdullah Ibrahim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdullah</b>.</p><b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Aleen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleena</b>.</p><p>Aleena to kobiece imię, prawdopodobnie wariant Aliny. Może odnosić się do:</p>", "Adedapo": "<p>Adédàpọ̀ to imię i nazwisko pochodzenia joruba, co oznacza \"korona łączy ludzi\" lub \"królewskość łączy ludzie\" (lub korona lub królewskości łączy się podobnie.\") Znani ludzie z nazwiskiem to: Naima Adedapo (urodzona 5 października 1984), amerykańska piosenkarka i tancerka Adedapo Tejuoso (urodzony w 1938 roku), nigerijski monarch Książę Adedapo Benjamin Adelegan, nigerijski polityk Adedapo Awokoya-Mebude, nigeriński piłkarz</p>", "Alexiy": "<p>Alexey (rosyjski: Алексей, romanized: Aleksey [ɐljɪkˈsjej]) to rosyjskie imię męskie pochodzące od greckiego Aléxios (Αλέξιος), co oznacza \"Obrannik\", a zatem z tego samego pochodzenia jak łacina Alexius. Podobne ukraińskie i białoruskie nazwy są romanizowane odpowiednio jako Oleksii (Олексій) i Aliaksiej (Аляксей).</p>", "Ardijan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ardian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ardiana</b>.</p><p>Ardian to albanska nazwa. Chociaż podobna do Adrian, nazwy pochodzenia łacińskiego, albanska Ardian (Ardjan i Ardijan są innymi wariantami) jest pochodem Ardiaei, nazwy starożytnego lyryjskiego ludu.</p>", "Akyl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akil</b>.</p><p>Akil to miasto w stanie Yucatán w Meksyku. W 2005 roku liczba mieszkańców miasta wynosiła 9765 osób.</p>", "Artemon": "<b>Artemon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się od imienia wczesnochrześcijańskiego biskupa św. Artemona.", "Andreo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>André</b>.</p><p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Alexander Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexander</b>.</p><p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Ali Ahmed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Arun Raj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arun</b>.</p><p>Arun (Mongolski: ⁇ ⁇ Arun qosiɣu, Kirin Mongoli: Арун хошуу; przenoszone: 阿荣旗; subtyp: 阿榮旗; przenośne: Āróng Qí, Hán Việt: A Vinh kỳ) jest okresem urzędu miasta Hulunbuir (Holun Luan Uy), Autonomicznego Obszaru Mongolicznego, Chiny. Miasto graniczy z prowincją Hắc Long Giang na wschodzie i południu i znajduje się 92 km (57 mi) na północno-zachodni od miasta Tề Tề Cápur w prowincji Hắc Long.</p>", "Aytac": "<p>Aytaç to tureckie imię i nazwisko. Ay to tureckie słowo dla \"księżyca\" i taç dla \"korony\", więc Aytaç można przetłumaczyć jako \"korona księżyca\" lub \"korona miesiąca\".</p>", "Akhil Raj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Akhil</b>.</p><p>Akhil (w Devanagari: अखिल, IAST: akhila) to imię pochodzenia sanskrytycznego, co oznacza \"całość\" lub \"całość\". Równoważne nazwisko kobiece to Akhila (IAST: akhilā).</p>", "Aldy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aldi</b>.</p><b>Aldi</b> (nazwa stylizowana: <b>ALDI</b>) – <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">niemiecka</a> sieć dyskontów spożywczo-przemysłowych obecna na pięciu kontynentach. Siódma pod względem sprzedaży sieć marketów na świecie. Nazwa przedsiębiorstwa pochodzi od skrótu nazwiska <b>Al</b>brecht i słowa <b>di</b>skont. Przedsiębiorstwo powstało i do dziś jest <a href=\"https://pl.wikipedia.org/wiki/Przedsi%C4%99biorstwo_rodzinne\" target=\"_blank\" rel=\"noopener noreferrer\">firmą rodzinną</a> Albrechtów z <a href=\"https://pl.wikipedia.org/wiki/Essen\" target=\"_blank\" rel=\"noopener noreferrer\">Essen</a>.", "Adamya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adamia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adami</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Anzhela": "<p>Angela to imię kobiety. Pochodzi od greckiego słowa ángelos (⁇ γγελος), co oznacza anioła z greckiego systemu wierzeń.</p>", "Alex Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Artur-Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Artur</b>.</p><b>Artur</b> wymowa – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Powstało ze złożenia dwóch wyrazów wywodzących się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">języków celtyckich</a>: <i>Art</i> – niedźwiedź, <i>ur</i> – młody, piękny, kwitnący. Podstawę imienia może także stanowić celtyckie słowo ard – wysoki, szlachetny.", "Athul Krishna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Athul</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Atul</b>.</p><p>Atul jest miasteczkiem w Valsad w stanie Gujarat w Indiach.</p>", "Alfa": "<b>Alfa</b> (<b>ἄλφα</b>, pisana <b>Αα</b>) − pierwsza <a href=\"https://pl.wikipedia.org/wiki/Litera\" target=\"_blank\" rel=\"noopener noreferrer\">litera</a> <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a>. W greckim systemie liczbowym oznacza liczbę <a href=\"https://pl.wikipedia.org/wiki/1_(liczba)\" target=\"_blank\" rel=\"noopener noreferrer\">1</a>. Alfa pochodzi od litery <a href=\"https://pl.wikipedia.org/wiki/Alfabet_fenicki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu fenickiego</a> <a href=\"https://pl.wikipedia.org/wiki/Alef\" target=\"_blank\" rel=\"noopener noreferrer\">alef</a> <a href=\"https://pl.wikipedia.org/wiki/Plik:Phoenician_aleph.svg\" target=\"_blank\" rel=\"noopener noreferrer\"></a>. Od alfy pochodzą <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/A\" target=\"_blank\" rel=\"noopener noreferrer\">A</a> i <a href=\"https://pl.wikipedia.org/wiki/Cyrylica\" target=\"_blank\" rel=\"noopener noreferrer\">cyrylickie</a> <a href=\"https://pl.wikipedia.org/wiki/%D0%90_(cyrylica)\" target=\"_blank\" rel=\"noopener noreferrer\">А</a>.", "Anderson Estiven": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Andres Santiago": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Alberico": "Starofrancusko-normańska forma <b>Aubrey</b> jest używana w krajach anglojęzycznych jako imię a także nazwisko. Od <a href=\"https://pl.wikipedia.org/wiki/Lata_70._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">lat 70. XX wieku</a> częściej nadawana jest kobietom, być może pod wpływem podobieństwa z żeńskim imieniem <a href=\"https://pl.wikipedia.org/wiki/Edeltruda\" target=\"_blank\" rel=\"noopener noreferrer\">Audrey</a>. Możliwe, że żeńska forma jest w istocie odmiennym imieniem i wywodzi się również poprzez starofrancuski z germańskiego żeńskiego imienia <i>Albrad</i>, od <i>alb</i> – elf oraz drugiego członu o nieustalonej etymologii.", "Abdullah Saleh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdullah</b>.</p><b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Aldrine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aldrin</b>.</p>Została nazwana imieniem twórcy metody jej wytwarzania – noblisty z 1950 <a href=\"https://pl.wikipedia.org/wiki/Kurt_Alder\" target=\"_blank\" rel=\"noopener noreferrer\">Kurta Aldera</a>.", "Adrian-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Abhinava": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abhinav</b>.</p><p>Abhinava (Devanagari: अभिनव) to indyjskie imię męskie. Sanskrit abhinava oznacza \"nowy\".</p>", "Abdul Razak": "<p>'Abd al-Razzāq (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów ʿabd i al-Razzāq, jednego z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Alex Alfonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Aveli": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Avel</b>.</p><p>Avel to męskie imię. Inną definicją Avel jest HİLAL</p>", "Alejandro Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alejandro</b>.</p><p>Alejandro - hiszpańska forma imienia Aleksandra.</p>", "Anh Huy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Armando Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Armando</b>.</p><p>Armando - pierwszy hiszpański album studiowy (i piąty w dyskografii) repera z Miami Pitbull. Relizja albumu odbyła się 2 listopada 2010 roku.</p>", "Anh Quang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Arland": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arlanda</b>.</p>W marcu 2026 roku lotnisko Arlanda w Sztokholmie obsłużyło prawie 1,9 mln pasażerów, co oznacza wzrost o około 5 proc. w porównaniu z analogicznym miesiącem rok wcześniej. Jak podała Swedavia&#65279;<a href=\"https://www.wikidata.org/wiki/Q1571428#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>, wzrost objął zarówno ruch międzynarodowy, jak i krajowy. W segmencie zagranicznym obsłużono nieco ponad 1,5 mln pasażerów, a w krajowym blisko 378 tys. osób. Według tych samych danych przez dziesięć lotnisk spółki przewinęło się w marcu około 2,6 mln pasażerów, co również oznacza wzrost o nieco ponad 5 proc. w ujęciu rocznym.", "As'ad": "<p>As'ad, nieformalnie przetłumaczony jako Asaad lub Assaad, jest arabskim imieniem męskim pochodzącym z wyższego stopnia przymiotnika Sa'id sa'īd, co oznacza \"więcej/najbardziej szczęścia, szczęśliwsza/najszczęśliwsza, szczęśliwszą/najszczesniejszą\". Istnieje też jako nazwisko.</p>", "Abdulfattah": "<p>'Abd al-Fattāḥ (ALA-LC) to muzułmańskie imię męskie i w nowoczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Fattāḥ, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Ariet": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arieta</b>.</p><b>Arietta</b> – <a href=\"https://pl.wikipedia.org/wiki/Forma_muzyczna\" target=\"_blank\" rel=\"noopener noreferrer\">forma muzyczna</a>, <a href=\"https://pl.wikipedia.org/wiki/Aria\" target=\"_blank\" rel=\"noopener noreferrer\">aria</a> o mniejszych rozmiarach, zwykle w formie 2-częściowej lub utwór instrumentalny.", "Ahmed M": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Andrès": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andresa</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Anatoliii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anatolii</b>.</p><p>Anatolii (rosyjski: Анатолий, romanizowany: Anatoliy, ukraiński: Анато́лій, romanized: Anatolii) jest powszechną rosyjską i ukraińską nazwą męską, pochodzącą z greckiego imienia Anatolios (⁇ νατόλιος), co oznacza \"on wschodu słońca\", z ἀνατολή anatolē, \"wychod słońca\". Anatoly było jednym z pięciu najpopularniejszych imion dla chłopców urodzonych w St.</p>", "Anh Khoi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Ayar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ayari</b>.</p><p>Ayari (arabsko: العياري przymiot عَيّار ayyār) to magrebijska (Tunisia, Algieria) i perskie nazwisko. W Francji mieszka ponad 400 osób z tym nazwiskiem (tj.</p>", "Ariian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arian</b>.</p><b>Arian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jego patronem jest św. Arian, wspominany razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Teotyk_(m%C4%99czennik_egipski)\" target=\"_blank\" rel=\"noopener noreferrer\">Teotykiem</a>.", "Apollonius": "<p>Apollonius (w starożytnym greckim: ⁇ πολλώνιος) to męskie imię (z polskim językiem: Apoloniusz), które może odnosić się do:</p>", "Antonio Carlos": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonio</b>.</p><p>Antonio James Uri (włoski: Antonio James Uri)  Antonio jest angielski.</p>", "Alba": "<b>Alba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od łac. <i>Albus/a</i>, od <i>albus</i> \"jasny, biały, świetlisty\". W Polsce spotykane bardzo rzadko, choć notowane już w średniowieczu.", "Abdulrazzaq": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdulrazaq</b>.</p><p>'Abd al-Razzāq (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów ʿabd i al-Razzāq, jednego z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Andrii-Dmytro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrii</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Ali Mohammed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Ahmadullah": "<p>Ahmadullah lub Ahmad Ulla to zarówno imię i nazwisko. Do wybitnych osób z nazwą należą: Ahmadullah Shah (1787-1858), indyjski bojownik o wolność Ahmadullah Affandi (1922-2013), indyjski skaut Ahmadullah Alizai (ur. 1972), afgański polityk Sheikh Ahmadullah bin Delwar Hossain (ur. 1981), bangladeski islamski uczony Ahmad Ullah Maizbhandari (1826-1906), bengalski sufi św. Ahmadullah Muttaqi (ur.</p>", "Akrem": "<p>Akram (arabski: أکرم) to nazwisko i nazwisko pochodzące od arabskiego słowa korzeni Karam (كرم), co oznacza \"rodność\". W języku arabskim, Akram jest przymiotem porównawczym i oznacza \"dziecko\". W Turcji i Europie Wschodniej nazwa jest również przetłumaczana jako Ekrem/Eqrem.</p>", "André Luis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>André</b>.</p><p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Apolinar": "<p>Apolinar to męskie imię, które może odnosić się do: Apolinar de Jesús Soto Quesada (1827-1911), boliwskiego polityka Apolinar Serrano (1833-1876), hiszpańskiego biskupa Hawany Apolinar Velez (1865-1939), filipińskiego polityka</p>", "Alick": "<p>Alick to zarówno męskie imię, jak i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Adrian-Ion": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Armandó": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Armand</b>.</p><b>Herman</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „wojownik”. Innym jego wariantem jest <b><a href=\"https://pl.wikipedia.org/wiki/Armin\" target=\"_blank\" rel=\"noopener noreferrer\">Armin</a></b>, natomiast nazwisko <a href=\"https://pl.wikipedia.org/wiki/Menzel\" target=\"_blank\" rel=\"noopener noreferrer\">Menzel</a> stanowi podwójne zdrobnienie imienia Hermann. W średniowiecznej Polsce odnotowywano polskie formy Jerzman i Jirzman.", "Adegoke": "<p>Adégòkè jest zarówno nazwiskiem jak i nazwiskiem pochodzenia joruba, co oznacza \"korona lub królewska rodzina wzrosła na szczyt lub zdobyła postęp\". Znanymi osobami z nazwiska są: Adegoke Adelabu (1915-1958), nigerijski polityk Adegoke Fadare, kanadyjski polityk adegoke Olubummo (1923-1992), nigerijski akademik i matematyka Imię Enoch Olaoluwa Adegoke (urodzony 2000), nigeriński sprinter Jimmy Adegoke ...</p>", "Ageusz": "<b>Aggeusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, biblijne, z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Haggai</i>, 'urodzony w święto', zatem odpowiadałoby to <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiemu</a> <i>Dominicus</i> czy <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiemu</a> <i>Kyriakós</i> (<i>świąteczny</i> lub <i>urodzony w święto</i>). Imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Aggeusz\" target=\"_blank\" rel=\"noopener noreferrer\">jeden z proroków mniejszych</a> w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>.", "Aquib": "<p>Aquib to męskie imię. Znani ludzie z nazwiskiem to: Aquib Afzaal (ur. 1985), angielski gracz kryketu Aquib Nabi (ur. 1996), indyjski gracz krykietu Aquib Nazir, indyjski kryketacz</p>", "Adrian Felipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Aoi": "<b>Aoi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あおい, アオイ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, używane jest także jako nazwisko. Oznacza „malwa” lub „niebieski”. Imieniny obchodzi 27 marca.", "Adrian-Marius": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Angel Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Ali Osman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Agamemnon": "<b>Agamemnon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Ἀγαμέμνων <i>Agamémnōn</i>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Agamemnon</i>) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> syn <a href=\"https://pl.wikipedia.org/wiki/Atreus\" target=\"_blank\" rel=\"noopener noreferrer\">Atreusza</a> i <a href=\"https://pl.wikipedia.org/wiki/Aerope_(c%C3%B3rka_Katreusa)\" target=\"_blank\" rel=\"noopener noreferrer\">Aerope</a>, (w niektórych mitach ojcostwo przypisywane jest <a href=\"https://pl.wikipedia.org/wiki/Plejstenes\" target=\"_blank\" rel=\"noopener noreferrer\">Plejstenesowi</a>), starszy brat <a href=\"https://pl.wikipedia.org/wiki/Menelaos\" target=\"_blank\" rel=\"noopener noreferrer\">Menelaosa</a>, pochodził z rodu <a href=\"https://pl.wikipedia.org/wiki/Atrydzi\" target=\"_blank\" rel=\"noopener noreferrer\">Atrydów</a>. Król <a href=\"https://pl.wikipedia.org/wiki/Argolida\" target=\"_blank\" rel=\"noopener noreferrer\">Argolidy</a>, krainy, w której najważniejszymi miastami były <a href=\"https://pl.wikipedia.org/wiki/Argos_(Grecja)\" target=\"_blank\" rel=\"noopener noreferrer\">Argos</a>, <a href=\"https://pl.wikipedia.org/wiki/Mykeny\" target=\"_blank\" rel=\"noopener noreferrer\">Mykeny</a>, <a href=\"https://pl.wikipedia.org/wiki/Tyryns\" target=\"_blank\" rel=\"noopener noreferrer\">Tiryns</a>, Midea. Według najpóźniejszego przekazu był królem Lakedajmonu ze stolicą Amyklaj. Od jego przodków nazywano go czasem Atrydą, Pelopidą lub Tantalidą.", "Artion": "<p>Artion to albanianki imię. Do znanych osób z nazwiskiem należą: Artion Alillari (ur. 1995), albanianki piłkarz zawodowy Artion Poçi (ur. 1977), albanianski były piłkarzek</p>", "Abdulqader": "<p>Abd al-Qadir lub Abdulkadir (arabsko: عبد القادر) to męskie muzułmańskie imię. Utworzona jest z arabskich słów Abd, al- i Qadir.</p>", "Abdulkader": "<p>Abd al-Qadir lub Abdulkadir (arabsko: عبد القادر) to męskie muzułmańskie imię. Utworzona jest z arabskich słów Abd, al- i Qadir.</p>", "Anh Thắng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "António José": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonio</b>.</p><p>Antonio James Uri (włoski: Antonio James Uri)  Antonio jest angielski.</p>", "Anh Khôi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Andres Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Alexandru-Ciprian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Anthonio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Antonio</b>.</p><p>Antonio James Uri (włoski: Antonio James Uri)  Antonio jest angielski.</p>", "Adrian-Alin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Alysson": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alisson</b>.</p><p>Alison Ramses Becker (port. - Nieźle. Alisson Ramses Becker; rodzaj.</p>", "Aliks": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alix</b>.</p><p>Święta Alice (francuski: Alix de Schaerbeek, Alice, Adélaïde, Aleyde, 1225, Skarbek (obecnie Belgia) - 1250, Abbotstwo Cambr, Bruksela) - święta Kościoła rzymskokatolicznego, czczona jako patronka ślepych i paraliżowanych.</p>", "Artsyom": "<p>Artsyom (bieloruska: Арцём), również przetransliterowany jako Artsiom, jest popularną nazwą męską w Białorusi. Jest to wersja nazwy Artem/Artyom.</p>", "Anh Duong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Abdel Rahman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Azfar": "<p>Azfar (urdu: اظفر) jest zarówno męskim nazwiskiem, jak i nazwiskiem występującym głównie w Pakistanie, ale także w Bangladeszu i Malezji. Do wybitnych osób z tym nazwiskiem należą:</p>", "Abdulahi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdulah</b>.</p><p>Abd Allah (arabsko: عبد الله, romanized: ʻAbd Allāh), również pisane Abdullah, Abdhullah, Abdellah, Abdollah, Abdallah, Abdulla, Abdalla i wiele innych, jest arabską nazwą teoforyczną oznaczającą sługę Boga lub \"szońca Boga\". Został zbudowany z arabskich słów ʿabd (عبد) i Allāh (Allah).</p>", "Andrii-Vasyl": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrii</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Anderson De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Ali Burak": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Antti Juhani": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antti</b>.</p><p>Antti to fińskie imię męskie pochodzące od greckiego imienia Andreas. W Estonii bardziej powszechna jest wariant anty.</p>", "Anderson Stiven": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Ali̇ Emre": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Ashoka": "Pierwszym jego zarządzeniem był rozkaz zgładzenia wszystkich przyrodnich braci – ewentualnych pretendentów do królewskiego tronu. Przy życiu pozostawił tylko młodszego brata – pochodzącego od tej samej matki Tisidżę. Król miał syna, Mahendrę (Mahindę), urodzonego w 284 roku p.n.e. oraz córkę, Sanghamitrę, urodzoną w 268 roku p.n.e.", "Andres Elias": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Anwer": "<p>Anwar (lub Anwer, Anwaar, Anouar, Anvar, Enver, Enwer) jest angielską transliteracją dwóch arabskich nazw, które są powszechnie używane w świecie arabskim zarówno przez arabskich chrześcijan, jak i muzułmanów: męskie imię ʼAnwar (أنور), co oznacza \"światło\" lub żeńskie imię ʼ Anwār (أنوار), co oznacza\" zbiór światła \". W języku arabskim Anwar jest również przymiotem porównawczym o znaczeniu \"bardziej oświecony\".</p>", "Ali̇ Haydar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Antoni Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Arsen-Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arsen</b>.</p><p>Arsen (na armeńsku, Արսեն; gruzińsku, არსენ; rosyjski, Арсен; ukraiński, Арсен) jest nazwiskiem, diminutiwem greckiego Arsenios. Do wybitnych osób z tym nazwiskiem należą: Arsen Akayev (ur. 1970), Kumyk-Roski trener i były gracz piłki nożnej Arsen Avakov (ur. 1964), ukraiński polityk Arsen Awakov (ur., 1971), były tajczyk piłkarz piłkarza Arsen Avetisyan (ur. 1973), armenijski piłkarze piłkarzy Arsen Aydinian (1825-1902), armeni...</p>", "Aaqib": "<p>Aqib i Aaqib to imiona męskie. Znani ludzie z tymi nazwami to: Aqib Ilyas (ur. 1992), kryketar Omani Aqib Javed (ur. 1997), kryketer pakistański Aaqib Javed, ur. 1972), pakistański kryketar i trener Aqib Khan (ur. 1994), pakistajski aktor Aaqib Khan (urat. 2003), indyjski kryketar Aqib Shah (ur. 1995), pakistański kryketar Aaqib Talib (ur. 1986), amerykański piłkarz piłki nożnej</p>", "Allan Jay": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Allan</b>.</p><p>Harry Howard Barton Allan (27 kwietnia 1882 - 29 października 1957) - nowozelandski botanik.</p>", "Adrian-Paul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Austine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Austin</b>.</p><p>Austen (ang. Austin) - angielskojęzyczna nazwisko, toponim i nazwa.</p>", "Ariel Esteban": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ariel</b>.</p><b>Ariel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֲרִיאֵל&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> słów oznaczających „lew Boga”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> używane było jako alternatywna nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolima</a>.", "Adolfo David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adolfo</b>.</p><p>21°14′8′′N 49°38′38′′D Adolfo to miasto w São José do Rio Preto, w stanie São Paulo, Brazylia. Miasto zostało założone 30 listopada 1959 roku, ma ludność (w 2007 roku) 3609 osób, obszar 210,843 km2, density ludności 18,9 osób/km2.</p>", "Ariel Mauricio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ariel</b>.</p><b>Ariel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֲרִיאֵל&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> słów oznaczających „lew Boga”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> używane było jako alternatywna nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolima</a>.", "Abdi̇": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abd</b>.</p><b>Abd</b> albo <b>`Abd</b> – w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskich</a> imionach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskich</a> oznacza sługę. Występuje zawsze w połączeniu z jednym z <a href=\"https://pl.wikipedia.org/wiki/99_atrybut%C3%B3w_Allaha\" target=\"_blank\" rel=\"noopener noreferrer\">99 imion Boga</a>.Np.: <a href=\"https://pl.wikipedia.org/wiki/Abdallah\" target=\"_blank\" rel=\"noopener noreferrer\">Abdallah</a> – Sługa Allaha, Abd al-Aziz – Sługa Wszechmocnego, … .„Abd” używane było w imionach również w <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCahilijja\" target=\"_blank\" rel=\"noopener noreferrer\">czasach przedislamskich</a> jak np. w imieniu prapradziada <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a> <i>Abd <a href=\"https://pl.wikipedia.org/wiki/Manaf\" target=\"_blank\" rel=\"noopener noreferrer\">Manaf</a></i>.", "Allex": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Alexandru-Mihail": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Ala-Eddine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ala</b>.</p><p>Alanin (2-aminopropanowy kwas) - aminokwas alifatyczny. α-alanina jest częścią wielu białek, β-alanina - w szeregu związków biologicznie aktywnych.</p>", "Ahmad Fawad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmad</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Amalric": "<p>Amalryczny lub amalaricki (także Americ, Almerich, Emerich, Emeric, Emerick, Emerik i inne warianty) to imię osobiste pochodzące od plemienia Amal (w odniesieniu do gotickich Amali) i ric (gotic reiks) oznaczające \"władca, książę\". Równoważne w różnych językach obejmują: francuski: Amaury (nazwa/nazwa dana), Amalric (nazwa), Amaurich (nazwa) niemiecki: Amalrich, Emmerich włoski: Amerigo, Arrigo Węgierskie: Imre Latin:...</p>", "Arun Antony": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arun</b>.</p><p>Arun (Mongolski: ⁇ ⁇ Arun qosiɣu, Kirin Mongoli: Арун хошуу; przenoszone: 阿荣旗; subtyp: 阿榮旗; przenośne: Āróng Qí, Hán Việt: A Vinh kỳ) jest okresem urzędu miasta Hulunbuir (Holun Luan Uy), Autonomicznego Obszaru Mongolicznego, Chiny. Miasto graniczy z prowincją Hắc Long Giang na wschodzie i południu i znajduje się 92 km (57 mi) na północno-zachodni od miasta Tề Tề Cápur w prowincji Hắc Long.</p>", "Adao": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ada</b>.</p><b>Ada</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/Kobieta\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> znaczy: upiększać się, stroić się. Imię Ada jest wymieniane w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> w pierwszej księdze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, gdzie jest jedną z żon Lemecha i matką Jubala. W Biblii jest także mowa o Adzie, matce flecistów i grających na harfie (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Rdz.</a> 4, 21).", "Anderson Julian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Anh Phương": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Alex Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Adam Roman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Abdul Gaffar": "<p>'Abd al-Ghaffār (ALA-LC) to męskie muzułmańskie imię i nazwisko, a w nowoczesnym użyciu nazwisko, zbudowane z arabskich słów 'abd i al-Ghoffār, jednego z imion Boga w Koranie, które dają początek muzułmanskim nazwom teoforycznym. Może odnosić się do:</p>", "Alin-Constantin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Alexander Stefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexander</b>.</p><p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Abdelnour": "<p>'Abd al-Nūr (ALA-LC) to męskie imię i nazwisko. Nazwa ta jest używana przez muzułmanów, a także przez koptyjskich i prawosławnych chrześcijan na Bliskim Wschodzie.</p>", "Andres De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Abdul-Halim": "<p>'Abd al-Ḥalīm (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów ʿabd i al-Ḥalīm, jednego z imion Boga w Koranie, co daje początek muzułmańskich nazw teoforycznych.</p>", "Aliona": "<p>Aliona alena (lat. Aliona alena) - rodzaj motyle-sąków, jedyny w składzie gatunku Aliona z podrodzinnego lęków ziemnych (Noctuinae). Chiny.</p>", "Amir Mohammad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amir</b>.</p><b>Amir</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أمير&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „książę” lub „dowódca”.", "Abdel Aziz": "<p>Abd al-Aziz (arabski: عبد العزيز, DMG: ʽAbd al-ʽAzīz), często również przetransliterowany jako Abdul Aziz, to arabskie muzułmańskie imię i nazwisko mężczyzny i, w nowoczesnym użyciu, nazwisko. Zostało zbudowane z słów ʽAbd, arabski artykuł określony i ʽAzīz \"Wszechmogący\".</p>", "Anh Ɖức": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Afaq": "<p>Afaq to męskie imię pochodzenia arabskiego. Znani ludzie z nazwiskiem to: Afaq Ahmed (ur. 1962), pakistański polityk Afaq Hussain (1939-2002), pakistański kryketar Afaq Khoja (1626-1694), uighurski przywódca polityczny i religijny Afaq Raheem (ur. 1985), pakistański kryketar</p>", "Aurele": "<p>Aurèle to imię. Do wybitnych osób z nazwą należą: Aurèle Audet (1920-2015), członek Zgromadzenia Narodowego Quebec Aurèle Cardinal, architekt Quebec, urbanista i akademik Aurèle Chartrand (1903-1975), Ontario barrister i polityczna postać Aurèle Gervais (1933-2021), kanadyjska polityka Aurèle Joliat (1901-1986), kanadyjski profesjonalny hokej na lodzie lewicowy Aurèle Lacombe (1887-1963), członek National Assembly of...</p>", "Abdus-Sobur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdus</b>.</p><p>Abdul (tzw. Abd, Abdel, Abdil, Abdol, Abdool lub Abdoul) jest najczęstszą transliteracją połączenia arabskiego słowa Abd (عبد, oznaczające \"Służebnik\") i prefiksu al / el (ال, oznaczający \"The\"). Jest to początkowy składnik wielu nazw związanych, takich jak Abd الحميد ʿAbd al-Ḥamīd (zwykle pisane Abdel Hamid, Abdelhamid, Abd El Hamid lub Abdul Hamid; lit.</p>", "Alexander Leon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexander</b>.</p><p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Alekssandro": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksandro</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Akhmedi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akhmed</b>.</p><p>Ahmad (arabski: أحمد, romanized: ʾAḥmad) jest arabską nazwą męską powszechną w większości części świata muzułmańskiego, ponieważ jest to jedno z dobrze znanych imion proroka Muhammada. Inne angielskie pisowni nazwy obejmują Ahmed, Ahmmad.</p>", "Adrian-Moise": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Andrée": "<p>Andree lub Andrée może odnosić się do: Andree Right Hand, wietnamskiego rapera i muzyka 1296 Andrée, asteroida</p>", "Anil Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anil</b>.</p><p>Anil to rodzaj roślin kwiatowych z rodziny Białego.</p>", "Abimbola": "<p>Abimbola jest zarówno nazwiskiem jorubańskim, jak i unisexnym nazwiskiem, co oznacza \"urodzony z bogactwem\".</p>", "Alexander Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexander</b>.</p><p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Abdulhakeem": "<p>Abdul Hakim (arabski: عبد الحكيم, romanized: ʻAbd al-Ḥakīm) to muzułmańskie imię męskie, a w nowoczesnym użyciu, imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Hakim.</p>", "Ahmad Ali Ahmad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmad</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Aliyaan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aliyan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alian</b>.</p>Populacja dzielnicy Alian w 2016 roku liczyła 29&#160;093 mieszkańców – 14&#160;407 kobiet i 14&#160;686 mężczyzn. Liczba gospodarstw domowych wynosiła 9407, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,09 osób.", "Aryaan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aryan</b>.</p><p>\"Arya\" (i jego odmiany) to słowo oznaczające \"rod\" (boże święte) które kiedyś było używane jako samozwa indyjsko-iranijskich narodów. Słowo to zostało użyte przez lud Indy-Arya od czasów wedyjskich w Indiach jako nazwisko dla siebie, a także do osób należących do szlachty i geologicznych regionów Āryāvarta, w których pochodzą indy-Aryanskiej kultury.</p>", "Abdul Samad": "<p>Abdul Samad Abdul Samed, itp. Można go przenieść na \"sługa samostanowionego Mistrza\" lub \"sługowiec Wiecznego Schronienia\".</p>", "Andres Francisco": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Abdirashid": "<p>'Abd al-Rashīd (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów ʿabd i al-Rashīd, jednego z nazw Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Anderson Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Amílcar": "<p>Amílcar to hiszpańskie i portugalskie imię pochodzące od łacińskiego Hamilcar, samo w sobie imię puniczne znane Rzymianom poprzez ich kartaginjskich wrogów, zwłaszcza Hamilcar Barca. Wśród znanych osób z imieniem Amílcar to: Amílcar Álvarez, argentyński pływacz Amílcar Barbuy, brazylijczy piłkarz Amílcar Cabral, polityk z Bizsywy-Gwinie/Kap Verde Amílcar de Castro, brazylijski rzeźbiarz i graficzny Amílcar Fonseca, portugalczy...</p>", "Ali̇ Mert": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Abed El Rahman": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abed</b>.</p><p>Abid (arabski: عابد 'Ābid), również Abed, dosłownie oznacza czciciel, czciciel i pobożny, to arabska nazwa. Może to być nazwisko lub imię.</p>", "Andres Manuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Alli": "<p>Alli to nazwisko i unisex. Do wybitnych osób z tym nazwiskiem należą:</p>", "Abdelghany": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdelghani</b>.</p><p>Abdul Ghani (arabsko: عبد الغني) lub Abdulghani lub Abdelghani lub podobne warianty to męskie muzułmańskie nazwisko i w współczesnym użyciu nazwisko. Został zbudowany z arabskich słów Abd, al- i Ghani.</p>", "Aaron Steven": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aaron</b>.</p><b>Aaron</b>, <b>Aron</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> Aharon <b>אַהֲרֹן</b> – możliwa <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologia</a> <i>oświecony</i>, <i>wywyższony</i>, być może imię pochodzenia egipskiego) – <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijne</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Nosił je starszy brat i pomocnik <a href=\"https://pl.wikipedia.org/wiki/Moj%C5%BCesz\" target=\"_blank\" rel=\"noopener noreferrer\">Mojżesza</a> i <a href=\"https://pl.wikipedia.org/wiki/Miriam_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Miriam</a> (<i>zobacz <a href=\"https://pl.wikipedia.org/wiki/Aaron_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Aaron (postać biblijna)</a>).</i> Wśród świętych – m.in. św. Aaron, męczennik (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Ali Asghar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Aimane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aiman</b>.</p><p>Aiman (arabski: أيمن) to neutralna nazwa płci z pochodzenia w języku arabskim, urdu i kazacku. Jest to alternatywne alfabet latynski śpiewki imienia Ayman.</p>", "Amarjeet Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amarjeet</b>.</p><p>Amarjit lub Amarjeet to indyjskie imię, które oznacza \"wieczny triumf\". Wśród znanych osób z nazwiskiem to: Amarjit Singh Bal (1940-2010), oficer Indii Armia Amarjeet Singh Bedi (fl.</p>", "Armany": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Armani</b>.</p><p>Giorgio Armani S.p. A. - włoska firma specjalizująca się w produkcji i handlu odzieżą i różnymi akcesoriami.</p>", "Antoni Ryszard": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Arun Prasath": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arun</b>.</p><p>Arun (Mongolski: ⁇ ⁇ Arun qosiɣu, Kirin Mongoli: Арун хошуу; przenoszone: 阿荣旗; subtyp: 阿榮旗; przenośne: Āróng Qí, Hán Việt: A Vinh kỳ) jest okresem urzędu miasta Hulunbuir (Holun Luan Uy), Autonomicznego Obszaru Mongolicznego, Chiny. Miasto graniczy z prowincją Hắc Long Giang na wschodzie i południu i znajduje się 92 km (57 mi) na północno-zachodni od miasta Tề Tề Cápur w prowincji Hắc Long.</p>", "Absalon": "<b>Absalon</b>, <b>Absalom</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się z hebrajskiego <i>Abishalom</i> oznaczającego „Ojciec [Bóg] jest pokojem”. Formą przyjętą w Polsce jest <b>Absalon</b>. Skandynawską formą tego imienia jest <b>Axel</b>.", "Aliyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alian</b>.</p>Populacja dzielnicy Alian w 2016 roku liczyła 29&#160;093 mieszkańców – 14&#160;407 kobiet i 14&#160;686 mężczyzn. Liczba gospodarstw domowych wynosiła 9407, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,09 osób.", "André Marc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>André</b>.</p><p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Anoop Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anoop</b>.</p><p>Anup (sanskrit: अनुप anūpa) to indyjskie imię męskie. Sanskritskie słowo anūpa ma następujące znaczenia: \"wodna\", \"położona w pobliżu wody\", \"brzeg rzeki\", \"zbiornik\", \"lagona\".</p>", "Admin": "<b>Administrator systemów komputerowych</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>administrator</em> „zarządca”), żargonowo <b>sysadmin</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>system administrator</em>) – <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatyk</a> zajmujący się zarządzaniem <a href=\"https://pl.wikipedia.org/wiki/System_informatyczny\" target=\"_blank\" rel=\"noopener noreferrer\">systemem informatycznym</a> i odpowiadający za jego sprawne działanie.", "Artha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arta</b>.</p><p>Arta (Greek: ?) jest samodzielnym terytorium w Grecji. Autonomiczna dzielnica Arta ma powierzchnię 457 km2, populacja według badania z 18 marca 2001 roku wynosi 44136 osób.</p>", "Abdullah Mohammed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdullah</b>.</p><b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Alex-Ştefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Adrian-Cosmin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Al Din": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Al</b>.</p><p>Aluminium (chymiczny symbol - Al, od łacińskiego Aluminium), wcześniej również gliny (od rosyjskiego.</p>", "Antton": "<p>Antton to imię i pseudonim. Do znanych osób z tym nazwiskiem należą: Antton Luengo (ur. 1981), baskijski rowerzyst Antton, pseudonim Antony Lant lub Anthony Lant, angielski perkusista</p>", "Ahmed Awad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "André Jean": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>André</b>.</p><p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Alexandru-Gheorghe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Amat": "<b>Amat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od łacińskiej nazwy rodowej (<i>Amatus</i>), która z kolei dosłownie oznacza \"ukochany, drogi, kochany\".", "April": "<p>April (kr. 에이프릴; często stylizowana jako APRIL, wymawia się jako April (April) - południowo koreańska dziewczęta-grupa, utworzona w 2015 roku przez DSP Media. Składa się z sześciu uczestników: Čekyon, Čevon, Naын, Jena, Rachel i Jinsol.</p>", "Alin-Vasile": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Aang": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ang</b>.</p>W Wielkiej Brytanii i Australii angielski jest <i>de facto</i> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urz%C4%99dowy\" target=\"_blank\" rel=\"noopener noreferrer\">językiem urzędowym</a>, choć formalnie państwa te nie objęły takim statusem żadnego języka. Angielszczyzna należy do oficjalnych języków <a href=\"https://pl.wikipedia.org/wiki/Organizacja_Narod%C3%B3w_Zjednoczonych\" target=\"_blank\" rel=\"noopener noreferrer\">ONZ</a>, a od XX wieku jest najczęściej używanym językiem w kontaktach międzynarodowych. Bywa określana jako pierwszy uniwersalny nowożytny język ludzkości. Stanowi główny język nauki, handlu i polityki, a w niektórych krajach także kształcenia wyższego.", "Alin-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Afro": "<b>Afro</b> – <a href=\"https://pl.wikipedia.org/wiki/Fryzura\" target=\"_blank\" rel=\"noopener noreferrer\">sposób ułożenia włosów</a>. Są to włosy kręcone, ułożone stercząco – te z brzegu na boki, pośrodku ku górze tak, aby fryzura tworzyła kształt kuli. Nazwa pochodzi od amerykańskiego wyrażenia „Afro-Americans”, odnoszącego się do czarnoskórych Amerykanów.", "Alexandru-Florinel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Argjend": "<p>Argjend lub Argjent to kosowsko-albanska męska nazwa, która może odnosić się do Argjenda Beqiri (ur. 1974), makedonii piłkarz i menedżer etnicznej etniki Albanii Argjent Halili (ur. 1982), albanian piłkarza Argjenda Malaj (ur. 1994), kosowsko - albanian piłki nożnej półfałowca Argjend Mustafa (ur. 1992), kosowskiego - albanianki półfałownik piłki noży Argjend Mustafa (urek, ur. 1993), kosowski - albaniancki piłkarze</p>", "Antoine Hubert": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoine</b>.</p><p>Franz Antoine (niem. Franz Antoine, 23 lutego 1815 - 11 marca 1886) - austriacki botanik, artysta i fotograf.</p>", "Ali Onur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Allan Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Allan</b>.</p><p>Harry Howard Barton Allan (27 kwietnia 1882 - 29 października 1957) - nowozelandski botanik.</p>", "Aditia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aditi</b>.</p>W <i>Bryhadajranjakopaniszad</i> (1.2.5) określenie dla oznaczenia <a href=\"https://pl.wikipedia.org/wiki/Absolut\" target=\"_blank\" rel=\"noopener noreferrer\">bytu absolutnego</a>.", "Andre Leon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>André</b>.</p><p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Awwad": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Awad</b>.</p><p>Awad lub Aouad lub Awwad (arabski: عوض lub czasami عوّاد) to arabskie imię i nazwisko. Do osób z tym nazwiskiem należą:</p>", "Ashok Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ashok</b>.</p><p>Ashok to imię. Może odnosić się do:</p>", "Adrian-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Ali̇ Eren": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Anh Tài": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Albert Henri": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Albert</b>.</p><b>Albert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających <i>adal</i> (ród szlachecki) i <i>beraht</i> (jasny, błyszczący), oznaczało „pochodzącego ze szlachetnego rodu”. Jest zredukowaną formą staroniemieckiego imienia <i>Athalbraht</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbert</a>). Alternatywną wersją Alberta jest <i><b>Olbracht</b></i> – por. <a href=\"https://pl.wikipedia.org/wiki/Jan_I_Olbracht\" target=\"_blank\" rel=\"noopener noreferrer\">Jan I Olbracht</a>, król Polski.", "Ahmed Mohamed Fathi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Abby": "<p>David Aebischer (niem. David Aebisher; 7 lutego 1978, Friburg, Szwajcaria) - były szwajcarski hokejista, występujący w pozycji bramkarza.</p>", "Abdul-Salam": "<p>Abd al-Salam (arabski: عبد السلام) to męskie muzułmańskie imię honorowe lub nazwisko, oparte na arabskich słowach Abd, al- i Salam. Nazwa oznacza \"sługę Wszechświata\", a As-Salam jest jednym z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Alexandru-Sorin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Abdül": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdula</b>.</p><p>Abd Allah (arabsko: عبد الله, romanized: ʻAbd Allāh), również pisane Abdullah, Abdhullah, Abdellah, Abdollah, Abdallah, Abdulla, Abdalla i wiele innych, jest arabską nazwą teoforyczną oznaczającą sługę Boga lub \"szońca Boga\". Został zbudowany z arabskich słów ʿabd (عبد) i Allāh (Allah).</p>", "An Ninh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Arame": "O procesie powstawania Urartu zachowało się mało informacji. Pozostaje niejasnym, kto był następcą Arama: jego rywal <a href=\"https://pl.wikipedia.org/wiki/Lutipri\" target=\"_blank\" rel=\"noopener noreferrer\">Lutipri</a> czy syn Lutipriego – <a href=\"https://pl.wikipedia.org/wiki/Sarduri_I\" target=\"_blank\" rel=\"noopener noreferrer\">Sarduri I</a>. W połowie IX wieku p.n.e. na terenie niegdysiejszego Urartu trwał proces zjednoczenia plemion <a href=\"https://pl.wikipedia.org/wiki/Nairi\" target=\"_blank\" rel=\"noopener noreferrer\">Nairi</a> w jedno scentralizowane państwo. Prawdopodobnie Aramu i Lutipri stali na czele dwóch różnych plemion. Walkę o przejęcie władzy zwierzchniej wygrał ostatecznie Lutipri. Za czasów Arama stolicą Urartu było miasto Arzaszkun. Po jego zburzeniu przez <a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">Asyryjczyków</a>, już za panowania Sarduriego I, stolica została przeniesiona do <a href=\"https://pl.wikipedia.org/wiki/Tuszpa\" target=\"_blank\" rel=\"noopener noreferrer\">Tuszpy</a>.", "Andrḗs": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andresa</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Ayala": "<p>Ayala, Ayala (hisz. Ayala) - własna nazwa; rozpowszechniona w postaci nazwisk i toponimów.</p>", "Alexe": "<p>Alexe to rumuńskie imię i nazwisko, które mogą odnosić się do:</p>", "Abdul Kadir": "<p>Abd al-Qadir lub Abdulkadir (arabsko: عبد القادر) to męskie muzułmańskie imię. Utworzona jest z arabskich słów Abd, al- i Qadir.</p>", "Abd Errahmane": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abd</b>.</p><b>Abd</b> albo <b>`Abd</b> – w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskich</a> imionach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskich</a> oznacza sługę. Występuje zawsze w połączeniu z jednym z <a href=\"https://pl.wikipedia.org/wiki/99_atrybut%C3%B3w_Allaha\" target=\"_blank\" rel=\"noopener noreferrer\">99 imion Boga</a>.Np.: <a href=\"https://pl.wikipedia.org/wiki/Abdallah\" target=\"_blank\" rel=\"noopener noreferrer\">Abdallah</a> – Sługa Allaha, Abd al-Aziz – Sługa Wszechmocnego, … .„Abd” używane było w imionach również w <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCahilijja\" target=\"_blank\" rel=\"noopener noreferrer\">czasach przedislamskich</a> jak np. w imieniu prapradziada <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a> <i>Abd <a href=\"https://pl.wikipedia.org/wiki/Manaf\" target=\"_blank\" rel=\"noopener noreferrer\">Manaf</a></i>.", "Arjun Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arjun</b>.</p><b>Arjun</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskr.</a> <i>अर्जुन</i>) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjski</a> <a href=\"https://pl.wikipedia.org/wiki/Czo%C5%82g_podstawowy\" target=\"_blank\" rel=\"noopener noreferrer\">czołg podstawowy</a>, produkowany od 2004 roku, w <a href=\"https://pl.wikipedia.org/wiki/Armia_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">armii indyjskiej</a> od 2007 roku. Nazwa czołgu pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Ard%C5%BAuna\" target=\"_blank\" rel=\"noopener noreferrer\">Ardźuna</a> - jednego z bohaterów <a href=\"https://pl.wikipedia.org/wiki/Epos\" target=\"_blank\" rel=\"noopener noreferrer\">eposu</a> <i><a href=\"https://pl.wikipedia.org/wiki/Mahabharata\" target=\"_blank\" rel=\"noopener noreferrer\">Mahabharata</a></i>.", "Adelheid": "<p>Adelheid (niem. Adelheid; 977 - 14 stycznia 1044) - córka cesarza Świętej Imperium Rzymskiego Ottona II Rzeźnego i cesarzy Feofanos, od 999 do 1044 r. przewodniczyła opatstwu Kwedlinburg.</p>", "Anh Tai": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Abel Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abel</b>.</p><b>Abel</b> (hebr. הבל) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z hebrajskiego <i>abhal</i> – „mgła, dym, tchnienie”. Być może wiązało się jednak z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>aplu || ibil</i> lub asyryjskim <i>ahbla || ablu</i> – „syn rodzony”. Nosiła je <a href=\"https://pl.wikipedia.org/wiki/Kain_i_Abel\" target=\"_blank\" rel=\"noopener noreferrer\">postać biblijna</a>, syn Adama i Ewy, który był pasterzem. Abel został zamordowany przez swego brata Kaina, rolnika. Imię to było notowane na terenie Polski już w średniowieczu, na przełomie <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIV wieku</a>, początkowo jako imię zakonne. Patronem tego imienia w Kościele katolickim są, obok Abla, syna Adama i Ewy, m.in. Abel, biskup Metzu, i <a href=\"https://pl.wikipedia.org/wiki/Abel_z_Reims\" target=\"_blank\" rel=\"noopener noreferrer\">Abel</a>, arcybiskup Reims.", "Ali̇ Kemal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Amir Khossein": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amir</b>.</p><b>Amir</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أمير&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „książę” lub „dowódca”.", "Alysher": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alisher</b>.</p><p>Alisher to drugi mini album Morgenschtern, wydany 14 lutego 2025 roku. W mini-albumie weszło 5 utworów o łącznej długości 12 minut 54 sekund.</p>", "Abdurashyd": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdurashid</b>.</p><p>'Abd al-Rashīd (ALA-LC) to męskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów ʿabd i al-Rashīd, jednego z nazw Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Arved": "<p>Arved to męskie imię. Wśród znanych osób z nazwiskiem: Arved Birnbaum (ur. 1962), niemiecki aktor Arved Crüger (1911-1942), niemiecka wojenna wojska Luftwaffe Arved Deringer (1913-2011), niemiecki prawnik i polityk Arved Fuchs (ur. 1953), niemieckiej badacz polarnej i pisarz Arved Heinrichsen (znany również jako Arvydas Hainričsenas; 1879-1900), niemiecko-litwalski mistrz szachów Arved-Ervin Sapar (1933-2021), estyjski teoretyczny...</p>", "Alexis De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexis</b>.</p><p>Alexis może wskazywać: Alexis de Tocqueville Jacques-Édouard Alexis</p>", "Angelino": "<p>Angelino to męskie imię: Angelino Alfano (ur. 1970), włoski polityk Angelino Apelar (1927-2006), ewangeliczny chrześcijański przywódca Angelino Dulcert (ur. 1339), włosko-majorkański kartograf Angelino Fons (1936-2011), hiszpański reżyser i scenarzysta Angelino Garzón (ur. 1946), były wiceprezes Kolumbii Angelino Medoro (1567-1631), włoska malarz, aktywna w Ameryce Łacińskiej Angelino Rosa (1948-2009), włoska...</p>", "Anh Tân": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Aliaxandr": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aliaksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Abraham Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abraham</b>.</p><p>Abraham (Abraham) - męskie imię, niemieckie lub angielskie nazwisko, a także toponim. W starych źródłach przekazywano ją jako Abraham.</p>", "Adri̇an": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adryan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Abdul Jaleel": "<p>'Abd al-Jalīl (ALA-LC) to muzułmańskie imię męskie, używane również przez chrześcijan, a w współczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Jalil, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Andrzej Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Alan David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alan</b>.</p><b>Alan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia najprawdopodobniej <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Może też wywodzić się od nazwy irańskiego plemienia <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alanów</a>. Znaczenie tego imienia nie jest dokładnie znane, prawdopodobne znaczenia:", "Alin-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Ali Mahmood": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Antoi̇ne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Antoin</b>.</p><p>Antoin jest irlandzką nazwą męską, pochodzącą od Antoniusa, która jest powszechnie używana w Irlandii. W irlandzkim (Gaeilge) jest przetłumaczana jako Antóin.</p>", "An Nam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Ajaks": "<b>Ajaks</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, które może wywodzić się od słowa oznaczającego „ruch, poruszenie, życie” albo „kraj, kraina”, a być może stanowi skrócenie z imienia <i>Filajas</i>. Imię to nosiły dwie postaci <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiej mitologii</a>. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> jest nadawane od średniowiecza.", "Abdülhamid": "<p>'Abd al-Ḥamīd (ALA-LC romanizacja arabskiej: عبد الحميد; perskiego: عبدالحمید, romanized: Abdolhamid; tureckiego: Abdülhamit), również pisowniony jako Abdulhamid, Abdelhamid, Abd-ul Hamid i Abd ol-Hamid, jest muzułmańskie męskie imię i nazwisko. Jest to muzułmańska nazwa teoforyczna zbudowana z arabskich słów 'abd ('sługa') i al-Ḥamīd (jedno z nazw Boga w Koranie), a zatem oznacza 'sługa Wszechchchch chwalnego'.</p>", "Alexandru-Nicolae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Almeida": "Nazwa miejscowości wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> <i>al-Ma’ida</i>, co oznacza „stół”. Odnosi się to do płaskiego ukształtowania terenu otaczającego miejscowość.", "Andrea Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Arsłan": "<b>Arsłan</b> – <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">polski</a> <a href=\"https://pl.wikipedia.org/wiki/Herb_szlachecki\" target=\"_blank\" rel=\"noopener noreferrer\">herb szlachecki</a> używany przez rodzinę <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%85%C5%BC%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">książęcą</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Tatarzy\" target=\"_blank\" rel=\"noopener noreferrer\">tatarskiego</a>.", "Alexandru-Radu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Abdesslam": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdeslam</b>.</p><p>Abd al-Salam (arabski: عبد السلام) to męskie muzułmańskie imię honorowe lub nazwisko, oparte na arabskich słowach Abd, al- i Salam. Nazwa oznacza \"sługę Wszechświata\", a As-Salam jest jednym z imion Boga w Koranie, które powodują muzułmańskie nazwy teoforyczne.</p>", "Alin-Claudiu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Anh Tung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Aleksander Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aleksander</b>.</p><b>Aleksander</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἀλέξανδρος, <i>aleksandros</i> – obrońca ludzi) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> składające się z dwóch członów: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;αλέξειν (bronić, wspomagać) i ἀνδρός (od ἀνήρ – mąż, mężczyzna). Całość bywa interpretowana jako „broniący mężów, troszczący się o mężów, opiekujący się mężami”.", "Anastasia": "<b>Anastazja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anastazy\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazy</a>. Oznacza „zmartwychwstała, wskrzeszona”.", "Abdul Vahid": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdul Wahid</b>.</p><p>ʽAbd al-Wāḥid (ALA-LC) to męskie muzułmańskie imię i nazwisko. Została zbudowana z arabskich słów ʽabd, co oznacza podległy, i al-Wāḥid, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Anthony Francis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anthony</b>.</p><p>Anthony może odnosić się do: Anthony Hopkins Anthony Giddens Anthony van Dyck</p>", "Aatif": "<p>Atif (zwany również Atef lub Atiph, arabski: عاطف) jest arabskim męskim imieniem, które jest używane w świecie muzułmańskim, oznacza \"dobry\".</p>", "Adad": "<b>Adad</b> – bóg burzy, wiatru, deszczu i piorunów oraz siły niszczycielskiej, jedno z ważniejszych bóstw w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_babilo%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii babilońskiej</a>. Geneza Adada sięga okresu <a href=\"https://pl.wikipedia.org/wiki/Sumer\" target=\"_blank\" rel=\"noopener noreferrer\">sumeryjskiego</a>. Był on utożsamiany z pomniejszym bóstwem w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_sumeryjska\" target=\"_blank\" rel=\"noopener noreferrer\">panteonie sumeryjskim</a> – <a href=\"https://pl.wikipedia.org/wiki/Iszkur\" target=\"_blank\" rel=\"noopener noreferrer\">Iszkurem</a>, którego cechy rozwinęły się w okresie <a href=\"https://pl.wikipedia.org/wiki/Babilonia\" target=\"_blank\" rel=\"noopener noreferrer\">babilońskim</a>, a następnie <a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">asyryjskim</a>, gdy Adadowi przypisano atrybuty i cechy wojskowe. O randze Adada świadczy włączanie jego imienia do imion królów.", "André Maurice": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>André</b>.</p><p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Abdulmecit": "<p>'Abd al-Majīd (ALA-LC romanizacja arabskiego: عبد المجيد, perskiego: عبدالمجید), również pisowany jako Abd ul Majid, Abd ul-Majid, Abd ol Majid, Abdul ol-Majed i Abdolmajid, jest muzułmańskie męskie imię i nazwisko. Jest to połączenie arabskich słów 'abd i al-Majīd, jednego z nazw Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Ain": "<p>Ain jest prowincją we Francji. Prowincja jest nazwana po rzeki Ain na wschodnim krańcu Francji.</p>", "Antoni Franciszek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Anastasiya": "<p>Anastasiya to kobiece imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Ali̇ Kaan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Ahmad Fauzi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmad</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Aadesh": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adesh</b>.</p><p>Adesh to męskie imię. Znani ludzie z nazwiskiem to: Adesh Kanwarjit Singh Brar (1949-2012), indyjski polityk i rolnik Adesh Chauhan, indyjski politik Adesh Gupta (ur. 1969), indyjski politika Adesh Pratap Singh Kairon, indycki polityk Adesh Samaroo, trynadytowy i tobago muzyk Aadesh Shrivastava (1964-2015), indyjski kompozytor</p>", "Anil Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anil</b>.</p><p>Anil to rodzaj roślin kwiatowych z rodziny Białego.</p>", "Ali D": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Andres Leonel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Anry": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anri</b>.</p><p>Anri (jap. 川島 栄子 Kawasima Эйко, 31 sierpnia 1961) - japońska piosenkarka i autorka piosenek.</p>", "Aleksander Piotr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aleksander</b>.</p><b>Aleksander</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἀλέξανδρος, <i>aleksandros</i> – obrońca ludzi) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> składające się z dwóch członów: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;αλέξειν (bronić, wspomagać) i ἀνδρός (od ἀνήρ – mąż, mężczyzna). Całość bywa interpretowana jako „broniący mężów, troszczący się o mężów, opiekujący się mężami”.", "Abdullah I": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdullah</b>.</p><b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Angel Alfonso": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Anuoluwapo": "<p>Anuoluwapo to nigerijskie imię. Jest to imię unisex i pochodzące z języka jorubskiego, co oznacza \"Miłosierdzie Boże jest obfito\".</p>", "Adam Władysław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Alain Joseph": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alain</b>.</p><p>Alain - rządca Harmoran w latach 1268-1290 z rodu Macруаiri.</p>", "Alaeddin": "<p>Aladdin (arabski: علاء الدين, powszechnie 'Alāʼ ud-Dīn/ 'Alā' ad-Dīn) (różne pisownię i transliteracje) jest imieniem męskim, co oznacza \"szlachetność wiary\" lub \"szlachety wiary/religii\". Jest to jedna z dużych klas nazw kończących się na ad-Din.</p>", "Alon-Yosef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alon</b>.</p><p>ALON (Alon Valerievich Mullayev; ur. 16 lipca 1995, Netania, Izrael) - rosyjski muzykiem, piosenkarzem, artystą, autorem piosenek.</p>", "Alin-Bogdan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Ahmed Ahmed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Adam Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Artur-Vasyl": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Artur</b>.</p><b>Artur</b> wymowa – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Powstało ze złożenia dwóch wyrazów wywodzących się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">języków celtyckich</a>: <i>Art</i> – niedźwiedź, <i>ur</i> – młody, piękny, kwitnący. Podstawę imienia może także stanowić celtyckie słowo ard – wysoki, szlachetny.", "Abd El Karim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abd</b>.</p><b>Abd</b> albo <b>`Abd</b> – w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskich</a> imionach <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskich</a> oznacza sługę. Występuje zawsze w połączeniu z jednym z <a href=\"https://pl.wikipedia.org/wiki/99_atrybut%C3%B3w_Allaha\" target=\"_blank\" rel=\"noopener noreferrer\">99 imion Boga</a>.Np.: <a href=\"https://pl.wikipedia.org/wiki/Abdallah\" target=\"_blank\" rel=\"noopener noreferrer\">Abdallah</a> – Sługa Allaha, Abd al-Aziz – Sługa Wszechmocnego, … .„Abd” używane było w imionach również w <a href=\"https://pl.wikipedia.org/wiki/D%C5%BCahilijja\" target=\"_blank\" rel=\"noopener noreferrer\">czasach przedislamskich</a> jak np. w imieniu prapradziada <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a> <i>Abd <a href=\"https://pl.wikipedia.org/wiki/Manaf\" target=\"_blank\" rel=\"noopener noreferrer\">Manaf</a></i>.", "Azziz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aziz</b>.</p><p>Aziz-bi (Azyzkul, Mirza Aziz) (z uzb. Aziz roku, Emirat Bucharsk - 1860, Emirat Bocharsk) - polityk i wojskowy, dyplomat, główny zakjatczy - minister finansów, kuszbeg - premier minister (1837-1860) Emiratu Bucharskiego.</p>", "Artemyi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Artemy</b>.</p><p>Artemy (rosyjski: Артемий), czasami romanizowany jako Artemiy, Artemi, lub Artemij, jest pełną unikalną formą rosyjskiego krótkiego męskiego Artyoma.</p>", "An Khang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Ahmed Abdo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Ahmmed": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Abdelhamid Mohamed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdelhamid</b>.</p><p>'Abd al-Ḥamīd (ALA-LC romanizacja arabskiej: عبد الحميد; perskiego: عبدالحمید, romanized: Abdolhamid; tureckiego: Abdülhamit), również pisowniony jako Abdulhamid, Abdelhamid, Abd-ul Hamid i Abd ol-Hamid, jest muzułmańskie męskie imię i nazwisko. Jest to muzułmańska nazwa teoforyczna zbudowana z arabskich słów 'abd ('sługa') i al-Ḥamīd (jedno z nazw Boga w Koranie), a zatem oznacza 'sługa Wszechchchch chwalnego'.</p>", "Arras": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aras</b>.</p><p>Oddział antyterrorystycznych operacji Aras (Orёл) Departamentu Policji Litwy (lit. Lietuvos policijos antiteroristinių operacijų rinktinė ⁇ Aras\") - oddzielne specjalne oddział anty-terrorystyczne policji Litwy.</p>", "Andrzej Ignacy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Artur-Mykola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Artur</b>.</p><b>Artur</b> wymowa – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Powstało ze złożenia dwóch wyrazów wywodzących się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">języków celtyckich</a>: <i>Art</i> – niedźwiedź, <i>ur</i> – młody, piękny, kwitnący. Podstawę imienia może także stanowić celtyckie słowo ard – wysoki, szlachetny.", "Albert Jerzy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Albert</b>.</p><b>Albert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających <i>adal</i> (ród szlachecki) i <i>beraht</i> (jasny, błyszczący), oznaczało „pochodzącego ze szlachetnego rodu”. Jest zredukowaną formą staroniemieckiego imienia <i>Athalbraht</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbert</a>). Alternatywną wersją Alberta jest <i><b>Olbracht</b></i> – por. <a href=\"https://pl.wikipedia.org/wiki/Jan_I_Olbracht\" target=\"_blank\" rel=\"noopener noreferrer\">Jan I Olbracht</a>, król Polski.", "Adam Frank": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Alex Samuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Aytek": "<p>Aytek to tureckie imię męskie. Nazwa składa się z jednego słowa i sufiksu: Ay i -tek.</p>", "Amarjit Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amarjit</b>.</p><p>Amarjit lub Amarjeet to indyjskie imię, które oznacza \"wieczny triumf\". Wśród znanych osób z nazwiskiem to: Amarjit Singh Bal (1940-2010), oficer Indii Armia Amarjeet Singh Bedi (fl.</p>", "Addeen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aden</b>.</p><p>Aden jest portem i tymczasowym stolicą Jemenu, położonym na brzegu wschodniego wejścia do Morza Czerwonego (Głębia Aden), około 170 km (110 mi) na wschód od szczeliny Bab-el-Mandeb. Miasto liczy około 800 000 mieszkańców.</p>", "Abdulaziz A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdulaziz</b>.</p><p>Abdulaziz (Turk. Abdül'l Azīz, Tur. I. Abdülaziz; 82/1830 - 4 czerwca 1876) był 32. sultanem Cesarstwa Osmańskiego, rządził od 25 czerwca 1861 do 30 maja 1876.</p>", "Adarsha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adarsh</b>.</p><p>Adarsh (Devanagari: आदर्श ādarś) to indyjskie imię męskie oznaczające \"ideal\".</p>", "Angel Mauricio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Aric": "<p>Aric to męskie imię, które może odnosić się do: Aric Almirola (ur. 1984), amerykański profesjonalny kierowca wyścigowy Aric Anderson (ur. 1965), amerykańskiego byłego piłkarza Aric Hagberg, amerykańskiej matematyka i akademika Aric Nesbitt (ur. 1980), amerykańskiego polityka, członka Senatu Michigan Aric Putnam, amerykański polityk wybrany do Senatu Minnesoty w 2020 roku Aric Sigman, brytyjski psycholog</p>", "Anh Việt": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Andres Gerardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Allyn": "<p>Allyn to jednocześnie unisex i nazwisko. Znanymi osobami z nazwiska są: Leigh-Allyn Baker (ur. 1972), amerykańska aktorka, reżyserka i artysta głosowy Allyn L.</p>", "Alex-Iuliu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Adrian-Vasile": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "An Tuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Alvaro Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alvaro</b>.</p><b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Abdulghani": "<p>Abdul Ghani (arabsko: عبد الغني) lub Abdulghani lub Abdelghani lub podobne warianty to męskie muzułmańskie nazwisko i w współczesnym użyciu nazwisko. Został zbudowany z arabskich słów Abd, al- i Ghani.</p>", "Ariko": "<p>Ariko to japońskie nazwisko kobiece. Znani ludzie z nazwiska to: Ariko Inaoka (稲岡 亜里子; ur. 1975), japoński fotograf Ariko Iso (磯 有理子; ur., 1970), japoński trener piłki nożnej Fujiwara no Ariko (藤原 有子; 1207 - 1286), był żoną cesarza Japonii</p>", "Arystydes": "<b>Arystydes</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> Αριστειδης, co oznacza „najlepszy rodzaj”, stanowiąc złożenie członów αριστος (aristos) „najlepszy” i ειδος (eidos) - „rodzaj, gatunek”. <b>Arystydes</b> <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/31_sierpnia\" target=\"_blank\" rel=\"noopener noreferrer\">31 sierpnia</a>.", "Anil Antony": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anil</b>.</p><p>Anil to rodzaj roślin kwiatowych z rodziny Białego.</p>", "Ardiyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ardian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ardiana</b>.</p><p>Ardian to albanska nazwa. Chociaż podobna do Adrian, nazwy pochodzenia łacińskiego, albanska Ardian (Ardjan i Ardijan są innymi wariantami) jest pochodem Ardiaei, nazwy starożytnego lyryjskiego ludu.</p>", "André Jacques": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>André</b>.</p><p>Edwarda François André (francuski: Édouard François André)  Édouard François André lub fr.</p>", "Angel Yesid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Anh Kiet": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Aneirin": "<b>Aneirin</b> lub <b>Neirin</b> – wczesnośredniowieczny poeta pochodzenia brytońskiego (<a href=\"https://pl.wikipedia.org/wiki/Walia\" target=\"_blank\" rel=\"noopener noreferrer\">walijskiego</a>). Uważany za <a href=\"https://pl.wikipedia.org/wiki/Bard\" target=\"_blank\" rel=\"noopener noreferrer\">barda</a> lub poetę nadwornego w jednym z kumbryjskich królestw <i>Starej Północy</i> (Hen Ogledd), prawdopodobnie Gododin w <a href=\"https://pl.wikipedia.org/wiki/Edynburg\" target=\"_blank\" rel=\"noopener noreferrer\">Edynburgu</a>. Od XVII wieku jego imię często zapisywano błędnie jako <b>Aneurin</b>.", "Ahmad Fahim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmad</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Arsenii-Vasyl": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arsenii</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arseniusz</b>.</p><b>Arseniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa ἀρσεν (<i>arsen</i>) oznaczającego „męski”.", "Ahmed Hussein": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Anh Van": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Antoni Krzysztof": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Alenn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alen</b>.</p><p>Alen jest konkretną formą genu, która ma określone funkcje genetyczne. Jest to jeden z najważniejszych pojęć w genezie, który jest tłumaczony z angielskiego słowa \"allelu\".</p>", "Arshag": "<p>Arshak (lub w zachodniej armenii Arshag) (w perskim آرشاک) (w armenijskim Արշակ) jest perskim i armenijskim nazwiskiem.</p>", "Andrzej Jacek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Antoni Tomasz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Adolphus": "<p>Adolf (zwany również Adolph lub Adolphe, Adolfo, a kiedy latynistycznie Adolphus) jest nazwiskiem z niemieckiego pochodzenia. Nazwa jest związkiem pochodzącym z starożytnego wysokiego niemieckiego Atalwolfa (lub Hadulfa), składu atalu lub adalu, co oznacza \"szlachetny\" (lub miał (u) -, co oznacza \"bojo, walka\") i wilka.</p>", "Abdillahi": "<p>Abdullahi (zwany również Abdollahi i Abdillahi) to męskie imię i nazwisko, które jest również powszechne jako nazwisko. Jest to wariant arabskiego imienia Abdullah.</p>", "Ahmad Wali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmad</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Ayman Aly Sayed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ayman</b>.</p><b>Ayman</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> َأيْمَن) – arabskie imię męskie, oznaczające: błogosławiony, szczęśliwy. Bywa zapisywane także jako Ajman, Aiman, Aimen, Aymen.", "Adesh": "<p>Adesh to męskie imię. Znani ludzie z nazwiskiem to: Adesh Kanwarjit Singh Brar (1949-2012), indyjski polityk i rolnik Adesh Chauhan, indyjski politik Adesh Gupta (ur. 1969), indyjski politika Adesh Pratap Singh Kairon, indycki polityk Adesh Samaroo, trynadytowy i tobago muzyk Aadesh Shrivastava (1964-2015), indyjski kompozytor</p>", "Adai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ada</b>.</p><b>Ada</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/Kobieta\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> znaczy: upiększać się, stroić się. Imię Ada jest wymieniane w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> w pierwszej księdze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, gdzie jest jedną z żon Lemecha i matką Jubala. W Biblii jest także mowa o Adzie, matce flecistów i grających na harfie (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Rdz.</a> 4, 21).", "Alexander John": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexander</b>.</p><p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Antony De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antony</b>.</p><p>Antony może odnosić się do: Antony (nazwa), męskie imię</p>", "Adegboyega": "<p>Adegboyega to nigerijska nazwa i nazwisko pochodzenia joruba, stosowane głównie w południowo-zachodniej Nigerii. Łączy w sobie słowa joruba \"ade\" (co oznacza \"koronę\"), \"gbe\" (co znaczy \"noszenie\"), \"oye\" (co znaczy \"głóstwo\" lub \"honor\") i \"ga\" (co significa \"wysoka\" lub \"wysoka\").</p>", "Assen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asen</b>.</p><p>Arsen (starowsza nazwa: arsen, pochodząca od francuskiego arsenic), również napisany jako a-sen, arsen, kwas, to element chemiczny o znaku As i liczbie atomowej 33. Arsenik został po raz pierwszy opisany przez Albertus Magnus (Niemcy) w 1250 roku.</p>", "Asad Ullah": "<p>Asadullāh (arabski: أَسَدُ ٱلله), również napisany jako Asadollah, Assadullah lub Asad Ullah, to muzułmańskie imię maleńskie oznaczające Lew Allaha. Nazwa ta początkowo była używana do odniesienia się do najbliższych krewnych islamskiego proroka Muhammada, Hamzy ibn Abd al-Muttaliba i Ali ibn Abi Taliba.</p>", "Adrian-Constantin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Anando": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anand</b>.</p><p>Anand - indyjska nazwa, nazwisko i toponim: Viswanathan Anand (ur.</p>", "Alcayde": "<p>Qaid (arabsko: قَائِد qāʾid, \"komandor\"; z dużej liczby Qáadăta qāda, lub قُوَّاد quwwād), również pisowniony jako Quaid, kaid lub caïd, jest słowem oznaczającym \"komandora\" lub \"leader\". Był to tytuł w królestwie normandzkiej Sycylii, stosowany do palatin urzędników i członków kurii, zwykle do tych, którzy byli muzułmanami lub nawróconymi na islam.</p>", "Aijaz": "<p>Aijaz to nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Angelina": "<b>Angelina</b> – forma pochodna <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>.", "Amrik Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amrik</b>.</p><p>Amrik to indyjska męska nazwa, która może odnosić się do Amrik Anand (ur. 1947), indyjskiego kryketa Amrik Singh (1948-1984), prezesa Federacji Indii Sikhów Sikhów Amrik Singh Cheema (1918-1982), indyjski urzędnik i autor Amrik Singh Dhillon, indyjski polityk Sikhów Punjabi Amrik Virk (ur. 1963 lub 1964), kanadyjski polityk</p>", "Ariel Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ariel</b>.</p><b>Ariel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֲרִיאֵל&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> słów oznaczających „lew Boga”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> używane było jako alternatywna nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolima</a>.", "Arjun Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arjun</b>.</p><b>Arjun</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskr.</a> <i>अर्जुन</i>) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjski</a> <a href=\"https://pl.wikipedia.org/wiki/Czo%C5%82g_podstawowy\" target=\"_blank\" rel=\"noopener noreferrer\">czołg podstawowy</a>, produkowany od 2004 roku, w <a href=\"https://pl.wikipedia.org/wiki/Armia_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">armii indyjskiej</a> od 2007 roku. Nazwa czołgu pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Ard%C5%BAuna\" target=\"_blank\" rel=\"noopener noreferrer\">Ardźuna</a> - jednego z bohaterów <a href=\"https://pl.wikipedia.org/wiki/Epos\" target=\"_blank\" rel=\"noopener noreferrer\">eposu</a> <i><a href=\"https://pl.wikipedia.org/wiki/Mahabharata\" target=\"_blank\" rel=\"noopener noreferrer\">Mahabharata</a></i>.", "Aksen": "<p>Avksenty (rosyjski: Авксе́нтий) to rosyjskie imię chrześcijańskie męskie. Nazwa pochodzi od greckiego imienia Auxentios, które z kolei pochodzi od słowa auxano, co oznacza wzrost, wzrost.</p>", "Andrzej Piotr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Andrzej Michał": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Aleksander Władysław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aleksander</b>.</p><b>Aleksander</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἀλέξανδρος, <i>aleksandros</i> – obrońca ludzi) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> składające się z dwóch członów: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;αλέξειν (bronić, wspomagać) i ἀνδρός (od ἀνήρ – mąż, mężczyzna). Całość bywa interpretowana jako „broniący mężów, troszczący się o mężów, opiekujący się mężami”.", "Amarachi": "<p>Amarachi Uyanne (ur. 17 lipca 2004), publicznie znany pod pseudonimem Amarachi, jest nigerijską piosenkarką, tancerką i skrzypkiem. Najbardziej znana została po zwycięstwie w pierwszej edycji Nigerii Got Talent.</p>", "Ali Abbas": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Anh Vu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Andrzej Franciszek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Abdul Hameed": "<p>'Abd al-Ḥamīd (ALA-LC romanizacja arabskiej: عبد الحميد; perskiego: عبدالحمید, romanized: Abdolhamid; tureckiego: Abdülhamit), również pisowniony jako Abdulhamid, Abdelhamid, Abd-ul Hamid i Abd ol-Hamid, jest muzułmańskie męskie imię i nazwisko. Jest to muzułmańska nazwa teoforyczna zbudowana z arabskich słów 'abd ('sługa') i al-Ḥamīd (jedno z nazw Boga w Koranie), a zatem oznacza 'sługa Wszechchchch chwalnego'.</p>", "Adrian Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Artur Tadeusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Artur</b>.</p><b>Artur</b> wymowa – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Powstało ze złożenia dwóch wyrazów wywodzących się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">języków celtyckich</a>: <i>Art</i> – niedźwiedź, <i>ur</i> – młody, piękny, kwitnący. Podstawę imienia może także stanowić celtyckie słowo ard – wysoki, szlachetny.", "Akseli": "<b>Absalon</b>, <b>Absalom</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się z hebrajskiego <i>Abishalom</i> oznaczającego „Ojciec [Bóg] jest pokojem”. Formą przyjętą w Polsce jest <b>Absalon</b>. Skandynawską formą tego imienia jest <b>Axel</b>.", "Arnat": "<p>Arnett to zarówno nazwisko, jak i imię. Znanymi osobami z imieniem są: Nazwisko: Benjamin W.</p>", "Alexius": "<p>Alexius jest łacińską formą nazwy Alexios (grecki: Αλέξιος, polityczny ⁇ λέξιος \"obronacz\", por. Aleksander), szczególnie powszechna w Imperium Bizantyjskim.</p>", "Atanasie": "<p>Atanasie jest rumuńską formą Athanasios, używaną głównie jako męska nazwisko. Może odnosić się do: Atanasie Anghel Popa (m.</p>", "Akpan": "<p>Akpan () to nigerijskie męskie imię i nazwisko pochodzenia Ibibio i Efik, co oznacza \"pierwszy syn\".</p>", "Armando Luis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Armando</b>.</p><p>Armando - pierwszy hiszpański album studiowy (i piąty w dyskografii) repera z Miami Pitbull. Relizja albumu odbyła się 2 listopada 2010 roku.</p>", "Arnob": "<p>Arnav, Arnab lub Arnov to popularne w Indiach imię i oznacza \"ocean\" w sanskrycie. Arnab to bengalijska, odia i asamska forma nazwy.</p>", "Adam Stanisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Alexandru-Virgil": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Allwin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alwin</b>.</p><b>Alwin</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Stanowi skróconą formę imienia <a href=\"https://pl.wikipedia.org/wiki/Albwin\" target=\"_blank\" rel=\"noopener noreferrer\">Albwin</a> lub <a href=\"https://pl.wikipedia.org/wiki/Adalwin\" target=\"_blank\" rel=\"noopener noreferrer\">Adalwin</a>.", "Ati̇f": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Atiph</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Atif</b>.</p><p>Atif (zwany również Atef lub Atiph, arabski: عاطف) jest arabskim męskim imieniem, które jest używane w świecie muzułmańskim, oznacza \"dobry\".</p>", "Andy David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andy</b>.</p><p>Andranic Madadian (ang. Andranik Madadian, broń.</p>", "Ahmad Farid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmad</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Abdelbaki": "<p>'Abd al-Bāqī (ALA-LC) to męskie muzułmańskie imię. Został zbudowany z arabskich słów ʿabd i al-Bāqī, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Atiph": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Atif</b>.</p><p>Atif (zwany również Atef lub Atiph, arabski: عاطف) jest arabskim męskim imieniem, które jest używane w świecie muzułmańskim, oznacza \"dobry\".</p>", "Aatu": "<p>Aatu to fińskie imię męskie i wariant niemieckiego imienia Adolf. Zyskała popularność w XIX wieku podczas Finnizacji nazw.</p>", "Albina": "<b>Albina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Albin\" target=\"_blank\" rel=\"noopener noreferrer\">Albin</a>. Prawdopodobnie wywodzi się od słowa \"albus\", czyli czysty, biały. Inna hipoteza głosi, że to połączenie germańskich słów „alb” i „wini”, co ma oznaczać „przyjaciółkę elfów”.", "Anh Kiệt": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Antoni Jacek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Anh Kien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Ammon": "<b>Ammon</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> 𐐈𐐣𐐊𐐤) – imię męskie występujące w wyznaniach należących do <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów). Pochodzi z Księgi Mormona, w której nosiły je dwie postacie. Pojawiło się w źródłach już w początkach mormonizmu. Popularne w zdominowanym przez świętych w dniach ostatnich stanie Utah. Występuje wśród wyznających mormonizm Maorysów oraz w Meksyku. Znalazło odzwierciedlenie w szerszej mormońskiej kulturze. Jako imię wywiedzione z pism świętych uznawane jest za powód do dumy. Ma także wywierać pozytywny wpływ na życie duchowe noszącego je człowieka.", "Alex-Vasile": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Andres Ricardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Ansgary": "<b>Oskar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> oznaczające „bożą włócznię” lub „włócznię boga” (<i>os</i> lub <i>ans</i> „bóg” i <i>gār</i> „włócznia”) lub <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">iryjskiego</a>, gdzie oznaczało „przyjaciela jeleni” (<i>os</i> „jeleń”, <i>cara</i> „przyjaciel”). W tekstach po polsku pojawiło się w XV wieku. Imię to nosili m.in. królowie <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">Szwecji</a>. Jego wariantem przyjętym w Polsce jest <b>Ansgar</b>.", "Andrzej Benedykt": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Avia": "<p>AVIA Motors - czeska firma założona w 1919 roku na produkcję samolotów. Od 1946 roku produkuje również samochody ciężarowe i autobusy.</p>", "Abdel-Rahman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Atti̇la": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Attyla</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Attila</b>.</p><b>Attila</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, szczególnie popularne w Turcji i na <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">Węgrzech</a>, gdzie używa się także formy Etele. Żeński odpowiednik – Etelka.", "Andrzej Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Al-Farabi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Al</b>.</p><p>Aluminium (chymiczny symbol - Al, od łacińskiego Aluminium), wcześniej również gliny (od rosyjskiego.</p>", "Adrian-Ionut": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Aditiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aditia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aditi</b>.</p>W <i>Bryhadajranjakopaniszad</i> (1.2.5) określenie dla oznaczenia <a href=\"https://pl.wikipedia.org/wiki/Absolut\" target=\"_blank\" rel=\"noopener noreferrer\">bytu absolutnego</a>.", "Abdul Saboor": "<p>'Abd al-Ṣabūr (ALA-LC) to muzułmańskie imię męskie, oparte na arabskich słowach 'abd i al-Ṣabour, jednym z imion Boga w Koranie, które powodują muzułmanskie nazwy teoforyczne. To znaczy \"służący cierpliwego\".</p>", "Andres Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Alan Ezequiel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alan</b>.</p><b>Alan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia najprawdopodobniej <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Może też wywodzić się od nazwy irańskiego plemienia <a href=\"https://pl.wikipedia.org/wiki/Alanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Alanów</a>. Znaczenie tego imienia nie jest dokładnie znane, prawdopodobne znaczenia:", "Assane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Assan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asan</b>.</p><p>Asan (w języku wietnskim Nha Sơn) jest miastem w prowincji Chungcheong-South w Korei. Miasto znajduje się na południu od stolicy Seulu.</p>", "Adrianne": "<p>Adrianne to imię. To kobieca forma męskiego imienia Adrian.</p>", "Alexandre Bruno": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandre</b>.</p><p>Alexandre Dumas może odnosić się do: Alexandre Dumas Alexandre Yersin Alexandre de Rhodes Alexandre Varenne Alexandre Dumas syn Alexandre Pato Alexandre Sabès Pétion</p>", "Albus": "<b>Alba Sylwiusz</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac</a>. <i>Alba Silvius</i>) – legendarny król miasta <a href=\"https://pl.wikipedia.org/wiki/Alba_Longa\" target=\"_blank\" rel=\"noopener noreferrer\">Alba Longa</a>, syn <a href=\"https://pl.wikipedia.org/wiki/Latinus_Silvius\" target=\"_blank\" rel=\"noopener noreferrer\">Latynusa Sylwiusza</a>, wnuk <a href=\"https://pl.wikipedia.org/wiki/Aeneas_Silvius\" target=\"_blank\" rel=\"noopener noreferrer\">Eneasza Sylwiusza</a>, przodek: <a href=\"https://pl.wikipedia.org/wiki/Silvius\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwiusza</a>, <a href=\"https://pl.wikipedia.org/wiki/Askaniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Askaniusza</a> i <a href=\"https://pl.wikipedia.org/wiki/Eneasz\" target=\"_blank\" rel=\"noopener noreferrer\">Eneasza</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Capetus\" target=\"_blank\" rel=\"noopener noreferrer\">Kapeta</a> (imię według narracji <a href=\"https://pl.wikipedia.org/wiki/Dionizjusz_z_Halikarnasu\" target=\"_blank\" rel=\"noopener noreferrer\">Dionizjusza z Halikarnasu</a>, przez Liwiusza zwany <i>Atysem</i>). Rządził 39 lat.", "Alin-Iosif": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Anderson Damian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Amira": "<b>Amira</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> أميرة) – imię arabskie, oznaczające „<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99%C5%BCniczka\" target=\"_blank\" rel=\"noopener noreferrer\">księżniczka</a>”. Słowo to także funkcjonuje w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języku arabskim</a> potocznie.", "Albert Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Albert</b>.</p><b>Albert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających <i>adal</i> (ród szlachecki) i <i>beraht</i> (jasny, błyszczący), oznaczało „pochodzącego ze szlachetnego rodu”. Jest zredukowaną formą staroniemieckiego imienia <i>Athalbraht</i> (pol. <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbert</a>). Alternatywną wersją Alberta jest <i><b>Olbracht</b></i> – por. <a href=\"https://pl.wikipedia.org/wiki/Jan_I_Olbracht\" target=\"_blank\" rel=\"noopener noreferrer\">Jan I Olbracht</a>, król Polski.", "Amrit Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amrit</b>.</p><p>Amrit (arabski: عمريت), starożytne imię Marathus (gr. αραθ ς, Marathos), był obecnie finiockim portem znajdującym się blisko Tartus w Syrii. Założony w III millenium pne, Marat (Fenickie: ⁇ , MRT) był ważnym północnym miastem starożytnej Feneki i był przeciwnikiem sąsiedniego Arwad.</p>", "Asitha": "<p>Asitha to imię. Znani ludzie z nazwiskiem to: Asitha Ameresekere (ur. 1971), brytyjsko-sri Lankański filmowiec Asitha Costa (ur. 1970), krykerka z Sri Lanki Asitha Fernando (ur. 1997), krykerka z Sri Lanky Asitha Rathnaweera, kryker z Sri Lanku</p>", "Awigdor": "<p>Avigdor (Hebrajskie: אביגדור, również Abigdor, Awigdor, z I Kronik 4.18, אבי גדור = Avi Gedor) to hebrajskie imię męskie.</p>", "Alexandru-Dorin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Ali̇ Baran": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Ahmad Siar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmad</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Abdul Vahab": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdul Wahab</b>.</p><p>Abdul Wahhab (arabsko: عبد الوهاب, romanized: ʻAbd al-Wahhāb) to męskie imię i nazwisko pochodzenia arabskiego. Został zbudowany z arabskich słów ʿabd i al-Wahhāb, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Adlai": "<b>Adlai</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia hebrajskiego. Jego znaczenie to „Bóg jest sprawiedliwy” lub „Bóg jest ozdobą”.", "Avivi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aviv</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aviva</b>.</p><p>Aviva plc - brytyjska firma ubezpieczeniowa, jedna z największych na świecie, należąca do kategorii systematycznie istotnych dla światowej gospodarki. Głównymi rynkami dla niej są Wielka Brytania, Irlandia, Kanada i Włochy.</p>", "Alexandru-Ştefan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Ahmed Abdalla": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Aymard": "<p>Aymard to francuskie imię.</p>", "Ali Mohammad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Antoni Michał": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Asgeir": "<p>Ansgar (latynistycznie Ansgarius; starożytny norweski Ásgeirr) jest niemieckim imieniem, składającym się z elementów ans \"bóg\" i gar \"piedź\". Ansgar to starożytna forma nazwy w Wielkiej Niemczech.</p>", "Andrzej Wojciech": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Andres Yesid": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Abubakar-Sidik": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abubakar</b>.</p><p>Abu Bakr (arabsko: أبو بكر) to arabskie imię, które oznacza \"ojciec młodego wielbłąda\" (Abu oznacza \"ojca\" i Bakr oznacza \"młody wielbłąd\"), które jest szeroko stosowane przez muzułmanów sunnitów. Inne transliteracje obejmują Abu Bakar, Abu Bekr, Ebubekir, Aboubacar, Abubakar itp.</p>", "Antoine Tadeusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoine</b>.</p><p>Franz Antoine (niem. Franz Antoine, 23 lutego 1815 - 11 marca 1886) - austriacki botanik, artysta i fotograf.</p>", "Arkadia": "<b>Arkadia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi od słowa (<i>arkadios</i>) oznaczającego „pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Arkadia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Arkadii</a>, krainy szczęśliwości”.", "Ataullah": "<p>Ataullah (arabski: عطاء الله lub عطا الله) lub alternatywna Atallah to arabskie imię, które oznacza \"dar Boga\", składające się z Ata (dar) + Allah (Bóg). Jest to również nazwisko chrześcijan na Bliskim Wschodzie.</p>", "Abdul-Hamid": "<p>'Abd al-Ḥamīd (ALA-LC romanizacja arabskiej: عبد الحميد; perskiego: عبدالحمید, romanized: Abdolhamid; tureckiego: Abdülhamit), również pisowniony jako Abdulhamid, Abdelhamid, Abd-ul Hamid i Abd ol-Hamid, jest muzułmańskie męskie imię i nazwisko. Jest to muzułmańska nazwa teoforyczna zbudowana z arabskich słów 'abd ('sługa') i al-Ḥamīd (jedno z nazw Boga w Koranie), a zatem oznacza 'sługa Wszechchchch chwalnego'.</p>", "Anh Linh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Azym": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Azim</b>.</p><p>Azim (ʿAẓīm عظيم) jest jednym z imion Allaha w islamu, co oznacza \"Wielki\" lub \"Wspaniały\" lub \"Ochrony\". Jest używany przez wielu Sahrawiów jako nazwisko pochodzące z arabskiego Hasania.</p>", "Arashi": "<b>Arashi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;嵐&#59; dosł. <i>burza</i>) - <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone przez mężczyzn oraz kobiety.", "Alin-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Adam Andrzej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Austyn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Austin</b>.</p><p>Austen (ang. Austin) - angielskojęzyczna nazwisko, toponim i nazwa.</p>", "Antwan": "<p>Antwan - wariant francuskiej nazwy Antoine - to męskie imię, które jest powszechnie używane wśród Afroamerykanów. Wśród znanych osób z tym nazwiskiem są: Antwan Barnes, amerykański piłkarz Antwan Odom, amerykański piłkarze Antwan Patton, amerykańskiego rapera znany jako Big Boi Antwan Peek, amerykańczy piłkarza Ant Wan, szwedzki raper</p>", "Abdolkarim": "<p>'Abd al-Karīm (ALA-LC) to muzułmańskie imię męskie i w nowoczesnym użyciu także nazwisko. Została zbudowana z arabskich słów ʿabd i al-Karīm, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Alex Dario": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Adrian-Ioan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Amitha": "<p>Amita to imiona indyjskiego pochodzenia. Nazwa oznacza \"bezgraniczny, bezgraniczny\" w sanskryty.</p>", "Ainsley": "<p>Ainsley (zwane również Ainsleigh) jest zarówno nazwiskiem unisex, jak i nazwiskiem i nazwisku miejsca. Pochodzi z słów oznaczających wygrzewanie i wyczyszczanie (staroang. \"anne\" (\"samotna, samotna\") lub ānsetl (\"wygrzewanie\") + lēah (\"les, wyczyszczenie\")).</p>", "Angell": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Abhishek Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abhishek</b>.</p><p>Abhishek to męskie imię, które ma swoje korzenie w sanskrytycznym słowie abhiseka. Konceptualne znaczenie abhisek jest związane z oczyszczeniem, oczyszczaniem lub pomazanie.</p>", "Andrzej Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Alvaro Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alvaro</b>.</p><b>Alwar</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „strażnik wszystkiego/wszystkich”.", "Abdolvahab": "<p>Abdul Wahhab (arabsko: عبد الوهاب, romanized: ʻAbd al-Wahhāb) to męskie imię i nazwisko pochodzenia arabskiego. Został zbudowany z arabskich słów ʿabd i al-Wahhāb, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Alex-Manuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Arsenije": "<p>Arsenije (Serbski cyrylski: Арсеније; Serbskie wymowa: [ǎrsɛːnijɛ]) to serbskie imię, wariant greckiej nazwy Arsenios. Do skróconych nazw należą Arsen, Arsa i Arso.</p>", "Ahmad Zia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmad</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Ali Hassan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Almin": "<p>Almin to imię męskie. Na Bałkanach Almin jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Adrian-Bogdan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Andrzej Ryszard": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Anand Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anand</b>.</p><p>Anand - indyjska nazwa, nazwisko i toponim: Viswanathan Anand (ur.</p>", "Amerigo": "<b>Emeryk</b>, Amalaryk, Amalryk – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze starogermańskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Amalaryk\" target=\"_blank\" rel=\"noopener noreferrer\">Amalaryk</a>, oznaczającego „władca <a href=\"https://pl.wikipedia.org/wiki/Amalowie\" target=\"_blank\" rel=\"noopener noreferrer\">Amalów</a>” (Amalowie według gockiej legendy to ród królewski pochodzenia boskiego). Człon <i>amal</i> może także oznaczać „gorliwy” lub „dzielny, aktywny”. Emeryk może wywodzić się również z saksońskiego <i>Emmerich</i>, oznaczającego „zawsze bogaty”.", "Abdul Wahab": "<p>Abdul Wahhab (arabsko: عبد الوهاب, romanized: ʻAbd al-Wahhāb) to męskie imię i nazwisko pochodzenia arabskiego. Został zbudowany z arabskich słów ʿabd i al-Wahhāb, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Agustin Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Agustin</b>.</p><p>Agustín to hiszpańskie imię i czasami nazwisko. Jest związany z Augustinem.</p>", "Alexys": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alexis</b>.</p><p>Alexis może wskazywać: Alexis de Tocqueville Jacques-Édouard Alexis</p>", "Ariel Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ariel</b>.</p><b>Ariel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֲרִיאֵל&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> słów oznaczających „lew Boga”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> używane było jako alternatywna nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolima</a>.", "Adrian-Valentin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Anderson Felipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Artür": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arturi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Artur</b>.</p><b>Artur</b> wymowa – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>. Powstało ze złożenia dwóch wyrazów wywodzących się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">języków celtyckich</a>: <i>Art</i> – niedźwiedź, <i>ur</i> – młody, piękny, kwitnący. Podstawę imienia może także stanowić celtyckie słowo ard – wysoki, szlachetny.", "Abdul Wahid": "<p>ʽAbd al-Wāḥid (ALA-LC) to męskie muzułmańskie imię i nazwisko. Została zbudowana z arabskich słów ʽabd, co oznacza podległy, i al-Wāḥid, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Adám": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adama</b>.</p><p>Adama (oromo: Adaamaa lub Hadaamaa) jest miastem w centrum Oromia. Adama jest obszarem Oromia i otoczony jest obszarami wschodniej Shewa.</p>", "Atiqullah": "<p>Atiqlah (arabsko: عتیق الله) to muzułmańskie imię, utworzone z elementów Atiq, co oznacza wolny, i Allah, co oznacza Boga. Może odnosić się do: Atiqullah Atifmal (ur. 1957), afgańskiego dyplomat Atiqullah Baryalai (ur. 1965), afgański oficer wojskowy Atiqullah Ludin, gubernator afgańskiej prowincji, 2008-2013 Atiqullah Raufi (?-2014), afgańskego administratora sądowego Atiq Ullah (piłkarz) (ur. 1983), pakistańskiego piłkarza Atiq Ulla (Kashmiri...</p>", "Aquino Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aquino</b>.</p><p>Aquino jest miastem w prowincji Frosinone w włoskim regionie Lazio. Święty Thomas d'Aquin urodził się w Aquino w 1225 roku.</p>", "Antonio-Nicolas": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonio</b>.</p><p>Antonio James Uri (włoski: Antonio James Uri)  Antonio jest angielski.</p>", "Archyp": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Archip</b>.</p><b>Archip</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">pochodzenia</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z członów: <i>αρχος (archos)</i>, oznaczającego \"mistrz\" oraz <i>‘ιππος (híppos)</i> – „koń”.", "Anthony Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anthony</b>.</p><p>Anthony może odnosić się do: Anthony Hopkins Anthony Giddens Anthony van Dyck</p>", "Anderson Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anderson</b>.</p><p>Anderson - angielskie nazwisko i toponim.</p>", "Antoni Tadeusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Avishka": "<p>Avishka to imię. Znani ludzie z nazwiska to: Avishka Chenuka (ur. 1999), Sri Lankaniec Avishka Fernando (ur. 1998), Sri Lanka Avishka Fernando, Sri Lanka A. Gunawardene (ur. 1977), Sri Lankowa Avishka Perera (ur. 2001), Sri Lanki Avishka Tharindu (ur. 2001)</p>", "Alex-Matei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Antoni Leopold": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Andrev": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andrew</b>.</p><p>Andrew może odnosić się do: Św. Andrew: jeden z dwunastu apostołów Jezusa Andrew Johnson: 17 prezydent Stanów Zjednoczonych i w pełni od 1865 do 1867 roku Andrew Jackson</p>", "Andrii-Artur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrii</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Arumugam": "<p>Arumugam lub Arumukan to tamyłowe imię męskie. Ze względu na tamilską tradycję używania nazwisk patronymicznych może być również nazwiskiem dla mężczyzn i kobiet.</p>", "Anasse": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anass</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anas</b>.</p><p>Uci rzeki lub uci szlachetne (lat. Anas), to rodzaj ptaków rodziny uci.</p>", "Alena": "<p>Alena (lat. Alena) - rodzaj prawdziwych wielbłądków (Raphidiidae). W Ameryce Północnej jest około 10 gatunków.</p>", "Adam Konrad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Ahmed Mousa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Abdelwahed": "<p>ʽAbd al-Wāḥid (ALA-LC) to męskie muzułmańskie imię i nazwisko. Została zbudowana z arabskich słów ʽabd, co oznacza podległy, i al-Wāḥid, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Amrit Pal Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amrit</b>.</p><p>Amrit (arabski: عمريت), starożytne imię Marathus (gr. αραθ ς, Marathos), był obecnie finiockim portem znajdującym się blisko Tartus w Syrii. Założony w III millenium pne, Marat (Fenickie: ⁇ , MRT) był ważnym północnym miastem starożytnej Feneki i był przeciwnikiem sąsiedniego Arwad.</p>", "Arséne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arsen</b>.</p><p>Arsen (na armeńsku, Արսեն; gruzińsku, არსენ; rosyjski, Арсен; ukraiński, Арсен) jest nazwiskiem, diminutiwem greckiego Arsenios. Do wybitnych osób z tym nazwiskiem należą: Arsen Akayev (ur. 1970), Kumyk-Roski trener i były gracz piłki nożnej Arsen Avakov (ur. 1964), ukraiński polityk Arsen Awakov (ur., 1971), były tajczyk piłkarz piłkarza Arsen Avetisyan (ur. 1973), armenijski piłkarze piłkarzy Arsen Aydinian (1825-1902), armeni...</p>", "Ayan-Nicolas": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ayan</b>.</p><p>⁇ Nieuchwytny ⁇ (tam. அயன், Ayan) - indyjski film przygodowy reżysera K.</p>", "Adam Francis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Andy Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andy</b>.</p><p>Andranic Madadian (ang. Andranik Madadian, broń.</p>", "Abdulbaset": "<p>'Abd al-Bāsiṭ (ALA-LC) to męskie muzułmańskie imię. Został zbudowany z arabskich słów ʿabd i al-Bāsiṭ, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Ahmed Elsayed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Angel Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Angel Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Ahssan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ahsan</b>.</p><p>Ahsan to męskie imię pochodzące z arabskiego i sanskrytu. W arabskim, trójkononentalny korzeń Ḥ-S-N, również jako diminutiw Hasana.</p>", "Aniefiok": "<p>Aniefok to nigerijskie imię pochodzenia Ibibio, co oznacza \"kto wie jutro\" lub \"kto może przewidzieć przyszłość\". Jest to ogólnie uważane za jednoosłuchane imię, chociaż jest to powszechniejsze w współczesnym użyciu przez mężczyzn.</p>", "An Phu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Andrada": "<p>Andrada to nazwisko, a także rumuńskie kobiece imię. Do wybitnych osób z nazwiskiem należą: Alonso Andrada (1590-1672), biograf i pisarz asketyczny Diogo de Paiva de Andrada (1528-1575), portugalski teolog urodzony w Coimbra Edgardo Andrada (1939-2019), emerytowany profesjonalny piłkarz argentyński, który grał jako bramkarz Esteban Andrada (urodzony w 1991 roku), argentyński międzynarodowy bramkarze José Andrada (1948-2025), argenty...</p>", "Anushka": "<p>Nazwa Anoushka, Anouska, Anuschka, Anushka i Annushka są drobnymi formami nazwiska żeńskiego Anna, pochodzącym z rosyjskiego drobnego Annuшка. Anoushka (انوشکا) oznacza również \"łaska\" lub \"fałsza\" lub \"kwień\" w perskim.</p>", "Aser": "Miał sześciu synów oraz jedną córkę (Serach). Od niego wywodzi się jedno z <a href=\"https://pl.wikipedia.org/wiki/Dwana%C5%9Bcie_Plemion_Izraela\" target=\"_blank\" rel=\"noopener noreferrer\">dwunastu pokoleń Izraela</a>. Według tradycji dożył 123 lat.", "Aday": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ada</b>.</p><b>Ada</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/Kobieta\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> znaczy: upiększać się, stroić się. Imię Ada jest wymieniane w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> w pierwszej księdze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, gdzie jest jedną z żon Lemecha i matką Jubala. W Biblii jest także mowa o Adzie, matce flecistów i grających na harfie (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Rdz.</a> 4, 21).", "Ali Han": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Assif": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asif</b>.</p><p>Asif (arabski: آصف) to arabskie męskie imię. W językach perskim i urdu często wymawia się jako \"Asif\" lub \"Asef\".</p>", "Antoni John": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Anil Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anil</b>.</p><p>Anil to rodzaj roślin kwiatowych z rodziny Białego.</p>", "Arnold Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arnold</b>.</p><b>Arnold</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Stanowi złożenie członów oznaczających „orzeł” i „panujący”. Jednym z patronów tego imienia w Kościele katolickim jest <a href=\"https://pl.wikipedia.org/wiki/Arnold_Janssen\" target=\"_blank\" rel=\"noopener noreferrer\">Arnold Janssen</a>.", "Abdul-Rahman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Ali Mohamed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Adrian-Nicolae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Awadh": "<b>Awadh</b> lub <b>Oudh</b> – region w <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjskim</a> stanie <a href=\"https://pl.wikipedia.org/wiki/Uttar_Pradesh\" target=\"_blank\" rel=\"noopener noreferrer\">Uttar Pradesh</a> graniczący od południowego zachodu z <a href=\"https://pl.wikipedia.org/wiki/Doab\" target=\"_blank\" rel=\"noopener noreferrer\">doabem</a> <a href=\"https://pl.wikipedia.org/wiki/Ganges\" target=\"_blank\" rel=\"noopener noreferrer\">Gangesu</a> i <a href=\"https://pl.wikipedia.org/wiki/Jamuna\" target=\"_blank\" rel=\"noopener noreferrer\">Jamuny</a>, od północnego zachodu z regionem Rohilkhand, od wschodu z Purvanchal a od północy z <a href=\"https://pl.wikipedia.org/wiki/Nepal\" target=\"_blank\" rel=\"noopener noreferrer\">Nepalem</a>. Mieszkańcy regiony posługują się językiem <a href=\"https://pl.wikipedia.org/wiki/Awadhi\" target=\"_blank\" rel=\"noopener noreferrer\">Awadhi</a>. Nazwa regionu pochodzi od miasta <a href=\"https://pl.wikipedia.org/wiki/Ayodhya\" target=\"_blank\" rel=\"noopener noreferrer\">Ayodhya</a>, stolicy starożytnego królestwa Kosala, którego obszar pokrywał się z dzisiejszym obszarem regionu Awadh&#8201;.", "Abdelhady": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdelhadi</b>.</p><p>'Abd al-Hādī (ALA-LC) to muzułmańskie imię męskie, a w współczesnym użyciu nazwisko. Został zbudowany z arabskich słów ʿabd i al-Hādī, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Amrit Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amrit</b>.</p><p>Amrit (arabski: عمريت), starożytne imię Marathus (gr. αραθ ς, Marathos), był obecnie finiockim portem znajdującym się blisko Tartus w Syrii. Założony w III millenium pne, Marat (Fenickie: ⁇ , MRT) był ważnym północnym miastem starożytnej Feneki i był przeciwnikiem sąsiedniego Arwad.</p>", "Abdool": "<p>Abdul (tzw. Abd, Abdel, Abdil, Abdol, Abdool lub Abdoul) jest najczęstszą transliteracją połączenia arabskiego słowa Abd (عبد, oznaczające \"Służebnik\") i prefiksu al / el (ال, oznaczający \"The\"). Jest to początkowy składnik wielu nazw związanych, takich jak Abd الحميد ʿAbd al-Ḥamīd (zwykle pisane Abdel Hamid, Abdelhamid, Abd El Hamid lub Abdul Hamid; lit.</p>", "Amir Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amir</b>.</p><b>Amir</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أمير&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „książę” lub „dowódca”.", "Ali Firat": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Abdulmajeed": "<p>'Abd al-Majīd (ALA-LC romanizacja arabskiego: عبد المجيد, perskiego: عبدالمجید), również pisowany jako Abd ul Majid, Abd ul-Majid, Abd ol Majid, Abdul ol-Majed i Abdolmajid, jest muzułmańskie męskie imię i nazwisko. Jest to połączenie arabskich słów 'abd i al-Majīd, jednego z nazw Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Aravind Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aravind</b>.</p><p>Aravind (z sanskrytu: अरविन्द aravinda) to powszechne indyjskie imię męskie oznaczające lotos. Nazwa jest pochodzenia hinduskiego.</p>", "Ardy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ardi</b>.</p><i><b>Ardipithecus ramidus</b></i> (syn. <i>Australopithecus ramidus</i>; <i>Ardipithecus ramidus ramidus</i>) – <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunek</a> wymarłego ssaka <a href=\"https://pl.wikipedia.org/wiki/Naczelne\" target=\"_blank\" rel=\"noopener noreferrer\">naczelnego</a> z rodziny <a href=\"https://pl.wikipedia.org/wiki/Cz%C5%82owiekowate\" target=\"_blank\" rel=\"noopener noreferrer\">człowiekowatych</a> (Hominidae) żyjącego w <a href=\"https://pl.wikipedia.org/wiki/Pliocen\" target=\"_blank\" rel=\"noopener noreferrer\">pliocenie</a> na terenach <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>. Najbardziej kompletne <a href=\"https://pl.wikipedia.org/wiki/Skamienia%C5%82o%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">skamieniałości</a> <i>A. ramidus</i> pochodzą z okolic wioski Aramis w <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">Etiopii</a> i liczą około 4,4 mln lat. Znaleziony tam szkielet młodej samicy nie przypomina budową szkieletu <a href=\"https://pl.wikipedia.org/wiki/Szympans\" target=\"_blank\" rel=\"noopener noreferrer\">szympansa</a>, <a href=\"https://pl.wikipedia.org/wiki/Goryl\" target=\"_blank\" rel=\"noopener noreferrer\">goryla</a>, ani innych naczelnych blisko spokrewnionych z człowiekiem. <i>A. ramidus</i> wykazywał cechy zarówno hominidów nadrzewnych, jak i pewną formę naziemnej <a href=\"https://pl.wikipedia.org/wiki/Dwuno%C5%BCno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">dwunożności</a>, bardziej prymitywną niż występująca u <i><a href=\"https://pl.wikipedia.org/wiki/Australopiteki\" target=\"_blank\" rel=\"noopener noreferrer\">Australopithecus</a></i>. Żył prawdopodobnie głównie w <a href=\"https://pl.wikipedia.org/wiki/Las\" target=\"_blank\" rel=\"noopener noreferrer\">lasach</a>. Był stworzeniem dwunożnym, miał chwytne stopy, stosunkowo niewielką czaszkę – objętość puszki mózgowej wynosiła 300–350 cm³. Wiele cech budowy czaszki występowało także u <i><a href=\"https://pl.wikipedia.org/wiki/Sahelantrop\" target=\"_blank\" rel=\"noopener noreferrer\">Sahelanthropus</a></i>, dowodząc, że czaszki środkowoplioceńskich hominidów znacząco różniły się od tych u australopiteków oraz współczesnych małp. Odnaleziono ponad 145 zębów <i>Ardipithecus ramidus</i> – ich budowa sugeruje, że hominid ten był prawdopodobnie wszystkożercą lub owocożercą. Samica miała około 120 cm wzrostu i ważyła 50 kg.", "Aiko": "<p>Aiko - robot-ginoid.</p>", "Arnolf": "<b>Arnulf</b>, <b>Arnolf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Pierwszy człon imienia stanowi <i>arn</i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">staro-wysoko-niemiecki (stwniem.)</a>-frankoński, średnio-dolno-niemiecki (śrdniem.) <i>arn</i> („<a href=\"https://pl.wikipedia.org/wiki/Or%C5%82y\" target=\"_blank\" rel=\"noopener noreferrer\">orzeł</a>”); drugim członem jest <i>wolf</i> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germ.</a> <i>wulfa &gt; wolfa</i> („<a href=\"https://pl.wikipedia.org/wiki/Wilk_w_kulturze\" target=\"_blank\" rel=\"noopener noreferrer\">wilk</a>”); stwniem. <i>wolf</i>. Formy z <i>-ulf</i> są odbiciem zromanizowanego germ. <i>-wulf</i>. Wariantami drugiego członu są: <i>-wulf</i>, który stanowi kontynuację najstarszej, germańskiej formy, zachowanej w śrdniem. i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_dolnoniemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">dolnoniemiecki (dniem.)</a>, oraz <i>-wolf</i>, kontynuacja młodszej formy germańskiej, przejętej przez stwniem., <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">średnio-wysoko-niemiecki (śrwniem.)</a> i nowoniemiecki. Imię to notowane było w Polsce już w średniowieczu, w formie (Arnolf) (<a href=\"https://pl.wikipedia.org/wiki/1219\" target=\"_blank\" rel=\"noopener noreferrer\">1219</a>), Arnolfus (Arnulf) (<a href=\"https://pl.wikipedia.org/wiki/1435\" target=\"_blank\" rel=\"noopener noreferrer\">1435</a>). Niektóre możliwe staropolskie zdrobnienia: Arnek, Arnko.", "Anele": "<p>Anele to imię. Znanymi osobami z nazwiska są: Anele Lungisa (ur. 1992), gracz rugby południowoafrykański Anele Mdoda (ur. 1984), prezenterka telewizyjna południo Afryki Anele Ngcongca (1987-2020), piłkarz południowej Afryki</p>", "Arkadiush": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arkadiusz</b>.</p><b>Arkadiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa Αρκαδικóς (Arkadikós) oznaczającego „pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Arkadia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Arkadii</a>”.", "Ahmad Faisal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmad</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Alexander Sebastian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexander</b>.</p><p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Atabeg": "<b>Atabeg</b> – tytuł seldżucki nadawany wychowawcy synów <a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tan\" target=\"_blank\" rel=\"noopener noreferrer\">sułtana</a> lub namiestnikowi prowincji. Atabeg podlegał <a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tan\" target=\"_blank\" rel=\"noopener noreferrer\">sułtanowi</a>, ale stał w hierarchii wyżej niż <a href=\"https://pl.wikipedia.org/wiki/Chan_(w%C5%82adca)\" target=\"_blank\" rel=\"noopener noreferrer\">chan</a>. Słowo <i>atabeg</i> można przetłumaczyć jako \"ojciec księcia\". Tytuł ten był powszechny wśród <a href=\"https://pl.wikipedia.org/wiki/Seld%C5%BCukidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Seldżuków</a> od <a href=\"https://pl.wikipedia.org/wiki/XI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XI</a> do <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a>. Z czasem miano atabega oznaczało tytuł dygnitarza. W <a href=\"https://pl.wikipedia.org/wiki/Egipt_mameluk%C3%B3w_(%C5%9Bredniowieczny)\" target=\"_blank\" rel=\"noopener noreferrer\">Egipcie mameluków</a> natomiast atabeg był wysokim rangą oficerem. Po upadku Seldżukidów i sułtanatu mameluków tytuł ten był używany sporadycznie.", "Ahmed Ali M": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Aatos": "<p>Aatos to fińskie imię męskie. Ludzie z nazwiskiem są następującymi:</p>", "Antonia": "<b>Antonia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antoni_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antoni</a>. W Polsce pojawiło się wcześniej niż imię <a href=\"https://pl.wikipedia.org/wiki/Antonina\" target=\"_blank\" rel=\"noopener noreferrer\">Antonina</a>, ale następnie zostało przez nie wyparte. W Kościele katolickim istnieją dwie patronki tego imienia.", "Ahmed Khan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Alex Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Ahmed Mohammed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Antoni Wojciech": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Armando De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Armando</b>.</p><p>Armando - pierwszy hiszpański album studiowy (i piąty w dyskografii) repera z Miami Pitbull. Relizja albumu odbyła się 2 listopada 2010 roku.</p>", "Andrii-Davyd": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrii</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Alin-Cosmin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Avril": "<p>Avril - francuska grupa agroprzemysłowa specjalizująca się w produkcji oleju roślinnego i biodiesel. Szefskopalnia znajduje się w VIII okręgu Paryża.</p>", "Aarnav": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arnav</b>.</p><p>Arnav, Arnab lub Arnov to popularne w Indiach imię i oznacza \"ocean\" w sanskrycie. Arnab to bengalijska, odia i asamska forma nazwy.</p>", "Anh Chien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Abdul Hamid": "<p>'Abd al-Ḥamīd (ALA-LC romanizacja arabskiej: عبد الحميد; perskiego: عبدالحمید, romanized: Abdolhamid; tureckiego: Abdülhamit), również pisowniony jako Abdulhamid, Abdelhamid, Abd-ul Hamid i Abd ol-Hamid, jest muzułmańskie męskie imię i nazwisko. Jest to muzułmańska nazwa teoforyczna zbudowana z arabskich słów 'abd ('sługa') i al-Ḥamīd (jedno z nazw Boga w Koranie), a zatem oznacza 'sługa Wszechchchch chwalnego'.</p>", "Abel-Moise": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abel</b>.</p><b>Abel</b> (hebr. הבל) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z hebrajskiego <i>abhal</i> – „mgła, dym, tchnienie”. Być może wiązało się jednak z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>aplu || ibil</i> lub asyryjskim <i>ahbla || ablu</i> – „syn rodzony”. Nosiła je <a href=\"https://pl.wikipedia.org/wiki/Kain_i_Abel\" target=\"_blank\" rel=\"noopener noreferrer\">postać biblijna</a>, syn Adama i Ewy, który był pasterzem. Abel został zamordowany przez swego brata Kaina, rolnika. Imię to było notowane na terenie Polski już w średniowieczu, na przełomie <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIV wieku</a>, początkowo jako imię zakonne. Patronem tego imienia w Kościele katolickim są, obok Abla, syna Adama i Ewy, m.in. Abel, biskup Metzu, i <a href=\"https://pl.wikipedia.org/wiki/Abel_z_Reims\" target=\"_blank\" rel=\"noopener noreferrer\">Abel</a>, arcybiskup Reims.", "Aarya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arya</b>.</p><p>\"Arya\" (i jego odmiany) to słowo oznaczające \"rod\" (boże święte) które kiedyś było używane jako samozwa indyjsko-iranijskich narodów. Słowo to zostało użyte przez lud Indy-Arya od czasów wedyjskich w Indiach jako nazwisko dla siebie, a także do osób należących do szlachty i geologicznych regionów Āryāvarta, w których pochodzą indy-Aryanskiej kultury.</p>", "Avian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aviana</b>.</p><p>Aviana lub Avianna jest imieniem kobiece z wieloma pochodzeniami. Jest to grönolandska nazwa, wariant grönolanderskiej nazwy Avek, co oznacza \"rodzina\", połączona z grönoländskim końcem -na, który wskazuje na imię pierwsze.</p>", "Andrzej Julian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Akhter": "<p>Akhtar (perskie: اختر, pasztów: اختر) oznacza \"gwiazdę\" w perskim i jest używany w pasztówce na Nowrudz i Dzień Wielkanocny. Jest to również powszechne nazwisko.</p>", "Alexandru-Eduard": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandru</b>.</p><p>Alexandru to męskie imię, rumuńska forma angielskiego imienia Aleksandra, pochodząca z łacińskiego Aleksandra i starożytnego greckiego Aléxandros (Αλέξανδρος), co oznacza \"obrójcę ludzkości\". Alexandru jest stosunkowo popularną nazwą w Rumunii i Mołdawii, głęboko zakorzenioną w tradycji kulturalnej, a nawet odzwierciedlającą się w imionach miejscowych takich jak Alexăndreni.</p>", "Alain G": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alain</b>.</p><p>Alain - rządca Harmoran w latach 1268-1290 z rodu Macруаiri.</p>", "Aravinda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aravind</b>.</p><p>Aravind (z sanskrytu: अरविन्द aravinda) to powszechne indyjskie imię męskie oznaczające lotos. Nazwa jest pochodzenia hinduskiego.</p>", "Abdulwahid": "<p>ʽAbd al-Wāḥid (ALA-LC) to męskie muzułmańskie imię i nazwisko. Została zbudowana z arabskich słów ʽabd, co oznacza podległy, i al-Wāḥid, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Angel Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Aldan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aldana</b>.</p><p>Aldana jest samorządem w prowincji Nariño w Kolumbii. Gmina Aldana ma 46 km2 i ma swoją siedzibę w Aldana.</p>", "Alexander Edward": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexander</b>.</p><p>Aleksander (dr. - Grecja. ἀλέξω ⁇ chronić ⁇ , ἀνήρ (r.p.</p>", "Alex-Cristian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Alfred Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alfred</b>.</p><b>Alfred</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „mądry jak <a href=\"https://pl.wikipedia.org/wiki/Elf_(fantastyka)\" target=\"_blank\" rel=\"noopener noreferrer\">Elf</a>”.", "Alisdair": "<p>Alistair to imię męskie. Jest angiliczowaną formą szkockiego gaelicznego imienia Alasdair.</p>", "Aneel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anel</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anele</b>.</p><p>Anele to imię. Znanymi osobami z nazwiska są: Anele Lungisa (ur. 1992), gracz rugby południowoafrykański Anele Mdoda (ur. 1984), prezenterka telewizyjna południo Afryki Anele Ngcongca (1987-2020), piłkarz południowej Afryki</p>", "Aishwarya": "Pochodziła z arystokratycznego rodu Rana (w latach 1846–1950 <i>de facto</i> dziedzicznie sprawującego funkcję premiera Nepalu). Jej rodzicami byli generał Kendra Shumsher Jang Bahadur Rana i jego żona Rani Rajya Lakshmi Rana.", "Abdul Rehman": "<p>Abdelrahman lub Abd al-Rahman lub Abdul Rahman lub Abdur Rahman lub Abdurahman lub Abdrrahman (arabski: عبد الرحمن lub czasami عبد الرحمان; DMG ʿAbd ar-Raḥman) to męskie arabskie muzułmańskie imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Rahman.</p>", "Adelajd": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adelajda</b>.</p><b>Adelajda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Składa się z elementów <i>adal</i> \"ród, ród szlachetny\" i <i>heit</i> \"osoba, stan, rodzaj\" i oznaczać mogło osobę wywodzącą się ze szlachetnego rodu.", "Adeniran": "<p>Adéníran to męskie imię i nazwisko pochodzenia jorubańskiego. Oznacza to: \"Rodzina królewska ma znany przodek; król (lub głowa) ma wizję; lub moja linia ma królewską rodzinę\".</p>", "A Mohamed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>A</b>.</p><p>A (U+0410) lub A (U +0041) może oznaczać: A - pierwsza litera alfabetu cyrylskiego. A to pierwsza litera alfabetu łacińskiego.</p>", "Antoni Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antoni</b>.</p><b>Antoni</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Pochodzi od <i>Antonii</i> (<a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Antoniuszów</a>), znaczącego rodu w starożytnym <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a>. Wśród imion nadawanych nowo narodzonym dzieciom, Antoni w 2017, 2018, 2019, 2020, 2021 r. zajmował 1. miejsce w grupie imion męskich. W całej populacji Polaków Antoni zajmował w 2017 r. 51. miejsce (130 174 nadań).", "Alodiusz": "<b>Alodiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie urobione od <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankońskiego</a> <i>al-ôd</i>, co oznacza „dziedzictwo, pełne posiadanie”. Imię to łączy się także ze średniowiecznym <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a> wyrazu <i><a href=\"https://pl.wikipedia.org/wiki/Alodium\" target=\"_blank\" rel=\"noopener noreferrer\">allodium</a></i>, który oznaczał „majątek ziemski wolny od ciężarów i powinności lennych”, a pochodzi również od tego samego wyrazu frankońskiego. W Kościele katolickim istnieje kilku świętych patronów tego imienia, m.in. św. Alodiusz, biskup <a href=\"https://pl.wikipedia.org/wiki/Auxerre\" target=\"_blank\" rel=\"noopener noreferrer\">Auxerre</a>, następca <a href=\"https://pl.wikipedia.org/wiki/German_z_Auxerre\" target=\"_blank\" rel=\"noopener noreferrer\">św. Germana</a>.", "Alex-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alex</b>.</p><p>Alex - zmniejszająca się forma imion Aleksiej i Aleksandra (w ostatnim przypadku forma kobieca - Aleks), może również być samodzielną nazwą.</p>", "Arun Das": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Arun</b>.</p><p>Arun (Mongolski: ⁇ ⁇ Arun qosiɣu, Kirin Mongoli: Арун хошуу; przenoszone: 阿荣旗; subtyp: 阿榮旗; przenośne: Āróng Qí, Hán Việt: A Vinh kỳ) jest okresem urzędu miasta Hulunbuir (Holun Luan Uy), Autonomicznego Obszaru Mongolicznego, Chiny. Miasto graniczy z prowincją Hắc Long Giang na wschodzie i południu i znajduje się 92 km (57 mi) na północno-zachodni od miasta Tề Tề Cápur w prowincji Hắc Long.</p>", "Abel-Samuel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abel</b>.</p><b>Abel</b> (hebr. הבל) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z hebrajskiego <i>abhal</i> – „mgła, dym, tchnienie”. Być może wiązało się jednak z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> <i>aplu || ibil</i> lub asyryjskim <i>ahbla || ablu</i> – „syn rodzony”. Nosiła je <a href=\"https://pl.wikipedia.org/wiki/Kain_i_Abel\" target=\"_blank\" rel=\"noopener noreferrer\">postać biblijna</a>, syn Adama i Ewy, który był pasterzem. Abel został zamordowany przez swego brata Kaina, rolnika. Imię to było notowane na terenie Polski już w średniowieczu, na przełomie <a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIV wieku</a>, początkowo jako imię zakonne. Patronem tego imienia w Kościele katolickim są, obok Abla, syna Adama i Ewy, m.in. Abel, biskup Metzu, i <a href=\"https://pl.wikipedia.org/wiki/Abel_z_Reims\" target=\"_blank\" rel=\"noopener noreferrer\">Abel</a>, arcybiskup Reims.", "Ahmadiyya": "<b>Ahmadijja</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمدية&#8206;, <a href=\"https://pl.wikipedia.org/wiki/Transkrypcja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">trans.</a> <b>ʾaḥmadiyya</b>, także: <b>ahmadija</b>) – ruch reformatorski w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamie</a> założony przez <a href=\"https://pl.wikipedia.org/wiki/Muzu%C5%82manin\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanina</a> <a href=\"https://pl.wikipedia.org/wiki/Mirza_Gulam_Ahmad\" target=\"_blank\" rel=\"noopener noreferrer\">Mirzę Ghulama Ahmada</a> z <a href=\"https://pl.wikipedia.org/wiki/Qadian\" target=\"_blank\" rel=\"noopener noreferrer\">Qadian</a> (1839–1908) (<a href=\"https://pl.wikipedia.org/wiki/Pend%C5%BCab\" target=\"_blank\" rel=\"noopener noreferrer\">Pendżab</a>), który ogłosił się (zgodnie z objawieniami otrzymywanymi od 1865 roku) <a href=\"https://pl.wikipedia.org/wiki/Mahdi\" target=\"_blank\" rel=\"noopener noreferrer\">mahdim</a> i powtórnie przybyłym <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusem</a>, później zaś także <a href=\"https://pl.wikipedia.org/wiki/Inkarnacja\" target=\"_blank\" rel=\"noopener noreferrer\">inkarnacją</a> <a href=\"https://pl.wikipedia.org/wiki/Kryszna\" target=\"_blank\" rel=\"noopener noreferrer\">Kryszny</a>. Ruch w 1900 roku został oficjalnie uznany przez władze brytyjsko-indyjskie.", "Abdul Azim": "<p>'Abd al-ʻAẓīm (ALA-LC) to męskie muzułmańskie imię. Został zbudowany z arabskich słów ʿabd i al-ʻAẓīm, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Ameer Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ameer</b>.</p><p>Emir (; arabski: أمير ʾAmīr [ʔæˈmiːr]), czasami przenoszony do Amir, Amier lub Ameer, jest szlachectwem lub szlachetnym urzędnikiem używanym w wielu regionach w krajach Arabskich. Dosłownie oznacza to dowódca, generał, król lub król.</p>", "Andrew Robert": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrew</b>.</p><p>Andrew może odnosić się do: Św. Andrew: jeden z dwunastu apostołów Jezusa Andrew Johnson: 17 prezydent Stanów Zjednoczonych i w pełni od 1865 do 1867 roku Andrew Jackson</p>", "Arlet": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arleta</b>.</p><b>Arleta</b>, <b>Arletta</b> – imię żeńskie zapożyczone z francuskiego; powstało prawdopodobnie jako zdrobnienie germańskiego imienia <i>Carletta</i> (<i>Karletta</i>), żeńskiej formy imienia Karl (<a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>).", "Assef": "<p>Asif (arabski: آصف) to arabskie męskie imię. W językach perskim i urdu często wymawia się jako \"Asif\" lub \"Asef\".</p>", "Ananya": "<p>Ananya jest powszechnym angielskim pisownią dwóch indyjskich nazw: męskiej अनन्य ananya i kobiecej अनन्या ananyā. Znaczenie imienia Ananya jest \"unikalne\".</p>", "Alfonso Carlos": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alfonso</b>.</p><p>Alfonso jest 3rd classmostem w prowincji Cavite, w Filipinach. Według zeszłej ankiety populacyjnej z Filipin, mieście to liczy 47,973 mieszkańców na obszarze 70 km2.</p>", "Asif Khan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Asif</b>.</p><p>Asif (arabski: آصف) to arabskie męskie imię. W językach perskim i urdu często wymawia się jako \"Asif\" lub \"Asef\".</p>", "Adalia": "<p>Adalia (lat. Adalia) - rodzaj boskich krowy z podrodzin Coccinellinae.</p>", "Andrzej Janusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrzej</b>.</p><b>Andrzej</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od greckiego imienia Andréas, którego rdzeń <i>andr-</i> nawiązuje do znaczenia: „człowiek, mężczyzna, taki jak mężczyzna” (inne źródło tłumaczy go jako „dzielny, mężny”). To greckie imię Andréas nosił jeden z <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostołów</a>, brat Szymona Piotra. Imię występuje także w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a>. W języku polskim przybrał formę Andrzej<b>.</b>", "Adam Piotr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adam</b>.</p><b>Adam</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> אדום <i>adom</i> oznacza „czerwony”, od koloru ziemi, z której <a href=\"https://pl.wikipedia.org/wiki/Adam_i_Ewa\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a> był ulepiony. Bardziej jednak prawdopodobne, że <i>Adam</i> wywodzi się od hebrajskiego słowa <i>adamah</i>, które oznacza „ziemię, rolę”, wtedy znaczyłoby „rolnik”, albo „że człowiek, z ziemi powstały, do ziemi wróci”. W takim ujęciu, używane jest zazwyczaj w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>, chociaż w początkowych rozdziałach Starego Testamentu przyjęło się traktować je jako imię własne. Także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_a%C5%82tajskie\" target=\"_blank\" rel=\"noopener noreferrer\">językach ałtajskich</a> słowo <i>adam</i> oznacza „człowiek”. Współcześnie dopatruje się pochodzenia imienia w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a>, w którym miał oznaczać „mój ojciec” (od <i>ada.mu</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akadyjskim</a> „zbudowany”, lub „zrodzony”', a także w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskim</a> „łączyć się” (od <i>adama</i>).", "Adrian-Cătălin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Ali̇ Cem": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Anastase": "<p>Anastase jest męskim imieniem pochodzącym z starożytnego greckiego Anastasíā. Może odnosić się do:</p>", "Abdussamad": "<p>Abdul Samad Abdul Samed, itp. Można go przenieść na \"sługa samostanowionego Mistrza\" lub \"sługowiec Wiecznego Schronienia\".</p>", "Anh Tùng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Abdelaali": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdelali</b>.</p><p>'Abd al-ʻAlī (ALA-LC romanizacja arabskiej: عبد العلي, perskiego: عبدالعلی), również pisowany jako Abd ul Ali, Abd ul-Ali, Abd ol Ali i Abd ol-Ali, to męskie muzułmańskie imię. Został zbudowany z arabskich słów ʿabd i al-ʻAlī, jednego z imion Boga w Koranie, które dają początek muzułmańskich nazw teoforycznych.</p>", "Agnieszka": "<b>Agnieszka</b> – imię żeńskie, jedno z najpopularniejszych w Polsce, gdzie pojawiło się wraz z chrześcijaństwem. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγνή – „czysta”, „dziewicza”, „nieskalana”. Może również pochodzić od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>agnus</em> – „baranek” (to jednocześnie rodzaj męski greckiej „h-agne”). Do Czech imię to dotarło w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Agnes</em>, następnie zostało zaadaptowane do języka polskiego w obecnej formie. Imię to funkcjonuje również w języku polskim w formie Inka, początkowo było ono polskim zdrobnieniem imienia Inez — francusko-iberyjskiej formy imienia Agnieszka (Inês, Inés, Inès) — z czasem jednak zaczęło funkcjonować w Polsce jako samodzielne imię.", "Agata": "<b>Agata</b> – imię żeńskie, pochodzące od przymiotnika <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;ἀγαθός („dobry”), w Polsce znane od XIII wieku.", "Aneta": "<b>Aneta</b>, <b>Anetta</b> – forma pochodna imienia <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anna</a>, powstała jako przeniesienie francuskiego zdrobnienia tego imienia, <i>Anette</i>, do języka polskiego. Pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>. Imię dotarło do Polski w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX w.</a>, wcześniej używano tylko imienia Anna.", "Angelika": "<b>Angelika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, w języku łacińskim oznacza „anielica”, „posłanka”.", "Aniela": "<b>Aniela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które jest spolszczoną formą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa <i>ángelos</i> „posłaniec”. Imię trafiło do Polski z Włoch prawdopodobnie w XVIII wieku. W świecie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> upowszechniło się jako nawiązanie do <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">aniołów</a> i <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_Str%C3%B3%C5%BC_(religioznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioła Stróża</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>.", "Adrianna": "<b>Adrianna</b>, <b>Adriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Adrian_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adrian</a>, które pojawiło się w średniowieczu. Pochodzi od męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadrian</a> lub Adrian, to znaczy <i>należący do miasta Hadrii</i> w Picenum (Włochy). Częściej – w formie Adrian – nadawano je chłopcom. Jako imię żeńskie w zapiskach po raz pierwszy znalazło się około 1350 roku.", "Anastazja": "<b>Anastazja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anastazy\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazy</a>. Oznacza „zmartwychwstała, wskrzeszona”.", "Aldona": "<b>Aldona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzi ono od staropruskiego miana <i>Aldegut</i> lub białoruskiego <i>Ałdonia</i>, będącego przekształceniem greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Eudoksja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eudokia</a> (Eudocja). Nosiło je wiele księżniczek litewskich wydawanych za polskich książąt (głównie mazowieckich).", "Aurelia": "<b>Aurelia</b> – imię żeńskie pochodzące od nazwy rzymskiego rodu Aurelia, która z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>aureolus</em> – „złocisty, złoty”, co mogło znaczyć także „wspaniały”.", "Andżelika": "<b>Angelika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, w języku łacińskim oznacza „anielica”, „posłanka”.", "Apolonia": "<b>Apolonia</b> – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające osobę należącą do boga <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apolla</a>. W <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">starożytności</a> mogło także pochodzić od nazwy miasta (dotyczy wyzwoleńców).", "Adela": "<b>Adela</b> – imię żeńskie pochodzenia germańskiego. Jest ono skróconą formą dwuczłonowych imion takich jak Adalberga, <a href=\"https://pl.wikipedia.org/wiki/Adalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Adalgunda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelinda\" target=\"_blank\" rel=\"noopener noreferrer\">Adelinda</a>, tj. imion z pierwszym członem <i>adal</i> oznaczającym „szlachetny ród”, „szlachetny stan”. Skrócenie to powstało na gruncie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">języka francuskiego</a>.", "Arleta": "<b>Arleta</b>, <b>Arletta</b> – imię żeńskie zapożyczone z francuskiego; powstało prawdopodobnie jako zdrobnienie germańskiego imienia <i>Carletta</i> (<i>Karletta</i>), żeńskiej formy imienia Karl (<a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>).", "Alfreda": "<b>Alfreda</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Alfred\" target=\"_blank\" rel=\"noopener noreferrer\">Alfred</a>.", "Amanda": "<b>Amanda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, stanowiące żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Amand_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Amand</a>, wywodzące się od czasownika <i>amare</i> – „kochać” i oznaczające „ta, która powinna być kochana” lub „godna miłości”. Znane w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnym Rzymie</a>. W Niemczech rozpowszechnione w początkach XIX wieku. W <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanach Zjednoczonych</a> nadawane często. W Polsce notowane co najmniej od II połowy <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a>, a w średniowieczu znana była tylko męska forma Amandus(z). Imię nadal rzadkie w Polsce. W styczniu 2025 r. w rejestrze <a href=\"https://pl.wikipedia.org/wiki/PESEL\" target=\"_blank\" rel=\"noopener noreferrer\">PESEL</a>, wśród publicznie dostępnych danych dotyczących osób żyjących, wykazano 5766 kobiet o imieniu Amanda nadanym jako imię pierwsze.", "Adelajda": "<b>Adelajda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Składa się z elementów <i>adal</i> \"ród, ród szlachetny\" i <i>heit</i> \"osoba, stan, rodzaj\" i oznaczać mogło osobę wywodzącą się ze szlachetnego rodu.", "Angela": "<b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Adelina": "<b>Adelina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, utworzone za pomocą zdrabniającego przyrostka <i>-ina</i> od imienia <a href=\"https://pl.wikipedia.org/wiki/Adela\" target=\"_blank\" rel=\"noopener noreferrer\">Adela</a>.", "Amina": "<p>Amina (ang. Amina, Aminatu, 1533 - około 1610) - rządnica (od 1576 roku) muzułmańskiego państwa Zazzau (Zaria) w Centralnym Sudanie, jednym z miast-państw narodu chaus.</p>", "Arletta": "<b>Arleta</b>, <b>Arletta</b> – imię żeńskie zapożyczone z francuskiego; powstało prawdopodobnie jako zdrobnienie germańskiego imienia <i>Carletta</i> (<i>Karletta</i>), żeńskiej formy imienia Karl (<a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>).", "Aurora": "<b>Aurora</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> oznaczające „zorzę poranną, jutrzenkę”. Imię pochodzi od bogini <a href=\"https://pl.wikipedia.org/wiki/Aurora_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Aurory</a>, identyfikowanej później z grecką <a href=\"https://pl.wikipedia.org/wiki/Eos_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Eos</a>.", "Alice": "<p>Alice lub ALICE: Alice (język programowania) - dialekt języka Standard ML. Alice to marka firmy Telecom Italia.</p>", "Ariana": "<b>Ariana</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Arian\" target=\"_blank\" rel=\"noopener noreferrer\">Arian</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Arianna, Ariana, Ariane w jęz. angielskim, francuskim i włoskim to odpowiedniki imienia <a href=\"https://pl.wikipedia.org/wiki/Ariadna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ariadna</a>.", "Alicia": "<b>Alicia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskiego</a>.", "Amalia": "Odpowiedniki w innych językach:", "Andriana": "<p>Andriana to rodzaj roślin kwiatowych z rodziny Apiaceae.</p>", "Alesia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksandra</b>.</p><b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Anika": "<b>Anika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, jedna ze zdrobniałych form imienia <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anna</a> m.in. w jęz. duńskim i holenderskim.", "Augustyna": "<b>Augustyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Augustyn\" target=\"_blank\" rel=\"noopener noreferrer\">Augustyn</a>.", "Angelica": "<p>Dudnik, czyli aniolica (lat. Angélica) - rodzaj trawniczośnych roślin rodziny Zontickich (Apiaceae).</p>", "Ariadna": "<p>Ariadna jest pająkiem z rodziny Segestriidae.</p>", "Aida": "<b>Aida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnym pochodzeniu, być może arabskim albo greckim lub twór literacki.", "Ania": "<p>Tainia (lat. Tainia) - rodzaj jednokładnych roślin z rodu rodziny Orchid (Orchidaceae).</p>", "Alma": "<p>Alma (lat. Alma - ⁇ krmiąca, karmiąca.</p>", "Arianna": "<b>Ariadna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<i>Ἀριάδνη</i> gr. <i>ari</i> – „naj”, <i>adne</i> – „czysta, święta, szlachetna”). Patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Ariadna_(m%C4%99czennica)\" target=\"_blank\" rel=\"noopener noreferrer\">Ariadna</a> z <a href=\"https://pl.wikipedia.org/wiki/Frygia\" target=\"_blank\" rel=\"noopener noreferrer\">Frygii</a> (zm. w roku 130).", "Astrid": "<b>Astryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronorweskich</a> wyrazów <i>áss</i> – „bóg” i <i>fríðr</i> – „piękna” (mogło zatem oznaczać „piękna jak bóg”). Patronką tego imienia jest bł. Astryda.", "Aisha": "<p>Aia Andrzejeva (lat. Aija Andrejeva; rod.</p>", "Andżelina": "<b>Angelina</b> – forma pochodna <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>.", "Amelie": "<p>⁇ Ameli ⁇ (francuski: Améli ⁇). Le Fabuleux Destin d'Amélie Poulain z fr.</p>", "Adamina": "<b>Adamina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a>/<a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> <a href=\"https://pl.wikipedia.org/wiki/Adam\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a>. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> 6 kwietnia, <a href=\"https://pl.wikipedia.org/wiki/16_maja\" target=\"_blank\" rel=\"noopener noreferrer\">16 maja</a> i <a href=\"https://pl.wikipedia.org/wiki/24_grudnia\" target=\"_blank\" rel=\"noopener noreferrer\">24 grudnia</a>. Imię pochodzi z języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> i oznacza ono \"człowiek\", a w znaczeniu biblijnym \"pierwszy człowiek od <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g_Ojciec\" target=\"_blank\" rel=\"noopener noreferrer\">Boga</a>\".", "Augusta": "<b>Augusta</b> – imię łacińskiego pochodzenia, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/August_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">August</a>. W Polsce rzadko używane.", "Anna-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aniceta": "<b>Aniceta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anicet\" target=\"_blank\" rel=\"noopener noreferrer\">Anicet</a>, które z kolei jest zlatynizowaną formą greckiego imienia Aniketos (Ἀνίκητος) oznaczającego „niepokonany”. Jego patronem jest m.in. jeden z wczesnych <a href=\"https://pl.wikipedia.org/wiki/Papie%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">papieży</a>, <a href=\"https://pl.wikipedia.org/wiki/Anicet_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Anicet</a>.", "Ameliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amelia</b>.</p><b>Amelia</b>, <b><a href=\"https://pl.wikipedia.org/wiki/Amalia\" target=\"_blank\" rel=\"noopener noreferrer\">Amalia</a></b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako skrócenie imion dwuczłonowych z pierwszym członem <i>Amal-</i>, takich jak między innymi <a href=\"https://pl.wikipedia.org/wiki/Amalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Amalgunda</a> lub <a href=\"https://pl.wikipedia.org/wiki/Amalberga\" target=\"_blank\" rel=\"noopener noreferrer\">Amalberga</a>.", "Ava": "<p>Angels &amp; Airwaves - zespół rock'n'roll założony w 2005 roku przez gitarzystę Blink-182 Toma Delonga. W pierwszym składzie zespołu wchodził jego przyjaciel i były gitarzysta Box Car Racer, David Kennedy, bębniarz Atom Willard, który wcześniej grał w The Offspring i były basista Distillers Ryan Synn.</p>", "Anja": "<b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aya": "<b>Aya</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あや, アカネ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Aurela": "<p>Aurela (znana ICAO = LSK) jest lotniczą linią lotniczą Litwy, z siedzibą w Vilnius. Transportery subskrybują podróżne firmy z krajów Bałtyku.</p>", "Arlena": "<b>Arlena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, którego pochodzenie jest niepewne. Być może wywodzi się od <i>Arlene</i>, co oznacza w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_irlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">języku irlandzkim</a> „gwarancję, zobowiązanie”. Imię to może być też skróconą formą imion żeńskich kończących się na -arlena, np. <a href=\"https://pl.wikipedia.org/wiki/Marlena\" target=\"_blank\" rel=\"noopener noreferrer\">Marlena</a>. Istnieje też hipoteza, jakoby imię to miało być wariantem <i>Arline</i>, imienia prawdopodobnie wymyślonego przez mało znanego kompozytora irlandzkiego <a href=\"https://pl.wikipedia.org/wiki/Michael_William_Balfe\" target=\"_blank\" rel=\"noopener noreferrer\">Michaela Williama Balfego</a> dla głównej bohaterki najbardziej znanej jego opery „Czeszka” (<i>The Bohemian girl</i>).", "Asia": "<p>Azja - część świata, która wraz z Europą tworzy kontynent Eurazja. Termin może również oznaczać:</p>", "Agatha": "<p>Agatha (Agafia, angielski Agatha) - żona Edwarda Izgannika, dziedzica tronu angielskiego, i matka Edgar Ethelinga i Margarity Świętej, królowej Szkocji.</p>", "Ałła": "<b>Alla</b>, <i>Ałła</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie prawdopodobnie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> i wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;άλλη – „inna”. Używane przede wszystkim w Rosji, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a> i <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a>.", "Alojza": "<b>Alojza</b>, <b>Alojzja</b> – imię żeńskie pochodzenia germańskiego.", "Amaliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amalia</b>.</p>Odpowiedniki w innych językach:", "Albertyna": "<b>Albertyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Albert_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Albert</a>, pierwotnie zdrobnienie od żeńskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Alberta_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Alberta</a>. Patronką tego imienia jest bł. <a href=\"https://pl.wikipedia.org/wiki/Albertyna_Berkenbrock\" target=\"_blank\" rel=\"noopener noreferrer\">Albertyna Berkenbrock</a>.", "Anna-Maria": "<p>⁇ Anna-Maria ⁇ (ukraińska: Анна-Марія) - ukraiński muzyczny duet sióstr bliźniaków Anna i Marii Opanaсюk, założony w 2004 roku.</p>", "Adele": "<p>Adele Laurie Blue Edkins (ang. Adele Laurie Blue Adkins; rodzaj.</p>", "Andreea": "<p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Atena": "<b>Atena</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Ἀθηνή Athene, Ἀθηναίη Athenaie, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> Minerva) – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> bogini <a href=\"https://pl.wikipedia.org/wiki/M%C4%85dro%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">mądrości</a>, <a href=\"https://pl.wikipedia.org/wiki/Sztuka\" target=\"_blank\" rel=\"noopener noreferrer\">sztuki</a>, sprawiedliwej wojny oraz opiekunka miast, m.in. <a href=\"https://pl.wikipedia.org/wiki/Ateny\" target=\"_blank\" rel=\"noopener noreferrer\">Aten</a> i <a href=\"https://pl.wikipedia.org/wiki/Sparta\" target=\"_blank\" rel=\"noopener noreferrer\">Sparty</a>. Jest jedną z dwunastu głównych bogów olimpijskich. Jej atrybutami są: włócznia, tarcza i łuk. Jej świętym zwierzęciem jest <a href=\"https://pl.wikipedia.org/wiki/Sowa_Ateny\" target=\"_blank\" rel=\"noopener noreferrer\">sowa</a>, a rośliną – oliwka. Jej rzymskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Minerwa\" target=\"_blank\" rel=\"noopener noreferrer\">Minerwa</a>.", "Aliya": "<p>Alija, Aaliyah, Alia lub Aliyah (arabickie: عَلِيَّة lub عَالِيَّۃ) to arabskie kobiece imię. Jest to kobiece imię Ali, co oznacza \"wysoki\", \"wywyższony\", \"wyniosły\", \"wzniosły\" lub \"wzrastający\".</p>", "Adolfina": "<b>Adolfina</b> – żeński odpowiednik (obok <a href=\"https://pl.wikipedia.org/wiki/Adolfa\" target=\"_blank\" rel=\"noopener noreferrer\">Adolfy</a>) <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Adolf\" target=\"_blank\" rel=\"noopener noreferrer\">Adolf</a>.", "Alexia": "<p>Aleksja (włoski: Alexia). Alexia, imię urodzone. Alessia Aquilani, rodzina.</p>", "Anatola": "<b>Anatolia</b>, <b>Anatola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające \"pochodząca ze wschodu, wschodnia\".", "Alana": "<b>Alana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, odpowiednik męski: <a href=\"https://pl.wikipedia.org/wiki/Alan\" target=\"_blank\" rel=\"noopener noreferrer\">Alan</a>.", "Andżela": "<b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Anya": "<p>Anya, Ania lub Anja to imię. Nazwa jest kobieca w większości krajów Europy Wschodniej, a unisex w kilku krajach afrykańskich.</p>", "Alisiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alisia</b>.</p><p>Alicia to kobiece imię. Jest to wariant Alice, który pochodzi z germańskiego imienia Adalheidis (Adelaide), co oznacza \"szlachetny natury\" (szlachetnego rodzaju).</p>", "Anatolia": "<p>Azja Malwa (Grzecko: Μικρά Ασία Mikra Asia), lub Anatolia (Ανατολία, co oznacza \"sunne wschody\", \"wschodnie\") to półwyspie Azji, które jest obecnie w terytorium Turcji, na północ od Morza Czarnego, na południe od Morza Śródziemnego, oddzielone od Europy przez Morze Egejskie i Morze Marmara (należące do Morza Środziemnego) na zachodzie i obciążone przez pozostałe duże tereny Azji na wschodzie. W czasach Nowego Kamienia Anatolia była jednym z najbardziej niskich...</p>", "Angie": "<p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Anfisa": "<b>Antuza</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od gr. <i>Ανθουσα (Anthousa)</i>, które pochodzi od słowa <i>ανθος (anthos)</i> – „kwiat”. Patronką tego imienia jest św. Antuza (ur. 751 w <a href=\"https://pl.wikipedia.org/wiki/Konstantynopol\" target=\"_blank\" rel=\"noopener noreferrer\">Konstantynopolu</a>, zm. 801 także).", "Ariela": "<b>Ariela</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ariel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ariel</a>. Posiadaczka imienia <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/16_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">16 listopada</a>.", "Adolfa": "<b>Adolfa</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Adolf\" target=\"_blank\" rel=\"noopener noreferrer\">Adolf</a> (o znaczeniu „szlachetny wilk”).", "Anabella": "<b>Anabella</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> utworzone wtórnie na gruncie anglosaskim spopularyzowane w literaturze i mediach. Imię to pochodzi od złożenia dwóch innych: Anny, z hebrajskiego <i>hannah</i> – pełna łaski i Izabeli – hiszpańskiej wersji imienia Isabel - (Jezabel) pochodzącej od hebrajskiego Eliszebeth od którego pochodzi także Elżbieta. W Polsce imię to pojawiło się razem z wpływami francuskimi (Izabelle) - <i>belle</i> po francusku znaczy piękna.", "Areta": "<b>Areta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie niejasnego pochodzenia. <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Bubak\" target=\"_blank\" rel=\"noopener noreferrer\">Józef Bubak</a> łączy je ze skróconą formą <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a> (niem. <i>Margareta</i>), powstałą na gruncie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a>. Imię to nosiła także <a href=\"https://pl.wikipedia.org/wiki/Arete_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">postać z mitologii greckiej</a>, królowa <a href=\"https://pl.wikipedia.org/wiki/Feakowie\" target=\"_blank\" rel=\"noopener noreferrer\">Feaków</a>, której imię stanowi przymiotnik odczasownikowy od wyrazu <i>αραομαι (araomai)</i> („modlę się o coś, gorąco pragnę”) i oznacza „dziecko upragnione”(por. <a href=\"https://pl.wikipedia.org/wiki/Dezyderia\" target=\"_blank\" rel=\"noopener noreferrer\">Dezyderia</a>, <a href=\"https://pl.wikipedia.org/wiki/Aspazja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Aspazja</a>). Można także spotkać się z poglądem, iż imię to pochodzi od greckiego słowa <i>αρετη (<a href=\"https://pl.wikipedia.org/wiki/Aret%C3%A9\" target=\"_blank\" rel=\"noopener noreferrer\">areté</a>)</i> oznaczającego „cnotę”, „męstwo”; Areta stanowiłaby wówczas żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Aretas\" target=\"_blank\" rel=\"noopener noreferrer\">Aretas</a>.", "Alexa": "<b>Alexa Internet</b>, <b>Alexa</b> – <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańska</a> spółka, funkcjonująca w latach 1996–2022, kontrolowana przez <a href=\"https://pl.wikipedia.org/wiki/Amazon.com\" target=\"_blank\" rel=\"noopener noreferrer\">Amazon.com</a>, prowadząca witrynę <i>Alexa</i>, która dostarczała informacje na temat ruchu sieciowego na stronach internetowych oraz udostępniała rankingi najpopularniejszych serwisów ostatniego miesiąca. Sam serwis był notowany w tym rankingu na miejscu 3195 (czerwiec 2020).", "Amélie": "<p>Cudowne życie Amélie Poulain (Francuz: Le Fabuleux Destin d'Amélie Poulain, skrócona jako Amélie) to francuski film komedy romantyczny, który został zrealizowany przez Jean-Pierre Jeunet. Film ten, który rozgrywa się w Paryżu, opowiada historię Amélie Poulain, jasnej, życzliwej dziewczyny, która niewiele planowała, ale przynosiła ogromne zmiany ludziom.</p>", "Asya": "<p>Asya (rosyjski: Ася) to średni opowieść pisarza Ivana Turgenewa, urodzona w 1858 roku.</p>", "Antonella": "<b>Antonella</b> – imię żeńskie, będące <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_du%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">duńskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_norweski\" target=\"_blank\" rel=\"noopener noreferrer\">norweskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_szwedzki\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkim</a> <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnieniem</a> od imienia <a href=\"https://pl.wikipedia.org/wiki/Antonia\" target=\"_blank\" rel=\"noopener noreferrer\">Antonia</a>. Używane jest głównie w wielu krajach <a href=\"https://pl.wikipedia.org/wiki/Ameryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Południowej</a> i <a href=\"https://pl.wikipedia.org/wiki/Ameryka_%C5%9Arodkowa\" target=\"_blank\" rel=\"noopener noreferrer\">Środkowej</a>, różnych częściach <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a>, a także we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a>, <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">krajach skandynawskich</a>. Męskim odpowiednikiem tego imienia jest Antonello.", "Agustina": "<p>Agustyna to imię, żeńska wersja Augustyna. Jest to popularne nazwa w Argentynie, Indonezji i Urugwaju.</p>", "Alyona": "<p>Alyona (rosyjski: Алёна) lub Aliona to rosyjska kobieca nazwisko pochodzące od starożytnego greckiego imienia ⁇ λένη, Helenē (variant dialektyczny: ⁇ λένα, Helena). Zobacz \"Helen\" dla historii.</p>", "Alisha": "<p>Alice Ann Itkin (ang. Alisha Ann Itkin; po ślubie - Alice Sinamon (ang.</p>", "Aline": "<p>\"Aline\" to utwór w pojedynczym utworze piosenki francuskiego piosenkarza Christophe'a. Piosenka stała się jedną z dwóch najpopularniejszych piosenek we Francji w lecie 1965 roku wraz z \"Capri c'est fini\" Hervé Vilard.</p>", "Adelia": "<p>Adelia borealis (lat. - rodzaj śpiewających cykadów rodza Adelia z rodziny Cicadidae (Auchenorrhyncha).</p>", "Alojzja": "<b>Alojza</b>, <b>Alojzja</b> – imię żeńskie pochodzenia germańskiego.", "Aaliyah": "<p>Aaliyah Dana Haughton (znana z imieniem Aali; 16 stycznia 1979, Brooklyn, Nowy Jork, USA - 25 sierpnia 2001, Bahamas) - amerykańska piosenkarka, aktorka i modelka.</p>", "Amaya": "<p>Amaya to wolny WYSIWYG edytor stron internetowych z wbudowanym przeglądarkiem internetowym (zapewniony tylko dla wygodności edycji), opracowany przez konsorcjum W3C. Dostępny dla systemów operacyjnych Linux, UNIX, Windows, Mac OS X.</p>", "Aidana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aidan</b>.</p><b>Aidan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia celtyckiego, od staroirlandzkiego <i>Áedán</i> – zdrobniałej formy imienia <i>Áed</i>, oznaczającego „płomień, ogień”. Jest to imię irlandzkiego świętego z <a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII</a> w.", "Alberta": "<p>Alberta: Alberta - prowincja Kanady. Alberta to miasto w Stanach Zjednoczonych.</p>", "Anais": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Allison": "<p>Allison Engine Company (w rosyjskiej transkrypcji - Allison) - amerykańska firma produkująca silniki lotnicze, która należała do General Motors, ale w 1992 roku GM postanowiła sprzedać Allison, aby skupić się na rynku samochodowym. Transakcja z Rolls-Royce plc została zawarta w 1995 roku, kiedy Allison Engine Company stała się jednym z podziałów Rolls- Royce. Firma produkuje również urządzenia, które...</p>", "Anelia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aneli</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anel</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anele</b>.</p><p>Anele to imię. Znanymi osobami z nazwiska są: Anele Lungisa (ur. 1992), gracz rugby południowoafrykański Anele Mdoda (ur. 1984), prezenterka telewizyjna południo Afryki Anele Ngcongca (1987-2020), piłkarz południowej Afryki</p>", "Anna Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anastazia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastazya</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastazy</b>.</p><b>Anastazy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „wskrzeszenie”, „zmartwychwstanie”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Anastazja\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazja</a>.", "Aigul": "<p>Aigul (Ai (księżyc) + Gül (kwiat), rosyjski: Айгуль) to turkijska kobieca nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Arnika": "<b>Arnika</b> (<i>Arnica</i> <a href=\"https://pl.wikipedia.org/wiki/Karol_Linneusz\" target=\"_blank\" rel=\"noopener noreferrer\">L.</a>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin należących do rodziny <a href=\"https://pl.wikipedia.org/wiki/Astrowate\" target=\"_blank\" rel=\"noopener noreferrer\">astrowatych</a>. Należy do niego 31 gatunków roślin. Przedstawiciele tego rodzaju występują głównie na terenie <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a>, tylko dwa gatunki pochodzą z <a href=\"https://pl.wikipedia.org/wiki/Eurazja\" target=\"_blank\" rel=\"noopener noreferrer\">Eurazji</a> (<i>A. montana</i>, <i>A. angustifolia</i>). Rośliny te rosną głównie w górach, sięgają także strefy arktycznej na północy. We <a href=\"https://pl.wikipedia.org/wiki/Flora_ro%C5%9Blin_naczyniowych_Polski\" target=\"_blank\" rel=\"noopener noreferrer\">florze Polski</a> występuje tylko jeden gatunek – <a href=\"https://pl.wikipedia.org/wiki/Arnika_g%C3%B3rska\" target=\"_blank\" rel=\"noopener noreferrer\">arnika górska</a> <i>Arnica montana</i>.", "Anastassiya": "<p>Anastassiya to imię kobiece. Wśród znanych osób z tym nazwiskiem są: Anastassiya Bannova (ur. 1989), kazachstaniczna łukarka Anastassiya Batuyeva (ur. 1987), kazachstanka piłkarka handbalisty Anastassiya Krestova (ur., 1996), kazachska skaterka prędkości na krótkim torze Anastassiya Prilepa (ur. 1990), kazachstańska pływaczka Anastassiya Rodina (ur. 1991), kazachskie piłkarko Anastassiya Rostovchshikova (ur.).</p>", "Adeliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adelia</b>.</p><p>Adelia borealis (lat. - rodzaj śpiewających cykadów rodza Adelia z rodziny Cicadidae (Auchenorrhyncha).</p>", "Annabella": "<p>Annabella (Annabella, 14 lipca 1907 - 18 września 1996), urodzona jako Suzanne Georgette Charpentier (francuski: Suzanne Georjette Charpentie) - francuska aktorka, filmowała we Francji i w Hollywood.</p>", "Aysel": "<p>Aysel Məhəmməd qızı Teymurzadə (Azerbaijan) - azerbaijanka R\"n\"B piosenkarka.</p>", "Anzelma": "<b>Anzelma</b> (znane też w formie <i>Selma</i>) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anzelm_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anzelm</a>. W niektórych krajach jako zdrobnienie od tego imienia funkcjonuje forma Selma.", "Athina": "<p>Athina jest odmianą literacki Atheny, a także jest w języku greckim nowoczesnym nazwą transliteratywnym Aten. Athina może być: Główna godzina Athina, australijska MS Athina B, w 1980 roku wylądowała w Brighton.</p>", "Asiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asia</b>.</p><p>Azja - część świata, która wraz z Europą tworzy kontynent Eurazja. Termin może również oznaczać:</p>", "Alodia": "<b>Alodia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, wywodzące się prawdopodobnie od <a href=\"https://pl.wikipedia.org/wiki/Frankowie\" target=\"_blank\" rel=\"noopener noreferrer\">frankońskiego</a> <i>al-ôd</i>, co oznacza \"dziedzictwo, pełne posiadanie\". Imię to łączy się także ze średniowiecznym <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskim</a> wyrazem <i><a href=\"https://pl.wikipedia.org/wiki/Alodium\" target=\"_blank\" rel=\"noopener noreferrer\">allodium</a></i>, który oznaczał \"majątek ziemski wolny od ciężarów i powinności lennych\", a pochodzi również od tego samego wyrazu frankońskiego.", "Ameliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amelia</b>.</p><b>Amelia</b>, <b><a href=\"https://pl.wikipedia.org/wiki/Amalia\" target=\"_blank\" rel=\"noopener noreferrer\">Amalia</a></b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako skrócenie imion dwuczłonowych z pierwszym członem <i>Amal-</i>, takich jak między innymi <a href=\"https://pl.wikipedia.org/wiki/Amalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Amalgunda</a> lub <a href=\"https://pl.wikipedia.org/wiki/Amalberga\" target=\"_blank\" rel=\"noopener noreferrer\">Amalberga</a>.", "Athena": "<p>Athena [Атэна] - (ang. ⁇ Афина ⁇) - turecka (sk) grupa punk-rock.</p>", "Anka": "<b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Almira": "<p>Almira, Königin von Castilien, HWV 1 (wietn. Almira, Królowa Kastilii, pełna nazwa Der w Krohnen erlangte Glücks-Wechsel, oder: Almira, Königigin von Castilian) jest pierwszą operą niemieckiego angielskiego kompozytora George'a Frideric Handel'a. Autorem jest Christian Feustking.</p>", "Angelique": "<p>Angelique (jap. アンジェリーク Anдзери:ku) - nazwa serii symulatorów związków romantycznych dla kobiet, z których motywami zostały zarysowane TV i OVA.</p>", "Adina": "<p>Adina (lat. Adina) - rodzaj drewnianych roślin z rodziny Marenowych (Rubiaceae).</p>", "Alida": "<b>Adelajda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Składa się z elementów <i>adal</i> \"ród, ród szlachetny\" i <i>heit</i> \"osoba, stan, rodzaj\" i oznaczać mogło osobę wywodzącą się ze szlachetnego rodu.", "Astryda": "<b>Astryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronorweskich</a> wyrazów <i>áss</i> – „bóg” i <i>fríðr</i> – „piękna” (mogło zatem oznaczać „piękna jak bóg”). Patronką tego imienia jest bł. Astryda.", "Aileen": "<p>Aileen to irlandzkie imię żeńskie, wariant Eileen. Znani ludzie z tego nazwiska to: Aileen Adams (ur. 1923), brytyjska konsultantka anestetyka Aileen Allen (1888-1950), amerykańska nurkaczka Aileen Armitage (ur. 1930), brytyjska pisarka i autorka Aileen Baviera (1959-2020), filipinański politolog i sinolog Aileen Bernal (ur. 1994), panamska modelka i zwycięzca konkursu pięknowego Aileen Britton (1916-1986), australijska...</p>", "Aina": "<p>Aina to progresywny metal zespół utworzony przez Sasha Paeta z udziałem wielu zaproszonych muzyków, wśród których Glenn Hughes, Michael Kiske i Candace Knight. W wyniku wspólnej pracy powstała metalowa opera Days of Rising Doom, która została wydana w 2003 roku pod wytwórniami Transmission i The End Records.</p>", "Anne-Marie": "<p>Ann-Marie Rose Nicholson (ang. Anne-Marie Rose Nicholson; rodzaj.</p>", "Aura": "<p>⁇ Aura ⁇ (rosyjski: Аура) - piosenka amerykańskiej piosenkarki i autorki Lady Gaga z jej trzeciego albumu studiowego Artpop.</p>", "Alwina": "<b>Alwina</b> – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">staroangielskiego</a> imienia <b>Ælfwine</b> (<i>przyjaciel <a href=\"https://pl.wikipedia.org/wiki/Elf_(fantastyka)\" target=\"_blank\" rel=\"noopener noreferrer\">elfów</a></i>). <b>Alwina</b> jest również skróconą formą imienia <a href=\"https://pl.wikipedia.org/wiki/Adalwina\" target=\"_blank\" rel=\"noopener noreferrer\">Adalwina</a>.", "Aliyah": "<p>Aliyah to imigracja Żydów do Ziemi Izraela (Eretz Yisrael). Jest to podstawowa zasada żydowskiej myśli i ważny element judaizmu.</p>", "Andrzeja": "<b>Andrzeja</b>, <b>Ondrzeja</b>, <b>Anda</b> – polskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Dzisiaj raczej rzadko spotykane (według materiałów Instytutu Języka Polskiego <a href=\"https://pl.wikipedia.org/wiki/Polska_Akademia_Nauk\" target=\"_blank\" rel=\"noopener noreferrer\">PAN</a> w roku <a href=\"https://pl.wikipedia.org/wiki/1998\" target=\"_blank\" rel=\"noopener noreferrer\">1998</a> imię to nosiło 78 mieszkanek Polski). Imię było bardziej popularne w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a>.", "Aliza": "<p>Aliza (Hebrajczy: עֲלִיזָה) jest kobiece imię, co oznacza \"wesołe\" w języku hebrajskim. Został używany jako tłumaczenie jiddish nazwy Freyde.</p>", "Anda": "<b>Andrzeja</b>, <b>Ondrzeja</b>, <b>Anda</b> – polskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Dzisiaj raczej rzadko spotykane (według materiałów Instytutu Języka Polskiego <a href=\"https://pl.wikipedia.org/wiki/Polska_Akademia_Nauk\" target=\"_blank\" rel=\"noopener noreferrer\">PAN</a> w roku <a href=\"https://pl.wikipedia.org/wiki/1998\" target=\"_blank\" rel=\"noopener noreferrer\">1998</a> imię to nosiło 78 mieszkanek Polski). Imię było bardziej popularne w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a>.", "Azra": "<p>Azra - jugosławski z Zagrzebu (wówczas Sosyjalistyczna Republika Chorwacji), który był popularny w latach 80. Zespół został utworzony w 1977 roku przez frontmena Branimira ⁇ Johnni ⁇ Štuliccha (Branimir Štulić).</p>", "Ariane": "<p>⁇ Arian ⁇ (francuski Ariane - od francuskiego wersji pisma postaci mitologicznej Ariadne) - rodzina rakiet kosmicznych nosiących Europejską Agencję Kosmiczną (EKA), przeznaczonych do wyciągania na niskie, średnie i geostacjonarne orbity aparatów kosmicznych różnej klasy (w tym grupy KA).</p>", "Armina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Armin</b>.</p><b>Armin</b> – oboczna forma imienia <a href=\"https://pl.wikipedia.org/wiki/Herman\" target=\"_blank\" rel=\"noopener noreferrer\">Herman</a>.", "Anabelle": "<p>Anabelle to kobiece imię. Znani ludzie z tym nazwiskiem: Anabelle Acosta, kubańsko-amerykańska aktorka Anabelle Ghabach, australijska piłkarka, Anabelle Langlois, kanadyjska patinarka pary, Anabelle Prawerman, francuska piłkarzka z siatkówki plażowej Anabelle Rodríguez, poratorka z Puerto Rico, murycyjska polityka Anabelle Smith, australijski nurkownik</p>", "Asenata": "<b>Asenata</b> – pochodzące z <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia egipskiego, oznaczające prawdopodobnie \"ta, która należy do swojego ojca\".", "Atina": "<p>Atina jest miastem w prowincji Frosinone w włoskiej regionie Lazio. Miasto ma powierzchnię 29 km2, ludności 4480 osób.</p>", "Alisia": "<p>Alicia to kobiece imię. Jest to wariant Alice, który pochodzi z germańskiego imienia Adalheidis (Adelaide), co oznacza \"szlachetny natury\" (szlachetnego rodzaju).</p>", "Aisel": "<p>Aysel to kobiece turskie imię popularne w Turcji i Azerbejdżanie. W języku tureckim \"Aysel\" pochodzi od Ay-sili i oznacza piękny księżyc lub księżyc piękno.</p>", "Ariella": "<p>Ariella to kobieca wersja płciowo neutralnego hebrajskiego imienia Ariel. Ariela to alternatywne pisowni.</p>", "Aelita": "<p>Aelita to imię kobiety.  ⁇ Aelita ⁇ - powieść A.</p>", "Agrypina": "<b>Agrypina, Agryppina</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>Αγριππίνα)</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Oznacza 'należąca do <a href=\"https://pl.wikipedia.org/wiki/Agryppa_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Agryppy</a>'. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Agrypin\" target=\"_blank\" rel=\"noopener noreferrer\">Agrypin</a>. Wśród świętych m.in. <a href=\"https://pl.wikipedia.org/wiki/Agrypina_(%C5%9Bwi%C4%99ta)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Agrypina</a>, męczennica, z <a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wieku</a>.", "Anaya": "<p>Anaya jest miastem w prowincji Segovia, Kastilia i Leon, Hiszpania. Według badania ludności z 2004 roku przeprowadzonego przez Hiszpański Instytut Statystyczny Narodowy, mieście to miało 136 mieszkańców.</p>", "Aneliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anelia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aneli</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anel</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anele</b>.</p><p>Anele to imię. Znanymi osobami z nazwiska są: Anele Lungisa (ur. 1992), gracz rugby południowoafrykański Anele Mdoda (ur. 1984), prezenterka telewizyjna południo Afryki Anele Ngcongca (1987-2020), piłkarz południowej Afryki</p>", "Andreia": "<p>Andréia (lub Andreia) to portugalskie imię dla kobiet. Dla starożytnego greckiego terminu ἀνδρεία lub andreia, patrz Odwaga.</p>", "Amna": "<p>Amna lub Aamna mnæ]) to arabskie imię żeńskie, które oznacza bezpieczne, opiekuńcze i uczciwe. To jest wariant transliteracji Amina.</p>", "Ayshat": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aishat</b>.</p><p>Aisha (arabsko: عائشة, romanized: ʿʿʾishah, lit. 'żyjący' lub 'żyjący'; również pisowniane A'aisha, A'isha, Aischa, Aische, Aishah, Aishat, Aishath, Aicha, Aïcha, Aisya, Aisyah, Aiša, Ajša, Aixa, Ayesha, Aysha, Ayşe, Ayisha lub Iesha) jest arabską nazwą żeńską.</p>", "Ayse": "<p>Ayse jest gminą w prowincji Haute-Savoie w regionie Auvergne-Rhône-Alpes w południowo-wschodniej Francji.</p>", "Ayu": "<p>Ayumy Hamasaki (jap. 浜崎 あゆみ Hamasaki Ayumy, rodzaj.</p>", "Anouk": "<p>Anuk Teuve (np. Anouk Teeuwe; rodzaj.</p>", "Anabell": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anabella</b>.</p><b>Anabella</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> utworzone wtórnie na gruncie anglosaskim spopularyzowane w literaturze i mediach. Imię to pochodzi od złożenia dwóch innych: Anny, z hebrajskiego <i>hannah</i> – pełna łaski i Izabeli – hiszpańskiej wersji imienia Isabel - (Jezabel) pochodzącej od hebrajskiego Eliszebeth od którego pochodzi także Elżbieta. W Polsce imię to pojawiło się razem z wpływami francuskimi (Izabelle) - <i>belle</i> po francusku znaczy piękna.", "Aviva": "<p>Aviva plc - brytyjska firma ubezpieczeniowa, jedna z największych na świecie, należąca do kategorii systematycznie istotnych dla światowej gospodarki. Głównymi rynkami dla niej są Wielka Brytania, Irlandia, Kanada i Włochy.</p>", "Amela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amel</b>.</p><p>Amel (Francuz: Amblève) jest miastem w regionie Wallonie, prowincji Liège, i należy do niemieckojęzycznej społeczności w Belgii (German: Deutschsprachige Gemeinschaft Belgiens). Na 1 stycznia 2006 roku Amel miał łącznie 5.282 mieszkańców.</p>", "Ashanti": "<p>Ashanti Sheqvoy Douglas (ang. Ashanti Shequoiya Douglas; rodzaj.</p>", "Anamaria": "<p>Anamaria to kobiece imię. Znani ludzie z nazwiska to: Anamaria Govorčinović (urodzona 1997), chorwacka kanosarka Anamaria Ioniță (urodzono 1988), rumuńska sportowca Anamaria Marinca (urodzony 1978), rumuńskiej aktorki Anamaria Nesteriuc (urodzone 1993), rumuński obstajer Anamaria Ocolișan (urodzonych 1997), rumuńczyka gimnastka artystyczna Anamaria Tămârjan (urodzena 1991), rumuyńska gimnastka sztuki Anamaria Vartolomei (urodzina 1999), francusko-rumuńska aktorka</p>", "Amaliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amalia</b>.</p>Odpowiedniki w innych językach:", "Aranka": "<b>Aurelia</b> – imię żeńskie pochodzące od nazwy rzymskiego rodu Aurelia, która z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>aureolus</em> – „złocisty, złoty”, co mogło znaczyć także „wspaniały”.", "Amrita": "<b>Amryta</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> अमृत, pali amata; tyb. dutsi; jap. kanro, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> amrita) – w <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmie</a> boski napój dający pijącemu nieśmiertelność; <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjski</a> odpowiednik greckiego <a href=\"https://pl.wikipedia.org/wiki/Nektar_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">nektaru</a>. Termin pojawiający się często w <a href=\"https://pl.wikipedia.org/wiki/Wedy\" target=\"_blank\" rel=\"noopener noreferrer\">Wedach</a> oraz tekstach buddyjskich. Niebiański napój <a href=\"https://pl.wikipedia.org/wiki/Dewa\" target=\"_blank\" rel=\"noopener noreferrer\">dewów</a> i <a href=\"https://pl.wikipedia.org/wiki/Dewi\" target=\"_blank\" rel=\"noopener noreferrer\">dewi</a> dający nieśmiertelność lub inne moce oraz usuwający cierpienie.", "Aysha": "<p>Aysha jest pająkiem z rodziny Anyphaenidae.</p>", "Adelaide": "<p>Adelgayda Burgunda (Adelaida; it. Adelaide, do niego.</p>", "Alexandria": "<p>Aleksandria (arabickie, egipski: اسكندريه Eskendereyya; grecki: Aλεξάνδρεια), koptyckie: Rakota, z ludnością 4,1 miliona, jest drugim co do wielkości miastem Egiptu, a jest największym portem w kraju, przez które przechodzi około 80% całkowitego eksportu i importu kraju. Aleksandria jest również dużym ośrodkiem turystycznym.</p>", "Ayna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aina</b>.</p><p>Aina to progresywny metal zespół utworzony przez Sasha Paeta z udziałem wielu zaproszonych muzyków, wśród których Glenn Hughes, Michael Kiske i Candace Knight. W wyniku wspólnej pracy powstała metalowa opera Days of Rising Doom, która została wydana w 2003 roku pod wytwórniami Transmission i The End Records.</p>", "Anju": "<p>Anju może odnosić się do: Anju, prowincja Pyongan Nam, Korea Północna Anju (gady), ogólny termin używany do wskazywania na północnokoreańskich potraw w przypadku picia alkoholu</p>", "Aparecida": "<p>Aparecida może odnosić się do następujących miejsc:</p>", "Anastacia": "<p>Anastycha Lin Newkork (ang. Anastacia Lyn Newkirk; rodzaj.</p>", "Aneliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anelia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aneli</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anel</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anele</b>.</p><p>Anele to imię. Znanymi osobami z nazwiska są: Anele Lungisa (ur. 1992), gracz rugby południowoafrykański Anele Mdoda (ur. 1984), prezenterka telewizyjna południo Afryki Anele Ngcongca (1987-2020), piłkarz południowej Afryki</p>", "Ayana": "<p>Ayana Voss (japoński)  Bośあやな Bossu: Ayana, roмадzi: Bosu Ayana; rodzaj.</p>", "Aminata": "<p>Aminata to kobiece imię. Mieszkańcy tej nazwy to: Aminata Aidara (ur. 1984), włosko-senegalski dziennikarz, pisarz opowieści i powieści Aminata Barrow (ur. 2004), gwinijska piłkarz Aminata Camara (ur., 2003), winiarz Aminata Kamara (ur.) (ur. 1973), emeryturz Aminata Coulibaly (ur. 1989), francuska piłkarka w siatkówce Aminata Diallo (ur. 1995), francuska Piłkarka Aminata Dialo...</p>", "Anabela": "<p>Annabella, Anabella lub Anabela to imiona żeńskie. Do znanych osób z nazwiskiem należą: Annabella z Szkocji (kr.</p>", "Anghelina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anghel</b>.</p><p>Anghel to rumuńskie nazwisko i nazwisko.</p>", "Asteria": "<b>Asteria</b> – żeński odpowiednik łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Asteriusz\" target=\"_blank\" rel=\"noopener noreferrer\">Asteriusz</a>. Patronką tego imienia jest św. Asteria, zm. w 310 roku.", "Annalisa": "<p>Analiza Skarrone, bardziej znana jako Annaliza lub Naly (italij. Annalisa Scarrone; rodzaj.</p>", "Akiko": "<b>Akiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきこ, アキコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Andromeda": "<b>Andromeda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>. Pochodzi od słów <i>andros</i> „człowiek” i <i>medesthai</i> „myśleć”.", "Anca": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anka</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aurelie": "<p>Aurélie (lub jego warianty Aurelie lub Aurelia) to imiona kobiece występujące głównie we Francji, pochodzące z łacińskiej Aurelius (złota) rodziny. Mężczyźni to Aurèle i Aurélien.</p>", "Aygun": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aigun</b>.</p><p>Aigun (stylo: ⁇; język szłowny: ⁇ , ślonski: Àihún; język mannski: ⁇ ⁇ Aihūn hoton; chiński: Ái Hūn) jest chińską zabytkiem historycznym w północnej części Manczua, położonym na prawej stronie rzeki Amur, 30 km (19 mi) na południe od centrum Czarnogóra (w którym w kolejności płynie przez rzeki Zeya i Blagoveschensk). Chińska nazwa miasta, co dosłownie oznacza \"Bright Jade\", jest pierwotnym tłumaczeniem...</p>", "Ashleigh": "<p>Ashleigh jest formą angielskiej nazwy Ashley, z staroangelskiego æsc (śmieci popiołowe) i lēah (drewno, wyczyszczenie, trawnik, obudowa) oznaczające \"mieszkańca w pobliżu lasu drzewa popiołowego\". Jako imię to najczęściej używane w Anglii i Walii.</p>", "Altynai": "<p>Altynai (kazachski: Алтынай) lub Altynay, to kazachska i kirgijska transkrypcja tureckiej nazwy Altınay. Do osób znanych z tej nazwy należą: Altynai Asylmuratova (ur. 1961), były balarka z urodzenia w Kazachstanie, dyrektor artystyczny zespołu baletowego w Astana Opera Altynai Botoyarova (ur., 2004), tytułowa w konkursie modelek i urody, Miss Kirgistan 2021 Altynai Omurbekova, wiceprzewodnicząca parlamentu Kirgistanu Altynay Sapargalieva...</p>", "Amadea": "<b>Amadea</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Amadeusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Amadeusz</a>, powstałego w kręgach zakonnych w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a>. Oznacza „kochającą Boga”. Podobne znaczenie ma imię <a href=\"https://pl.wikipedia.org/wiki/Teofila\" target=\"_blank\" rel=\"noopener noreferrer\">Teofila</a>.", "Arisa": "<p>Arisa (jap. アリサ Arissa) - seria Nazuimi Ando, która ukazała się w czasopiśmie Nakayoshi od lutego 2009 roku do września 2012 roku.</p>", "Alica": "<p>Andrej Georjan Belan (r. Andreea Georgiana Bǎlan; urodz.</p>", "Anitta": "Imię Anitty pojawia się w dokumentach pochodzących z asyryjskiej kolonii kupieckiej w Kanesz (hetycka Nesa, obecnie stanowisko Kültepe w <a href=\"https://pl.wikipedia.org/wiki/Turcja\" target=\"_blank\" rel=\"noopener noreferrer\">Turcji</a>). W jednym z tekstów, wymieniającym jako władcę Kanesz/Nesy jego ojca Pithanę, Anitta występuje jako następca tronu i nosi akadyjski tytuł <i>rabi simmiltim</i>. W innym sam nosi już tytuł „władcy” (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akad</a>. <i>rubā'um</i>), a jako <i>rabi simmiltim</i> występuje jego syn <a href=\"https://pl.wikipedia.org/wiki/Peruwa\" target=\"_blank\" rel=\"noopener noreferrer\">Peruwa</a>. Imię Anitty pojawia się też w tekstach z <a href=\"https://pl.wikipedia.org/wiki/Ankuwa\" target=\"_blank\" rel=\"noopener noreferrer\">Ankuwy</a>, w których nosi on tytuł „władcy” (<i>rubā'um</i>) i „wielkiego władcy” (<i>rubā'um rabium</i>), co sugeruje, że zarówno Nesa, jak i Ankuwa znajdowały się pod jego kontrolą. Siedziba Anitty mogła znajdować się w Nesie – wskazują na to zarówno pochodzące stąd teksty, jak i odnaleziony tu sztylet z brązu noszący inskrypcję „pałac Anitty, księcia”.", "Aparna": "<p>Aparna może odnosić się do: Jednego z imion hinduskiej bogini Parvati</p>", "Alisiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alisia</b>.</p><p>Alicia to kobiece imię. Jest to wariant Alice, który pochodzi z germańskiego imienia Adalheidis (Adelaide), co oznacza \"szlachetny natury\" (szlachetnego rodzaju).</p>", "Aditi": "W <i>Bryhadajranjakopaniszad</i> (1.2.5) określenie dla oznaczenia <a href=\"https://pl.wikipedia.org/wiki/Absolut\" target=\"_blank\" rel=\"noopener noreferrer\">bytu absolutnego</a>.", "Aretta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Areta</b>.</p><b>Areta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie niejasnego pochodzenia. <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Bubak\" target=\"_blank\" rel=\"noopener noreferrer\">Józef Bubak</a> łączy je ze skróconą formą <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a> (niem. <i>Margareta</i>), powstałą na gruncie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a>. Imię to nosiła także <a href=\"https://pl.wikipedia.org/wiki/Arete_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">postać z mitologii greckiej</a>, królowa <a href=\"https://pl.wikipedia.org/wiki/Feakowie\" target=\"_blank\" rel=\"noopener noreferrer\">Feaków</a>, której imię stanowi przymiotnik odczasownikowy od wyrazu <i>αραομαι (araomai)</i> („modlę się o coś, gorąco pragnę”) i oznacza „dziecko upragnione”(por. <a href=\"https://pl.wikipedia.org/wiki/Dezyderia\" target=\"_blank\" rel=\"noopener noreferrer\">Dezyderia</a>, <a href=\"https://pl.wikipedia.org/wiki/Aspazja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Aspazja</a>). Można także spotkać się z poglądem, iż imię to pochodzi od greckiego słowa <i>αρετη (<a href=\"https://pl.wikipedia.org/wiki/Aret%C3%A9\" target=\"_blank\" rel=\"noopener noreferrer\">areté</a>)</i> oznaczającego „cnotę”, „męstwo”; Areta stanowiłaby wówczas żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Aretas\" target=\"_blank\" rel=\"noopener noreferrer\">Aretas</a>.", "Adriane": "<p>Nazwa Adriane może odnosić się do: Adriane Carr (ur. 1952), kanadyjskiej akademicki, aktywisty i polityk Adriane dos Santos (ur. 1988), brazylijskiej piłkarki Adriane Fugh-Berman, amerykańskiej medycyny Adriane Galisteu (ur. 1973), brazylijskiej modelu, aktorki i prowadzącą telewizję Adriane Garcia (ur. 1983), prezenterki telewizyjnej, aktorki oraz byłego piosenkarka-poopisty mieszkającego obecnie w Portugalii Adriane Johnson, amerykańskiej politykki Adriane...</p>", "Angélique": "<p>Angélique to opera francuskiego kompozytora Jacques Iberta. Autorem jest Michel Veber.</p>", "Altynay": "<p>Altynai (kazachski: Алтынай) lub Altynay, to kazachska i kirgijska transkrypcja tureckiej nazwy Altınay. Do osób znanych z tej nazwy należą: Altynai Asylmuratova (ur. 1961), były balarka z urodzenia w Kazachstanie, dyrektor artystyczny zespołu baletowego w Astana Opera Altynai Botoyarova (ur., 2004), tytułowa w konkursie modelek i urody, Miss Kirgistan 2021 Altynai Omurbekova, wiceprzewodnicząca parlamentu Kirgistanu Altynay Sapargalieva...</p>", "Arevik": "<p>Arevik jest miastem w prowincji Armavir w Armenii. W 2011 roku liczba ludności wynosiła 2872.</p>", "Anastassia": "<p>Anastassia to kobiece imię. Znanymi osobami z nazwiskiem to: Anastassia Kovalenko (ur. 1991), estyjska motocyklowa wyścigacz drogowy Anastassja Khozissova (ur. 1979), rosyjska modelka Anastassya Michaeli (ur. 1975), izraelska dziennikarz, telewizyjna prezenterka i polityk Anastassie Morkovkina (ur. 1981), estyckie piłkarz</p>", "Analyn": "<p>Analyn to imię. Znanymi osobami z nazwiska są: Analyn Barro (ur. 1996), filipińska aktorka Analyn Santos, fikcyjna postać z filipińskiego serialu dramowego Abot-Kamay na Pangarap</p>", "Asiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asia</b>.</p><p>Azja - część świata, która wraz z Europą tworzy kontynent Eurazja. Termin może również oznaczać:</p>", "Alita": "<p>GUNNM (jap. 銃夢 дзю: [orużania] mu , czyta się jako ガンム gammu, w oficjalnym tłumaczeniu po rosyjsku ⁇ Obrażania marzeń ⁇ , dopł.</p>", "Alsu": "<p>Alsu Ralifovna Abramova (rosyjski: Алсу Ралиф кызы Абрамова, łaciński: Alsu Rälif qızı Abramova), znana pod pseudonimem Alsu (Алсу), jest piosenkarką i muzyką rosyjskiej licznych scen.</p>", "Anisha": "<p>Anisha może odnosić się do Anisha Ambrose, indyjskiej aktorki filmowej i modelu Anisha Basheel (ur. 1997), malawjskiej profesjonalnej bokserki Anisha Nagarajan (ur. 1983), amerykańskiej aktorki i piosenkarki Anisha Nicole (ur. 1985), amerykańskiej piosenkarky Anisha Rosnah (ur. 1993) brunejskiej królewskiej Anisha Vekemans (ur. 1991), belgijskiej profesjonalne rowerzystka wyścigowa</p>", "Araceli": "<p>Araceli jest piątym miastem w prowincji Palawan, w Filipinach. Według przeprowadzonego w 2000 roku spisu populacji mieście miało 10 894 mieszkańców w 2 550 domach.</p>", "Amalya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amalia</b>.</p>Odpowiedniki w innych językach:", "Arietta": "<b>Arietta</b> – <a href=\"https://pl.wikipedia.org/wiki/Forma_muzyczna\" target=\"_blank\" rel=\"noopener noreferrer\">forma muzyczna</a>, <a href=\"https://pl.wikipedia.org/wiki/Aria\" target=\"_blank\" rel=\"noopener noreferrer\">aria</a> o mniejszych rozmiarach, zwykle w formie 2-częściowej lub utwór instrumentalny.", "Arlette": "<p>Herleva (znana również jako Erleva, Ereleva, Arletta lub Arlotta Falezskiej; fr. Herleva, Erlève, Herlève, Arlette, Herlotte de Falaise; około 1003 - około 1050) - viconteza de Conteville, matka księcia Normandii i króla Anglii Wilhelma I Zdobywcy.</p>", "Aygul": "<p>Aygül lub Aygul to kobiece turskie i turkmenskie nazwisko i nazwisko. Składa się z dwóch tureckich słów: \"Ay\" oznacza \"księżyc\" i \"Gül\" oznacza \"różę\".</p>", "Arwen": "<p>Arwen Undómiel jest postacią w powieści The Lord of the Rings (Panie Pierścieni) przez J. R.</p>", "Asmat": "<p>Asmat jest podregiem znajdującym się w północno-zachodniej części regionu Anseba (Zoba Anseba) w Eritrii. Jego stolicą jest Asmat.</p>", "Adelgunda": "<b>Adalgunda</b>, <b>Adelgunda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, składające się z członów <i>adal-</i> // <i>adel-</i> // <i>edel-</i> — \"szlachetny ród\" oraz <i>-gund</i> // <i>-gunt</i> — \"walka, bitwa\". Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ta_Adelgunda\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adelgunda (Aldegunda)</a> — według niektórych źródeł <a href=\"https://pl.wikipedia.org/wiki/Aldegunda\" target=\"_blank\" rel=\"noopener noreferrer\">Aldegunda</a>, imię notowane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1320\" target=\"_blank\" rel=\"noopener noreferrer\">1320</a> roku, jest wariantem imienia Adalgunda, według innych zaś — odrębnym imieniem o odmiennym znaczeniu.", "Annelise": "<p>Anneliese to nazwisko żeńskie pochodzące z Niemiec, Holandii lub Skandynacji. Jest to mieszane z \"Anny\" i \"Liese\", krótka forma \"Elisabeth\".</p>", "Astra": "<p>Astra, Astra (od greckiego αστερ - gwiazda): Astra (lat.</p>", "Aleena": "<p>Aleena to kobiece imię, prawdopodobnie wariant Aliny. Może odnosić się do:</p>", "Awa": "<b>Ewa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które pierwszy raz pojawia się 2000 lat p.n.e. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_sumeryjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku sumeryjskim</a> jako „Awa” gdzie oznacza „życie”. W języku hebrajskim, który zapożyczył to imię od Sumerów wywodzi się od rdzenia חוה <i>hajja</i> lub hawwa – i również oznacza ‘dająca życie’. Imię wyprowadzane też z arabskiego słowa <i>hajja</i> ‘wąż’.", "Anastasya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastasia</b>.</p><b>Anastazja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anastazy\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazy</a>. Oznacza „zmartwychwstała, wskrzeszona”.", "Azalia": "<b>Różanecznik</b>, azalia, rododendron (<i>Rhododendron</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny\" target=\"_blank\" rel=\"noopener noreferrer\">roślin</a> z rodziny <a href=\"https://pl.wikipedia.org/wiki/Wrzosowate\" target=\"_blank\" rel=\"noopener noreferrer\">wrzosowatych</a> (<i>Ericaceae</i>). Obejmuje ponad tysiąc <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a>. W stanie naturalnym występują głównie w <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">Azji</a>, w mniejszej liczbie gatunków w obydwu <a href=\"https://pl.wikipedia.org/wiki/Ameryka\" target=\"_blank\" rel=\"noopener noreferrer\">Amerykach</a> i w <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europie</a>. Rosną zwykle na obszarach górskich, na glebach próchnicznych i kwaśnych, często także na <a href=\"https://pl.wikipedia.org/wiki/Torfowisko\" target=\"_blank\" rel=\"noopener noreferrer\">torfowiskach</a> i na glebach oraz skałach wapiennych. Zasiedlają lasy, formacje krzewiaste i wrzosowiska. Nieliczne gatunki są <a href=\"https://pl.wikipedia.org/wiki/Epifit\" target=\"_blank\" rel=\"noopener noreferrer\">epifitami</a>. Kwiaty są u części gatunków wonne, u innych nie. <a href=\"https://pl.wikipedia.org/wiki/Zapylenie\" target=\"_blank\" rel=\"noopener noreferrer\">Zapylane</a> są przez <a href=\"https://pl.wikipedia.org/wiki/Owady\" target=\"_blank\" rel=\"noopener noreferrer\">owady</a>, niektóre gatunki w Himalajach także przez <a href=\"https://pl.wikipedia.org/wiki/Ptaki\" target=\"_blank\" rel=\"noopener noreferrer\">ptaki</a>.", "Aryiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ariiana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ariian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arian</b>.</p><b>Arian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jego patronem jest św. Arian, wspominany razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Teotyk_(m%C4%99czennik_egipski)\" target=\"_blank\" rel=\"noopener noreferrer\">Teotykiem</a>.", "Argentina": "<p>Argentyna (szp. argentyna - ⁇ serbisty ⁇ , od łacińskiego.</p>", "Anne-Sophie": "<p>Anne-Sophie to kobiece imię. Wśród znanych osób z tej nazwy są: Ann Sophie (Ann-Sophie Dürmeyer, urodzona 1990), niemiecka piosenkarka Anne-Sophie Barthet (urodzona 1988), francuska narciarka i żołnierz Anne-S Sophie Bion, francuska redaktorka filmowa, najbardziej znana z pracy w filmie niemycznym z 2011 roku, Artysta Anne-Sophy Brasme (urodzony 1984), francuska pisarka Anne-Sopie Calvez (urodzone 1983), francuska patinarka figurna Anne-Sophi de Kristoffy, francuska dawna figura...</p>", "Ajla": "<p>Ajla (zwany \"eye-lə\") jest imieniem kobiecym w różnych regionach wschodniego Morza Śródziemnego. W języku arabskim oznacza to \"najświatniejsze\", \"najświecniejsze\", \"najsłyskotliwiejsze\", inteligentne.</p>", "Anelya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anelia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aneli</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anel</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anele</b>.</p><p>Anele to imię. Znanymi osobami z nazwiska są: Anele Lungisa (ur. 1992), gracz rugby południowoafrykański Anele Mdoda (ur. 1984), prezenterka telewizyjna południo Afryki Anele Ngcongca (1987-2020), piłkarz południowej Afryki</p>", "Aude": "<p>Aude jest francuską prowincją, należącą do regionu administracyjnego Occitanie, w której stolica jest Carcassonne, składająca się z trzech okręgów z pozostałymi stolicami: Limoux, Narbonne.</p>", "Anahita": "<b>Anahita</b> (آناهیتا, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_awestyjski\" target=\"_blank\" rel=\"noopener noreferrer\">awest.</a> <i>Aredwi Sura Anahita</i> \"Wilgotna Jaśniejąca Nietykalna\", <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">npers.</a> <i>Nahid</i>) – w <a href=\"https://pl.wikipedia.org/wiki/Zaratusztrianizm\" target=\"_blank\" rel=\"noopener noreferrer\">dawnej religii irańskiej</a> bogini, później jazata, słodkiej wody i płodności oraz porządku społecznego, zwana też Naną (Piastunką). Imię Anahita wzięła od mitycznej rzeki.", "Aspazja": "Starożytni pisarze wspominają również, że Aspazja prowadziła dom publiczny i sama była <a href=\"https://pl.wikipedia.org/wiki/Prostytucja\" target=\"_blank\" rel=\"noopener noreferrer\">nierządnicą</a>, jednakże współcześni naukowcy kwestionują te relacje, które miałyby pochodzić od komediopisarzy zainteresowanych zniesławianiem Peryklesa. Niektórzy badacze kwestionują nawet historyczną tradycję, zgodnie z którą miała być ona <a href=\"https://pl.wikipedia.org/wiki/Hetera\" target=\"_blank\" rel=\"noopener noreferrer\">heterą</a> albo <a href=\"https://pl.wikipedia.org/wiki/Kurtyzana\" target=\"_blank\" rel=\"noopener noreferrer\">kurtyzaną</a>. Zasugerowali, że w rzeczywistości mogła być żoną Peryklesa. Aspazja miała z Peryklesem syna, <a href=\"https://pl.wikipedia.org/wiki/Perykles_M%C5%82odszy\" target=\"_blank\" rel=\"noopener noreferrer\">Peryklesa Młodszego</a>, który później, będąc strategiem w armii greckiej, został stracony po <a href=\"https://pl.wikipedia.org/wiki/Bitwa_pod_Arginuzami\" target=\"_blank\" rel=\"noopener noreferrer\">bitwie pod Arginuzami</a>. Przyjmuje się, że po śmierci Peryklesa Starszego została kurtyzaną Lizyklesa, innego ateńskiego dowódcy i męża stanu.", "Aldana": "<p>Aldana jest samorządem w prowincji Nariño w Kolumbii. Gmina Aldana ma 46 km2 i ma swoją siedzibę w Aldana.</p>", "Aureliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aurelia</b>.</p><b>Aurelia</b> – imię żeńskie pochodzące od nazwy rzymskiego rodu Aurelia, która z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>aureolus</em> – „złocisty, złoty”, co mogło znaczyć także „wspaniały”.", "Adila": "<b>Adila</b> – arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a>, żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Adil\" target=\"_blank\" rel=\"noopener noreferrer\">Adil</a>. Imię Adila jest oboczną formą <a href=\"https://pl.wikipedia.org/wiki/Adela\" target=\"_blank\" rel=\"noopener noreferrer\">Adeli</a> pochodzącą od <i>Athala</i>, gdzie wyraz <i>athal</i> oznacza \"szlachetny\". W IV wieku, na ówczesnych terenach Francji, przybrało formę <i>Adèle</i>.", "Aliie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alii</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Aglaia": "<p>Aglaia (lat. Aglaia) - rodzaj roślin kwiatowych z rodziny Meliaceae.</p>", "Afra": "<b>Afra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od nazwy <i>Afri</i>, oznaczającej osobę pochodzącą z <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>. Było to imię dwóch świętych we wczesnym okresie chrześcijaństwa (<a href=\"https://pl.wikipedia.org/wiki/Afra_z_Augsburga\" target=\"_blank\" rel=\"noopener noreferrer\">Afry z Augsburga</a>, zm. ok. 304 i Afry, męczennicy w <a href=\"https://pl.wikipedia.org/wiki/Brescia\" target=\"_blank\" rel=\"noopener noreferrer\">Brescii</a> za cesarza <a href=\"https://pl.wikipedia.org/wiki/Lucjusz_Domicjusz_Aurelian\" target=\"_blank\" rel=\"noopener noreferrer\">Aureliana</a>).", "Alfonsa": "<b>Alfonsa, Alfonsyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Alfons\" target=\"_blank\" rel=\"noopener noreferrer\">Alfons</a>, powstałe ze złożenia członów <i>al</i> (\"cały\") lub <i>adal</i> (\"szlachetny ród\") oraz <i>funs</i> (\"szybka, chętna, życzliwa\"). Patronką tego imienia jest św. Alfonsa od Niepokalanego Poczęcia zm. w Muttathupadam (w <a href=\"https://pl.wikipedia.org/wiki/1946\" target=\"_blank\" rel=\"noopener noreferrer\">1946</a> roku) oraz czcigodna Alfonsa Eppinger. Imię to występuje również bardzo rzadko w wersji Alfonsyna, stanowiącej spolszczenie zdrobnienia imienia Alfonsa, powstałego na gruncie romańskim.", "Aishat": "<p>Aisha (arabsko: عائشة, romanized: ʿʿʾishah, lit. 'żyjący' lub 'żyjący'; również pisowniane A'aisha, A'isha, Aischa, Aische, Aishah, Aishat, Aishath, Aicha, Aïcha, Aisya, Aisyah, Aiša, Ajša, Aixa, Ayesha, Aysha, Ayşe, Ayisha lub Iesha) jest arabską nazwą żeńską.</p>", "Aia": "<p>Aia jest miastem w prowincji Guipúzcoa w samorządowej społeczności Baskiej, Hiszpania. Od San Sebastián 30 km na zachód i około 10 km w terenie węgla od Zarautz.</p>", "Athanasia": "<p>Athanasia to rodzina roślin kwiatowych w rodzinie Asteraceae.</p>", "Adaobi": "<p>Adaobi jest kobiece nazwisko pochodzenia Igbo w południowo-wschodniej Nigerii. W języku Igbo \"Ada\" oznacza \"pierwszą córkę\" i \"Obi\" oznacza \"serce\" lub \"dom\". Adaobi jest tłumaczana w języku angielskim jako \"pierwsza córka serca\" lub \"pierwska córka domu\".</p>", "Angella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angela</b>.</p><b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Aitana": "<p>Aitana Ocaña Morales (ur. 27 czerwca 1999 r.) - hiszpańska piosenkarka, aktorka i autorka piosenek, znana pod pseudonimem Aitana. Po raz pierwszy uzyskała uznanie narodowe w 2017 roku, zdobywając drugie miejsce w odrodzonej serii hiszpańskiego konkursu telewizyjnego talentów Operación Triunfo.</p>", "Anna-Viktoriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anula": "<p>Anula może odnosić się do: Anula, Terytorium Północne, przedmieścia Darwin, Australia Anula Anuradhapura, królowa Anuradapura w dzisiejszej Sri Lance, również buddyjskiej zakonnicy Anula Vidyalaya, buddyjskie szkoły w Sri Lanka Anul, wioska w Indiach; znana również jako Anula</p>", "Ai": "<b>Ai</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;愛, 藍, あい, アイ) – popularne żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>. Jest ono skróconą, nowocześniejszą formą <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Aiko_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Aiko</a> (w latach 80. XX wieku żeńskie imiona z końcówką 子 <i>ko</i> wyszły z mody).", "Ayako": "<b>Ayako</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あやこ, アヤコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Andronika": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andronik</b>.</p><b>Andronik</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od starogreckiego imienia <i>Andronikos</i> (gr. <i>Ανδρόνικος</i>) wywodzącego się od słów <i>andros</i> (człowiek) i <i>nike</i> (zwycięstwo), które w złożeniu znaczą „zwycięzca”.", "Axelle": "<p>Axelle to francuskie imię żeńskie, pochodne skandynawskiego imienia Axel. Wśród znanych osób z tego nazwiska są: Axelle Axell (urodzona 1937), szwedzka aktorka Axelle Carolyn (urodzono 1979), belgijska filmowca Axelle Crevier (urodzony 1997), kanadyjska piłkarka w wodzie Axelle Dauwens (urodzone 1990), belgijska sportowca Axelle Étienne (urodzonych 1998), francuska rowerka Axelle Kabou (urodzena 1955), kamerońska dziennikarka Axelle Klinckaert (urodzeni 2000),...</p>", "Alicija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alicia</b>.</p><b>Alicia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskiego</a>.", "Adelya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adelia</b>.</p><p>Adelia borealis (lat. - rodzaj śpiewających cykadów rodza Adelia z rodziny Cicadidae (Auchenorrhyncha).</p>", "Aurélia": "<p>Aurelia (zwany również Aurelía, Aurélia lub Aurelija) jest imieniem kobiece z łacińskiej nazwy Aurelius, która pochodziła od aureus oznaczającego \"złote\". Aurelia może odnosić się do:</p>", "Anastasiia-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Antonela": "<p>Antonela to chorwackie imię żeńskie, które jest diminutiwą formą Antonia i alternatywną formą Antonella używaną w Chorwacji. Znanymi osobami z tym nazwiskiem są: Antonela Anić (ur. 1985), chorwacka piłkarka koszykówki Antonela Curatola (ur. 1991), argentyńską piłkarkę siatkówki Antonella Đinđić, znana Nela, chorwacka śpiewaczka i autorka Antonela Ferenčić (ur., 1994), chorwackia rowerka Antonela Fortuna (ur. 1995),...</p>", "Ayaka": "<b>Ayaka</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あやか, アヤカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Alanna": "<p>Alanna, Alanah lub Alannah to imię z dyskusyjnym pochodzeniem. Pochodzi od starożytnego niemieckiego, co oznacza \"kobiety\" lub od irlandzkiego, co znaczy dziecko\" lub od słowa \"child\", w języku angielskim.</p>", "Aisling": "<b>Aisling</b> – <a href=\"https://pl.wikipedia.org/wiki/Irlandia\" target=\"_blank\" rel=\"noopener noreferrer\">irlandzkie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, oznaczające <i>sen</i> lub <i>wizję</i>.", "Alime": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alim</b>.</p><b>Ulem</b> – muzułmański teolog i uczony. Słowo pochodzi z wyrazu <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> <i>alim</i>, oznaczającego uczonego. W skład grupy ulemów wchodzili wszyscy duchowni muzułmańscy: <a href=\"https://pl.wikipedia.org/wiki/Mufti\" target=\"_blank\" rel=\"noopener noreferrer\">muftiowie</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Imam\" target=\"_blank\" rel=\"noopener noreferrer\">imamowie</a>. Ulemów określa się również mianem znawców <a href=\"https://pl.wikipedia.org/wiki/Szariat\" target=\"_blank\" rel=\"noopener noreferrer\">szariatu</a>. Ich główną siedzibą były <a href=\"https://pl.wikipedia.org/wiki/Meczet\" target=\"_blank\" rel=\"noopener noreferrer\">meczety</a>. Główną rolę posiadał meczet <a href=\"https://pl.wikipedia.org/wiki/Al-Azhar\" target=\"_blank\" rel=\"noopener noreferrer\">al-Azhar</a> w <a href=\"https://pl.wikipedia.org/wiki/Kair\" target=\"_blank\" rel=\"noopener noreferrer\">Kairze</a>.", "Abigajl": "<b>Abigail</b>, <b>Abigajl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego imienia אביגיל <i>Awigajil</i> znaczącego „radość ojca”, „mój ojciec się uradował”.", "Anna Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anna Maria</b>.</p><p>Anna Maria dał Violín (italij. Anna Maria dal Violin; ok.</p>", "Aidai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aida</b>.</p><b>Aida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnym pochodzeniu, być może arabskim albo greckim lub twór literacki.", "Arieta": "<b>Arietta</b> – <a href=\"https://pl.wikipedia.org/wiki/Forma_muzyczna\" target=\"_blank\" rel=\"noopener noreferrer\">forma muzyczna</a>, <a href=\"https://pl.wikipedia.org/wiki/Aria\" target=\"_blank\" rel=\"noopener noreferrer\">aria</a> o mniejszych rozmiarach, zwykle w formie 2-częściowej lub utwór instrumentalny.", "Adeliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adelia</b>.</p><p>Adelia borealis (lat. - rodzaj śpiewających cykadów rodza Adelia z rodziny Cicadidae (Auchenorrhyncha).</p>", "Aleksja": "<b>Aleksja</b> – imię żeńskie pochodzenia greckiego (od męskiego imienia Alexius), żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksy\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksy</a>. Występuje również w formie <b>Aleksa</b>. Być może powiązane jest z imieniem <a href=\"https://pl.wikipedia.org/wiki/Alicja\" target=\"_blank\" rel=\"noopener noreferrer\">Alicja</a>.", "Andrzela": "<b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Aigun": "<p>Aigun (stylo: ⁇; język szłowny: ⁇ , ślonski: Àihún; język mannski: ⁇ ⁇ Aihūn hoton; chiński: Ái Hūn) jest chińską zabytkiem historycznym w północnej części Manczua, położonym na prawej stronie rzeki Amur, 30 km (19 mi) na południe od centrum Czarnogóra (w którym w kolejności płynie przez rzeki Zeya i Blagoveschensk). Chińska nazwa miasta, co dosłownie oznacza \"Bright Jade\", jest pierwotnym tłumaczeniem...</p>", "Ailen": "<p>Irlandia jest wyspą w północnym Atlantyku. Wyspa ta oddziela się od Wyspy Wielkiej Brytanii na wschodzie przez Zatok Północny, Morze Irlandzkie i Zatok St George'a.</p>", "Albertina": "<p>Albertina to znany muzeum w Wiedniu, w Austrii, gdzie znajduje się najcenniejsza kolekcja sztuki i druku. Albertina, czyli podobny do męskiego imienia Albert, może również odnosić się do:</p>", "Ainara": "<p>Ainara lub Enara jest baskijską nazwą żeńską, co oznacza \"ptakę połykającą\".</p>", "Adanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adana</b>.</p><b>Adana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia hebrajskiego o znaczeniu \"ziemia\". Obecnie rzadko jest nadawane.", "Aurea": "<b>Aurea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"ukoronowana, uwieńczona\". Wśród patronek dwie święte: <a href=\"https://pl.wikipedia.org/wiki/Aurea_z_Ostii\" target=\"_blank\" rel=\"noopener noreferrer\">Aurea z Ostii</a>, męczennica (zm. ok. 253) oraz Aurea Paryska (ok. 633-666).", "Autumn": "<p>Autumn: Autumn (grupa, Holandia) - holenderska gotyckie metal-grupa. Autumn (grupa, Rosja) - rosyjska gotyczna/myśl-metal-grupa.</p>", "Arwa": "<p>Arwa - oddział The Coca-Cola Company w Dubaju.</p>", "Anna-Sofiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Armela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Armel</b>.</p><p>Armel (r. Armel) - kamienny meteoryt, zwykły chondryt o wadze 9200 g.</p>", "Ayra": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aira</b>.</p><p>Aira (lat. Aīra) - rodzaj małych jednorocznych traw z rodziny Zlaki lub Mlotlicowych (Poaceae), rosnących w umiarkowanych obszarach obu półkuli, zwłaszcza wśródmorzawych rejonach Europy, Azji i Afryki.</p>", "Azul": "<p>Azul Brazilian Airlines (portu. Azul Linhas Aéreas Brasileiras S/A, działająca jako Azul) - brasilijska spółka lotnicza o siedzibie w mieście Barueeri, wykonująca regularne i charterne przewozy pasażerskie w lotniskach kraju i poza nim.</p>", "Anh Thu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Aušra": "<p>⁇ Aušra ⁇ (lit. Aušra, ⁇ Zarya ⁇; w oryginalnej orfografii - Auszra) - pierwsza litewska gazeta społeczno-literacka.</p>", "Ayumi": "<b>Ayumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あゆみ, アユミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Amata": "<b>Amata</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Amat\" target=\"_blank\" rel=\"noopener noreferrer\">Amat</a>. Francuskim odpowiednikiem tego imienia jest <i>Aimée</i>.", "Ambrozja": "<b>Ambrozja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od gr. <i>ambrósios</i> – boski, nieśmiertelny; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Ambro%C5%BCy\" target=\"_blank\" rel=\"noopener noreferrer\">Ambroży</a>. Według stanu na 17 stycznia 2015 r. imię to miało w Polsce 5 nadań.", "Athira": "<p>Athira to imię. Wśród znanych osób z tym nazwiskiem są: Athira Patel, indyjska aktorka L.</p>", "Andrea Carolina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Aniko": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anik</b>.</p><p>Anik: Anik to seria satelitów telekomunikacyjnych geostacjonarnych uruchomionych przez Telesat Canada. Anik G1 - satelitę telekomunikacyjną stworzoną przez amerykańską firmę Space Systems/Loral.</p>", "Amrutha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amruta</b>.</p><p>Amrita (sanskrit: अमृत, IAST: amṛta), Amrit lub Amata w języku Pali, (zwany również Sudha, Amiy, Ami) jest słowem sanskryckim, które oznacza \"nieśmiertelność\". Jest to centralna koncepcja w indyjskich religiach i często jest określana w starożytnych tekstach indyjskich jako elixir.</p>", "Aleksiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksii</b>.</p><p>Alexey (rosyjski: Алексей, romanized: Aleksey [ɐljɪkˈsjej]) to rosyjskie imię męskie pochodzące od greckiego Aléxios (Αλέξιος), co oznacza \"Obrannik\", a zatem z tego samego pochodzenia jak łacina Alexius. Podobne ukraińskie i białoruskie nazwy są romanizowane odpowiednio jako Oleksii (Олексій) i Aliaksiej (Аляксей).</p>", "Azada": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Azad</b>.</p><b>Azad</b>, właściwie <b>Azad Azadpour</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/24_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">24 listopada</a> <a href=\"https://pl.wikipedia.org/wiki/1973\" target=\"_blank\" rel=\"noopener noreferrer\">1973</a> w <a href=\"https://pl.wikipedia.org/wiki/Sanandad%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">Sanandadżu</a>, <a href=\"https://pl.wikipedia.org/wiki/Iran\" target=\"_blank\" rel=\"noopener noreferrer\">Iran</a>) – niemieckojęzyczny <a href=\"https://pl.wikipedia.org/wiki/Rap\" target=\"_blank\" rel=\"noopener noreferrer\">raper</a> irańsko-kurdyjskiego pochodzenia. Mieszka we <a href=\"https://pl.wikipedia.org/wiki/Frankfurt_nad_Menem\" target=\"_blank\" rel=\"noopener noreferrer\">Frankfurcie nad Menem</a>. Jego imię po kurdyjsku znaczy \"wolny\".", "Akari": "<p>Akari (jap. あかり акаri, ⁇ свет ⁇ , przed uruchomieniem - Astro-F) - japoński satelitę naukowy do badań przestrzeni kosmicznej w zakresie infragłonnym.</p>", "Alyson": "<p>Alyson to imię, wariant Alison. Do wybitnych osób z tym nazwiskiem należą:</p>", "Angélica": "<p>Angélica jest miastem w stanie Mato Grosso do Sul w Brazylii. Miasto to ma powierzchnię 1273,199 km2, liczba ludności w 2007 roku wynosi 7253 mieszkańców, a jego gęstość 5,7 mieszkańców/km2.</p>", "Ailyn": "<p>Pilar Maria del Carmen Monica Himénes García (hisp. Pilar Maria Del Carmen Monica Giménez García; urodz.</p>", "Apolina": "<b>Apollina</b>, <b>Apolina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/Apollo_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">imienia boga Apollona</a>. Patronką tego imienia jest św. Apollina, zm. w <a href=\"https://pl.wikipedia.org/wiki/249\" target=\"_blank\" rel=\"noopener noreferrer\">249</a> roku w <a href=\"https://pl.wikipedia.org/wiki/Aleksandria\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandrii</a>.", "Adelle": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adele</b>.</p><p>Adele Laurie Blue Edkins (ang. Adele Laurie Blue Adkins; rodzaj.</p>", "Arabela": "<b>Arabella</b>, <b>Arabela</b> – imię żeńskie, być może łacińskiego pochodzenia.", "Anna-Marie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anne-Marie</b>.</p><p>Ann-Marie Rose Nicholson (ang. Anne-Marie Rose Nicholson; rodzaj.</p>", "Aiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ayan</b>.</p><p>⁇ Nieuchwytny ⁇ (tam. அயன், Ayan) - indyjski film przygodowy reżysera K.</p>", "Aira": "<p>Aira (lat. Aīra) - rodzaj małych jednorocznych traw z rodziny Zlaki lub Mlotlicowych (Poaceae), rosnących w umiarkowanych obszarach obu półkuli, zwłaszcza wśródmorzawych rejonach Europy, Azji i Afryki.</p>", "Angelica Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angelica</b>.</p><p>Dudnik, czyli aniolica (lat. Angélica) - rodzaj trawniczośnych roślin rodziny Zontickich (Apiaceae).</p>", "Angy": "<p>Ángela Maria Fernandez Gonzalez (hisz. Ángela María Fernández González, urodz.</p>", "Anna-Anastasiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Alessa": "<p>Alessa to kobiece imię, wersja greckiej nazwy Alexa i nazwa w innych językach. Do znanych osób z nazwiskiem należą: Alessa Ries (ur. 1981), niemiecka pływaczka Alessa-Catriona Pröpster (ur. 2001), niemiecki rowerzysta torów Mohamed Mahmood Alessa (ur. 1989 lub 1990), amerykański przestępca</p>", "Azucena": "Azucena jest <a href=\"https://pl.wikipedia.org/wiki/Romowie\" target=\"_blank\" rel=\"noopener noreferrer\">Cyganką</a>, córką kobiety, która spłonęła na stosie podejrzana o rzucenie uroków na dzieci hiszpańskiego hrabiego di Luna. Mszcząc się za śmierć matki, z maleńkim dzieckiem na ręku wdarła się do zamku hrabiego i wykradła jego synka. Gdy dogasał już stos starej Cyganki, Azucena rzuciła również dziecko w płomienie. Niestety dla niej, w szoku i w bólu spaliła własne dziecko, tym samym ratując życie synowi hrabiego. Kierowana sprzecznymi uczuciami – wyrzutami sumienia, litością, specyficzną miłością matki, ale też dalszą żądzą zemsty, wychowała chłopca jak własnego syna i nadała mu imię <a href=\"https://pl.wikipedia.org/wiki/Manrico\" target=\"_blank\" rel=\"noopener noreferrer\">Manrico</a>. Także on, żyjąc w nieświadomości swego pochodzenia, traktował ją jak matkę, a gdy dorósł, stał się stronnikiem księcia Urgel, podczas gdy drugi z braci wiernie służył królowi, szukając przy tym nadal zaginionego w dzieciństwie brata.", "Aja": "<p>Aja - szósty album amerykańskiej grupy jazz-rock Steely Dan, wydany 23 września 1977 roku na wytwórni ABC Records. Disk osiągnął 3. miejsce w USA i 5. w Wielkiej Brytanii i otrzymał 23 lutego 1978 roku nagrodę Grammy w kategorii Najlepszego inżynierii albumu, nie klasycznego (nagrodę otrzymali inżynierowie dźwięku Elli Shethooter, Bill Schnee, Al Schmitt i Roger Nichols).</p>", "Aviya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Avia</b>.</p><p>AVIA Motors - czeska firma założona w 1919 roku na produkcję samolotów. Od 1946 roku produkuje również samochody ciężarowe i autobusy.</p>", "Alicya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alicia</b>.</p><b>Alicia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskiego</a>.", "Ashlee": "<p>Ashley to imię, które pierwotnie było staroangelską nazwą. Pochodzi z angielskiego słowa æsċ (poślad) i lēah (przejście, łąka) i tłumaczy się na \"Mieszkający w pobliżu łąki z piecza\".</p>", "Adryiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adryian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adriian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Aleksandryna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksandr</b>.</p><p>Aleksander lub Aleksandr może odnosić się do Aleksandra Michajłowicza Zaitsewa Aleksandr Valterovich Litvinenko Aleksandr II Rosji Aleksandr Grin Aleksandr Isayevich Solzhenitsyn Aleksandr Danilovich Menshikov</p>", "Ademi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adem</b>.</p><b>Adem</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie będące <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">sturkizowaną</a> wersją imienia <a href=\"https://pl.wikipedia.org/wiki/Adam\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a>, występujące też jako nazwisko.", "Albana": "<b>Albana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Alban_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Alban</a>. Wywodzi się od nazwiska rzymskiej rodziny <i>Albanus</i> oznaczającego \"pochodzący z Alby\".", "Aliénor": "<p>Eleanor () to żeńskie imię, pochodzące z starofrancuskiej adaptacji starej prowencalski nazwy Aliénor. Było to imię wielu kobiet z rodziny królewskiej i szlachty w Europie Zachodniej w średniowieczu.</p>", "Assol": "Istnieją dwie wersje pochodzenia imienia. Według pierwszej pisarza natchnęło pytanie skierowane do kelnera: <i>А соль?</i> (pol. <i>A sól?</i>), według drugiej imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> <i>al sol</i> (pol. <i>ku słońcu</i>).", "Abida": "<p>Abida (arabsko: عابدہ) to kobiece imię. Mężczyzna nazywa się Abid.</p>", "Anila": "<p>Anila jest rodzajem roślin kwiatowych z rodziny Białego.</p>", "Akane": "<b>Akane</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あかね, アカネ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Arantxa": "<p>Arantza lub Arantxa to baskijska kobieca nazwa, co oznacza \"szczur\". Jest to hipokorystyczny dla Arantzazu, który pochodzi od Matki Bożej z Arantzazu , świątyni Maryi, matki Jezusa, w Gipuzkowie.</p>", "Anna-Mariya": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "An Nhien": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Abegail": "<p>Abigail to kobiece imię. Nazwa pochodzi z biblijnego hebrajskiego: אֲבִיגַיִל / אֲבִִיגָיִל ʾĂ ⁇ īḡayīl, co oznacza \"radość mego ojca\" (alternatywnie \"moje ojciec jest radowany\" lub \"moje ojcowie są radości\", między innymi).</p>", "Anela": "<p>Anela jest miastem w prowincji Sassari w regionie Sardinia, znajdującym się około 140 km na północ od Cagliari i około 50 km na południe od Sassari na wschód. Na dzień 31 grudnia 2004 roku mieście miało 764 mieszkańców i obszarze 37,0 km2.</p>", "Anna-Lena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Adrijana": "<p>Adrijana jest nazwiskiem pochodzenia słowiańskiego, co oznacza Adriana. Do wybitnych osób z nazwiskiem należą: Adrijana Delić (ur. 1996), serbska piłkarka Adrijana Hodžić (ur., 1975), kosowska polityk Adrijana Knežević (ur.1987), serbska koszykarka Adriana Krasniqi (ur. 1997), szwedzka piosenkarka pochodzenia albańsko-makedońskiego Adrijana Lekaj (ur. 1995), kosowsko-chorwacka tenisa Adrijana Mori (ur. 2000), słoneczna piłkarzka Adrijana...</p>", "Anielka": "<p>Aniela jest polskim imieniem dla kobiet, spokrewnionym z greckim nazwiskiem Angela. Anielka to hipokoryzm tej nazwy.</p>", "Aine": "Aine jest silnie powiązana z <a href=\"https://pl.wikipedia.org/wiki/Limerick_(hrabstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">hrabstwem Limerick</a>. Wzgórze Knockainey, nazwane jej imieniem (po irlandzku: <i>Cnoc Áine</i>, „Wzgórze Aine”), było miejscem obrzędów na jej cześć, które miały miejsce jeszcze w 1879 roku. Jest również związana z takimi miejscami jak: Toberanna, w <a href=\"https://pl.wikipedia.org/wiki/Tyrone_(hrabstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">hrabstwie Tyrone</a>; Dunany, w <a href=\"https://pl.wikipedia.org/wiki/Louth_(hrabstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">hrabstwie Louth</a>; Lissan, w <a href=\"https://pl.wikipedia.org/wiki/Londonderry_(hrabstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">hrabstwie Londonderry</a>; i Cnoc Áine koło Teelin, w <a href=\"https://pl.wikipedia.org/wiki/Donegal_(hrabstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">hrabstwie Donegal</a>.", "Anh Thư": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Anzhella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anzhela</b>.</p><p>Angela to imię kobiety. Pochodzi od greckiego słowa ángelos (⁇ γγελος), co oznacza anioła z greckiego systemu wierzeń.</p>", "Annastasia": "<p>Annastasia to kobiece imię. Wśród znanych osób z tym nazwiskiem są Annastasia Baker (ur. 1988), brytyjska piosenkarka i pisarka piosenek Annastasia Batikis (1927 - 2016), amerykańska piłkarka bejsbolowa Annastasia Raj (ur. 1975), malezyjska biegaczka.</p>", "Ariadne": "<p>Ariadne (; greckie: ⁇ ριάδνη; łacińskie: Ariadne) była kretową księżniczką w greckiej mityce. Jest związana głównie z labiryntem ze względu na jej udział w mitycznych opowieściach o Minotaurze i Theseusie.</p>", "Amala": "<p>Amala (dokładna literatura: Amala) jest nigerijską potrawą wykonaną z tłuszczowego mączki i/lub czyszczącego. To powód, który został wypełniony, wyprostowany, wypryszony, wysuszony, a następnie rozmieszany w powód.</p>", "Abigael": "<p>Abigail to kobiece imię. Nazwa pochodzi z biblijnego hebrajskiego: אֲבִיגַיִל / אֲבִִיגָיִל ʾĂ ⁇ īḡayīl, co oznacza \"radość mego ojca\" (alternatywnie \"moje ojciec jest radowany\" lub \"moje ojcowie są radości\", między innymi).</p>", "Antigoni": "<p>Antigony Baxton (grek. Αντιγόνη Μπάξτον; rodzaj.</p>", "Aracely": "<p>Araceli lub Aracely, hiszpańskie imię kobiety z łacińskiego Ara Cœli, \"ołtarz w niebie\", może odnosić się do:</p>", "Amena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amen</b>.</p>Na <a href=\"https://pl.wikipedia.org/wiki/Bliski_Wsch%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Bliskim Wschodzie</a> termin ten pierwotnie oznaczał potwierdzenie przysięgi żołnierskiej (<a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">Asyria</a>) – odpowiednik dzisiejszego „tak jest”, „rozkaz” lub „wykonam”. Jego wypowiedzenie po wysłuchaniu modlitw i błogosławieństw zastępowało ich odmówienie – w starożytności niewiele osób znało modlitwy na pamięć.", "Akua": "<p>Akua jest kobiece imię Akan wśród ludu Akan (tj. Ashanti, Akuapem, Bono, Akwamu, Akyem, Fante) w Ghanie, co oznacza \"narodzone w środę\" w języku Akan, zgodnie z ich systemem nazwań dnia.</p>", "Alora": "<p>Dolmio (r. Dolmio) - marka sosów do makaronu produkowanych przez Mars, Incorporated.</p>", "Anina": "<p>Anina jest miejscowością w prowincji Caraș-Severin, Rumunii. W 2002 roku liczba ludności wynosiła 9172.</p>", "Ariiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ariian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arian</b>.</p><b>Arian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jego patronem jest św. Arian, wspominany razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Teotyk_(m%C4%99czennik_egipski)\" target=\"_blank\" rel=\"noopener noreferrer\">Teotykiem</a>.", "Anthea": "<p>Anthea (w starożytnym greckim ⁇ νθεια), \"kwiecień\" w greckim, był epitetem klasycznej greckich bogini Hery, bogini małżeństwa, kobiet i rodziny, a ochroniarz kobiet podczas porodu. Anthea jest używane jako imię żeńskie w języku angielskim.</p>", "Aischa": "<p>Aisha (arabsko: عائشة, romanized: ʿʿʾishah, lit. 'żyjący' lub 'żyjący'; również pisowniane A'aisha, A'isha, Aischa, Aische, Aishah, Aishat, Aishath, Aicha, Aïcha, Aisya, Aisyah, Aiša, Ajša, Aixa, Ayesha, Aysha, Ayşe, Ayisha lub Iesha) jest arabską nazwą żeńską.</p>", "Alannah": "<p>Alannah to kobiece imię, wariant Alanna. Do wybitnych osób z nazwiskiem należą: Alannah Beirne (ur. 1993), irlandzka modelka mody i osobowość telewizji reality Alannah Currie (ur. 1957), nowozelandzką muzyką z Thompson Twins Alannah Halay (ur. 1990), brytyjską kompozytorką i autorką Alannah Hill (ur. 1962), australijską projektantką mody Alannah MacTiernan (ur. 1953), australijką polityką Alannah Mathews (ur. 1999),...</p>", "Aleksandrina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksandr</b>.</p><p>Aleksander lub Aleksandr może odnosić się do Aleksandra Michajłowicza Zaitsewa Aleksandr Valterovich Litvinenko Aleksandr II Rosji Aleksandr Grin Aleksandr Isayevich Solzhenitsyn Aleksandr Danilovich Menshikov</p>", "Anizja": "<b>Anizja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Anizjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Anizjusz</a> niejasnego pochodzenia. Według jednych źródeł pochodzi ono od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwiska</a> <i>Anisia</i>, <i>Anisii</i> niewiadomej proweniencji; według innych jego etymologia jest <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecka</a>, od <i>anisos</i> – „niejednakowy”.", "Ardiana": "<p>Ardian to albanska nazwa. Chociaż podobna do Adrian, nazwy pochodzenia łacińskiego, albanska Ardian (Ardjan i Ardijan są innymi wariantami) jest pochodem Ardiaei, nazwy starożytnego lyryjskiego ludu.</p>", "Agnieshka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Agnieszka</b>.</p><b>Agnieszka</b> – imię żeńskie, jedno z najpopularniejszych w Polsce, gdzie pojawiło się wraz z chrześcijaństwem. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγνή – „czysta”, „dziewicza”, „nieskalana”. Może również pochodzić od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>agnus</em> – „baranek” (to jednocześnie rodzaj męski greckiej „h-agne”). Do Czech imię to dotarło w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Agnes</em>, następnie zostało zaadaptowane do języka polskiego w obecnej formie. Imię to funkcjonuje również w języku polskim w formie Inka, początkowo było ono polskim zdrobnieniem imienia Inez — francusko-iberyjskiej formy imienia Agnieszka (Inês, Inés, Inès) — z czasem jednak zaczęło funkcjonować w Polsce jako samodzielne imię.", "Amirah": "<p>Amira (أميرة ʾamīrah) to kobiece imię oznaczające księżniczkę, dowódcę lub władcę. To kobieca wersja męskiego imienia Amir.</p>", "Almina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Almin</b>.</p><p>Almin to imię męskie. Na Bałkanach Almin jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Angie Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Ayleen": "<p>Aileen to irlandzkie imię żeńskie, wariant Eileen. Znani ludzie z tego nazwiska to: Aileen Adams (ur. 1923), brytyjska konsultantka anestetyka Aileen Allen (1888-1950), amerykańska nurkaczka Aileen Armitage (ur. 1930), brytyjska pisarka i autorka Aileen Baviera (1959-2020), filipinański politolog i sinolog Aileen Bernal (ur. 1994), panamska modelka i zwycięzca konkursu pięknowego Aileen Britton (1916-1986), australijska...</p>", "Alizée": "<p>Alizée (francuski: Alizée), urodzona w Alise Jacotte (francuska: Alise Jacoté).</p>", "Annmarie": "<p>Annemarie (lub Annamarie, Annmarie) jest duńskim, holenderskim i niemieckim imieniem żeńskim. To połączenie nazw Anne i Marie.</p>", "America": "<p>Ameryka (ang. America) zwykle oznacza: Ameryka - część świata.</p>", "Adriiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adriian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Akemi": "<b>Akemi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あけみ, アケミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Azime": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Azim</b>.</p><p>Azim (ʿAẓīm عظيم) jest jednym z imion Allaha w islamu, co oznacza \"Wielki\" lub \"Wspaniały\" lub \"Ochrony\". Jest używany przez wielu Sahrawiów jako nazwisko pochodzące z arabskiego Hasania.</p>", "Apolinaria": "<b>Apolinaria</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Apolinary\" target=\"_blank\" rel=\"noopener noreferrer\">Apolinary</a>. W <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a> i krajach wschodniosłowiańskich utworzono od Apolinarii skróconą formę Polina (możliwą też od <a href=\"https://pl.wikipedia.org/wiki/Pelagia\" target=\"_blank\" rel=\"noopener noreferrer\">Pelagii</a> lub współcześnie jako fonetyczne przeniesienie francuskiej <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Pauline</a> na grunt rosyjski), która w 2007 roku imię była drugim pod względem liczby nadań wśród noworodków imieniem żeńskim w okręgu moskiewskim w Rosji. Według stanu na 17 stycznia 2015 imię to miało w Polsce 5 nadań.", "Aleksandrova": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksandrov</b>.</p><p>Aleksandrov jest miastem i centrum administracyjnym Aleksandrovskiego w Vladimir Oblastie, Rosja, 120 km (75 mi) na północny wschód od Moskwy. Populacja: 61,551 (Populska ankieta 2010), 64,824 (Populsa ankieta 2002) i 68,220 (Populsta ankieta 1989).</p>", "Arna": "<p>Alfa Romeo Arna (Seria 920) - kompaktowy samochód produkowany przez włoską firmę samochodową Alfa Romeo Nissan Autoveicoli S.p. A. w latach 1983 - 1987.</p>", "Apolinariia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Apolinaria</b>.</p><b>Apolinaria</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Apolinary\" target=\"_blank\" rel=\"noopener noreferrer\">Apolinary</a>. W <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a> i krajach wschodniosłowiańskich utworzono od Apolinarii skróconą formę Polina (możliwą też od <a href=\"https://pl.wikipedia.org/wiki/Pelagia\" target=\"_blank\" rel=\"noopener noreferrer\">Pelagii</a> lub współcześnie jako fonetyczne przeniesienie francuskiej <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Pauline</a> na grunt rosyjski), która w 2007 roku imię była drugim pod względem liczby nadań wśród noworodków imieniem żeńskim w okręgu moskiewskim w Rosji. Według stanu na 17 stycznia 2015 imię to miało w Polsce 5 nadań.", "Aglaya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aglaia</b>.</p><p>Aglaia (lat. Aglaia) - rodzaj roślin kwiatowych z rodziny Meliaceae.</p>", "Amaranta": "<b>Amaranta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia Amarant/Amarantus, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;αμάραντος (<i>amarantos</i>), co oznacza \"niezatarty\", \"niewygasający\". Patronem tego imienia jest św. Amarant(us) z <a href=\"https://pl.wikipedia.org/wiki/Albi\" target=\"_blank\" rel=\"noopener noreferrer\">Albi</a> (<a href=\"https://pl.wikipedia.org/wiki/VI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VI wiek</a>).", "Anitha": "<p>Anita Hassanandani (ur. 14 kwietnia 1981), znana również jako Natasha, jest indyjską modelką, aktorką filmową i telewizyjną.</p>", "Angele": "<p>Angél Van Lacken (francuski: Angél Van Lacén)  Angèle Van Laeken, rodzaj.</p>", "Angéla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Anatoliia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anatolii</b>.</p><p>Anatolii (rosyjski: Анатолий, romanizowany: Anatoliy, ukraiński: Анато́лій, romanized: Anatolii) jest powszechną rosyjską i ukraińską nazwą męską, pochodzącą z greckiego imienia Anatolios (⁇ νατόλιος), co oznacza \"on wschodu słońca\", z ἀνατολή anatolē, \"wychod słońca\". Anatoly było jednym z pięciu najpopularniejszych imion dla chłopców urodzonych w St.</p>", "Alissia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alisia</b>.</p><p>Alicia to kobiece imię. Jest to wariant Alice, który pochodzi z germańskiego imienia Adalheidis (Adelaide), co oznacza \"szlachetny natury\" (szlachetnego rodzaju).</p>", "Africa": "<p>Nie należy mylić z tym samym tytułem piosenki Africa - oryginalną angielską wersją piosenki L'Été indien. Africa to piosenka amerykańskiego zespołu rockowego Toto.</p>", "Amyra": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amira</b>.</p><b>Amira</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> أميرة) – imię arabskie, oznaczające „<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99%C5%BCniczka\" target=\"_blank\" rel=\"noopener noreferrer\">księżniczka</a>”. Słowo to także funkcjonuje w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języku arabskim</a> potocznie.", "Amaris": "Obszar doradztwa obejmuje sektor <a href=\"https://pl.wikipedia.org/wiki/Technologia_informacyjna\" target=\"_blank\" rel=\"noopener noreferrer\">IT</a>, strategii oraz usług <a href=\"https://pl.wikipedia.org/wiki/Outsourcing\" target=\"_blank\" rel=\"noopener noreferrer\">outsourcingowych</a> zawierających się w następujących pionach biznesowych: technologie informacyjne oraz biznesowe <a href=\"https://pl.wikipedia.org/wiki/System_informacyjny\" target=\"_blank\" rel=\"noopener noreferrer\">systemy informacyjne</a> zarządzania, inżynieria w zakresie zaawansowanych technologii, <a href=\"https://pl.wikipedia.org/wiki/Telekomunikacja\" target=\"_blank\" rel=\"noopener noreferrer\">telekomunikacja</a>, <a href=\"https://pl.wikipedia.org/wiki/Biotechnologia\" target=\"_blank\" rel=\"noopener noreferrer\">biotechnologia</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Farmacja\" target=\"_blank\" rel=\"noopener noreferrer\">farmacja</a>.", "Akwilina": "<b>Akwilina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego. Patronką tego imienia jest św. Akwilina (III wiek).", "Abena": "<p>Abena jako imię, to imię dziewczęce pochodzące z Ghany i oznacza urodzone w wtorek. Nazwa dziennika jest praktyką kulturalną mieszkańców Ghany.</p>", "Alanis": "<p>Alanis to debiutancki album studiowy Alanis Morissette'a, wydany na MCA Records tylko w Kanadzie w kwietniu 1991 roku i ostatecznie stały się platyną.</p>", "Akhila": "<p>Akhila (w Devanagari: अखिला akhilā) to hindusko-sanskrityckie imię indyjskie, co oznacza \"wszystko\" lub \"pełne\". Akhilā oznacza współmałżonka boga Akhil, który jest Gokul.</p>", "Allana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Allan</b>.</p><p>Harry Howard Barton Allan (27 kwietnia 1882 - 29 października 1957) - nowozelandski botanik.</p>", "Adél": "<p>Adela (zwane również Adéla lub Adella) jest nazwiskiem dla kobiet, latynatyczną formą Adele, co oznacza \"szlachetny\" lub \"serenny\". Adela to męskie imię w Etiopii, co oznacza \"favory\" i imię kobiety w języku arabskim (عدله).</p>", "Arleen": "<p>Arleen lub Arlene jest irlandzką kobiecą nazwą i wariantem Carlene lub Charlene, a w języku francuskim pochodząca od kobiecej diminutiwów Charles (co oznacza wolnego człowieka).</p>", "Anushree": "<p>Anushree i Anusree to imiona indyjskie pochodzące od kobiet. To imię pierwotnie oznaczało Piękne i Piękne / Przyjemne poranek.</p>", "Aliz": "<p>Alice to żeńskie imię z korzeniami w językach francuskim i niemieckim.</p>", "Anastazya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastazy</b>.</p><b>Anastazy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa oznaczającego „wskrzeszenie”, „zmartwychwstanie”. Jego żeńskim odpowiednikiem jest <a href=\"https://pl.wikipedia.org/wiki/Anastazja\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazja</a>.", "Andzhelika": "<p>Angelika jest wariantem Angelica, pochodzącym z łacińskiego angelicus oznacza \"aniolic\", ostatecznie związany z greckim ⁇ γγελος (ángelos) - \"przesłaniec\". Poety Boiardo i Ariosto użyli tego nazwiska w swoich wierszach \"Orlando\" (1495 i 1532), gdzie należy do zainteresowania miłosnego Orlando.</p>", "Anna-Liza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Atsuko": "<b>Atsuko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あつこ, アツコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Anaisa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anais</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Adelheida": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adelheid</b>.</p><p>Adelheid (niem. Adelheid; 977 - 14 stycznia 1044) - córka cesarza Świętej Imperium Rzymskiego Ottona II Rzeźnego i cesarzy Feofanos, od 999 do 1044 r. przewodniczyła opatstwu Kwedlinburg.</p>", "Aleksandra Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aleksandra</b>.</p><b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Abisola": "<p>Abisola to kobiece imię pochodzenia joruba, które tłumaczy się jako Born into wealth.</p>", "Aminah": "<p>Amina (lub Aminah) jest luźnym transkrypcją dwóch różnych arabskich nazwisk kobiet: ʾĀmina (arabski: آمنة, również anglicized jako Aaminah lub Amna) oznaczające \"bezpieczny, chroniony\" ʾAmīna (arabsko: أمينة, również angliczed jako Ameena), kobieca forma Amin, oznaczająca \"oddaną, uczciwą, prostą, wiarygodną, wartościową wiarę (wierzącą), lojalną, wierną, posłuszną Iman\". Nazwa jest bardzo popularna w Nigerii z powodu Aminy z Zazzau, a...</p>", "Ariia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aria</b>.</p><p>Aria: Aria to album brytyjskiego zespołu prog-rock Asia. Aria - instrumentalny album trybjutów poświęcony zespołowi ⁇ Aria ⁇ .</p>", "Adelinda": "<b>Adelinda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Składa się z członów <i>adal</i> – \"szlachetny ród\" (por. <a href=\"https://pl.wikipedia.org/wiki/Adalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Adalgunda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbert</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>) i <i>lind</i> – \"miękka, łagodna\" (por. <a href=\"https://pl.wikipedia.org/wiki/Rozalinda\" target=\"_blank\" rel=\"noopener noreferrer\">Rozalinda</a>). W Kościele katolickim patronką tego imienia jest Adelinda z <a href=\"https://pl.wikipedia.org/wiki/Bad_Buchau\" target=\"_blank\" rel=\"noopener noreferrer\">Buchau</a>.", "Arpita": "<p>Arpita to indyjskie imię i żeńska forma Arpita. Według Penguin Book of Indian Names oznacza to \"przyznany\" lub \"przywiązany, dostarczony, powierzony, oddawany, oddawany\".</p>", "Apollina": "<b>Apollina</b>, <b>Apolina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <a href=\"https://pl.wikipedia.org/wiki/Apollo_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">imienia boga Apollona</a>. Patronką tego imienia jest św. Apollina, zm. w <a href=\"https://pl.wikipedia.org/wiki/249\" target=\"_blank\" rel=\"noopener noreferrer\">249</a> roku w <a href=\"https://pl.wikipedia.org/wiki/Aleksandria\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandrii</a>.", "Ayano": "<b>Ayano</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あやの, アヤノ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Afaf": "<p>Afaf (عفاف), przetransliterowany z arabskiego tunizjańskiego jako Afef, jest arabską nazwą żeńską. Do wybitnych osób z tym nazwiskiem należą:</p>", "Aurella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aurela</b>.</p><p>Aurela (znana ICAO = LSK) jest lotniczą linią lotniczą Litwy, z siedzibą w Vilnius. Transportery subskrybują podróżne firmy z krajów Bałtyku.</p>", "Anuncjata": "<b>Anuncjata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>annuntio</em>, które oznacza „ogłaszać, obwieszczać, zapowiadać, zwiastować”. Początkowo imię nadawane dla upamiętnienia <a href=\"https://pl.wikipedia.org/wiki/Zwiastowanie_Pa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Zwiastowania Najświętszej Maryi Pannie</a>.", "Alys": "<p>Alys to kobiece imię. Do znanych osób z nazwiskiem należą: Alys, hrabina Vexin (kr.</p>", "Anna-Diana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ai</b>.</p><b>Ai</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;愛, 藍, あい, アイ) – popularne żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>. Jest ono skróconą, nowocześniejszą formą <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Aiko_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Aiko</a> (w latach 80. XX wieku żeńskie imiona z końcówką 子 <i>ko</i> wyszły z mody).", "Apolinara": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Apolinar</b>.</p><p>Apolinar to męskie imię, które może odnosić się do: Apolinar de Jesús Soto Quesada (1827-1911), boliwskiego polityka Apolinar Serrano (1833-1876), hiszpańskiego biskupa Hawany Apolinar Velez (1865-1939), filipińskiego polityka</p>", "Amelina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amel</b>.</p><p>Amel (Francuz: Amblève) jest miastem w regionie Wallonie, prowincji Liège, i należy do niemieckojęzycznej społeczności w Belgii (German: Deutschsprachige Gemeinschaft Belgiens). Na 1 stycznia 2006 roku Amel miał łącznie 5.282 mieszkańców.</p>", "Alwira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alvira</b>.</p><p>Alvira to imię. Jest to hiszpańskie nazwisko; jako nazwisko, jest czasami uważane za wariant Elviri.</p>", "Adiba": "<b>Adiba</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أديبة&#8206;) – arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Jego znaczenie to „kulturalna, wyrafinowana”. Żeńska wersja imienia Adib. W języku arabskim słowo <i>adiba</i> oznacza również <a href=\"https://pl.wikipedia.org/wiki/Pisarz\" target=\"_blank\" rel=\"noopener noreferrer\">pisarkę</a>.", "Anastasyia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Anna-Khrystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anuszka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anushka</b>.</p><p>Nazwa Anoushka, Anouska, Anuschka, Anushka i Annushka są drobnymi formami nazwiska żeńskiego Anna, pochodzącym z rosyjskiego drobnego Annuшка. Anoushka (انوشکا) oznacza również \"łaska\" lub \"fałsza\" lub \"kwień\" w perskim.</p>", "Angela Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angela</b>.</p><b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Angie Lorena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Anastasiia-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Anna-Anhelina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aika": "<b>Aika</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あいか, アイカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Antonyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anton</b>.</p><p>Anton (niem. Anton) z nazwiska Anton Dobry (niem.</p>", "Angie Lizeth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Anyela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aniela</b>.</p><b>Aniela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które jest spolszczoną formą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa <i>ángelos</i> „posłaniec”. Imię trafiło do Polski z Włoch prawdopodobnie w XVIII wieku. W świecie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> upowszechniło się jako nawiązanie do <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">aniołów</a> i <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_Str%C3%B3%C5%BC_(religioznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioła Stróża</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>.", "Artemia": "<b>Artemia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, wywodzące się od imienia bogini <a href=\"https://pl.wikipedia.org/wiki/Artemida\" target=\"_blank\" rel=\"noopener noreferrer\">Artemidy</a>, a oznaczające „zdrowa” lub „należąca do Artemidy, poświęcona Artemidzie”.", "Adriyana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adriiana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adriian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Amisha": "<p>Amisha to imię. Znani ludzie z nazwiskiem to: Amisha Patel (ur. 1975), indyjska aktorka z Bollywood Amisha Sethi, indyjska autorka, filantrop, lider biznesu i model.</p>", "Artemizja": "<b>Artemizja</b> – greckie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie.", "Aymani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ayman</b>.</p><b>Ayman</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> َأيْمَن) – arabskie imię męskie, oznaczające: błogosławiony, szczęśliwy. Bywa zapisywane także jako Ajman, Aiman, Aimen, Aymen.", "Annalise": "<p>Anneliese to nazwisko żeńskie pochodzące z Niemiec, Holandii lub Skandynacji. Jest to mieszane z \"Anny\" i \"Liese\", krótka forma \"Elisabeth\".</p>", "Astryd": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Astryda</b>.</p><b>Astryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronorweskich</a> wyrazów <i>áss</i> – „bóg” i <i>fríðr</i> – „piękna” (mogło zatem oznaczać „piękna jak bóg”). Patronką tego imienia jest bł. Astryda.", "Alina-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Angie Carolina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Adema": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adem</b>.</p><b>Adem</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie będące <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">sturkizowaną</a> wersją imienia <a href=\"https://pl.wikipedia.org/wiki/Adam\" target=\"_blank\" rel=\"noopener noreferrer\">Adam</a>, występujące też jako nazwisko.", "Astera": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aster</b>.</p>Nazwa rodzajowa <i>Aster</i> pochodzi od starogreckiego słowa ἀστέρı (astéri), co znaczy „gwiazda”. Nawiązuje ona do gwiaździstego kształtu <a href=\"https://pl.wikipedia.org/wiki/Koszyczek\" target=\"_blank\" rel=\"noopener noreferrer\">koszyczka</a> kwiatowego.", "Asija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asia</b>.</p><p>Azja - część świata, która wraz z Europą tworzy kontynent Eurazja. Termin może również oznaczać:</p>", "Alyssia": "<p>Alicia to kobiece imię. Jest to wariant Alice, który pochodzi z germańskiego imienia Adalheidis (Adelaide), co oznacza \"szlachetny natury\" (szlachetnego rodzaju).</p>", "Alina-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Anais-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anais</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aarna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arna</b>.</p><p>Alfa Romeo Arna (Seria 920) - kompaktowy samochód produkowany przez włoską firmę samochodową Alfa Romeo Nissan Autoveicoli S.p. A. w latach 1983 - 1987.</p>", "Allia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alli</b>.</p><p>Alli to nazwisko i unisex. Do wybitnych osób z tym nazwiskiem należą:</p>", "Almut": "<p>Almut to niemieckie imię. Do wybitnych osób z tym nazwiskiem należą: Almut Brömmel (ur. 1935), niemiecki rzucacz włóczni i dysków Almut Burchard, niemiecko-kanadyjski matematycz Almut Hintze (ur. 1957), niemiecka akademik, filolog, lingwist i uczony Almut Iken (1933-2018), niemiecki lodowiec Almut Kemperdick (ur. 1963), niemieccy piłkarz siatkówki Almut Lehmann (ur. 1953), niemiecko pater Almut Hege-Schöll (ur. 1958), niemiec...</p>", "Allie": "<p>Allie to unisex, pseudonim i rzadko nazwisko. Jest to drobna forma kilku nazw, które zaczynają się od Al-.</p>", "Agness": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Agnes</b>.</p><b>Agnieszka</b> – imię żeńskie, jedno z najpopularniejszych w Polsce, gdzie pojawiło się wraz z chrześcijaństwem. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγνή – „czysta”, „dziewicza”, „nieskalana”. Może również pochodzić od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>agnus</em> – „baranek” (to jednocześnie rodzaj męski greckiej „h-agne”). Do Czech imię to dotarło w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Agnes</em>, następnie zostało zaadaptowane do języka polskiego w obecnej formie. Imię to funkcjonuje również w języku polskim w formie Inka, początkowo było ono polskim zdrobnieniem imienia Inez — francusko-iberyjskiej formy imienia Agnieszka (Inês, Inés, Inès) — z czasem jednak zaczęło funkcjonować w Polsce jako samodzielne imię.", "Alysa": "<p>Alyssa to kobiece imię z wielu pochodzeń. Alysa to alternatywne pisowni.</p>", "Andrea Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Adinai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adina</b>.</p><p>Adina (lat. Adina) - rodzaj drewnianych roślin z rodziny Marenowych (Rubiaceae).</p>", "Aastha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Astha</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asta</b>.</p><p>Asta to rodzaj roślin kwiatowych z rodziny Części.</p>", "Astha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asta</b>.</p><p>Asta to rodzaj roślin kwiatowych z rodziny Części.</p>", "Akacja": "Akacje występują na <a href=\"https://pl.wikipedia.org/wiki/Sawanna\" target=\"_blank\" rel=\"noopener noreferrer\">sawannach</a>, w okresowo suchych formacjach leśnych i zaroślowych oraz na pustyniach. Stanowią kluczowy składnik takich australijskich formacji jak <a href=\"https://pl.wikipedia.org/wiki/Mulga\" target=\"_blank\" rel=\"noopener noreferrer\">mulga</a> czy <a href=\"https://pl.wikipedia.org/wiki/Brigalow\" target=\"_blank\" rel=\"noopener noreferrer\">brigalow</a>.", "Aviana": "<p>Aviana lub Avianna jest imieniem kobiece z wieloma pochodzeniami. Jest to grönolandska nazwa, wariant grönolanderskiej nazwy Avek, co oznacza \"rodzina\", połączona z grönoländskim końcem -na, który wskazuje na imię pierwsze.</p>", "Adwoa": "<p>Adwoa to imię używane dla kobiet urodzonych w poniedziałek w Afryce Zachodniej, szczególnie w Ghanie i niektórych częściach Togo, południowego Beninu i wybrzeża kości słoniowej. Nazwa dni to kulturowa praktyka mieszkańców Ghany i Wybrzeża Kości Słoniowej.</p>", "Antea": "<b>Antea</b> – imię <a href=\"https://pl.wikipedia.org/wiki/Kobieta\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/W%C4%99gry\" target=\"_blank\" rel=\"noopener noreferrer\">węgierskiego</a>. Pochodzi od imienia \"Anteo\" czyli <a href=\"https://pl.wikipedia.org/wiki/Antoni_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antoni</a>. Może też pochodzić od imienia greckiej bogini <a href=\"https://pl.wikipedia.org/wiki/Atena\" target=\"_blank\" rel=\"noopener noreferrer\">Ateny</a>. Imię to nosiła główna bohaterka powieści \"<a href=\"https://pl.wikipedia.org/wiki/Pi%C4%99cioro_dzieci_i_co%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Pięcioro dzieci i coś</a>\" autorstwa <a href=\"https://pl.wikipedia.org/wiki/Edith_Nesbit\" target=\"_blank\" rel=\"noopener noreferrer\">Edith Nesbit</a>. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> imię rzadko spotykane.", "Adamma": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adama</b>.</p><p>Adama (oromo: Adaamaa lub Hadaamaa) jest miastem w centrum Oromia. Adama jest obszarem Oromia i otoczony jest obszarami wschodniej Shewa.</p>", "Amruta": "<p>Amrita (sanskrit: अमृत, IAST: amṛta), Amrit lub Amata w języku Pali, (zwany również Sudha, Amiy, Ami) jest słowem sanskryckim, które oznacza \"nieśmiertelność\". Jest to centralna koncepcja w indyjskich religiach i często jest określana w starożytnych tekstach indyjskich jako elixir.</p>", "Abike": "<p>Àbíkẹ́ to nazwa joruba powszechna w Nigerii. Oznacza to \"Ten, który jest urodzony, by się o niego dbać\" lub \"Ten, kto jest urodzany, aby go rozbawić\".</p>", "Andreea-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Adjoa": "<p>Adwoa to imię używane dla kobiet urodzonych w poniedziałek w Afryce Zachodniej, szczególnie w Ghanie i niektórych częściach Togo, południowego Beninu i wybrzeża kości słoniowej. Nazwa dni to kulturowa praktyka mieszkańców Ghany i Wybrzeża Kości Słoniowej.</p>", "Angie Tatiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Alexandra-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Ameni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amen</b>.</p>Na <a href=\"https://pl.wikipedia.org/wiki/Bliski_Wsch%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Bliskim Wschodzie</a> termin ten pierwotnie oznaczał potwierdzenie przysięgi żołnierskiej (<a href=\"https://pl.wikipedia.org/wiki/Asyria\" target=\"_blank\" rel=\"noopener noreferrer\">Asyria</a>) – odpowiednik dzisiejszego „tak jest”, „rozkaz” lub „wykonam”. Jego wypowiedzenie po wysłuchaniu modlitw i błogosławieństw zastępowało ich odmówienie – w starożytności niewiele osób znało modlitwy na pamięć.", "Andreea-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Akgul": "<p>Akgül lub Akgul (co oznacza \"Biała Róża\" w kilku językach tureckich) może odnosić się do:</p>", "Aislinn": "<p>Aisling to irlandzkie imię żeńskie oznaczające \"mar\" lub \"wizja\". Odnosi się do paszportu, gatunku poetycznego, który rozwinął się w irlandzkiej poezji w XVII i XVIII wieku.</p>", "Angie Daniela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Aino": "Motyw młodej dziewczyny wydanej za mąż wbrew woli jest typowy dla romantyzmu lub średniowiecza. Elias Lönnrot spisywał Kalevalę na podstawie starych ludowych wierszy i pieśni (<i>fin. runo </i>) Niewątpliwie uległ jednak inspiracji wieloma innymi motywami literackimi pochodzącymi z innych epok i kultur. Postać Aino przypomina np. polską legendę o \"<a href=\"https://pl.wikipedia.org/wiki/Wanda_(legendarna_ksi%C4%99%C5%BCniczka)\" target=\"_blank\" rel=\"noopener noreferrer\">Wandzie, co nie chciała Niemca</a>\"", "Agnieszka Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Agnieszka</b>.</p><b>Agnieszka</b> – imię żeńskie, jedno z najpopularniejszych w Polsce, gdzie pojawiło się wraz z chrześcijaństwem. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγνή – „czysta”, „dziewicza”, „nieskalana”. Może również pochodzić od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>agnus</em> – „baranek” (to jednocześnie rodzaj męski greckiej „h-agne”). Do Czech imię to dotarło w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Agnes</em>, następnie zostało zaadaptowane do języka polskiego w obecnej formie. Imię to funkcjonuje również w języku polskim w formie Inka, początkowo było ono polskim zdrobnieniem imienia Inez — francusko-iberyjskiej formy imienia Agnieszka (Inês, Inés, Inès) — z czasem jednak zaczęło funkcjonować w Polsce jako samodzielne imię.", "Ariena": "Imiona wszystkich Majarów pochodzą z quenyi.", "Aretha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Areta</b>.</p><b>Areta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie niejasnego pochodzenia. <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Bubak\" target=\"_blank\" rel=\"noopener noreferrer\">Józef Bubak</a> łączy je ze skróconą formą <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzaty</a> (niem. <i>Margareta</i>), powstałą na gruncie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a>. Imię to nosiła także <a href=\"https://pl.wikipedia.org/wiki/Arete_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">postać z mitologii greckiej</a>, królowa <a href=\"https://pl.wikipedia.org/wiki/Feakowie\" target=\"_blank\" rel=\"noopener noreferrer\">Feaków</a>, której imię stanowi przymiotnik odczasownikowy od wyrazu <i>αραομαι (araomai)</i> („modlę się o coś, gorąco pragnę”) i oznacza „dziecko upragnione”(por. <a href=\"https://pl.wikipedia.org/wiki/Dezyderia\" target=\"_blank\" rel=\"noopener noreferrer\">Dezyderia</a>, <a href=\"https://pl.wikipedia.org/wiki/Aspazja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Aspazja</a>). Można także spotkać się z poglądem, iż imię to pochodzi od greckiego słowa <i>αρετη (<a href=\"https://pl.wikipedia.org/wiki/Aret%C3%A9\" target=\"_blank\" rel=\"noopener noreferrer\">areté</a>)</i> oznaczającego „cnotę”, „męstwo”; Areta stanowiłaby wówczas żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Aretas\" target=\"_blank\" rel=\"noopener noreferrer\">Aretas</a>.", "Ayca": "<p>Ayça jest powszechną kobiecą turską nazwą. Ayça pochodzi od Ay (księżyca) i może oznaczać jak księżyc, mały księżyc lub półksiężyc.</p>", "Anet": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aneta</b>.</p><b>Aneta</b>, <b>Anetta</b> – forma pochodna imienia <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anna</a>, powstała jako przeniesienie francuskiego zdrobnienia tego imienia, <i>Anette</i>, do języka polskiego. Pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>. Imię dotarło do Polski w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX w.</a>, wcześniej używano tylko imienia Anna.", "Anastasiae": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastasia</b>.</p><b>Anastazja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anastazy\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazy</a>. Oznacza „zmartwychwstała, wskrzeszona”.", "Amritha": "<p>Amrita (sanskrit: अमृत, IAST: amṛta), Amrit lub Amata w języku Pali, (zwany również Sudha, Amiy, Ami) jest słowem sanskryckim, które oznacza \"nieśmiertelność\". Jest to centralna koncepcja w indyjskich religiach i często jest określana w starożytnych tekstach indyjskich jako elixir.</p>", "Antonia-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonia</b>.</p><b>Antonia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antoni_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antoni</a>. W Polsce pojawiło się wcześniej niż imię <a href=\"https://pl.wikipedia.org/wiki/Antonina\" target=\"_blank\" rel=\"noopener noreferrer\">Antonina</a>, ale następnie zostało przez nie wyparte. W Kościele katolickim istnieją dwie patronki tego imienia.", "Afag": "<p>Afag (azerbajdżansko: Afaq, lit. 'Horizon') jest kobiece imię i nazwa pochodzenia azerbajdżanskiego.</p>", "Amellia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amelia</b>.</p><b>Amelia</b>, <b><a href=\"https://pl.wikipedia.org/wiki/Amalia\" target=\"_blank\" rel=\"noopener noreferrer\">Amalia</a></b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako skrócenie imion dwuczłonowych z pierwszym członem <i>Amal-</i>, takich jak między innymi <a href=\"https://pl.wikipedia.org/wiki/Amalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Amalgunda</a> lub <a href=\"https://pl.wikipedia.org/wiki/Amalberga\" target=\"_blank\" rel=\"noopener noreferrer\">Amalberga</a>.", "Aliane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alian</b>.</p>Populacja dzielnicy Alian w 2016 roku liczyła 29&#160;093 mieszkańców – 14&#160;407 kobiet i 14&#160;686 mężczyzn. Liczba gospodarstw domowych wynosiła 9407, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,09 osób.", "Arystyda": "<b>Arystyda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od gr. <i>Αριστειδης (Aristeides)</i>, co oznacza \"najlepszy rodzaj\", stanowiąc złożenie członów <i>αριστος (aristos)</i> – \"najlepszy\" i <i>ειδος (eidos)</i> – \"rodzaj, gatunek\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Arystydes_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Arystydes</a>, którego patronem w Kościele katolickim jest św. Arystydes Marcjanus (<a href=\"https://pl.wikipedia.org/wiki/II_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">II wiek</a>).", "Antonina Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonina</b>.</p><b>Antonina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antonin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonin</a>; uformowany przy użyciu <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, <i>-ina</i>, oznaczającego przynależność lub pochodzenie, <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwy rodowej</a> <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Antoniuszów</a>. W Polsce Antonina pojawiła się później niż obecna od średniowiecza <a href=\"https://pl.wikipedia.org/wiki/Antonia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonia</a>; notowana jest co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1637\" target=\"_blank\" rel=\"noopener noreferrer\">1637</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Antonina w 2017 r. zajmowała 15. miejsce w grupie imion żeńskich. W całej populacji Polek Antonina zajmowała w 2017 r. 90. miejsce (43 462 nadań).", "Akosua": "<p>Akosua to imię Akan dla dziewczynki urodzonej w niedzielę (Kwasiada). Jest praktykowana głównie przez wszystkich Akanów (tj. Ashanti, Akuapem, Akyem, Akwamu, Bono, Fante) którzy stosują tradycyjne zwyczaje.</p>", "Asami": "<b>Asami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あさみ, アサミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, może być używane także jako nazwisko.", "Afreen": "<p>Afreen آفرین to nazwisko kobiece, zwykle dawane, oznaczające \"Najpiękniejszy\", \"Oświecenie\" i Houri nieba. Jej pochodzenie leży na Bliskim Wschodzie.</p>", "Arminda": "<p>Arminda jest nazwą kobiecą pochodzącą od rzymskiego imienia Arminius. Do znanych osób z imieniem Arminda należą: Arminda, główna postać w operze Mozarta La finta giardiniera.</p>", "Aaira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aira</b>.</p><p>Aira (lat. Aīra) - rodzaj małych jednorocznych traw z rodziny Zlaki lub Mlotlicowych (Poaceae), rosnących w umiarkowanych obszarach obu półkuli, zwłaszcza wśródmorzawych rejonach Europy, Azji i Afryki.</p>", "Anna Zofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna-Valeriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Ami̇ne": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amin</b>.</p><b>Amin</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Oznacza „godny zaufania” lub „prawdomówny”. Nosił je szósty <a href=\"https://pl.wikipedia.org/wiki/Kalif\" target=\"_blank\" rel=\"noopener noreferrer\">kalif</a> <a href=\"https://pl.wikipedia.org/wiki/Abbasydzi\" target=\"_blank\" rel=\"noopener noreferrer\">abbasydzki</a>.", "Anthi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anti</b>.</p>Jego kult jest bardzo stary, pochodzi co najmniej z okresu <a href=\"https://pl.wikipedia.org/wiki/II_dynastia\" target=\"_blank\" rel=\"noopener noreferrer\">drugiej dynastii</a>, kiedy to miał już swoich kapłanów. Anti najprawdopodobniej był patronem dawnej okolicy Badari, które było centrum kultu <a href=\"https://pl.wikipedia.org/wiki/Horus\" target=\"_blank\" rel=\"noopener noreferrer\">Horusa</a>. Przedstawiany jest jako sokół stojący na łodzi.", "Antonova": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Antonov</b>.</p><p>Antonov, znany również jako Antonov Aviation Science/Technology Corporation (Antonov ASTC) (ukraińska: Авиационный науково-техничний комплекс имени Антонова, АНТК им. Антонова) jest Ukrainy (od 1952) (biuro projektowe z preliminarem An) z specjalizacją w produkcji superdużych samolotów transportowych.</p>", "Ainoa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aino</b>.</p>Motyw młodej dziewczyny wydanej za mąż wbrew woli jest typowy dla romantyzmu lub średniowiecza. Elias Lönnrot spisywał Kalevalę na podstawie starych ludowych wierszy i pieśni (<i>fin. runo </i>) Niewątpliwie uległ jednak inspiracji wieloma innymi motywami literackimi pochodzącymi z innych epok i kultur. Postać Aino przypomina np. polską legendę o \"<a href=\"https://pl.wikipedia.org/wiki/Wanda_(legendarna_ksi%C4%99%C5%BCniczka)\" target=\"_blank\" rel=\"noopener noreferrer\">Wandzie, co nie chciała Niemca</a>\"", "Alicja Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alicja</b>.</p>Może pochodzić od włoskiej, żeńskiej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksy\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksy</a> – Alessis, imię to przyjmowało w językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskim</a> formę Alexia.", "Aarushi": "<p>Arushi lub Aarushi może odnosić się do: Arushi, żony legendarnej mędrca Chyavana Arushi Sharma (urodzona w 1995 roku), indyjskiej aktorki Aarushi Sharma, indyjskiego aktorki i królowej piękności Aarushi Talwar (1994-2008), ofiary w sprawie podwójnego morderstwa w Noida w 2008 roku</p>", "Arijana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arijan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arian</b>.</p><b>Arian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jego patronem jest św. Arian, wspominany razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Teotyk_(m%C4%99czennik_egipski)\" target=\"_blank\" rel=\"noopener noreferrer\">Teotykiem</a>.", "Aleksia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksi</b>.</p><p>Aleksi to męskie fińskie imię. Do wybitnych osób z tym nazwiskiem należą: Aleksi Bardy, fiński scenarzysta i producent filmowy Aleksi Benashvili, gruziński piłkarz Aleksi Eeben, fiński kompozytor, projektant dźwięku, muzyk i programista Aleksi Elorinne, fiński hokejista lodowy Aleksi Heimosalmi, fiński gracz lodowy Hihnavaara Aleksi, fiński granicą Aleksi Holmberg, fiński piłka hokeja Aleksi Honka-Hallila, fiński...</p>", "Anna Antonina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Atinuke": "<p>Atinuke to kobiece imię pochodzenia joruba, co oznacza pielęgnowane lub pielęgnowane od łono matki.</p>", "Aureliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aurelia</b>.</p><b>Aurelia</b> – imię żeńskie pochodzące od nazwy rzymskiego rodu Aurelia, która z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>aureolus</em> – „złocisty, złoty”, co mogło znaczyć także „wspaniały”.", "Aura Cristina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aura</b>.</p><p>⁇ Aura ⁇ (rosyjski: Аура) - piosenka amerykańskiej piosenkarki i autorki Lady Gaga z jej trzeciego albumu studiowego Artpop.</p>", "Abdona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abdon</b>.</p><b>Abdon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa oznaczającego „sługa”. Nosił je <a href=\"https://pl.wikipedia.org/wiki/Abdon_i_Senen\" target=\"_blank\" rel=\"noopener noreferrer\">święty Abdon</a> żyjący w II lub III wieku. Abdon <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imieniny</a> obchodzi 30 lipca.", "Anastassiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastassia</b>.</p><p>Anastassia to kobiece imię. Znanymi osobami z nazwiskiem to: Anastassia Kovalenko (ur. 1991), estyjska motocyklowa wyścigacz drogowy Anastassja Khozissova (ur. 1979), rosyjska modelka Anastassya Michaeli (ur. 1975), izraelska dziennikarz, telewizyjna prezenterka i polityk Anastassie Morkovkina (ur. 1981), estyckie piłkarz</p>", "Azalea": "<b>Różanecznik</b>, azalia, rododendron (<i>Rhododendron</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny\" target=\"_blank\" rel=\"noopener noreferrer\">roślin</a> z rodziny <a href=\"https://pl.wikipedia.org/wiki/Wrzosowate\" target=\"_blank\" rel=\"noopener noreferrer\">wrzosowatych</a> (<i>Ericaceae</i>). Obejmuje ponad tysiąc <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunków</a>. W stanie naturalnym występują głównie w <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">Azji</a>, w mniejszej liczbie gatunków w obydwu <a href=\"https://pl.wikipedia.org/wiki/Ameryka\" target=\"_blank\" rel=\"noopener noreferrer\">Amerykach</a> i w <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europie</a>. Rosną zwykle na obszarach górskich, na glebach próchnicznych i kwaśnych, często także na <a href=\"https://pl.wikipedia.org/wiki/Torfowisko\" target=\"_blank\" rel=\"noopener noreferrer\">torfowiskach</a> i na glebach oraz skałach wapiennych. Zasiedlają lasy, formacje krzewiaste i wrzosowiska. Nieliczne gatunki są <a href=\"https://pl.wikipedia.org/wiki/Epifit\" target=\"_blank\" rel=\"noopener noreferrer\">epifitami</a>. Kwiaty są u części gatunków wonne, u innych nie. <a href=\"https://pl.wikipedia.org/wiki/Zapylenie\" target=\"_blank\" rel=\"noopener noreferrer\">Zapylane</a> są przez <a href=\"https://pl.wikipedia.org/wiki/Owady\" target=\"_blank\" rel=\"noopener noreferrer\">owady</a>, niektóre gatunki w Himalajach także przez <a href=\"https://pl.wikipedia.org/wiki/Ptaki\" target=\"_blank\" rel=\"noopener noreferrer\">ptaki</a>.", "Andrea Del Pilar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Alyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Agape": "<b>Agape</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;<a href=\"https://pl.wiktionary.org/wiki/%E1%BC%80%CE%B3%CE%AC%CF%80%CE%B7\" target=\"_blank\" rel=\"noopener noreferrer\">ἀγάπη</a> <i>agápē</i>) – „miłość: najwyższa forma miłości, zwłaszcza miłość braterska, dobroczynność, miłość Boga do ludzi i ludzi do Boga”. Nie należy mylić z <i>philēo</i> – miłością braterską – agápē unosi uniwersalną, bezwarunkową, transcendentalną (wszechobecną) miłość, która istnieje niezależnie od sytuacji. Rzeczownik ten pierwszy raz występuje w <a href=\"https://pl.wikipedia.org/wiki/Septuaginta\" target=\"_blank\" rel=\"noopener noreferrer\">Septuagincie</a>, a w formie czasownika zapisana już przez <a href=\"https://pl.wikipedia.org/wiki/Homer\" target=\"_blank\" rel=\"noopener noreferrer\">Homera</a> – dosłownie tłumacząc, jest to afekt, życzliwość, szacunek, np. „witać z uczuciem” i „okazywać uczucie martwym.” Inni starożytni autorzy używali tego słowa jako symbol miłości małżonka lub rodziny albo uczucie do konkretnej czynności, w kontraście do <i>philia</i> (przyjaźń, miłość braterska) i <i>eros</i> (miłość intymna).", "Annelis": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Annelise</b>.</p><p>Anneliese to nazwisko żeńskie pochodzące z Niemiec, Holandii lub Skandynacji. Jest to mieszane z \"Anny\" i \"Liese\", krótka forma \"Elisabeth\".</p>", "Aysegül": "<p>Ayşegül to tureckie imię dla kobiet. Nazwa pochodzi od \"Ayşe\", tureckiej formy arabskiej nazwy Aisha, co oznacza \"w kobiecości, życie\" plus \"Gül\", perskie słowo oznaczające róże. \" Wśród znanych kobiet z imieniem Ayşegül są:</p>", "Anna-Oleksandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Alcira": "<p>Alcira to hiszpańskie imię żeńskie. Osoby z nazwiskiem to: Alcira Argumedo (1940-2021), argentyński socjolog, akademik, członek Argentyńskiej Izby Deputowanych Alcira Cardona Torrico (1926-2003), boliwskie pisarz i poeta Alcira Espinoza Schmidt de Villegas, boliwskie polityk Alcira de la Peña (1910-1998), argentyński lekarz i polityk Alcera Soust Scaffo (1924-1997), urugujeva nauczyciel i poeta</p>", "Aleksiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksiy</b>.</p><p>Alexey (rosyjski: Алексей, romanized: Aleksey [ɐljɪkˈsjej]) to rosyjskie imię męskie pochodzące od greckiego Aléxios (Αλέξιος), co oznacza \"Obrannik\", a zatem z tego samego pochodzenia jak łacina Alexius. Podobne ukraińskie i białoruskie nazwy są romanizowane odpowiednio jako Oleksii (Олексій) i Aliaksiej (Аляксей).</p>", "Anniina": "<p>Annie to kobiece imię. Jest często skróceniem dla innych nazw, takich jak Anna, Annette, Anita, Andrea, Angela, Anastasia lub Anniken.</p>", "Anna-Sofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aferdita": "<p>Aferdita lub Afërdita to żeńskie imię pochodzenia albańskiego. Znanymi osobami z nazwiskiem są: Afërdita Deva-Zuna (ur. 1950), kosowska profesorka uniwersyteckia Afërdeta Dreshaj (ur. 1986), albanian-amerykańska piosenkarka, modelka i tytułowca konkursu piękności Aferdita Kameraj (ur. 1984), niemiecka były piłkarka Aferdita Suka (ur. 1980), niemiecki polityk Afërdito Tusha (1945-2018), albanianka kobieta strzeleczka sportowa Afërdisa Veveçka...</p>", "Annelisa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Annelis</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Annelise</b>.</p><p>Anneliese to nazwisko żeńskie pochodzące z Niemiec, Holandii lub Skandynacji. Jest to mieszane z \"Anny\" i \"Liese\", krótka forma \"Elisabeth\".</p>", "Ali M": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Andreea-Mihaela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Anna Katarzyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Amaryllis": "<b>Amarylis nadobny</b> (<i>Amaryllis belladonna</i> L.) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunek</a> rośliny z rodzaju <a href=\"https://pl.wikipedia.org/wiki/Amarylis\" target=\"_blank\" rel=\"noopener noreferrer\">amarylis</a> z <a href=\"https://pl.wikipedia.org/wiki/Rodzina_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodziny</a> <a href=\"https://pl.wikipedia.org/wiki/Amarylkowate\" target=\"_blank\" rel=\"noopener noreferrer\">amarylkowatych</a>, pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Afryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki Południowej</a>, <a href=\"https://pl.wikipedia.org/wiki/Introdukcja\" target=\"_blank\" rel=\"noopener noreferrer\">introdukowany</a> do <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a>, <a href=\"https://pl.wikipedia.org/wiki/Ameryka_%C5%9Arodkowa\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Środkowej</a>, <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europy</a>, <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australii</a> i <a href=\"https://pl.wikipedia.org/wiki/Nowa_Zelandia\" target=\"_blank\" rel=\"noopener noreferrer\">Nowej Zelandii</a>.", "Alina-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Anna-Karina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aszanti": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ashanti</b>.</p><p>Ashanti Sheqvoy Douglas (ang. Ashanti Shequoiya Douglas; rodzaj.</p>", "Adebimpe": "<p>Adebimpe to imię. To znaczy \"Korona urodziła mnie pełną\"</p>", "Anna-Sophie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aryanna": "<p>Ariana to łacińska kobieca nazwa. Arianna i Ariane są najczęstszymi wariantami.</p>", "Annikki": "<p>Annie to kobiece imię. Jest często skróceniem dla innych nazw, takich jak Anna, Annette, Anita, Andrea, Angela, Anastasia lub Anniken.</p>", "Antia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anti</b>.</p>Jego kult jest bardzo stary, pochodzi co najmniej z okresu <a href=\"https://pl.wikipedia.org/wiki/II_dynastia\" target=\"_blank\" rel=\"noopener noreferrer\">drugiej dynastii</a>, kiedy to miał już swoich kapłanów. Anti najprawdopodobniej był patronem dawnej okolicy Badari, które było centrum kultu <a href=\"https://pl.wikipedia.org/wiki/Horus\" target=\"_blank\" rel=\"noopener noreferrer\">Horusa</a>. Przedstawiany jest jako sokół stojący na łodzi.", "Aneesa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anees</b>.</p><p>Anees to męskie imię pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Akilina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akil</b>.</p><p>Akil to miasto w stanie Yucatán w Meksyku. W 2005 roku liczba mieszkańców miasta wynosiła 9765 osób.</p>", "Ajoke": "<p>Ajoke to kobiece imię. Co oznacza (spólnie cenione).</p>", "Avgustina": "<p>Avgustina (rosyjski: Августи́на) to rzadkie nazwisko rosyjskie dla kobiet. Jego męskie wersje to Avgustin i Avgust.</p>", "Anna-Karolina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aisyah": "<p>Aisha (arabsko: عائشة, romanized: ʿʿʾishah, lit. 'żyjący' lub 'żyjący'; również pisowniane A'aisha, A'isha, Aischa, Aische, Aishah, Aishat, Aishath, Aicha, Aïcha, Aisya, Aisyah, Aiša, Ajša, Aixa, Ayesha, Aysha, Ayşe, Ayisha lub Iesha) jest arabską nazwą żeńską.</p>", "Anna-Kristina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Atanazja": "<b>Atanazja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Atanazy\" target=\"_blank\" rel=\"noopener noreferrer\">Atanazy</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Atanazja_(%C5%9Bwi%C4%99ta)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Atanazja</a>, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/IX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IX wieku</a>.", "Angela Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angela</b>.</p><b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Areen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aren</b>.</p><p>Arenę lub areny to związki organiczne \"z charakterystycznymi właściwościami chemicznymi benzenu\" i \"zestawieniem zestawów\". Obecne definicje związków perfumicznych nie mają nic wspólnego z zapachami.</p>", "Akwila": "<b>Akwila</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od <i>Aquila</i> (słowa oznaczającego \"orzeł\"). W <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> opisany jest <a href=\"https://pl.wikipedia.org/wiki/Akwila_i_Pryska\" target=\"_blank\" rel=\"noopener noreferrer\">Akwila</a>. Wśród znanych nosicieli tego imienia byli też św. Akwila, męczennik oraz tłumacz <a href=\"https://pl.wikipedia.org/wiki/Akwila_z_Synopy\" target=\"_blank\" rel=\"noopener noreferrer\">Akwila z Synopy</a>.", "Arlleta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arleta</b>.</p><b>Arleta</b>, <b>Arletta</b> – imię żeńskie zapożyczone z francuskiego; powstało prawdopodobnie jako zdrobnienie germańskiego imienia <i>Carletta</i> (<i>Karletta</i>), żeńskiej formy imienia Karl (<a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>).", "An Nhiên": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Anays": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anais</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Alexia-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexia</b>.</p><p>Aleksja (włoski: Alexia). Alexia, imię urodzone. Alessia Aquilani, rodzina.</p>", "Ameera": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ameer</b>.</p><p>Emir (; arabski: أمير ʾAmīr [ʔæˈmiːr]), czasami przenoszony do Amir, Amier lub Ameer, jest szlachectwem lub szlachetnym urzędnikiem używanym w wielu regionach w krajach Arabskich. Dosłownie oznacza to dowódca, generał, król lub król.</p>", "Anastaciia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastacia</b>.</p><p>Anastycha Lin Newkork (ang. Anastacia Lyn Newkirk; rodzaj.</p>", "Alina-Mihaela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Aysegul": "<p>Ayşegül to tureckie imię dla kobiet. Nazwa pochodzi od \"Ayşe\", tureckiej formy arabskiej nazwy Aisha, co oznacza \"w kobiecości, życie\" plus \"Gül\", perskie słowo oznaczające róże. \" Wśród znanych kobiet z imieniem Ayşegül są:</p>", "Amelya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amelia</b>.</p><b>Amelia</b>, <b><a href=\"https://pl.wikipedia.org/wiki/Amalia\" target=\"_blank\" rel=\"noopener noreferrer\">Amalia</a></b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako skrócenie imion dwuczłonowych z pierwszym członem <i>Amal-</i>, takich jak między innymi <a href=\"https://pl.wikipedia.org/wiki/Amalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Amalgunda</a> lub <a href=\"https://pl.wikipedia.org/wiki/Amalberga\" target=\"_blank\" rel=\"noopener noreferrer\">Amalberga</a>.", "Anna-Solomiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Almi̇na": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Almin</b>.</p><p>Almin to imię męskie. Na Bałkanach Almin jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Anna - Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Abosede": "<p>Abọ́sẹ̀dé to nigerijskie imię z języka joruba oznaczające \"Narodzone na początku nowego tygodnia\" lub dziewczynka urodzona w niedzielę. Nazwa ta jest zazwyczaj nadawana dziewczynce urodzonej w niedzielę w południowo-zachodnim regionie kraju.</p>", "Annastazja": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastazja</b>.</p><b>Anastazja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anastazy\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazy</a>. Oznacza „zmartwychwstała, wskrzeszona”.", "Anija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ania</b>.</p><p>Tainia (lat. Tainia) - rodzaj jednokładnych roślin z rodu rodziny Orchid (Orchidaceae).</p>", "Anna Krystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Angelyn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angelin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angelina</b>.</p><b>Angelina</b> – forma pochodna <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>.", "Andrea Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Angie Julieth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Andreea-Gabriela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Andreea-Cristina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Adedoyin": "<p>Adédoyin to unisex imię i nazwisko pochodzenia jorubańskiego. Jako rodzimie imię kultury jorubskiej w Afryce Zachodniej, jego znaczenie jest \"korona lub królewska rodzina stała się słodka (jak miód) \".</p>", "Ayanna": "<p>Ayanna to kobiece imię. Wśród znanych osób z nazwiska są: Ayanna Alexander (ur. 1982), trójskokista Ayanna Dyette (1986-2018), Ayanna Howard (ur. 1972), amerykańska robotarka i badacz Ayanna Hutchinson (ur. 1978), atleta sprintu Ayanna McClean, obrońca hokeja terenowego w Trynidadzie i Tobago i sędzio Ayanna Oliva (ur. 1986), Filipinacka modelka, piosenkarka,...</p>", "Abeeha": "<p>Abiha Noor lub Abeeha (arabsko: ابیھا), to arabskie kobiece imię. Jego znaczenie jest \"jej ojciec\", który został dany Fatimie az-Zahra przez islamskiego proroka Mahometa jako \"Umm Abiha\".</p>", "Andrea Katherine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Aldina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aldin</b>.</p><p>Aldin to męskie imię i nazwisko. Na Bałkanach Aldin jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Aubree": "<p>Aubrey () to unisex angielskie imię. W średniowieczu był to powszechne dla mężczyzn i kobiet, ale przez pewien czas straciło przyzwolenie przed ożyciem ponownego wzrostu popularności dla mężczyzn w XIX wieku.</p>", "Aybike": "<p>Aybike jest powszechną turecką nazwą. Nazwa jest wytwarzana za pomocą dwóch tureckich słów: Ay i Bike.</p>", "April Ann": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>April</b>.</p><p>April (kr. 에이프릴; często stylizowana jako APRIL, wymawia się jako April (April) - południowo koreańska dziewczęta-grupa, utworzona w 2015 roku przez DSP Media. Składa się z sześciu uczestników: Čekyon, Čevon, Naын, Jena, Rachel i Jinsol.</p>", "Axela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Axel</b>.</p><p>Akcel (niem. Axel, czyli angielski.</p>", "Anna-Yelyzaveta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aimani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aiman</b>.</p><p>Aiman (arabski: أيمن) to neutralna nazwa płci z pochodzenia w języku arabskim, urdu i kazacku. Jest to alternatywne alfabet latynski śpiewki imienia Ayman.</p>", "Anastasie": "<p>Anastasie to francuskie imię żeńskie pochodzące od starożytnego greckiego Anastasíā. Do wybitnych osób z tym nazwiskiem należą: Anastasie Brown (1826-1918), amerykańska katolicka mniczka Anastasie Crimca (kr.</p>", "Andréia": "<p>Andréia (lub Andreia) to portugalskie imię dla kobiet. Dla starożytnego greckiego terminu ἀνδρεία lub andreia, patrz Odwaga.</p>", "Adelyn": "<p>Adeline jest kobiece imię, które oznacza \"szlachetny\" lub \"szlachetnicy\"; pochodzi z niemieckiego pochodzenia i pochodzi od starożytnego wysokiego niemieckiej adal \"szlachety\". Korzeń jest w języku niemieckim Adel \"szlachetność\", \"edel\" \"szlachety\" i \"adellig\" \"szlachta\".</p>", "Anna-Iryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Alba Luz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alba</b>.</p><b>Alba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od łac. <i>Albus/a</i>, od <i>albus</i> \"jasny, biały, świetlisty\". W Polsce spotykane bardzo rzadko, choć notowane już w średniowieczu.", "Akshata": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akshat</b>.</p><p>Akshat to męskie imię w kulturach hinduskich i buddyjskich. Pochodzi od sanskryckiego słowa Aksata, co oznacza \"niepowlekany\".</p>", "Ali̇na": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Adalyn": "<p>Adeline jest kobiece imię, które oznacza \"szlachetny\" lub \"szlachetnicy\"; pochodzi z niemieckiego pochodzenia i pochodzi od starożytnego wysokiego niemieckiej adal \"szlachety\". Korzeń jest w języku niemieckim Adel \"szlachetność\", \"edel\" \"szlachety\" i \"adellig\" \"szlachta\".</p>", "Anna Marta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anastasiia-Olha": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Afua": "<p>Afua (AF-wə) lub Efua (EF-wə), to imię dni Akan tradycyjnie nadawane dziewczynkom urodzonymi w piątek; równoważne męskie imię to Kofi.</p>", "Ariani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arian</b>.</p><b>Arian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jego patronem jest św. Arian, wspominany razem ze św. <a href=\"https://pl.wikipedia.org/wiki/Teotyk_(m%C4%99czennik_egipski)\" target=\"_blank\" rel=\"noopener noreferrer\">Teotykiem</a>.", "Aksinya": "<p>Xenia (varianty obejmują Ksenia, Kseniia, Ksenja, Kseniya; pochodzące z greckiego Ξένια xenia, \"gastotliwość\") jest nazwą dla kobiet. Poniższe sekcje zawierają listę znanych osób z jedną z wariantów tej nazwy.</p>", "Aasha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asha</b>.</p><p>Asha (Nokia) - seria telefonów Nokia, po raz pierwszy przedstawiona w 2011 roku. Asha w tłumaczeniu hindi oznacza nadzieja.</p>", "Anupa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anup</b>.</p><p>Anup (sanskrit: अनुप anūpa) to indyjskie imię męskie. Sanskritskie słowo anūpa ma następujące znaczenia: \"wodna\", \"położona w pobliżu wody\", \"brzeg rzeki\", \"zbiornik\", \"lagona\".</p>", "Abra": "<b>Abra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia hebrajskiego i arabskiego, spokrewnione z imieniem <a href=\"https://pl.wikipedia.org/wiki/Abraham_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Abraham</a> o znaczeniu \"ojciec wielu\". Warianty to Abame, <a href=\"https://pl.wikipedia.org/wiki/Abarrane\" target=\"_blank\" rel=\"noopener noreferrer\">Abarrane</a>, Abrah i Abrahana.", "Amayah": "<p>Amaya to kobiece imię i nazwisko pochodzące z Hiszpanii, pochodzące od wioski Amaya i sąsiedniej góry w Kastilii i Leonie, Hiszpania. Nazwa wioski ma w zamian indoeuropejskie korzenie i oznacza \"mamę\" lub \"matkę\".</p>", "Amide": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amid</b>.</p><p>Amyd (lub albo), znany również jako kwas amyd, jest związkiem z grupami funkcyjnymi RnE (O) xNR′2 (R i R' są grupami H lub grupami organicznymi). Najczęściej jest to karboxamid (organiczny amyd) (n = 1, E = C x = 1), ale wiele innych ważnych rodzajów amydów jest znanych, w tym fosforamid (n = 2, E = P x = 1 i wiele związanych formuł) i sulfonamid (E = S, x = 2).</p>", "Anna-Nikol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aniela Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aniela</b>.</p><b>Aniela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które jest spolszczoną formą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa <i>ángelos</i> „posłaniec”. Imię trafiło do Polski z Włoch prawdopodobnie w XVIII wieku. W świecie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> upowszechniło się jako nawiązanie do <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">aniołów</a> i <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_Str%C3%B3%C5%BC_(religioznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioła Stróża</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>.", "Amane": "<b>Amane</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あまね, アマネ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, może być używane także jako nazwisko.", "Anna-Andriana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Antonina Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonina</b>.</p><b>Antonina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antonin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonin</a>; uformowany przy użyciu <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, <i>-ina</i>, oznaczającego przynależność lub pochodzenie, <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwy rodowej</a> <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Antoniuszów</a>. W Polsce Antonina pojawiła się później niż obecna od średniowiecza <a href=\"https://pl.wikipedia.org/wiki/Antonia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonia</a>; notowana jest co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1637\" target=\"_blank\" rel=\"noopener noreferrer\">1637</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Antonina w 2017 r. zajmowała 15. miejsce w grupie imion żeńskich. W całej populacji Polek Antonina zajmowała w 2017 r. 90. miejsce (43 462 nadań).", "Anastasiia-Sofiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Annina": "<p>Annina jest diminutiwem nazwiska żeńskiego Anna w języku włoskim. Znanymi osobami z nazwiska są: Annina Enckell Annina Ruest</p>", "Alvira": "<p>Alvira to imię. Jest to hiszpańskie nazwisko; jako nazwisko, jest czasami uważane za wariant Elviri.</p>", "Angelin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angelina</b>.</p><b>Angelina</b> – forma pochodna <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>.", "Akina": "<b>Akina</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきな, アキナ) – głównie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, rzadko noszone przez mężczyzn.", "Afrah": "<p>Afrah lub Afraah (arabickie: أَفْرَاح, afrāḥ) to arabskie kobiece imię i nazwisko oznaczające \"wesołe, szczęście, radość, radość\", \"wyżyte duchy, radość (wesość) klatki piersiowej\" i jest również dosłownym słowem dla \"ślub\". Nazwa jest liczbą wielokrotną lub superlatywną formy nazwy Farah.</p>", "Andrea Camila": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Anița": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anit</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anita</b>.</p><b>Anita</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które powstało z hiszpańskiej zdrobniałej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anna</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> Ana). Istnieje też teza, że <b>Anita</b> jest skróconą formą <i>Juanity</i> – hiszpańskiego odpowiednika <a href=\"https://pl.wikipedia.org/wiki/Joanna\" target=\"_blank\" rel=\"noopener noreferrer\">Joanny</a>.", "Angelic": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angelica</b>.</p><p>Dudnik, czyli aniolica (lat. Angélica) - rodzaj trawniczośnych roślin rodziny Zontickich (Apiaceae).</p>", "Aneeta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aneta</b>.</p><b>Aneta</b>, <b>Anetta</b> – forma pochodna imienia <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anna</a>, powstała jako przeniesienie francuskiego zdrobnienia tego imienia, <i>Anette</i>, do języka polskiego. Pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>. Imię dotarło do Polski w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX w.</a>, wcześniej używano tylko imienia Anna.", "Ayu Putu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ayu</b>.</p><p>Ayumy Hamasaki (jap. 浜崎 あゆみ Hamasaki Ayumy, rodzaj.</p>", "Aronka": "<p>Aaron to angielskie imię męskie. W języku greckim ⁇ αρών, z którego pochodzi angielska forma, Aaron, wywodzi się fonem 'h' w oryginalnej hebrajskiej wymowie \"Aharon\" (אהרן).</p>", "Anh Ngoc": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Andreea-Georgiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Ahmed Saieed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Anna Irena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Arkadiusza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arkadiusz</b>.</p><b>Arkadiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa Αρκαδικóς (Arkadikós) oznaczającego „pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Arkadia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Arkadii</a>”.", "Aleksandra Ewa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aleksandra</b>.</p><b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Ayame": "<b>Ayame</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あやめ, アヤメ) – głównie żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, rzadko noszone przez mężczyzn.", "Aimei": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aime</b>.</p><p>Aime jest gminą w prowincji Savoie w regionie Auvergne-Rhône-Alpes w południowo-wschodniej Francji.</p>", "Antonina Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonina</b>.</p><b>Antonina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antonin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonin</a>; uformowany przy użyciu <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, <i>-ina</i>, oznaczającego przynależność lub pochodzenie, <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwy rodowej</a> <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Antoniuszów</a>. W Polsce Antonina pojawiła się później niż obecna od średniowiecza <a href=\"https://pl.wikipedia.org/wiki/Antonia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonia</a>; notowana jest co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1637\" target=\"_blank\" rel=\"noopener noreferrer\">1637</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Antonina w 2017 r. zajmowała 15. miejsce w grupie imion żeńskich. W całej populacji Polek Antonina zajmowała w 2017 r. 90. miejsce (43 462 nadań).", "Aamina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amina</b>.</p><p>Amina (ang. Amina, Aminatu, 1533 - około 1610) - rządnica (od 1576 roku) muzułmańskiego państwa Zazzau (Zaria) w Centralnym Sudanie, jednym z miast-państw narodu chaus.</p>", "Anna-Nadiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Adelina-Ionela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adelina</b>.</p><b>Adelina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, utworzone za pomocą zdrabniającego przyrostka <i>-ina</i> od imienia <a href=\"https://pl.wikipedia.org/wiki/Adela\" target=\"_blank\" rel=\"noopener noreferrer\">Adela</a>.", "Anca-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anca</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anka</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna Liza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Antonya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Antony</b>.</p><p>Antony może odnosić się do: Antony (nazwa), męskie imię</p>", "Aneli": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anel</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anele</b>.</p><p>Anele to imię. Znanymi osobami z nazwiska są: Anele Lungisa (ur. 1992), gracz rugby południowoafrykański Anele Mdoda (ur. 1984), prezenterka telewizyjna południo Afryki Anele Ngcongca (1987-2020), piłkarz południowej Afryki</p>", "Aaisha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aisha</b>.</p><p>Aia Andrzejeva (lat. Aija Andrejeva; rod.</p>", "Aliaksandryna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aliaksandr</b>.</p><p>Aleksander (grecki: ⁇ λέξανδρος) to męskie imię pochodzenia greckiego. Najbardziej znanym nosicielem nazwy jest Aleksander Wielki, król starożytnego greckiego królestwa Macedonii, który stworzył jedno z największych imperiów w starożytnej historii.</p>", "Anna Ewa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Asifa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asif</b>.</p><p>Asif (arabski: آصف) to arabskie męskie imię. W językach perskim i urdu często wymawia się jako \"Asif\" lub \"Asef\".</p>", "Alina-Emanuela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Andriana-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andriana</b>.</p><p>Andriana to rodzaj roślin kwiatowych z rodziny Apiaceae.</p>", "Arike": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arik</b>.</p><p>Arik to imię i może odnosić się do: Arik Ascherman, amerykański rabin reformator i palestyński działacz praw człowieka w Izraelu Arik Brauer, wizjoner artysta Arik Benado, kapitan Maccabi Haifa Arik Einstein, izraelskiego piosenkarza Arik Levy, projektanta przemysłowego i współczesnego artysty Arik Gilbert (ur. 2002), amerykańskiego piłkarza piłki nożnej Ariel \"Arik\" Ze'evi, izraelskiej judoki Arik Marshall, amerykańskiej muzyki Artoces, znanej również jako Arik, starożytnej...</p>", "Asana": "<b>Asana</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> योगासन, <a href=\"https://pl.wikipedia.org/wiki/Transliteracja\" target=\"_blank\" rel=\"noopener noreferrer\">transliteracja</a> yogāsana) – dosłownie: \"siedzenie\". Pojęcie używane w dwóch znaczeniach:", "Atyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Atina</b>.</p><p>Atina jest miastem w prowincji Frosinone w włoskiej regionie Lazio. Miasto ma powierzchnię 29 km2, ludności 4480 osób.</p>", "Anna-Romana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Amelia-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amelia</b>.</p><b>Amelia</b>, <b><a href=\"https://pl.wikipedia.org/wiki/Amalia\" target=\"_blank\" rel=\"noopener noreferrer\">Amalia</a></b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Imiona_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako skrócenie imion dwuczłonowych z pierwszym członem <i>Amal-</i>, takich jak między innymi <a href=\"https://pl.wikipedia.org/wiki/Amalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Amalgunda</a> lub <a href=\"https://pl.wikipedia.org/wiki/Amalberga\" target=\"_blank\" rel=\"noopener noreferrer\">Amalberga</a>.", "Ariah": "<p>Aria może być imieniem męskim, żeńskim, a nawet unisex w zależności od kraju pochodzenia. Perskie Arya (perskie: آریا) to męskie imię, które oznacza \"szlachetny\".</p>", "Alyce": "<p>Alyce to kobiece imię. Alyce lub Allyce może odnosić się do: Allyce Beasley (ur. 1954), amerykańskiej aktorki i komikany Alyce Clarke (ur. 1939), amerykańska politykka Alyce Cleese (ur. 1944), amerykański psychoterapeuta, autor i prowadzący rozmowy radiowe, byłej żony aktora / komiksa Johna Cleese Alyce Frank (ur. 1932), amerykańskiego malodawcy krajobrazu Alyce Fraser Denny (1896-1988), piosenkarki z Gwiany Brytyjskiej (Gwiany) Alyce King (1915-1996), jednego z The...</p>", "Augustė": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>August</b>.</p><b>August</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od przymiotnika <i>augustus</i>, nadanego jako przydomek <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">Oktawianowi</a> przez Senat i oznaczającego „dostojny, boski, majestatyczny, poświęcony, święty, czcigodny, pomyślny, wzniosły”. Przymiotnik ten pochodzi od rzeczownika <i>augur</i> i pierwotnie odnosił się tylko do rzeczy, tłumacząc się jako „uświęcony przez (dobre) przepowiednie, znaki” lub „przedsięwzięty pod sprzyjającymi znakami”. Po raz pierwszy imię August zostało poświadczone w Polsce w <a href=\"https://pl.wikipedia.org/wiki/1349\" target=\"_blank\" rel=\"noopener noreferrer\">1349</a> roku, w łac. formie <i>Augustus</i>.", "Akasha": "<b> Akaśa, akasza</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> आकाश, <a href=\"https://pl.wikipedia.org/wiki/Transliteracja\" target=\"_blank\" rel=\"noopener noreferrer\">trl.</a> <i>ākāśa</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a> <i>akasha</i>) – słowo pochodzące z <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrytu</a> oznaczające <i><a href=\"https://pl.wikipedia.org/wiki/Eter_(filozofia)\" target=\"_blank\" rel=\"noopener noreferrer\">eter</a></i> rozpatrywany w dwóch znaczeniach: w sensie <a href=\"https://pl.wikipedia.org/wiki/Mitologia\" target=\"_blank\" rel=\"noopener noreferrer\">mitologicznym</a> i jako jeden z <a href=\"https://pl.wikipedia.org/wiki/%C5%BBywio%C5%82y\" target=\"_blank\" rel=\"noopener noreferrer\">żywiołów</a>. Eter jest piątym, podstawowym elementem, który obejmuje pozostałe cztery <a href=\"https://pl.wikipedia.org/wiki/%C5%BBywio%C5%82y\" target=\"_blank\" rel=\"noopener noreferrer\">żywioły</a>: vata – powietrze, ap – woda, agni – ogień i prithivi – ziemia.", "Adéle": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adel</b>.</p><p>Adel - wieloznaczny termin.</p>", "Adryana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adryan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Alyana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alyan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alian</b>.</p>Populacja dzielnicy Alian w 2016 roku liczyła 29&#160;093 mieszkańców – 14&#160;407 kobiet i 14&#160;686 mężczyzn. Liczba gospodarstw domowych wynosiła 9407, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,09 osób.", "Annapurna": "Miejscowa nazwa góry jest połączeniem <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryckich</a> słów „anna” (pożywienie) i „purna” (wypełniona) i oznacza <i>Wypełnioną Pożywieniem</i>. Imieniem <a href=\"https://pl.wikipedia.org/wiki/Annapurna_(bogini)\" target=\"_blank\" rel=\"noopener noreferrer\">Annapurna</a> nazywana jest <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduistyczna</a> bogini, jedno z wcieleń <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a>, towarzyszki <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Śiwy</a>, czczonej za moc dostarczania pożywienia. Według innej wersji połączenie tych dwóch słów jest przydomkiem bogini <a href=\"https://pl.wikipedia.org/wiki/Durga\" target=\"_blank\" rel=\"noopener noreferrer\">Durgi</a> lub <a href=\"https://pl.wikipedia.org/wiki/Kali\" target=\"_blank\" rel=\"noopener noreferrer\">Kali</a> i mogłoby mieć znaczenie <i>Żywicielka</i>.", "Asefa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asef</b>.</p><p>Asif (arabski: آصف) to arabskie męskie imię. W językach perskim i urdu często wymawia się jako \"Asif\" lub \"Asef\".</p>", "Anastasiia-Khrystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Adaya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aday</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ada</b>.</p><b>Ada</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/Kobieta\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> znaczy: upiększać się, stroić się. Imię Ada jest wymieniane w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> w pierwszej księdze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, gdzie jest jedną z żon Lemecha i matką Jubala. W Biblii jest także mowa o Adzie, matce flecistów i grających na harfie (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Rdz.</a> 4, 21).", "Anu-Ujin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anu</b>.</p>Jego imię pisano za pomocą znaku klinowego w kształcie gwiazdy, który oznacza zarówno niebo (sum. <b>AN</b>), jak i boga (sum. <b>DINGIR</b>, akad. <i>ilu</i>). Pan wszystkich bogów rozsądza ich kłótnie, a jego wyroki są nieodwołalne; niewiele obchodzą go jednak sprawy ludzkie. Majestatyczny, szanowany, ale zajmujący najwyższą sferę nieba pozostaje zawsze kimś dalekim i w gruncie rzeczy dosyć niewyraźnym.", "Albine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Albin</b>.</p><b>Albin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „biały”. Ponadto istnieje germańskie imię <a href=\"https://pl.wikipedia.org/wiki/Albwin\" target=\"_blank\" rel=\"noopener noreferrer\">Albwin</a> (Albuin), od którego forma skrócona może być jednakowa z imieniem Albin.", "Aniela Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aniela</b>.</p><b>Aniela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które jest spolszczoną formą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa <i>ángelos</i> „posłaniec”. Imię trafiło do Polski z Włoch prawdopodobnie w XVIII wieku. W świecie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> upowszechniło się jako nawiązanie do <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">aniołów</a> i <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_Str%C3%B3%C5%BC_(religioznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioła Stróża</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>.", "Angie Katherine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Anna Magdalena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna-Veronika": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Areeg": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Areg</b>.</p><p>Areg (armeńska: Արեգ) to powszechne męskie imię w języku armeńskim oznaczające \"słońce\". Więcej informacji na temat Areg w artykule Wiktionary.</p>", "Anna-Sophia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Alide": "<p>Alide lub ALIDE może odnosić się do: Alide Dasnois (ur. 1950), południowoafrykańskiej dziennikarzy i redaktorki Alide Ertel (1877-1955), estonii pisarza Alide Maria Salvetta (1941-1991), włoskiej pianinki opera Alide Topp (1844-1935), niemieckiej pianisty Alide: An Episode of Goethe's Life, romans z 1874 roku napisany przez Emma Lazarus Liberal Alliance for Democracy (ALIDE), partię polityczną w Burundi</p>", "Angéle": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Anna-Mariana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Arpitha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arpita</b>.</p><p>Arpita to indyjskie imię i żeńska forma Arpita. Według Penguin Book of Indian Names oznacza to \"przyznany\" lub \"przywiązany, dostarczony, powierzony, oddawany, oddawany\".</p>", "Adilie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adili</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adil</b>.</p><b>Adil</b> – arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od słowa <i>adil</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عدل&#8206;, <i>’adil</i>) – 'sprawiedliwy', 'uczciwy'.", "Alesia-Sara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alesia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksandra</b>.</p><b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Arami": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aram</b>.</p><b>Aram</b> – jest to <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie popularne na <a href=\"https://pl.wikipedia.org/wiki/Bliski_Wsch%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">Bliskim Wschodzie</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_kurdyjski\" target=\"_blank\" rel=\"noopener noreferrer\">języku kurdyjskim</a> oznacza \"spokojny\". W Polsce nie obchodzi <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">imienin</a>. <a href=\"https://pl.wikipedia.org/wiki/Aram_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Aram</a> był według <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> synem <a href=\"https://pl.wikipedia.org/wiki/Sem_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Sema</a> i wnukiem <a href=\"https://pl.wikipedia.org/wiki/Noe\" target=\"_blank\" rel=\"noopener noreferrer\">Noego</a>.", "Aleksandera": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksander</b>.</p><b>Aleksander</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἀλέξανδρος, <i>aleksandros</i> – obrońca ludzi) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> składające się z dwóch członów: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;αλέξειν (bronić, wspomagać) i ἀνδρός (od ἀνήρ – mąż, mężczyzna). Całość bywa interpretowana jako „broniący mężów, troszczący się o mężów, opiekujący się mężami”.", "Andresa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andres</b>.</p><p>Andres jest gminą w prowincji Pas-de-Calais, w regionie Hauts-de-France, wschodniej Francji.</p>", "Angela Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angela</b>.</p><b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Anna Elżbieta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Antonia-Ioana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonia</b>.</p><b>Antonia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antoni_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antoni</a>. W Polsce pojawiło się wcześniej niż imię <a href=\"https://pl.wikipedia.org/wiki/Antonina\" target=\"_blank\" rel=\"noopener noreferrer\">Antonina</a>, ale następnie zostało przez nie wyparte. W Kościele katolickim istnieją dwie patronki tego imienia.", "Angelica Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angelica</b>.</p><p>Dudnik, czyli aniolica (lat. Angélica) - rodzaj trawniczośnych roślin rodziny Zontickich (Apiaceae).</p>", "Alisa-Anastasiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alisa</b>.</p><p>Alisa i Alissa to nazwiska kobiet, wersje Alice, używane w Rosji, Ukrainie, Finlandii, Estonii i innych krajach. Do znanych osób i postaci z tymi nazwami należą:</p>", "An Vy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Aloysia": "<b>Miłowonka</b> (<i>Aloysia</i>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin należących do rodziny <a href=\"https://pl.wikipedia.org/wiki/Werbenowate\" target=\"_blank\" rel=\"noopener noreferrer\">werbenowatych</a> (<i>Verbenaceae</i>). Obejmuje 41 gatunków. Rośliny te występują w strefie tropikalnej i subtropikalnej obu kontynentów amerykańskich od <a href=\"https://pl.wikipedia.org/wiki/Kalifornia\" target=\"_blank\" rel=\"noopener noreferrer\">Kalifornii</a>, <a href=\"https://pl.wikipedia.org/wiki/Utah\" target=\"_blank\" rel=\"noopener noreferrer\">Utah</a> i <a href=\"https://pl.wikipedia.org/wiki/Teksas\" target=\"_blank\" rel=\"noopener noreferrer\">Teksasu</a> po północną część <a href=\"https://pl.wikipedia.org/wiki/Chile\" target=\"_blank\" rel=\"noopener noreferrer\">Chile</a> i <a href=\"https://pl.wikipedia.org/wiki/Argentyna\" target=\"_blank\" rel=\"noopener noreferrer\">Argentyny</a>. Rośliny te występują zwykle w formacjach suchych, zaroślowych, często rosną na terenach skalistych.", "Arona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aron</b>.</p><p>Aron jest miejscowością i nagar panchayatem Guna w stanie Madhya Pradesh, India.</p>", "Anthonella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Antonella</b>.</p><b>Antonella</b> – imię żeńskie, będące <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_du%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">duńskim</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_norweski\" target=\"_blank\" rel=\"noopener noreferrer\">norweskim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_szwedzki\" target=\"_blank\" rel=\"noopener noreferrer\">szwedzkim</a> <a href=\"https://pl.wikipedia.org/wiki/Zdrobnienie\" target=\"_blank\" rel=\"noopener noreferrer\">zdrobnieniem</a> od imienia <a href=\"https://pl.wikipedia.org/wiki/Antonia\" target=\"_blank\" rel=\"noopener noreferrer\">Antonia</a>. Używane jest głównie w wielu krajach <a href=\"https://pl.wikipedia.org/wiki/Ameryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Południowej</a> i <a href=\"https://pl.wikipedia.org/wiki/Ameryka_%C5%9Arodkowa\" target=\"_blank\" rel=\"noopener noreferrer\">Środkowej</a>, różnych częściach <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a>, a także we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a>, <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Skandynawia\" target=\"_blank\" rel=\"noopener noreferrer\">krajach skandynawskich</a>. Męskim odpowiednikiem tego imienia jest Antonello.", "Andreea-Raluca": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Aiszat": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aishat</b>.</p><p>Aisha (arabsko: عائشة, romanized: ʿʿʾishah, lit. 'żyjący' lub 'żyjący'; również pisowniane A'aisha, A'isha, Aischa, Aische, Aishah, Aishat, Aishath, Aicha, Aïcha, Aisya, Aisyah, Aiša, Ajša, Aixa, Ayesha, Aysha, Ayşe, Ayisha lub Iesha) jest arabską nazwą żeńską.</p>", "Aniela Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aniela</b>.</p><b>Aniela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które jest spolszczoną formą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa <i>ángelos</i> „posłaniec”. Imię trafiło do Polski z Włoch prawdopodobnie w XVIII wieku. W świecie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> upowszechniło się jako nawiązanie do <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">aniołów</a> i <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_Str%C3%B3%C5%BC_(religioznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioła Stróża</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>.", "Andreea-Cătălina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Alize": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aliz</b>.</p><p>Alice to żeńskie imię z korzeniami w językach francuskim i niemieckim.</p>", "Anzelmina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anzelm</b>.</p><b>Anzelm</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> (<i>ans</i> &lt;<a href=\"https://pl.wikipedia.org/wiki/Azowie\" target=\"_blank\" rel=\"noopener noreferrer\">Azowie</a>&gt; + <i>helm</i> &lt;hełm&gt;, oznacza „strzeżony przez bóstwa”). Imię <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99_teoforyczne\" target=\"_blank\" rel=\"noopener noreferrer\">teoforyczne</a>. W Polsce używane w 1228 r. oraz od XIV w.", "Ashlynn": "<p>Ashlyn lub Ashlynn to nazwisko i nazwisko kobiet.</p>", "Andriana-Ivanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andriana</b>.</p><p>Andriana to rodzaj roślin kwiatowych z rodziny Apiaceae.</p>", "Azita": "<p>Azita (perską: آزیتا) to perskie kobiece imię, które oznacza \"wolną kobietę\" i \"Bógini Ognia\" popularne w Iranie.</p>", "Anastasiia-Nadiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Andreea-Alexandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Andreea-Ionela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Alyn": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Alba Lucia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alba</b>.</p><b>Alba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od łac. <i>Albus/a</i>, od <i>albus</i> \"jasny, biały, świetlisty\". W Polsce spotykane bardzo rzadko, choć notowane już w średniowieczu.", "Annastasiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastasia</b>.</p><b>Anastazja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anastazy\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazy</a>. Oznacza „zmartwychwstała, wskrzeszona”.", "Annaliese": "<p>Anneliese to nazwisko żeńskie pochodzące z Niemiec, Holandii lub Skandynacji. Jest to mieszane z \"Anny\" i \"Liese\", krótka forma \"Elisabeth\".</p>", "Asema": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asem</b>.</p><p>Asem (zwanego również Aasem, Assem, Asim, Aasim, Assim, Aassem) jest męskim imieniem arabskiego pochodzenia, co oznacza \"zbawiciel, ochroniarz, opiekun, obrońca\". Asem jest również imieniem żeńskim pochodzenia kazackiego, co oznacza: \"piękno, piękno, wyrafinowane, eleganckie, elegancką, doskonałą, wspaniałą, wspaniale\".</p>", "Aiida": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aida</b>.</p><b>Aida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnym pochodzeniu, być może arabskim albo greckim lub twór literacki.", "Anna Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Amia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ami</b>.</p><b>Ami</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あみ, アミ, 亜美) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Anna Urszula": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna Grażyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anastasiia-Viktoriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Androniki": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andronik</b>.</p><b>Andronik</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od starogreckiego imienia <i>Andronikos</i> (gr. <i>Ανδρόνικος</i>) wywodzącego się od słów <i>andros</i> (człowiek) i <i>nike</i> (zwycięstwo), które w złożeniu znaczą „zwycięzca”.", "Anelė": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anel</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anele</b>.</p><p>Anele to imię. Znanymi osobami z nazwiska są: Anele Lungisa (ur. 1992), gracz rugby południowoafrykański Anele Mdoda (ur. 1984), prezenterka telewizyjna południo Afryki Anele Ngcongca (1987-2020), piłkarz południowej Afryki</p>", "Anna-Katharina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna-Zlata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna Helena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Amelle": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amele</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amel</b>.</p><p>Amel (Francuz: Amblève) jest miastem w regionie Wallonie, prowincji Liège, i należy do niemieckojęzycznej społeczności w Belgii (German: Deutschsprachige Gemeinschaft Belgiens). Na 1 stycznia 2006 roku Amel miał łącznie 5.282 mieszkańców.</p>", "Armena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Armen</b>.</p><b>Armen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia ormiańskiego, wywodzi się z mitologii ormiańskiej. Skrócona forma imienia Armenak, które wyszło z użycia w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX</a> wieku. Żeński odpowiednik: Armenuhi (zdrobnienie: Armine lub Armina)", "Awia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Avia</b>.</p><p>AVIA Motors - czeska firma założona w 1919 roku na produkcję samolotów. Od 1946 roku produkuje również samochody ciężarowe i autobusy.</p>", "Aroha": "<p>Aroha to słowo maorskie oznaczające \"miłość\", spokrewnione z hawajskim terminem aloha. Jest to również imię i może być męskie lub żeńskie.</p>", "Alisija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alisia</b>.</p><p>Alicia to kobiece imię. Jest to wariant Alice, który pochodzi z germańskiego imienia Adalheidis (Adelaide), co oznacza \"szlachetny natury\" (szlachetnego rodzaju).</p>", "Anna-Milena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna Janina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anastasiia-Yuliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Azima": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Azim</b>.</p><p>Azim (ʿAẓīm عظيم) jest jednym z imion Allaha w islamu, co oznacza \"Wielki\" lub \"Wspaniały\" lub \"Ochrony\". Jest używany przez wielu Sahrawiów jako nazwisko pochodzące z arabskiego Hasania.</p>", "Akinai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akina</b>.</p><b>Akina</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あきな, アキナ) – głównie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, rzadko noszone przez mężczyzn.", "Aaminah": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aminah</b>.</p><p>Amina (lub Aminah) jest luźnym transkrypcją dwóch różnych arabskich nazwisk kobiet: ʾĀmina (arabski: آمنة, również anglicized jako Aaminah lub Amna) oznaczające \"bezpieczny, chroniony\" ʾAmīna (arabsko: أمينة, również angliczed jako Ameena), kobieca forma Amin, oznaczająca \"oddaną, uczciwą, prostą, wiarygodną, wartościową wiarę (wierzącą), lojalną, wierną, posłuszną Iman\". Nazwa jest bardzo popularna w Nigerii z powodu Aminy z Zazzau, a...</p>", "Adelija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adelia</b>.</p><p>Adelia borealis (lat. - rodzaj śpiewających cykadów rodza Adelia z rodziny Cicadidae (Auchenorrhyncha).</p>", "Arlett": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arlet</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arleta</b>.</p><b>Arleta</b>, <b>Arletta</b> – imię żeńskie zapożyczone z francuskiego; powstało prawdopodobnie jako zdrobnienie germańskiego imienia <i>Carletta</i> (<i>Karletta</i>), żeńskiej formy imienia Karl (<a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>).", "Alisya": "<p>Alicia to kobiece imię. Jest to wariant Alice, który pochodzi z germańskiego imienia Adalheidis (Adelaide), co oznacza \"szlachetny natury\" (szlachetnego rodzaju).</p>", "Amella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amela</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amel</b>.</p><p>Amel (Francuz: Amblève) jest miastem w regionie Wallonie, prowincji Liège, i należy do niemieckojęzycznej społeczności w Belgii (German: Deutschsprachige Gemeinschaft Belgiens). Na 1 stycznia 2006 roku Amel miał łącznie 5.282 mieszkańców.</p>", "Arena": "<b>Arena</b> (z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>harena</i>, <i>arena</i> - <a href=\"https://pl.wikipedia.org/wiki/Piasek\" target=\"_blank\" rel=\"noopener noreferrer\">piasek</a>) – usytuowany w centrum obiektu i wysypany piaskiem plac w kształcie koła lub elipsy. Miejsce walk, turniejów, popisów, igrzysk i widowisk. Wywodzi się ze <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnego</a> teatru greckiego i rzymskiego oraz cyrku rzymskiego.", "Alkmena": "Imię jej oznacza „silna w gniewie”. <a href=\"https://pl.wikipedia.org/wiki/Robert_Graves\" target=\"_blank\" rel=\"noopener noreferrer\">Robert Graves</a> uważa je za tytuł księżyca lub przydomek Hery.", "Ahmed Elsayed Attia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Anastasiia-Oleksandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Anna Victoria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Afsheen": "<p>Afshin (perskie افشین, romanized Afšin) jest powszechną perską nazwą pochodzącą z Avestanu. Afshin był używany przez Sogdyjczyków.</p>", "Aldonna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aldona</b>.</p><b>Aldona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, pochodzi ono od staropruskiego miana <i>Aldegut</i> lub białoruskiego <i>Ałdonia</i>, będącego przekształceniem greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Eudoksja_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eudokia</a> (Eudocja). Nosiło je wiele księżniczek litewskich wydawanych za polskich książąt (głównie mazowieckich).", "Anamaria-Adela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anamaria</b>.</p><p>Anamaria to kobiece imię. Znani ludzie z nazwiska to: Anamaria Govorčinović (urodzona 1997), chorwacka kanosarka Anamaria Ioniță (urodzono 1988), rumuńska sportowca Anamaria Marinca (urodzony 1978), rumuńskiej aktorki Anamaria Nesteriuc (urodzone 1993), rumuński obstajer Anamaria Ocolișan (urodzonych 1997), rumuńczyka gimnastka artystyczna Anamaria Tămârjan (urodzena 1991), rumuyńska gimnastka sztuki Anamaria Vartolomei (urodzina 1999), francusko-rumuńska aktorka</p>", "Anna-Nataliya": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Adalberta": "<b>Adalberta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Adalbert\" target=\"_blank\" rel=\"noopener noreferrer\">Adalbert</a>. W Polsce spotykane bardzo rzadko, choć notowane już w średniowieczu.", "Aleksandra-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aleksandra</b>.</p><b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Antonia-Andra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonia</b>.</p><b>Antonia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antoni_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antoni</a>. W Polsce pojawiło się wcześniej niż imię <a href=\"https://pl.wikipedia.org/wiki/Antonina\" target=\"_blank\" rel=\"noopener noreferrer\">Antonina</a>, ale następnie zostało przez nie wyparte. W Kościele katolickim istnieją dwie patronki tego imienia.", "Alina-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Andreea-Larisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Anna-Yuliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Angélika": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angelica</b>.</p><p>Dudnik, czyli aniolica (lat. Angélica) - rodzaj trawniczośnych roślin rodziny Zontickich (Apiaceae).</p>", "Anais Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anais</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Ardiani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ardian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ardiana</b>.</p><p>Ardian to albanska nazwa. Chociaż podobna do Adrian, nazwy pochodzenia łacińskiego, albanska Ardian (Ardjan i Ardijan są innymi wariantami) jest pochodem Ardiaei, nazwy starożytnego lyryjskiego ludu.</p>", "Alexandra-Ioana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Anna-Mishel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Alina-Kateryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Andrea Margarita": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Ahmed H": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Anna-Karyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Agora": "Od V wieku p.n.e. „agora jońska”, zakładana według <a href=\"https://pl.wikipedia.org/wiki/System_hippodamejski\" target=\"_blank\" rel=\"noopener noreferrer\">systemu hippodamejskiego</a>, miała najczęściej kształt prostokąta, który - począwszy od <a href=\"https://pl.wikipedia.org/wiki/Sztuka_grecka_w_okresie_klasycznym\" target=\"_blank\" rel=\"noopener noreferrer\">okresu klasycznego</a> - otaczały <a href=\"https://pl.wikipedia.org/wiki/Portyk\" target=\"_blank\" rel=\"noopener noreferrer\">portyki</a> kolumnowe (<a href=\"https://pl.wikipedia.org/wiki/Stoa\" target=\"_blank\" rel=\"noopener noreferrer\">stoa</a>). Przez jej środek z reguły przechodziła główna ulica miasta. Na agorze znajdowały się zazwyczaj budowle o przeznaczeniu religijnym i publicznym, mównice i siedzenia dla urzędników, studnie/fontanny oraz pomniki.", "Ali̇n": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Anna-Yaryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aida Luz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aida</b>.</p><b>Aida</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnym pochodzeniu, być może arabskim albo greckim lub twór literacki.", "Angie Dayanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Alesia-Rebeca": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alesia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksandra</b>.</p><b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Angie Natalia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Anastaciya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastacia</b>.</p><p>Anastycha Lin Newkork (ang. Anastacia Lyn Newkirk; rodzaj.</p>", "Anna-Monika": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Alitta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alita</b>.</p><p>GUNNM (jap. 銃夢 дзю: [orużania] mu , czyta się jako ガンム gammu, w oficjalnym tłumaczeniu po rosyjsku ⁇ Obrażania marzeń ⁇ , dopł.</p>", "Aliciia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alicia</b>.</p><b>Alicia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">hiszpańskiego</a>.", "Assha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asha</b>.</p><p>Asha (Nokia) - seria telefonów Nokia, po raz pierwszy przedstawiona w 2011 roku. Asha w tłumaczeniu hindi oznacza nadzieja.</p>", "Aesha": "<p>Aisha (arabsko: عائشة, romanized: ʿʿʾishah, lit. 'żyjący' lub 'żyjący'; również pisowniane A'aisha, A'isha, Aischa, Aische, Aishah, Aishat, Aishath, Aicha, Aïcha, Aisya, Aisyah, Aiša, Ajša, Aixa, Ayesha, Aysha, Ayşe, Ayisha lub Iesha) jest arabską nazwą żeńską.</p>", "Annikka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anika</b>.</p><b>Anika</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, jedna ze zdrobniałych form imienia <a href=\"https://pl.wikipedia.org/wiki/Anna\" target=\"_blank\" rel=\"noopener noreferrer\">Anna</a> m.in. w jęz. duńskim i holenderskim.", "Anh Tuyet": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Anastasiia-Solomiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Alexina": "<p>Alexina to kobiece imię. Wśród znanych osób z tej nazwy są: Alexina Duchamp (1906-1995), amerykańska handlarz sztuki Alexina Graham (ur. 1990), angielska modelka mody Alexina Kublu (ur. 1954), kanadyjska lingwistka, edukacja, tłumaczka i prawnik Alexina Louie (ur. 1949), kanadyjskie kompozytorka Alexina Ruthquist (1848-1892), szkocka misjonarka Alexina Maude Wildman (1867-1896), australijska dziennikarka</p>", "Amellie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amelie</b>.</p><p>⁇ Ameli ⁇ (francuski: Améli ⁇). Le Fabuleux Destin d'Amélie Poulain z fr.</p>", "Alfonsina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alfons</b>.</p><b>Alfons</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe ze złożenia członów <i>al</i> („cały”) lub <i>adal</i> („szlachetny ród”) oraz <i>funs</i> („szybki, chętny, życzliwy”). Imię to zostało spopularyzowane w Polsce w <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII</a> i <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a> przez zakon <a href=\"https://pl.wikipedia.org/wiki/Redemptory%C5%9Bci\" target=\"_blank\" rel=\"noopener noreferrer\">redemptorystów</a>, którego założycielem był św. <a href=\"https://pl.wikipedia.org/wiki/Alfons_Maria_Liguori\" target=\"_blank\" rel=\"noopener noreferrer\">Alfons Maria Liguori</a>. Popularność Alfonsa następnie spadła po przedstawieniu komedii <a href=\"https://pl.wikipedia.org/wiki/Alexandre_Dumas_(syn)\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Dumasa syna</a> „Monsieur Alphonse” z 1873 r., pod wpływem której <i>alfons</i> w roli rzeczownika pospolitego zyskał w Polsce znaczenie <i><a href=\"https://pl.wikipedia.org/wiki/Sutenerstwo\" target=\"_blank\" rel=\"noopener noreferrer\">sutener</a></i>. Taka konotacja imienia Alfons nie ma charakteru ogólnoświatowego i np. w <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpanii</a>, w której imię to nosiło kilkunastu królów (d. prowincji hiszpańskich), również obecnie imię to jest dość często spotykane.", "Abigaila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abigail</b>.</p><b>Abigail</b>, <b>Abigajl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego imienia אביגיל <i>Awigajil</i> znaczącego „radość ojca”, „mój ojciec się uradował”.", "Azra-Anabela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Azra</b>.</p><p>Azra - jugosławski z Zagrzebu (wówczas Sosyjalistyczna Republika Chorwacji), który był popularny w latach 80. Zespół został utworzony w 1977 roku przez frontmena Branimira ⁇ Johnni ⁇ Štuliccha (Branimir Štulić).</p>", "Anna Krisztina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anh Ðào": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anh</b>.</p><p>Anglia jest krajem, które stanowi Zjednoczone Królestwo Wielkiej Brytanii i Irlandii Północnej. Kraj ten ma granicy na północ z Szkocją i na zachód z Walią.</p>", "Amberly": "<p>Amber to kobiece imię pochodzące od ambra, skamieniał żywicy drzewnej, która jest często używana w produkcji biżuterii. Słowo to może również odnosić się do żółto-orange.</p>", "Anelie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aneli</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anel</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anele</b>.</p><p>Anele to imię. Znanymi osobami z nazwiska są: Anele Lungisa (ur. 1992), gracz rugby południowoafrykański Anele Mdoda (ur. 1984), prezenterka telewizyjna południo Afryki Anele Ngcongca (1987-2020), piłkarz południowej Afryki</p>", "Andrada-Denisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrada</b>.</p><p>Andrada to nazwisko, a także rumuńskie kobiece imię. Do wybitnych osób z nazwiskiem należą: Alonso Andrada (1590-1672), biograf i pisarz asketyczny Diogo de Paiva de Andrada (1528-1575), portugalski teolog urodzony w Coimbra Edgardo Andrada (1939-2019), emerytowany profesjonalny piłkarz argentyński, który grał jako bramkarz Esteban Andrada (urodzony w 1991 roku), argentyński międzynarodowy bramkarze José Andrada (1948-2025), argenty...</p>", "Anna Małgorzata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna-Mari": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Analisa": "Nakład „Analisa” wynosi ponad 300 tys. egzemplarzy. Obok gazety powstał pokrewny serwis informacyjny analisadaily.com.", "Akile": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akil</b>.</p><p>Akil to miasto w stanie Yucatán w Meksyku. W 2005 roku liczba mieszkańców miasta wynosiła 9765 osób.</p>", "Areena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arena</b>.</p><b>Arena</b> (z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>harena</i>, <i>arena</i> - <a href=\"https://pl.wikipedia.org/wiki/Piasek\" target=\"_blank\" rel=\"noopener noreferrer\">piasek</a>) – usytuowany w centrum obiektu i wysypany piaskiem plac w kształcie koła lub elipsy. Miejsce walk, turniejów, popisów, igrzysk i widowisk. Wywodzi się ze <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnego</a> teatru greckiego i rzymskiego oraz cyrku rzymskiego.", "Aiyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ayyan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ayan</b>.</p><p>⁇ Nieuchwytny ⁇ (tam. அயன், Ayan) - indyjski film przygodowy reżysera K.</p>", "Axella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Axela</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Axel</b>.</p><p>Akcel (niem. Axel, czyli angielski.</p>", "Andreea-Irina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Andriana-Olia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andriana</b>.</p><p>Andriana to rodzaj roślin kwiatowych z rodziny Apiaceae.</p>", "Anna Margarete": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Andjela": "<p>Anđela to sławskie imię kobiece, krewny Angeli. Do wybitnych osób z tym nazwiskiem należą: Anđela Bulatović (ur. 1987), w Czarnogórze handbalista Anđela Frajtović (ura. 2000), w Serbii piłkarz Anđela Janjušević (ur., 1995), w Serbii handbalista Andžela Mužinić (ur.: 1992), w Chorwacji tenisistka stołowa Anđela Šešlija (ur. 1995), w Bośni</p>", "Akylyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akilina</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akil</b>.</p><p>Akil to miasto w stanie Yucatán w Meksyku. W 2005 roku liczba mieszkańców miasta wynosiła 9765 osób.</p>", "Alethea": "<p>Alethea to angielskojęzyczne imię kobiety pochodzące z starożytnego greckiego rzeczoznacznika ἀλήθεια, al ⁇ theia, 'prawda'. Aletheia była osobowością prawdy w filozofii greckiej.</p>", "Alesia-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alesia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksandra</b>.</p><b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Adelina-Denisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adelina</b>.</p><b>Adelina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, utworzone za pomocą zdrabniającego przyrostka <i>-ina</i> od imienia <a href=\"https://pl.wikipedia.org/wiki/Adela\" target=\"_blank\" rel=\"noopener noreferrer\">Adela</a>.", "Alexandra Janina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Anna Halina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Alexandra Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Anna-Milana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aryadna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ariadna</b>.</p><p>Ariadna jest pająkiem z rodziny Segestriidae.</p>", "Akgül": "<p>Akgül lub Akgul (co oznacza \"Biała Róża\" w kilku językach tureckich) może odnosić się do:</p>", "Angelica Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angelica</b>.</p><p>Dudnik, czyli aniolica (lat. Angélica) - rodzaj trawniczośnych roślin rodziny Zontickich (Apiaceae).</p>", "Anna-Sofiya": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Amire": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amir</b>.</p><b>Amir</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أمير&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia arabskiego, oznacza „książę” lub „dowódca”.", "Adelisa": "<b>Adelisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a>. Powstało na skutek <a href=\"https://pl.wikipedia.org/wiki/Kontaminacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">kontaminacji</a> imion <a href=\"https://pl.wikipedia.org/wiki/Adela\" target=\"_blank\" rel=\"noopener noreferrer\">Adela</a> i Lisa. Można je spotkać także w formach Adalicia, Adaliz i Adeliza.", "Aula": "<b>Aula</b> – pojęcie o kilku znaczeniach:", "Ariell": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ariel</b>.</p><b>Ariel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֲרִיאֵל&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> słów oznaczających „lew Boga”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> używane było jako alternatywna nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolima</a>.", "Arissa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arisa</b>.</p><p>Arisa (jap. アリサ Arissa) - seria Nazuimi Ando, która ukazała się w czasopiśmie Nakayoshi od lutego 2009 roku do września 2012 roku.</p>", "Aasta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asta</b>.</p><p>Asta to rodzaj roślin kwiatowych z rodziny Części.</p>", "Angela Gabriela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angela</b>.</p><b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Alina-Mădălina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Agnetta": "<b>Agnieszka</b> – imię żeńskie, jedno z najpopularniejszych w Polsce, gdzie pojawiło się wraz z chrześcijaństwem. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγνή – „czysta”, „dziewicza”, „nieskalana”. Może również pochodzić od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>agnus</em> – „baranek” (to jednocześnie rodzaj męski greckiej „h-agne”). Do Czech imię to dotarło w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Agnes</em>, następnie zostało zaadaptowane do języka polskiego w obecnej formie. Imię to funkcjonuje również w języku polskim w formie Inka, początkowo było ono polskim zdrobnieniem imienia Inez — francusko-iberyjskiej formy imienia Agnieszka (Inês, Inés, Inès) — z czasem jednak zaczęło funkcjonować w Polsce jako samodzielne imię.", "Alyse": "<p>Alice to żeńskie imię z korzeniami w językach francuskim i niemieckim.</p>", "Anca-Daciana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anca</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anka</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Andrada-Mădălina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrada</b>.</p><p>Andrada to nazwisko, a także rumuńskie kobiece imię. Do wybitnych osób z nazwiskiem należą: Alonso Andrada (1590-1672), biograf i pisarz asketyczny Diogo de Paiva de Andrada (1528-1575), portugalski teolog urodzony w Coimbra Edgardo Andrada (1939-2019), emerytowany profesjonalny piłkarz argentyński, który grał jako bramkarz Esteban Andrada (urodzony w 1991 roku), argentyński międzynarodowy bramkarze José Andrada (1948-2025), argenty...</p>", "Anna Eleonora": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna Elizabeth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Avie": "<p>Avie to imię żeńskie lub męskie. Jako nick może być skróceniem Avis, Avery, Avanel i Ava.</p>", "Ali Naji": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Adelyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adel</b>.</p><p>Adel - wieloznaczny termin.</p>", "Aharona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aharon</b>.</p><p>Aharon אַהֲרֹן to męskie imię pierwotnie napisane, powszechnie w Izraelu, z późniejszej wersji Aarona, wybitnej postaci biblijnej w Starym Testamencie, \"Z gór\" lub \"Górnik\". Istnieją inne warianty, w tym \"Ahron\" i \"Aron\".</p>", "Anna-Kateryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Abdullah H": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdullah</b>.</p><b>Abdullah</b>, <b>Abdallah</b>, <b>Abd Allah</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عبد ﷲ&#8206;) to popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>sługa <a href=\"https://pl.wikipedia.org/wiki/Allah\" target=\"_blank\" rel=\"noopener noreferrer\">Allaha</a></i>. Jest ono często przybierane przez osoby nowo nawrócone na <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>.", "Andżella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andżela</b>.</p><b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Armita": "<p>Armita to kobiece perskie imię. Armita pochodzi od awestańskiej nazwy Ārmaiti, która odnosi się do \"świętej oddanności\" lub \"boskiej kreatywności\".</p>", "Amalia-Ionela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amalia</b>.</p>Odpowiedniki w innych językach:", "Anna-Maya": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Arleth": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arlet</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arleta</b>.</p><b>Arleta</b>, <b>Arletta</b> – imię żeńskie zapożyczone z francuskiego; powstało prawdopodobnie jako zdrobnienie germańskiego imienia <i>Carletta</i> (<i>Karletta</i>), żeńskiej formy imienia Karl (<a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>).", "Asmira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Asmir</b>.</p><p>Asmir to bosniackie imię męskie. Na Bałkanach Asmir jest popularny wśród bosniaków w dawnych krajach Jugosłowiańskiej.</p>", "Anna-Yaroslava": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anca-Georgeta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anca</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anka</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Adela-Simina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adela</b>.</p><b>Adela</b> – imię żeńskie pochodzenia germańskiego. Jest ono skróconą formą dwuczłonowych imion takich jak Adalberga, <a href=\"https://pl.wikipedia.org/wiki/Adalgunda\" target=\"_blank\" rel=\"noopener noreferrer\">Adalgunda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelinda\" target=\"_blank\" rel=\"noopener noreferrer\">Adelinda</a>, tj. imion z pierwszym członem <i>adal</i> oznaczającym „szlachetny ród”, „szlachetny stan”. Skrócenie to powstało na gruncie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">języka francuskiego</a>.", "Aysenur": "<p>Ayşenur to tureckie imię kobiet i może odnosić się do: Ayşenur Alpaslan (ur. 1953), turecki dyplomat i były ambasador Ayşenur Duman (ur. 1999), turecki olimpijski narciarz Ayşenur Ezgi Eygi (1998-2024), tureckiego urodzonego amerykańskiego działacza praw człowieka Ayşenur İslam (ur. 1958), tureckiej uczelni wykładowcy i polityk Ayşenur Sormaz (ur. 2000), tureckie piłkarz handbal Ayşenur Taşbakan (ur. 1982), turecki trener taekwondo...</p>", "Ayoka": "<p>Ayoka to kobiece imię, które jest powszechnie używane w Nigerii i pochodzi z języka joruba. Oznacza to \"który sprawia radość\" lub \"które sprawia radości wszędzie\".</p>", "Ahmed Khan Haji": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ahmed</b>.</p><b>Ahmad</b>, Ahmed, Ahmet (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;أحمد&#8206;, <i>Aḥmad</i>) – popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>.", "Anna Rose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Akshatha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akshata</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Akshat</b>.</p><p>Akshat to męskie imię w kulturach hinduskich i buddyjskich. Pochodzi od sanskryckiego słowa Aksata, co oznacza \"niepowlekany\".</p>", "Andrea Marcela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Angelli": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angell</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angel</b>.</p><p>Anioł jest istotą wyrażającą wolę Bożą. Może również oznaczać:</p>", "Anais-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anais</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Antonina Ewa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonina</b>.</p><b>Antonina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antonin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonin</a>; uformowany przy użyciu <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, <i>-ina</i>, oznaczającego przynależność lub pochodzenie, <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwy rodowej</a> <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Antoniuszów</a>. W Polsce Antonina pojawiła się później niż obecna od średniowiecza <a href=\"https://pl.wikipedia.org/wiki/Antonia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonia</a>; notowana jest co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1637\" target=\"_blank\" rel=\"noopener noreferrer\">1637</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Antonina w 2017 r. zajmowała 15. miejsce w grupie imion żeńskich. W całej populacji Polek Antonina zajmowała w 2017 r. 90. miejsce (43 462 nadań).", "Anna-Alina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anis Ilany": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anis</b>.</p><b>Anisette</b> – <a href=\"https://pl.wikipedia.org/wiki/Likier\" target=\"_blank\" rel=\"noopener noreferrer\">likier</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">francuskiego</a> o zawartości alkoholu 25-40%. Jest produkowany z likierów korzennych na bazie <a href=\"https://pl.wikipedia.org/wiki/Biedrzeniec_any%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">anyżu</a>, oliwki anyżowej z dodatkiem aromatu <a href=\"https://pl.wikipedia.org/wiki/Koper_ogrodowy\" target=\"_blank\" rel=\"noopener noreferrer\">kopru</a>, <a href=\"https://pl.wikipedia.org/wiki/Go%C5%BAdziki\" target=\"_blank\" rel=\"noopener noreferrer\">goździków</a>, bądź <a href=\"https://pl.wikipedia.org/wiki/Kolendra_siewna\" target=\"_blank\" rel=\"noopener noreferrer\">kolendry</a>. Alkohol jest często używany z barach jako składnik <a href=\"https://pl.wikipedia.org/wiki/Koktajl_alkoholowy\" target=\"_blank\" rel=\"noopener noreferrer\">koktajli</a>.", "Alexandra-Diana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Agatka": "<p>Agatha, również Agata, jest imieniem żeńskim pochodzącym z greckiej imienia żeńskiego ⁇ γάθη (Agáthē; alternatywna forma: ⁇ γαθή Agath ⁇), która jest nominalizacją ἀγαθή (agath ⁇), czyli żeńską formą przymiotnika ἀγαθός (agathós) \"dobry\".</p>", "Aryia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ariia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aria</b>.</p><p>Aria: Aria to album brytyjskiego zespołu prog-rock Asia. Aria - instrumentalny album trybjutów poświęcony zespołowi ⁇ Aria ⁇ .</p>", "Alicja Ewa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alicja</b>.</p>Może pochodzić od włoskiej, żeńskiej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksy\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksy</a> – Alessis, imię to przyjmowało w językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskim</a> formę Alexia.", "Angela Tatiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angela</b>.</p><b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Amyrah": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amirah</b>.</p><p>Amira (أميرة ʾamīrah) to kobiece imię oznaczające księżniczkę, dowódcę lub władcę. To kobieca wersja męskiego imienia Amir.</p>", "Avah": "<p>Ava (ang. /ˈeɪ.və/) to angielskie imię żeńskie.</p>", "Anna Danuta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anaysa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anaisa</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anais</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aurie": "<p>Aurélie (lub jego warianty Aurelie lub Aurelia) to imiona kobiece występujące głównie we Francji, pochodzące z łacińskiej Aurelius (złota) rodziny. Mężczyźni to Aurèle i Aurélien.</p>", "Alexandra-Cosmina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Adeela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adeel</b>.</p><p>Adeel (arabsko: عديل) to muzułmańskie imię męskie w Azji Południowej.</p>", "An-An": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Adee": "<p>Adee to zarówno nazwisko, jak i imię. Wśród znanych osób z imieniem Alvey A.</p>", "Angela Rocio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angela</b>.</p><b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Aara": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ara</b>.</p><p>Ara (lat. Ara) - rodzaj ptaków rodziny papugów.</p>", "Anna-Roksolana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Alba Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alba</b>.</p><b>Alba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od łac. <i>Albus/a</i>, od <i>albus</i> \"jasny, biały, świetlisty\". W Polsce spotykane bardzo rzadko, choć notowane już w średniowieczu.", "Alíz": "<p>Alice to żeńskie imię z korzeniami w językach francuskim i niemieckim.</p>", "Anna-Luiza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "An Như": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Aania": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ania</b>.</p><p>Tainia (lat. Tainia) - rodzaj jednokładnych roślin z rodu rodziny Orchid (Orchidaceae).</p>", "Aideen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aiden</b>.</p><p>Aidan, Aiden i Ayden są angielsko złożonymi wersjami irlandzkiego męskiego nazwiska Aodhán. Irlandzką kobiecy odpowiednik jest Aodhnait.</p>", "Andrea Alejandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Alexandra-Andrea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Ainslee": "<p>Ainslee może odnosić się do: Mary Ainslee (1919-1991), amerykańskiej aktorki filmowej Ainslee Cox (1936-1988), amerykańskiego dyrygenta muzycznego Ainslee Lamb, kanadyjskiego trenerka hokeja pola Ainslee's Magazine, amerykańską literaczną czasopismę opublikowaną w latach 1897 - grudnia 1926 Winifred Ainslee (ur. 1923 lub 1924), amerykańska aktorka</p>", "Adili": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adil</b>.</p><b>Adil</b> – arabskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od słowa <i>adil</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;عدل&#8206;, <i>’adil</i>) – 'sprawiedliwy', 'uczciwy'.", "Adunni": "<p>Àdùnní to jorubańska nazwisko dla kobiet, co oznacza \"kto jest przyjemny\". Àdùnní to orúkọ Oríkì (panegryki), które w języku joruba używane są do wywołania pożądanych cnót i cech.</p>", "Agnieszka Zofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Agnieszka</b>.</p><b>Agnieszka</b> – imię żeńskie, jedno z najpopularniejszych w Polsce, gdzie pojawiło się wraz z chrześcijaństwem. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Αγνή – „czysta”, „dziewicza”, „nieskalana”. Może również pochodzić od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>agnus</em> – „baranek” (to jednocześnie rodzaj męski greckiej „h-agne”). Do Czech imię to dotarło w formie <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Agnes</em>, następnie zostało zaadaptowane do języka polskiego w obecnej formie. Imię to funkcjonuje również w języku polskim w formie Inka, początkowo było ono polskim zdrobnieniem imienia Inez — francusko-iberyjskiej formy imienia Agnieszka (Inês, Inés, Inès) — z czasem jednak zaczęło funkcjonować w Polsce jako samodzielne imię.", "Aaya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aya</b>.</p><b>Aya</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;あや, アカネ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Appolinariia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Apolinaria</b>.</p><b>Apolinaria</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Apolinary\" target=\"_blank\" rel=\"noopener noreferrer\">Apolinary</a>. W <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a> i krajach wschodniosłowiańskich utworzono od Apolinarii skróconą formę Polina (możliwą też od <a href=\"https://pl.wikipedia.org/wiki/Pelagia\" target=\"_blank\" rel=\"noopener noreferrer\">Pelagii</a> lub współcześnie jako fonetyczne przeniesienie francuskiej <a href=\"https://pl.wikipedia.org/wiki/Paulina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Pauline</a> na grunt rosyjski), która w 2007 roku imię była drugim pod względem liczby nadań wśród noworodków imieniem żeńskim w okręgu moskiewskim w Rosji. Według stanu na 17 stycznia 2015 imię to miało w Polsce 5 nadań.", "Astrid Johanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Astrid</b>.</p><b>Astryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronorweskich</a> wyrazów <i>áss</i> – „bóg” i <i>fríðr</i> – „piękna” (mogło zatem oznaczać „piękna jak bóg”). Patronką tego imienia jest bł. Astryda.", "Alina-Mariya": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Ainé": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ain</b>.</p><p>Ain jest prowincją we Francji. Prowincja jest nazwana po rzeki Ain na wschodnim krańcu Francji.</p>", "Alexandra-Gabriela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Aleah": "<p>Alia lub Aleah jest nazwiskiem i nazwiskiem kobiecym, w obu przypadkach odmiany nazwiska Aaliyah. Nazwa ta ma arabski pochodzenie i oznacza \"wysoki\" lub \"wywyższony\".</p>", "Alix Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alix</b>.</p><p>Święta Alice (francuski: Alix de Schaerbeek, Alice, Adélaïde, Aleyde, 1225, Skarbek (obecnie Belgia) - 1250, Abbotstwo Cambr, Bruksela) - święta Kościoła rzymskokatolicznego, czczona jako patronka ślepych i paraliżowanych.</p>", "Anna-Nicole": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Arjola": "<p>Arjola to kobiece imię. Wśród znanych osób z imieniem: Arjola Dedaj (ur. 1981), włoska sportowca Arjola Trimi (ur. 1987), włoski pływacz</p>", "Anastasiia-Anhelina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Alix Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alix</b>.</p><p>Święta Alice (francuski: Alix de Schaerbeek, Alice, Adélaïde, Aleyde, 1225, Skarbek (obecnie Belgia) - 1250, Abbotstwo Cambr, Bruksela) - święta Kościoła rzymskokatolicznego, czczona jako patronka ślepych i paraliżowanych.</p>", "Anastassija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastassia</b>.</p><p>Anastassia to kobiece imię. Znanymi osobami z nazwiskiem to: Anastassia Kovalenko (ur. 1991), estyjska motocyklowa wyścigacz drogowy Anastassja Khozissova (ur. 1979), rosyjska modelka Anastassya Michaeli (ur. 1975), izraelska dziennikarz, telewizyjna prezenterka i polityk Anastassie Morkovkina (ur. 1981), estyckie piłkarz</p>", "Angie Alejandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Ada Luz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ada</b>.</p><b>Ada</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> <a href=\"https://pl.wikipedia.org/wiki/Kobieta\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języku hebrajskim</a> znaczy: upiększać się, stroić się. Imię Ada jest wymieniane w <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">Biblii</a> w pierwszej księdze <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starego Testamentu</a>, gdzie jest jedną z żon Lemecha i matką Jubala. W Biblii jest także mowa o Adzie, matce flecistów i grających na harfie (<a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Rdz.</a> 4, 21).", "Alexandra-Nadia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Arnoldyna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arnold</b>.</p><b>Arnold</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Stanowi złożenie członów oznaczających „orzeł” i „panujący”. Jednym z patronów tego imienia w Kościele katolickim jest <a href=\"https://pl.wikipedia.org/wiki/Arnold_Janssen\" target=\"_blank\" rel=\"noopener noreferrer\">Arnold Janssen</a>.", "Aleksandra Danuta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aleksandra</b>.</p><b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Arkadiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Arkadia</b>.</p><b>Arkadia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi od słowa (<i>arkadios</i>) oznaczającego „pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Arkadia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Arkadii</a>, krainy szczęśliwości”.", "Anna Phương": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Alaâ": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ala</b>.</p><p>Alanin (2-aminopropanowy kwas) - aminokwas alifatyczny. α-alanina jest częścią wielu białek, β-alanina - w szeregu związków biologicznie aktywnych.</p>", "Andreea-Diana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Anca-Gabriela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anca</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anka</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Ashhad": "<p>Ashhad (arabski: اشهد), 'Name' to indyjskie imię pochodzenia dla mężczyzny, ale słowo 'Ashhad' jest arabskim słowem, które oznacza 'świadczyciel' i może być używane jako imię i nazwisko. Może odnosić się do: Saiyed Saeed Ashhad, były sędzia Sądu Najwyższego Pakistanu</p>", "Anna Julia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Almeyda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Almeida</b>.</p>Nazwa miejscowości wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> <i>al-Ma’ida</i>, co oznacza „stół”. Odnosi się to do płaskiego ukształtowania terenu otaczającego miejscowość.", "Angie Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Angie Vanesa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Abdulhakim A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Abdulhakim</b>.</p><p>Abdul Hakim (arabski: عبد الحكيم, romanized: ʻAbd al-Ḥakīm) to muzułmańskie imię męskie, a w nowoczesnym użyciu, imię i nazwisko. Został zbudowany z arabskich słów Abd, al- i Hakim.</p>", "Alazne": "<p>Alazne to baskijska kobieca nazwa, co oznacza \"lustrze\". Nazwa została zaproponowana przez Sabino Arana w swojej liście baskijskich świętych nazw w 1910 roku jako odpowiednik Milagros.</p>", "Ametyst": "<b>Ametyst</b> – <a href=\"https://pl.wikipedia.org/wiki/Minera%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">minerał</a>, fioletowa i przezroczysta do przeświecającej odmiana <a href=\"https://pl.wikipedia.org/wiki/Kwarc\" target=\"_blank\" rel=\"noopener noreferrer\">kwarcu</a>. Kamień półszlachetny, używany w <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82otnictwo\" target=\"_blank\" rel=\"noopener noreferrer\">jubilerstwie</a>. Jego nazwa pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka greckiego</a> i oznacza „trzeźwy” (ἀ- <i>a</i> – ‘nie’, μέθυστος <i>méthystos</i> – ‘pijany’), gdyż według greckich wierzeń, picie <a href=\"https://pl.wikipedia.org/wiki/Wino\" target=\"_blank\" rel=\"noopener noreferrer\">wina</a> z czar ametystowych zabezpieczało pijącego przed upiciem się.", "Alina-Ivanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Aniela Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aniela</b>.</p><b>Aniela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, które jest spolszczoną formą <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Angela\" target=\"_blank\" rel=\"noopener noreferrer\">Angela</a>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa <i>ángelos</i> „posłaniec”. Imię trafiło do Polski z Włoch prawdopodobnie w XVIII wieku. W świecie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> upowszechniło się jako nawiązanie do <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">aniołów</a> i <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_Str%C3%B3%C5%BC_(religioznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioła Stróża</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>.", "Araina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ara</b>.</p><p>Ara (lat. Ara) - rodzaj ptaków rodziny papugów.</p>", "Andrea Isabel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Anna-Adelina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna-Olena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Angie Milena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Anna-Ivanna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "April Rose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>April</b>.</p><p>April (kr. 에이프릴; często stylizowana jako APRIL, wymawia się jako April (April) - południowo koreańska dziewczęta-grupa, utworzona w 2015 roku przez DSP Media. Składa się z sześciu uczestników: Čekyon, Čevon, Naын, Jena, Rachel i Jinsol.</p>", "Anasthasia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anastasia</b>.</p><b>Anastazja</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Anastazy\" target=\"_blank\" rel=\"noopener noreferrer\">Anastazy</a>. Oznacza „zmartwychwstała, wskrzeszona”.", "Alexandra-Narcisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Anna Adela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aryela": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aryel</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ariel</b>.</p><b>Ariel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;אֲרִיאֵל&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> słów oznaczających „lew Boga”. W <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a> używane było jako alternatywna nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Jerozolima\" target=\"_blank\" rel=\"noopener noreferrer\">Jerozolima</a>.", "Anna-Bozhena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Ayari": "<p>Ayari (arabsko: العياري przymiot عَيّار ayyār) to magrebijska (Tunisia, Algieria) i perskie nazwisko. W Francji mieszka ponad 400 osób z tym nazwiskiem (tj.</p>", "Alexandra-Andra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Afraa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Afra</b>.</p><b>Afra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, utworzone od nazwy <i>Afri</i>, oznaczającej osobę pochodzącą z <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afryki</a>. Było to imię dwóch świętych we wczesnym okresie chrześcijaństwa (<a href=\"https://pl.wikipedia.org/wiki/Afra_z_Augsburga\" target=\"_blank\" rel=\"noopener noreferrer\">Afry z Augsburga</a>, zm. ok. 304 i Afry, męczennicy w <a href=\"https://pl.wikipedia.org/wiki/Brescia\" target=\"_blank\" rel=\"noopener noreferrer\">Brescii</a> za cesarza <a href=\"https://pl.wikipedia.org/wiki/Lucjusz_Domicjusz_Aurelian\" target=\"_blank\" rel=\"noopener noreferrer\">Aureliana</a>).", "Angie Yulieth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Amele": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Amel</b>.</p><p>Amel (Francuz: Amblève) jest miastem w regionie Wallonie, prowincji Liège, i należy do niemieckojęzycznej społeczności w Belgii (German: Deutschsprachige Gemeinschaft Belgiens). Na 1 stycznia 2006 roku Amel miał łącznie 5.282 mieszkańców.</p>", "Alexiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alexia</b>.</p><p>Aleksja (włoski: Alexia). Alexia, imię urodzone. Alessia Aquilani, rodzina.</p>", "Aglaija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aglaia</b>.</p><p>Aglaia (lat. Aglaia) - rodzaj roślin kwiatowych z rodziny Meliaceae.</p>", "An Chi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Anastasiia-Iryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Anggy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Angy</b>.</p><p>Ángela Maria Fernandez Gonzalez (hisz. Ángela María Fernández González, urodz.</p>", "An Nhi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Alexandra-Andreea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Adithi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aditi</b>.</p>W <i>Bryhadajranjakopaniszad</i> (1.2.5) określenie dla oznaczenia <a href=\"https://pl.wikipedia.org/wiki/Absolut\" target=\"_blank\" rel=\"noopener noreferrer\">bytu absolutnego</a>.", "Ann-Christin": "<p>Ann-Christin to kobiece podwójne imię. Znanymi osobami z nazwiska są: Ann-Christin Ahlberg (ur. 1957), szwedzka polityk Ann-Chrstin Nykvist, szwedzki polityk Ann -Christin Strack (ur. 1993), niemiecki bobsledder</p>", "Adryanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adryana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adryan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adrian</b>.</p><b>Adrian</b>, również <b>Hadrian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia cesarza <a href=\"https://pl.wikipedia.org/wiki/Hadrian\" target=\"_blank\" rel=\"noopener noreferrer\">Hadriana</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> „Hadrianus”, czyli „pochodzący z Hadrii” lub „z regionu <a href=\"https://pl.wikipedia.org/wiki/Morze_Adriatyckie\" target=\"_blank\" rel=\"noopener noreferrer\">morza Adriatyckiego</a>”. Imię było noszone przez kilku wczesnochrześcijańskich świętych i męczenników m.in. <a href=\"https://pl.wikipedia.org/wiki/Adrian_z_Canterbury\" target=\"_blank\" rel=\"noopener noreferrer\">św. Adriana z Canterbury</a>.", "Alexandra-Camelia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "An Qi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Anga": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ang</b>.</p>W Wielkiej Brytanii i Australii angielski jest <i>de facto</i> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_urz%C4%99dowy\" target=\"_blank\" rel=\"noopener noreferrer\">językiem urzędowym</a>, choć formalnie państwa te nie objęły takim statusem żadnego języka. Angielszczyzna należy do oficjalnych języków <a href=\"https://pl.wikipedia.org/wiki/Organizacja_Narod%C3%B3w_Zjednoczonych\" target=\"_blank\" rel=\"noopener noreferrer\">ONZ</a>, a od XX wieku jest najczęściej używanym językiem w kontaktach międzynarodowych. Bywa określana jako pierwszy uniwersalny nowożytny język ludzkości. Stanowi główny język nauki, handlu i polityki, a w niektórych krajach także kształcenia wyższego.", "Alicja Krystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alicja</b>.</p>Może pochodzić od włoskiej, żeńskiej formy imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksy\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksy</a> – Alessis, imię to przyjmowało w językach: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niemieckim</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">angielskim</a> formę Alexia.", "Andreea-Beatrice": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Andreea-Denisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Andriia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Andrii</b>.</p><p>Andriy lub Andrii (ukraina: Андрі́й) jest ukraińską formą męskiego angielskiego imienia Andrew.</p>", "Antonina Zofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonina</b>.</p><b>Antonina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antonin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonin</a>; uformowany przy użyciu <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, <i>-ina</i>, oznaczającego przynależność lub pochodzenie, <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwy rodowej</a> <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Antoniuszów</a>. W Polsce Antonina pojawiła się później niż obecna od średniowiecza <a href=\"https://pl.wikipedia.org/wiki/Antonia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonia</a>; notowana jest co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1637\" target=\"_blank\" rel=\"noopener noreferrer\">1637</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Antonina w 2017 r. zajmowała 15. miejsce w grupie imion żeńskich. W całej populacji Polek Antonina zajmowała w 2017 r. 90. miejsce (43 462 nadań).", "Astrid Carolina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Astrid</b>.</p><b>Astryda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronorweskich</a> wyrazów <i>áss</i> – „bóg” i <i>fríðr</i> – „piękna” (mogło zatem oznaczać „piękna jak bóg”). Patronką tego imienia jest bł. Astryda.", "Alexandra-Ştefania": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alexandra</b>.</p><p>Alexandra (lat. - nazwisko biologicznych taksonów: Alexandra Bunge (Aleksandr) - synonim rodza roślin Świeda (Suaeda Forssk. ex J.F.Gmel.) Alexandra R. H. - Nie, nie. - Nie, nie.</p>", "Anna-Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aracelly": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aracely</b>.</p><p>Araceli lub Aracely, hiszpańskie imię kobiety z łacińskiego Ara Cœli, \"ołtarz w niebie\", może odnosić się do:</p>", "Anaaya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anaya</b>.</p><p>Anaya jest miastem w prowincji Segovia, Kastilia i Leon, Hiszpania. Według badania ludności z 2004 roku przeprowadzonego przez Hiszpański Instytut Statystyczny Narodowy, mieście to miało 136 mieszkańców.</p>", "Adana": "<b>Adana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia hebrajskiego o znaczeniu \"ziemia\". Obecnie rzadko jest nadawane.", "Adina-Alexandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adina</b>.</p><p>Adina (lat. Adina) - rodzaj drewnianych roślin z rodziny Marenowych (Rubiaceae).</p>", "Armella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Armela</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Armel</b>.</p><p>Armel (r. Armel) - kamienny meteoryt, zwykły chondryt o wadze 9200 g.</p>", "Angela Del Carmen": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angela</b>.</p><b>Angela</b> – imię pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <i>Angel</i>, które powstało od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> słowa ángelos \"posłaniec\". Imię to też zostało przyswojone w postaci <a href=\"https://pl.wikipedia.org/wiki/Aniela\" target=\"_blank\" rel=\"noopener noreferrer\">Aniela</a>, od niego powstały też imiona <a href=\"https://pl.wikipedia.org/wiki/Angelika\" target=\"_blank\" rel=\"noopener noreferrer\">Angelika</a> i <a href=\"https://pl.wikipedia.org/wiki/Angelina\" target=\"_blank\" rel=\"noopener noreferrer\">Angelina</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Anio%C5%82_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Anioł (Angel)</a>. W ostatnich czasach zapis imienia Angela bywa spolszczany i występuje w formie Andżela lub nawet <i>Andrzela</i> (część osób błędnie wywodzi jej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">źródłosłów</a> od imienia męskiego <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>). Ta druga wersja jest niepoprawna.", "Alía": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ali</b>.</p><b>Ali</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;علي&#8206;) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>. Wywodzi się od arabskiego słowa oznaczającego „wysoki”.", "Anna-Mária": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Antonina Katarzyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Antonina</b>.</p><b>Antonina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Antonin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonin</a>; uformowany przy użyciu <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, <i>-ina</i>, oznaczającego przynależność lub pochodzenie, <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a> od <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwy rodowej</a> <a href=\"https://pl.wikipedia.org/wiki/Drzewo_genealogiczne_Antoniusz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">rodu Antoniuszów</a>. W Polsce Antonina pojawiła się później niż obecna od średniowiecza <a href=\"https://pl.wikipedia.org/wiki/Antonia_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Antonia</a>; notowana jest co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1637\" target=\"_blank\" rel=\"noopener noreferrer\">1637</a> roku. Wśród imion nadawanych nowo narodzonym dzieciom, Antonina w 2017 r. zajmowała 15. miejsce w grupie imion żeńskich. W całej populacji Polek Antonina zajmowała w 2017 r. 90. miejsce (43 462 nadań).", "An Duong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Alisza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alisha</b>.</p><p>Alice Ann Itkin (ang. Alisha Ann Itkin; po ślubie - Alice Sinamon (ang.</p>", "Adelina-Narcisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Adelina</b>.</p><b>Adelina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, utworzone za pomocą zdrabniającego przyrostka <i>-ina</i> od imienia <a href=\"https://pl.wikipedia.org/wiki/Adela\" target=\"_blank\" rel=\"noopener noreferrer\">Adela</a>.", "Amalia-Sultana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Amalia</b>.</p>Odpowiedniki w innych językach:", "Anna-Lea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Atin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Atina</b>.</p><p>Atina jest miastem w prowincji Frosinone w włoskiej regionie Lazio. Miasto ma powierzchnię 29 km2, ludności 4480 osób.</p>", "Andreea-Roxana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Andreea-Mădălina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andreea</b>.</p><p>Andreea to rumuńskie imię żeńskie. Jest to kobiece Andrei, rumuńska forma Andrzeja.</p>", "Apoloniia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Apolonia</b>.</p><b>Apolonia</b> – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające osobę należącą do boga <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apolla</a>. W <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">starożytności</a> mogło także pochodzić od nazwy miasta (dotyczy wyzwoleńców).", "Altana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Altan</b>.</p><p>Altan to irlandzka grupa folk, założona w hrabstwie Donegal w 1987 roku przez wokalistkę Mayred Ni Winney i jej męża, Franki Kennedy. Grupa była przede wszystkim pod wpływem tradycyjnych irlandzkich piosenek z Donegal i sprzedała ponad milion płyt.</p>", "Anike": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anik</b>.</p><p>Anik: Anik to seria satelitów telekomunikacyjnych geostacjonarnych uruchomionych przez Telesat Canada. Anik G1 - satelitę telekomunikacyjną stworzoną przez amerykańską firmę Space Systems/Loral.</p>", "Asumpta": "<b>Asumpta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, nadawane w nawiązaniu do wniebowzięcia Marii, Matki Boskiej.", "Aleksandra Janina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aleksandra</b>.</p><b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Angelica Milena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angelica</b>.</p><p>Dudnik, czyli aniolica (lat. Angélica) - rodzaj trawniczośnych roślin rodziny Zontickich (Apiaceae).</p>", "Anais-Sara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anais</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anna-Kamila": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Angie Karina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Angie</b>.</p><p>⁇ Angie ⁇ (⁇ ⁇ 'Angji ⁇ , zmniejszający się na imię Angela) - piosenka brytyjskiego zespołu rockowego Rolling Stones z ich 1973 roku albumu Goats Head Soup. Niedługo przed wydaniem albumu wydano osobny single, wraz z piosenką ⁇ Silver Train ⁇ na odwrotnej stronie.</p>", "Alina-Sabina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Alina</b>.</p><b>Alina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, powstałe jako forma pochodna od <a href=\"https://pl.wikipedia.org/wiki/Adelajda_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelajda</a>, <a href=\"https://pl.wikipedia.org/wiki/Adelina_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Adelina</a>. W staropolszczyźnie pisane m.in. <b>Alena</b>, <b>Helina</b>.Imię to może mieć też związek z mianem <a href=\"https://pl.wikipedia.org/wiki/Halina\" target=\"_blank\" rel=\"noopener noreferrer\">Halina</a> – „ładna”, „dostojna”, „spokojna”. Alina to także pierwotna, pruska nazwa rzeki <a href=\"https://pl.wikipedia.org/wiki/%C5%81yna\" target=\"_blank\" rel=\"noopener noreferrer\">Łyny</a>, która w młodszych formach brzmiała Alna (1251 <a href=\"https://pl.wikipedia.org/wiki/Naszej_ery\" target=\"_blank\" rel=\"noopener noreferrer\">n.e.</a>) i Alne (1308). Alina w języku pruskim oznaczała samicę <a href=\"https://pl.wikipedia.org/wiki/Jele%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">jelenia</a> – łanię. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_litewski\" target=\"_blank\" rel=\"noopener noreferrer\">litewsku</a> słowo <i>elnias</i> oznacza jelenia.", "Anna Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Anastasiia-Nataliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anastasiia</b>.</p><p>Anastasia to imię. Do znanych osób z tej nazwy należą: Anastasiia Akchurina (ur. 1992), rosyjska gracz badminton Anastasija Antoniak (ur. 1997), ukraińska pływacz Anastasii Arkhipova (ur. 2003), ukraińską paterankę figurną Anastasię Bachynskę (ur. 2003), ukraińskiej gimnastki artystycznej Anastasią Blyshchyk, ukraińskiego dziennikarza i żołnierza Anastasiu Bryzginę (ur. 1998), ukraiński sprinter Anastasia Demurchian (ur. 2004), włoski...</p>", "Abijah": "<p>Abija (Hebrajskie: אֲבִיָּה Aviyyah) to biblijna hebrajska nazwa unisex, co oznacza \"moim Ojcem jest Jah\". Hebrajska forma Avijahu występuje również w Biblii.</p>", "An Phuong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>An</b>.</p><p>AN (lub An, an, aN) - łacińska abbrewiatura: AN - abbrewiata dla włoskiej partii ⁇ National alliance ⁇ (italij. Alleanza Nazionale).</p>", "Augustino": "<p>Augustino to męskie imię. Wśród znanych osób z nazwiska są: Augustino de Cazalla (1510-1559), hiszpański duchowny Augustino Jadalla Wani, południowsudanowy polityk Augustino Marial, sudanski bokser Augustino Masele (ur. 1966), tanzanijski polityk Augustin M. (1944-2022), tanzaniński polityk Augustina Oldoini (1612-1683), włoski nauczyciel jezuitów, historycz kościelny i bibliograf Augustino Ramadhani (1945-2020), tanzani...</p>", "Adełina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adelyna</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adel</b>.</p><p>Adel - wieloznaczny termin.</p>", "Alissiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alisiya</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Alisia</b>.</p><p>Alicia to kobiece imię. Jest to wariant Alice, który pochodzi z germańskiego imienia Adalheidis (Adelaide), co oznacza \"szlachetny natury\" (szlachetnego rodzaju).</p>", "Aude Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aude</b>.</p><p>Aude jest francuską prowincją, należącą do regionu administracyjnego Occitanie, w której stolica jest Carcassonne, składająca się z trzech okręgów z pozostałymi stolicami: Limoux, Narbonne.</p>", "Anna Paula": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Aliyya": "<p>Alija, Aaliyah, Alia lub Aliyah (arabickie: عَلِيَّة lub عَالِيَّۃ) to arabskie kobiece imię. Jest to kobiece imię Ali, co oznacza \"wysoki\", \"wywyższony\", \"wyniosły\", \"wzniosły\" lub \"wzrastający\".</p>", "Adene": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aden</b>.</p><p>Aden jest portem i tymczasowym stolicą Jemenu, położonym na brzegu wschodniego wejścia do Morza Czerwonego (Głębia Aden), około 170 km (110 mi) na wschód od szczeliny Bab-el-Mandeb. Miasto liczy około 800 000 mieszkańców.</p>", "Aybuke": "<p>Aybüke jest powszechną kobiecą turską nazwą. Nazwa ta ma znaczenie \"bardzo inteligentna kobieta (królowa), piękna i jasna jak księżyc\".</p>", "Adeen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aden</b>.</p><p>Aden jest portem i tymczasowym stolicą Jemenu, położonym na brzegu wschodniego wejścia do Morza Czerwonego (Głębia Aden), około 170 km (110 mi) na wschód od szczeliny Bab-el-Mandeb. Miasto liczy około 800 000 mieszkańców.</p>", "Anna Nicole": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Annais": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anais</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Andrea Stefania": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Andrea</b>.</p><b>Andrea</b> – żeńska forma łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Andreas\" target=\"_blank\" rel=\"noopener noreferrer\">Andreas</a>, które w języku polskim rozwinęło się w imię <a href=\"https://pl.wikipedia.org/wiki/Andrzej\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej</a>. Polskim odpowiednikiem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzeja</a> (a także <a href=\"https://pl.wikipedia.org/wiki/Andrzeja\" target=\"_blank\" rel=\"noopener noreferrer\">Ondrzeja</a>).", "Arlanda": "W marcu 2026 roku lotnisko Arlanda w Sztokholmie obsłużyło prawie 1,9 mln pasażerów, co oznacza wzrost o około 5 proc. w porównaniu z analogicznym miesiącem rok wcześniej. Jak podała Swedavia&#65279;<a href=\"https://www.wikidata.org/wiki/Q1571428#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>, wzrost objął zarówno ruch międzynarodowy, jak i krajowy. W segmencie zagranicznym obsłużono nieco ponad 1,5 mln pasażerów, a w krajowym blisko 378 tys. osób. Według tych samych danych przez dziesięć lotnisk spółki przewinęło się w marcu około 2,6 mln pasażerów, co również oznacza wzrost o nieco ponad 5 proc. w ujęciu rocznym.", "Anna Katharina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Anna</b>.</p><b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Annabeth": "<p>Annabeth to angielskie imię kobiety, stworzone z połączenia nazw Anna i Beth.</p>", "Antía": "<p>Antonia, Antónia, Antônia lub Antonía to kobiece imię i nazwisko. Jest pochodzenia rzymskiego, używane jako imię kobiet z rodziny Antonius.</p>", "Aleksandra Antonina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Aleksandra</b>.</p><b>Aleksandra</b> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a>: [<a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˌ</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_boczna_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">l</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_p%C3%B3%C5%82otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">ɛ</a><a href=\"https://pl.wikipedia.org/wiki/Akcent_wyrazowy\" target=\"_blank\" rel=\"noopener noreferrer\">ˈ</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">k</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">ã</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_nosowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">n</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">d</a><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a><a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a>], <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Ἀλεξάνδρα) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksander\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander</a> (Ἀλέξανδρος – obrońca ludzi). Imię Aleksandra w Polsce weszło w użycie w XIV wieku, a spopularyzował je m.in. <a href=\"https://pl.wikipedia.org/wiki/Henryk_Sienkiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk Sienkiewicz</a>, nadając to imię <a href=\"https://pl.wikipedia.org/wiki/Aleksandra_Billewicz%C3%B3wna\" target=\"_blank\" rel=\"noopener noreferrer\">bohaterce</a> <i><a href=\"https://pl.wikipedia.org/wiki/Potop_(powie%C5%9B%C4%87)\" target=\"_blank\" rel=\"noopener noreferrer\">Potopu</a></i>.", "Abygail": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Abigail</b>.</p><b>Abigail</b>, <b>Abigajl</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od hebrajskiego imienia אביגיל <i>Awigajil</i> znaczącego „radość ojca”, „mój ojciec się uradował”.", "Akvile": "<p>Akvilė to litewska żeńska nazwa. Mieszkańcy nazwiska Akvilė to: Akvilė Gedraitytė (ur. 2001), litewskie rowerzystka wyścigowa Akvilė Paražinskaitė (ur., 1996), litewskiej tenistki Akvilė Stapušaitytė (UR. 1986), litewskiego badmintonisty</p>", "Adeli": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Adel</b>.</p><p>Adel - wieloznaczny termin.</p>"};
